def _setup_panic(title="Setup Error", body="", detail="", setup_root=None):
    """Setup crash dialog — styled like the main app crash screen.
    Shows EXIT APPLICATION + VIEW LOG buttons, blocks setup window."""
    import sys as _s, os as _os, traceback as _tb
    _BG   = "#0d0d14"
    _PNL  = "#11111b"
    _BRD  = "#313244"
    _RED  = "#f38ba8"
    _ORG  = "#fab387"
    _DIM  = "#585b70"
    _GRN  = "#a6e3a1"
    _GRN2 = "#1a2a1a"

    try:
        import datetime as _dt
        _log_dir = globals().get("DEBUG_DIR") or _os.path.join(
            _os.path.dirname(_os.path.dirname(_os.path.abspath(_s.argv[0]))),
            "v0rtex_utils", "debug_log", "crash_log")
        _os.makedirs(_log_dir, exist_ok=True)
        _ts = _dt.datetime.now().strftime("%Y%m%d_%H%M%S")
        _crash_path = _os.path.join(_log_dir, f"SETUP_CRASH_{_ts}.txt")
        with open(_crash_path, "w", encoding="utf-8", errors="replace") as _cf:
            _cf.write(f"V0RTEX Setup Crash — {_ts}\n")
            _cf.write(f"Title : {title}\n")
            _cf.write(f"Body  : {body}\n\n")
            _cf.write(detail or "(no traceback)")
    except Exception:
        _crash_path = None

    try:
        import tkinter as _t

        if setup_root:
            try:
                setup_root.grab_release()
            except Exception: pass
            try:
                setup_root.attributes("-disabled", True)
            except Exception: pass

        _r = _t.Tk()
        _r.withdraw()
        _r.title(f"V0RTEX Setup — {title}")
        _r.configure(bg=_BG)
        _r.resizable(False, False)
        W, H = 680, 500
        sw, sh = _r.winfo_screenwidth(), _r.winfo_screenheight()
        _r.geometry(f"{W}x{H}+{(sw-W)//2}+{(sh-H)//2}")
        _r.attributes("-topmost", True)

        tbar = _t.Frame(_r, bg="#1a0010", pady=6, padx=14)
        tbar.pack(fill="x")
        _t.Label(tbar, text="  ● ● ●   SETUP CRASH — V0RTEX",
                 font=("Consolas", 9), bg="#1a0010", fg=_DIM).pack(side=_t.LEFT)

        _t.Frame(_r, bg=_RED, height=2).pack(fill="x")
        _t.Label(_r, text="⚠  " + title.upper(),
                 font=("Consolas", 13, "bold"),
                 bg=_BG, fg=_RED).pack(pady=(18, 4))
        if body:
            _t.Label(_r, text=body,
                     font=("Consolas", 9), bg=_BG, fg=_ORG,
                     wraplength=640, justify="center").pack(pady=(0, 8))
        _t.Frame(_r, bg=_BRD, height=1).pack(fill="x", padx=16)

        tb_frame = _t.Frame(_r, bg=_PNL)
        tb_frame.pack(fill="both", expand=True, padx=16, pady=8)

        _sc = _t.Scrollbar(tb_frame, bg=_BRD, width=7,
                           troughcolor=_PNL, relief="flat")
        _sc.pack(side="right", fill="y")
        _tx = _t.Text(tb_frame, bg=_PNL, fg=_DIM,
                      font=("Consolas", 8), relief="flat", bd=0,
                      padx=10, pady=8, wrap="word",
                      yscrollcommand=_sc.set, state="disabled")
        _sc.config(command=_tx.yview)
        _tx.pack(fill="both", expand=True)
        if detail:
            _tx.config(state="normal")
            _tx.insert("end", detail)
            _tx.see("end")
            _tx.config(state="disabled")

        _t.Frame(_r, bg=_BRD, height=1).pack(fill="x", padx=16)
        bot = _t.Frame(_r, bg="#11111b", pady=10, padx=14)
        bot.pack(fill="x")

        def _exit_app():
            try: _r.destroy()
            except Exception: pass
            if setup_root:
                try: setup_root.destroy()
                except Exception: pass
            try:
                import os as _ose
                _ose._exit(1)
            except Exception:
                pass
            _s.exit(1)

        def _view_log():
            if not _crash_path or not _os.path.exists(_crash_path):
                return
            lw = _t.Toplevel(_r)
            lw.title("Setup Crash Log")
            lw.geometry("700x460")
            lw.configure(bg=_BG)
            lw.attributes("-topmost", True)
            try: _r.grab_release(); lw.grab_set()
            except Exception: pass
            lbar = _t.Frame(lw, bg="#11111b", pady=5, padx=10)
            lbar.pack(fill=_t.X)
            _t.Label(lbar, text=f"  ● ● ●   {_os.path.basename(_crash_path)}",
                     font=("Consolas", 9), bg="#11111b", fg=_DIM).pack(side=_t.LEFT)
            def _close_lw():
                try: lw.grab_release(); _r.grab_set()
                except Exception: pass
                try: lw.destroy()
                except Exception: pass
            _t.Button(lbar, text=" ✕ ", command=_close_lw,
                      bg="#11111b", fg=_DIM, font=("Consolas", 9),
                      relief="flat", bd=0, cursor="hand2").pack(side=_t.RIGHT)
            lw.protocol("WM_DELETE_WINDOW", _close_lw)
            sc2 = _t.Scrollbar(lw, orient="vertical", bg=_BRD,
                               troughcolor=_BG, relief="flat", bd=0, width=7)
            sc2.pack(side=_t.RIGHT, fill=_t.Y)
            txt2 = _t.Text(lw, bg=_PNL, fg=_GRN,
                           font=("Consolas", 8), relief="flat", bd=0,
                           padx=10, pady=8, wrap="word",
                           yscrollcommand=sc2.set, state="disabled")
            sc2.config(command=txt2.yview)
            txt2.pack(fill=_t.BOTH, expand=True)
            try:
                with open(_crash_path, encoding="utf-8", errors="replace") as _lf:
                    _lc = _lf.read()
            except Exception as _re:
                _lc = f"Could not read log: {_re}"
            txt2.config(state="normal")
            txt2.insert(_t.END, _lc)
            txt2.see(_t.END)
            txt2.config(state="disabled")
            def _copy_panic_log():
                try:
                    _r.clipboard_clear()
                    _r.clipboard_append(txt2.get("1.0", _t.END).strip())
                except Exception: pass
            _btm2 = _t.Frame(lw, bg=_BG); _btm2.pack(side=_t.BOTTOM, fill=_t.X, pady=6, padx=10)
            _t.Button(_btm2, text="⎘ Copy Log", command=_copy_panic_log,
                      bg=_BRD, fg=_GRN, font=("Consolas", 9),
                      relief="flat", padx=10, pady=5,
                      cursor="hand2", bd=0).pack(side=_t.LEFT)
            _t.Button(_btm2, text="  Close  ", command=_close_lw,
                      bg=_BRD, fg=_DIM, font=("Consolas", 9),
                      relief="flat", padx=10, pady=5,
                      cursor="hand2", bd=0).pack(side=_t.RIGHT)

        _t.Button(bot, text="  ⛔  EXIT APPLICATION  ",
                  command=_exit_app,
                  bg=_RED, fg=_BG, font=("Consolas", 10, "bold"),
                  relief="flat", padx=14, pady=8,
                  cursor="hand2", bd=0,
                  activebackground="#a6040c").pack(side=_t.LEFT, padx=(0, 6))

        _t.Button(bot, text="  📋  VIEW LOG  ",
                  command=_view_log,
                  bg=_GRN2, fg=_GRN, font=("Consolas", 10, "bold"),
                  relief="flat", padx=14, pady=8,
                  cursor="hand2", bd=0).pack(side=_t.LEFT, padx=4)

        def _view_session_log_panic():
            _dbg = globals().get("DEBUG_DIR") or _os.path.join(
                _os.path.dirname(_os.path.dirname(_os.path.abspath(_s.argv[0]))),
                "v0rtex_utils", "debug_log")
            _slw = _t.Toplevel(_r)
            _slw.title("Session Log — debug_log/")
            _slw.geometry("720x480")
            _slw.configure(bg=_BG)
            _slw.attributes("-topmost", True)
            try: _r.grab_release(); _slw.grab_set()
            except Exception: pass
            def _close_slw():
                try: _slw.grab_release(); _r.grab_set()
                except Exception: pass
                try: _slw.destroy()
                except Exception: pass
            _slw.protocol("WM_DELETE_WINDOW", _close_slw)
            _slh = _t.Frame(_slw, bg="#11111b", pady=5, padx=10); _slh.pack(fill=_t.X)
            _t.Label(_slh, text="  ● ● ●   SESSION LOG — debug_log/",
                     font=("Consolas", 9), bg="#11111b", fg=_DIM).pack(side=_t.LEFT)
            _t.Button(_slh, text=" ✕ ", command=_close_slw,
                      bg="#11111b", fg=_DIM, font=("Consolas", 9),
                      relief="flat", bd=0, cursor="hand2").pack(side=_t.RIGHT)
            _sl_sc = _t.Scrollbar(_slw, orient="vertical", bg=_BRD,
                                   troughcolor=_BG, relief="flat", bd=0, width=7)
            _sl_sc.pack(side=_t.RIGHT, fill=_t.Y)
            _sl_txt = _t.Text(_slw, bg="#11111b", fg=_GRN,
                              font=("Consolas", 8), relief="flat", bd=0,
                              padx=10, pady=8, wrap="word", state="disabled",
                              yscrollcommand=_sl_sc.set)
            _sl_sc.config(command=_sl_txt.yview)
            _sl_txt.pack(fill=_t.BOTH, expand=True)
            _log_content = ""
            try:
                for _sd in (_os.path.join(_dbg, "session_log"), _dbg):
                    if _os.path.isdir(_sd):
                        _cands = sorted([f for f in _os.listdir(_sd) if f.endswith(".txt")], reverse=True)
                        if _cands:
                            with open(_os.path.join(_sd, _cands[0]), encoding="utf-8", errors="replace") as _lf:
                                _log_content = _lf.read()
                            break
            except Exception as _le:
                _log_content = f"Could not read session log: {_le}"
            if not _log_content:
                _log_content = detail or "No session log found."
            _sl_txt.config(state="normal")
            _sl_txt.insert(_t.END, _log_content)
            _sl_txt.see(_t.END)
            _sl_txt.config(state="disabled")
            _slbtm = _t.Frame(_slw, bg=_BG); _slbtm.pack(side=_t.BOTTOM, fill=_t.X, pady=6, padx=10)
            _t.Button(_slbtm, text="⎘ Copy", command=lambda: (
                _r.clipboard_clear(), _r.clipboard_append(_sl_txt.get("1.0", _t.END).strip())),
                bg=_BRD, fg=_GRN, font=("Consolas", 9),
                relief="flat", padx=10, pady=5, cursor="hand2", bd=0).pack(side=_t.LEFT)
            _t.Button(_slbtm, text="  Close  ", command=_close_slw,
                      bg=_BRD, fg=_DIM, font=("Consolas", 9),
                      relief="flat", padx=10, pady=5, cursor="hand2", bd=0).pack(side=_t.RIGHT)

        def _safe_exit_panic():
            try: _r.destroy()
            except Exception: pass
            if setup_root:
                try: setup_root.destroy()
                except Exception: pass
            try:
                import os as _ose2; _ose2._exit(0)
            except Exception: pass
            _s.exit(0)

        _t.Button(bot, text="  📄  SESSION LOG  ",
                  command=_view_session_log_panic,
                  bg="#1e2a3a", fg="#89b4fa", font=("Consolas", 10, "bold"),
                  relief="flat", padx=14, pady=8,
                  cursor="hand2", bd=0).pack(side=_t.LEFT, padx=4)

        _t.Button(bot, text="  ✓  SAFE EXIT  ",
                  command=_safe_exit_panic,
                  bg="#1a2a1a", fg=_GRN, font=("Consolas", 10, "bold"),
                  relief="flat", padx=14, pady=8,
                  cursor="hand2", bd=0).pack(side=_t.LEFT, padx=4)

        if _crash_path:
            _t.Label(bot, text=f"  log: {_os.path.basename(_crash_path)}",
                     font=("Consolas", 7), bg="#11111b", fg=_DIM).pack(side=_t.RIGHT)

        _r.deiconify()
        _r.lift()
        _r.focus_force()
        try: _r.grab_set()
        except Exception: pass
        _r.mainloop()

    except Exception as _fe:
        print(f"[SETUP CRASH] {title}: {body}\n{detail}\n[panic renderer failed: {_fe}]")
    _s.exit(1)


def _ensure_admin():
    import sys as _s, os as _o, platform as _pf, subprocess as _sp, re as _re
    system = _pf.system()

    _UUID_RE = _re.compile(
        r';[0-9a-f]{8}-[0-9a-f]{4}-[0-9a-f]{4}-[0-9a-f]{4}-[0-9a-f]{12}$',
        _re.IGNORECASE)
    _clean_argv = [_UUID_RE.sub('', a) for a in _s.argv]
    if _clean_argv:
        _clean_argv[0] = _o.path.abspath(_clean_argv[0])

    if system == "Windows":
        try:
            import ctypes
            if ctypes.windll.shell32.IsUserAnAdmin():
                return
        except Exception:
            pass
        try:
            import ctypes, subprocess as _sp2
            params = _sp2.list2cmdline(_clean_argv)
            ret = ctypes.windll.shell32.ShellExecuteW(
                None, _RUN_AS, _s.executable, params, None, 1)
            if ret > 32:
                _s.exit(0)
            else:
                _setup_panic(
                    "Admin Required",
                    "V0RTEX Setup requires administrator privileges.",
                    f"ShellExecute returned {ret} — UAC was likely declined."
                )
        except Exception as _e:
            _setup_panic("Admin Required",
                         "Could not request elevation.",
                         str(_e))

    elif system in ("Linux", "Darwin"):
        if _o.geteuid() == 0:
            return
        try:
            _sp.check_call(["sudo", _s.executable] + _clean_argv)
            _s.exit(0)
        except Exception as _e:
            _setup_panic("Admin Required",
                         "Run v0rtex.py with sudo for first-time setup.",
                         str(_e))


