SELF_HASH_PATH    = os.path.join(os.path.dirname(SELF_PATH), "guardian_hash.txt")
STARTUP_GRACE     = ARGS.startup_grace
STARTUP_T         = time.time()

FORBIDDEN_PATHS = [
    os.path.normcase(os.path.join(BASE_DIR, "config.json")),
    os.path.normcase(SELF_PATH),
    os.path.normcase(os.path.join(BASE_DIR, "v0rtex.py")),
]
FORBIDDEN_PREFIXES = [
    os.path.normcase(BASE_DIR + os.sep),
]
ALLOWED_WRITE_PREFIXES = [
    os.path.normcase(AI_WORK   + os.sep),
    os.path.normcase(AI_INPUT  + os.sep),
    os.path.normcase(AI_OUTPUT + os.sep),
]

_VIOLATION_LOCK = threading.Lock()
