def _log(msg):
    ts = time.strftime("%Y-%m-%dT%H:%M:%S")
    print(f"[{ts}] [GUARDIAN] {msg}", flush=True)

def _write_gate_log(entry: dict):
    try:
        existing = []
        if os.path.isfile(GATE_LOG):
            try:
                with open(GATE_LOG, "r", encoding="utf-8") as f:
                    existing = json.load(f)
            except Exception: pass
        existing.append(entry)
        with open(GATE_LOG, "w", encoding="utf-8") as f:
            json.dump(existing[-500:], f, indent=2)
    except Exception: pass

def _hash_file(path: str) -> str:
    try:
        h = hashlib.sha256()
        with open(path, "rb") as f:
            for chunk in iter(lambda: f.read(65536), b""): h.update(chunk)
        return h.hexdigest()
    except Exception: return ""

def _check_self_integrity() -> bool:
    current = _hash_file(SELF_PATH)
    if not current:
        return True
    vx_hash_path = os.path.join(os.path.dirname(SELF_PATH), "vx_ai_guardian_hash.txt")
    try:
        if os.path.isfile(vx_hash_path):
            with open(vx_hash_path, "r", encoding="utf-8") as f:
                vx_stored = f.read().strip()
            if vx_stored and vx_stored == current:
                with open(SELF_HASH_PATH, "w", encoding="utf-8") as f:
                    f.write(current)
                return True
    except Exception:
        pass
    try:
        if os.path.isfile(SELF_HASH_PATH):
            with open(SELF_HASH_PATH, "r", encoding="utf-8") as f:
                stored = f.read().strip()
            if stored and stored != current:
                try:
                    if os.path.isfile(vx_hash_path):
                        with open(vx_hash_path, "r", encoding="utf-8") as f:
                            vx2 = f.read().strip()
                        if vx2 and vx2 == current:
                            with open(SELF_HASH_PATH, "w", encoding="utf-8") as f:
                                f.write(current)
                            return True
                except Exception:
                    pass
                _log(f"INTEGRITY FAIL: self hash mismatch — stored={stored[:16]} current={current[:16]}")
                return False
        else:
            with open(SELF_HASH_PATH, "w", encoding="utf-8") as f:
                f.write(current)
    except Exception:
        pass
    return True

def _is_forbidden_write(path: str) -> bool:
    nc = os.path.normcase(os.path.abspath(path))
    for _pfx in ALLOWED_WRITE_PREFIXES:
        if nc.startswith(_pfx): return False
    if nc in FORBIDDEN_PATHS: return True
    for pfx in FORBIDDEN_PREFIXES:
        if nc.startswith(pfx): return True
    return False

def _assemble_violation_zip(violation_type: str, target_path: str, tb: str) -> str:
    ts = time.strftime("%Y%m%d_%H%M%S")
    os.makedirs(VIOLS_DIR, exist_ok=True)
    zip_path = os.path.join(VIOLS_DIR, f"violation_{ts}.zip")
