def _panic_token_master(size=250) -> str:
    import hashlib as _h
    raw = secrets.token_urlsafe(max(96, size))
    if len(raw) < size:
        raw = (raw + _h.sha256(raw.encode("utf-8", errors="ignore")).hexdigest())
    tok = raw[: size]
    seg = max(24, size // 5)
    parts = [tok[i:i+seg] for i in range(0, min(len(tok), seg*5), seg)]
    return ".".join(parts)

def _panic_token_thread(tid: str) -> str:
    t = secrets.token_urlsafe(32)
    _PANIC_TOKENS["threads"][tid] = t
    return t

def _panic_token_admin_mgr() -> str:
    _PANIC_TOKENS["admin_manager"] = secrets.token_urlsafe(40)[:64]
    return _PANIC_TOKENS["admin_manager"]

def _panic_token_prefix(tok: str) -> str:
    return str(tok or "")[:8] if tok else "none"

def panic_register_thread(thread_id: str, label: str, get_state_fn=None, stop_fn=None):
    with _PANIC_LOCK:
        _PANIC_REGISTRY["threads"][thread_id] = {
            "label": label,
            "state": "idle",
            "last_heartbeat_ts": "",
            "token": _panic_token_thread(thread_id),
            "get_state_fn": get_state_fn,
            "stop_fn": stop_fn,
            "error": "",
        }

def panic_set_thread_state(thread_id: str, state: str, details=None):
    with _PANIC_LOCK:
        t = _PANIC_REGISTRY["threads"].get(thread_id)
        if t:
            t["state"] = state
            t["last_heartbeat_ts"] = time.strftime("%Y-%m-%d %H:%M:%S")
            if details:
                t["last_details"] = details

def panic_heartbeat(thread_id: str, details=None):
    with _PANIC_LOCK:
        t = _PANIC_REGISTRY["threads"].get(thread_id)
        if t:
            t["last_heartbeat_ts"] = time.strftime("%Y-%m-%d %H:%M:%S")
            if details:
                t["last_details"] = details

def panic_broadcast(event: str):
    with _PANIC_LOCK:
        _PANIC_REGISTRY.setdefault("broadcasts", []).append({
            "ts": time.strftime("%Y-%m-%d %H:%M:%S"),
            "event": event,
            "threads": list(_PANIC_REGISTRY["threads"].keys()),
        })
        for tid, t in list(_PANIC_REGISTRY["threads"].items()):
            sf = t.get("stop_fn")
            if event in ("panic_stop", "panic_abort") and callable(sf):
                try:
                    sf()
                except Exception:
                    pass

