def _ai_read_limited_json_body(resp, max_bytes: int):
    buf = bytearray()
    while True:
        chunk = resp.read(65536)
        if not chunk:
            break
        if len(buf) + len(chunk) > max_bytes:
            raise ValueError("response_too_large")
        buf.extend(chunk)
    return json.loads(buf.decode("utf-8"))

def _ai_urlopen_request(req, timeout):
    import ssl as _ssl_oll
    import urllib.request as _uqr_oll
    from urllib.parse import urlparse as _up_oll
    try:
        url_s = req.full_url
    except Exception:
        url_s = req.get_full_url()
    if _up_oll(url_s).scheme.lower() == "https":
        return _uqr_oll.urlopen(req, timeout=timeout, context=_ssl_oll.create_default_context())
    return _uqr_oll.urlopen(req, timeout=timeout)

