def _checkpoint(phase: str, detail: str = ""):
    """
    Record a detailed checkpoint.
    Output destinations: debug_log file  +  CHECKPOINTS settings tab only.
    """
    try:
        _ckpt_counter[0] += 1
        ts  = _dt.datetime.now().strftime("%H:%M:%S.%f")[:-3]
        n   = _ckpt_counter[0]
        msg = f"[CKPT #{n:04d}] [{phase:<8}] {detail}"
        _session_log(msg, level="CHKPT")

        entry = (ts, n, phase, detail)
        _ckpt_buffer.append(entry)

        widget = _ckpt_txt_ref[0]
        if widget is not None:
            try:
                color = _CKPT_COLORS.get(phase.upper(), "#cdd6f4")
                def _push(e=entry, c=color):
                    _ts, _n, _ph, _det = e
                    widget.config(state="normal")
                    widget.insert("end", f"[{_ts}] ", "DIM")
                    widget.insert("end", f"#{_n:04d} ", "NUM")
                    widget.insert("end", f"[{_ph:<8}] ", ("PHASE", f"PH_{_ph}"))
                    if _det:
                        widget.insert("end", f"{_det}\n", "DETAIL")
                    else:
                        widget.insert("end", "\n", "DIM")
                    widget.see("end")
                    widget.config(state="disabled")
                try:
                    widget.after(0, _push)
                except Exception:
                    pass
            except Exception:
                pass
    except Exception:
        pass


