def _auto_gc(label: str = ""):
    """Run Python GC if enabled in settings. Thread-safe, never raises."""
    try:
        if not CONFIG.get("auto_gc_enabled", True):
            return
        cooldown = float(CONFIG.get("auto_gc_cooldown_sec", 2.0))
        import time as _t
        now = _t.monotonic()
        if now - _gc_last_run[0] < cooldown:
            return
        _gc_last_run[0] = now

        mode = CONFIG.get("auto_gc_mode", "gen0")
        if mode == "full":
            n = _gc.collect(2)
        elif mode == "gen1":
            n = _gc.collect(1)
        else:
            n = _gc.collect(0)

        _gc_run_count[0] += 1
        if CONFIG.get("debug_mode", False) and n:
            _checkpoint("GC", f"[{label}] freed {n} object(s)  mode={mode}  run#{_gc_run_count[0]}")
    except Exception:
        pass

