        dm = str(def_mode_sv.get() or "normal").lower().strip()
        if dm not in ("normal", "unmanaged"):
            dm = "normal"
        c["admin_manager_default_mode"] = dm
        c["admin_manager_session_ttl_s"] = max(30, min(300, int(sess_ttl_sv.get().strip() or "120")))
        c["admin_manager_request_timeout_ms"] = max(500, min(20000, int(req_to_sv.get().strip() or "2500")))
        c["admin_mode_enabled"] = bool(enabled_sv.get())
        c["admin_manager_admin"] = bool(enabled_sv.get())
        al_raw = al_txt.get("1.0", "end")
        paths = [ln.strip() for ln in al_raw.splitlines() if ln.strip()]
        c["admin_manager_allowed_processes"] = paths
        wl_raw = wl_txt.get("1.0", "end")
        wl = [ln.strip() for ln in wl_raw.splitlines() if ln.strip()]
        c["admin_manager_cmd_whitelist"] = wl
