def _deploy_admin_manager():
    try:
        # Deploy to V0rtex_System/v0rtex_utils (where _request_admin_elevation looks)
        _vx_dir = os.path.join(BASE_DIR, "V0rtex_System", "v0rtex_utils")
        os.makedirs(_vx_dir, exist_ok=True)
        adm_path = os.path.join(_vx_dir, "admin_manager.py")
        with open(adm_path, "w", encoding="utf-8") as f:
            f.write(_ADMIN_MANAGER_SOURCE.lstrip("\n"))
        return adm_path
    except Exception as e:
        _sl(f"Admin Manager deploy failed: {e}", "WARN")
        return ""

_ADMIN_MGR_PROC = [None]
_ADMIN_MGR_SESSION = {"session_id": "", "token": "", "expires_at": 0.0}
_ADMIN_JOBS = {}

def _admin_job_spawn(job_label: str, work_fn, done_fn=None):
    try:
        import secrets as _sec
        jid = _sec.token_urlsafe(12)[:16]
    except Exception:
        jid = str(int(time.time() * 1000))
    try:
        _ADMIN_JOBS[jid] = {"label": str(job_label or "admin_job"), "ts": time.time(), "done": False}
    except Exception:
        pass
    def _runner():
        res = None
        err = None
        try:
            res = work_fn()
        except Exception as _e:
            err = _e
        try:
            _ADMIN_JOBS[jid]["done"] = True
            _ADMIN_JOBS[jid]["ended_ts"] = time.time()
            if err is not None:
                _ADMIN_JOBS[jid]["error"] = str(err)
        except Exception:
            pass
        if done_fn:
            try:
                def _cb():
                    try:
                        done_fn(res, err)
                    except Exception:
                        pass
                root.after(0, _cb)
            except Exception:
                try:
                    done_fn(res, err)
                except Exception:
                    pass
    try:
        t = threading.Thread(target=_runner, daemon=True, name=f"ADMINJOB:{jid}:{job_label}"[:60])
        t.start()
        try:
            _ADMIN_JOBS[jid]["thread"] = t.name
        except Exception:
            pass
        return jid
    except Exception:
        try:
            _runner()
        except Exception:
            pass
        return ""

def _admin_mgr_get_auth_key() -> str:
    try:
        k = str(CONFIG.get("admin_manager_auth_key", "") or "")
        if len(k) < 48:
            import secrets as _sec
            k = _sec.token_urlsafe(72)[:96]
            CONFIG["admin_manager_auth_key"] = k
            try:
                _vx_cfg_write(CONFIG)
            except Exception:
                pass
        return k
    except Exception:
        return ""

def _admin_mgr_get_allowed_processes() -> list[str]:
    """Return normalized allowlist for Admin Manager caller process paths."""
    try:
        raw = CONFIG.get("admin_manager_allowed_processes", [])
        allowed = []
        if isinstance(raw, list):
            for p in raw:
                ps = str(p or "").strip()
                if ps:
                    allowed.append(os.path.normcase(os.path.abspath(ps)))
        
        defaults = [os.path.normcase(os.path.abspath(sys.executable))]
        try:
            defaults.append(os.path.normcase(os.path.abspath(__file__)))
        except Exception:
            pass
        for d in defaults:
            if d and d not in allowed:
                allowed.append(d)
        CONFIG["admin_manager_allowed_processes"] = allowed
        try:
            _vx_cfg_write(CONFIG)
        except Exception:
            pass
        return allowed
    except Exception:
        return []

def _start_admin_manager():
    
    try:
        if _ADMIN_MGR_PROC[0] and getattr(_ADMIN_MGR_PROC[0], "poll", lambda: None)() is None:
            return
    except Exception:
        pass
    adm_path = _deploy_admin_manager()
    if not adm_path:
        return
    try:
        pipe_name = str(CONFIG.get("admin_manager_pipe", r"\\.\pipe\V0RTEX_AdminManager") or r"\\.\pipe\V0RTEX_AdminManager")
        auth_key = _admin_mgr_get_auth_key()
        _admin_mgr_get_allowed_processes()
        
        hibernate = not bool(CONFIG.get("admin_manager_admin", False))
        args = [sys.executable, adm_path, "--base-dir", BASE_DIR, "--config-path", CONFIG_PATH,
                "--pipe-name", pipe_name, "--auth-key", auth_key]
        if hibernate:
            args.append("--hibernate")
        _kw = {"creationflags": subprocess.CREATE_NO_WINDOW} if sys.platform == "win32" else {}
        _p = subprocess.Popen(args, **_kw)
        _ADMIN_MGR_PROC[0] = _p
        _sl(f"Admin Manager started  pid={getattr(_p,'pid','?')}  hibernate={hibernate}", "INIT")
    except Exception as e:
        _sl(f"Admin Manager start failed: {e}", "WARN")

def _admin_mgr_restart_orchestrated(wait_ms: int = 4500, ping_retries: int = 5) -> tuple[bool, str]:
    try:
        p = _ADMIN_MGR_PROC[0]
        if p and getattr(p, "poll", lambda: None)() is None:
            try:
                p.terminate()
            except Exception:
                pass
            t0 = time.time()
            while (time.time() - t0) * 1000.0 < int(max(500, wait_ms)):
                try:
                    if getattr(p, "poll", lambda: None)() is not None:
                        break
                except Exception:
                    break
                time.sleep(0.08)
            try:
                if getattr(p, "poll", lambda: None)() is None:
                    p.kill()
            except Exception:
                pass
        _ADMIN_MGR_SESSION["session_id"] = ""
        _ADMIN_MGR_SESSION["token"] = ""
        _ADMIN_MGR_SESSION["expires_at"] = 0.0
        _start_admin_manager()
        for _ in range(int(max(1, ping_retries))):
            r = _admin_mgr_request({"type": "PING"}, timeout_ms=1200)
            if r.get("ok"):
                try:
                    _ap = CONFIG.get("admin_manager_allowed_processes", [])
                    if isinstance(_ap, list) and _ap:
                        _gs_admin_mgr_allowed_paths[:] = [str(p).strip() for p in _ap if str(p).strip()]
                except Exception:
                    pass
                return True, "ok"
            time.sleep(0.35)
        return False, "ping_timeout_after_restart"
    except Exception as e:
        return False, f"restart_exception:{e}"

try:
    _start_admin_manager()
except Exception:
    pass

def _admin_mgr_request(req: dict, timeout_ms: int = 2500) -> dict:
    """Client for Admin Manager named pipe. Returns dict; never raises."""
    try:
        if sys.platform != "win32":
            return {"ok": False, "error": "platform_not_supported"}
        import ctypes as _ct
        import json as _json
        from ctypes import wintypes as _wt

        pipe = str(CONFIG.get("admin_manager_pipe", r"\\.\pipe\V0RTEX_AdminManager") or r"\\.\pipe\V0RTEX_AdminManager")
        try:
            timeout_ms = int(CONFIG.get("admin_manager_request_timeout_ms", timeout_ms) or timeout_ms)
        except Exception:
            timeout_ms = timeout_ms

        WaitNamedPipeW = _ct.windll.kernel32.WaitNamedPipeW
        WaitNamedPipeW.argtypes = [_wt.LPCWSTR, _wt.DWORD]
        WaitNamedPipeW.restype = _wt.BOOL
        if not WaitNamedPipeW(pipe, int(timeout_ms)):
            return {"ok": False, "error": f"pipe_wait_fail:{_ct.get_last_error()}"}

        GENERIC_READ = 0x80000000
        GENERIC_WRITE = 0x40000000
        OPEN_EXISTING = 3
        INVALID_HANDLE_VALUE = _wt.HANDLE(-1).value

        CreateFileW = _ct.windll.kernel32.CreateFileW
        CreateFileW.argtypes = [_wt.LPCWSTR, _wt.DWORD, _wt.DWORD, _wt.LPVOID, _wt.DWORD, _wt.DWORD, _wt.HANDLE]
        CreateFileW.restype = _wt.HANDLE

        ReadFile = _ct.windll.kernel32.ReadFile
        ReadFile.argtypes = [_wt.HANDLE, _wt.LPVOID, _wt.DWORD, _ct.POINTER(_wt.DWORD), _wt.LPVOID]
        ReadFile.restype = _wt.BOOL

        WriteFile = _ct.windll.kernel32.WriteFile
        WriteFile.argtypes = [_wt.HANDLE, _wt.LPCVOID, _wt.DWORD, _ct.POINTER(_wt.DWORD), _wt.LPVOID]
        WriteFile.restype = _wt.BOOL

        CloseHandle = _ct.windll.kernel32.CloseHandle
        CloseHandle.argtypes = [_wt.HANDLE]
        CloseHandle.restype = _wt.BOOL

        h = CreateFileW(pipe, GENERIC_READ | GENERIC_WRITE, 0, None, OPEN_EXISTING, 0, None)
        if h == INVALID_HANDLE_VALUE:
            return {"ok": False, "error": f"pipe_open_fail:{_ct.get_last_error()}"}
        try:
            payload = (_json.dumps(req, ensure_ascii=False) + "\n").encode("utf-8", errors="replace")
            nw = _wt.DWORD(0)
            if not WriteFile(h, payload, len(payload), _ct.byref(nw), None):
                return {"ok": False, "error": f"pipe_write_fail:{_ct.get_last_error()}"}
            buf = _ct.create_string_buffer(65536)
            nr = _wt.DWORD(0)
            if not ReadFile(h, buf, 65536, _ct.byref(nr), None):
                return {"ok": False, "error": f"pipe_read_fail:{_ct.get_last_error()}"}
            raw = buf.raw[:nr.value].decode("utf-8", errors="replace").strip()
            try:
                return _json.loads(raw) if raw else {"ok": False, "error": "empty_reply"}
            except Exception:
                return {"ok": False, "error": "invalid_json_reply", "raw": raw}
        finally:
            try:
                CloseHandle(h)
            except Exception:
                pass
    except Exception as e:
        return {"ok": False, "error": str(e)}

def _admin_mgr_open_secure_session(ttl_s: int = 120) -> dict:
    """Open or reuse authenticated Admin Manager session."""
    try:
        import secrets as _sec
        import time as _time
        import hmac as _hmac
        import hashlib as _hashlib
        try:
            ttl_s = int(CONFIG.get("admin_manager_session_ttl_s", ttl_s) or ttl_s)
        except Exception:
            ttl_s = ttl_s

        now = _time.time()
        sid = str(_ADMIN_MGR_SESSION.get("session_id", ""))
        tok = str(_ADMIN_MGR_SESSION.get("token", ""))
        exp = float(_ADMIN_MGR_SESSION.get("expires_at", 0.0) or 0.0)
        if sid and tok and (now + 10.0) < exp:
            return {"ok": True, "session_id": sid, "token": tok, "expires_at": exp, "cached": True}

        chall = _admin_mgr_request({"type": "AUTH_CHALLENGE"})
        if not chall.get("ok"):
            return chall

        auth_key = _admin_mgr_get_auth_key()
        if not auth_key:
            return {"ok": False, "error": "auth_key_missing"}

        sid = _sec.token_urlsafe(18)[:32]
        tok = _sec.token_urlsafe(75)[:100]
        client_nonce = _sec.token_urlsafe(18)[:32]
        ts = str(_time.time())
        payload = "|".join([
            sid,
            tok,
            str(chall.get("challenge_id", "")),
            str(chall.get("server_nonce", "")),
            client_nonce,
            str(os.getpid()),
            ts,
        ])
        sig = _hmac.new(auth_key.encode("utf-8"), payload.encode("utf-8"), _hashlib.sha256).hexdigest()
        resp = _admin_mgr_request({
            "type": "OPEN_SESSION",
            "session_id": sid,
            "token": tok,
            "challenge_id": str(chall.get("challenge_id", "")),
            "client_nonce": client_nonce,
            "ts": ts,
            "sig": sig,
            "ttl_s": int(max(30, min(300, ttl_s))),
            "scope": {"caller": "v0rtex.py", "pid": os.getpid()},
        })
        if resp.get("ok"):
            exp = float(resp.get("expires_at", now + 120))
            _ADMIN_MGR_SESSION.update({"session_id": sid, "token": tok, "expires_at": exp})
        return resp
    except Exception as e:
        return {"ok": False, "error": f"open_secure_session_error:{e}"}

def _admin_mgr_secure_call(action: str, payload: dict | None = None, timeout_ms: int = 2500, mode: str = "normal") -> dict:
    """Authenticated call with one-time op token."""
    try:
        import secrets as _sec
        s = _admin_mgr_open_secure_session()
        if not s.get("ok"):
            return s
        req = {
            "type": "CALL",
            "action": str(action or "").upper().strip(),
            "mode": str(mode or "normal").lower().strip(),
            "session_id": str(_ADMIN_MGR_SESSION.get("session_id", "")),
            "token": str(_ADMIN_MGR_SESSION.get("token", "")),
            "op_token": _sec.token_urlsafe(75)[:100],
            "payload": payload or {},
        }
        return _admin_mgr_request(req, timeout_ms=timeout_ms)
    except Exception as e:
        return {"ok": False, "error": f"secure_call_error:{e}"}

def _admin_mode_enabled() -> bool:
    try:
        return bool(CONFIG.get("admin_mode_enabled", False))
    except Exception:
        return False

def _admin_run_cmd_safe(job_label: str, cmd: str, timeout_s: int = 20, danger_action_id: str = "EXEC", done_fn=None):
    def _go():
        def _work():
            return _admin_mgr_secure_call("RUN_CMD_SAFE", {"cmd": str(cmd or ""), "timeout_s": int(timeout_s)}, timeout_ms=int(max(1000, timeout_s * 1000 + 1500)))
        _admin_job_spawn(job_label, _work, done_fn)
    try:
        if not _admin_mode_enabled():
            try:
                messagebox.showwarning("Admin mode", "Admin mode is OFF.\nEnable it in Settings -> 🔑 ADMIN MANAGER, then restart Admin Manager.", parent=root)
            except Exception:
                pass
            return
        _danger_gate(str(danger_action_id or "EXEC"), _go, parent=root)
    except Exception:
        try:
            _go()
        except Exception:
            pass

def _admin_run_cmd_sync(cmd: str, timeout_s: int = 20, mode: str = "normal") -> dict:
    try:
        if not _admin_mode_enabled():
            return {"ok": False, "error": "admin_mode_off"}
        try:
            if not str(mode or "").strip():
                mode = str(CONFIG.get("admin_manager_default_mode", "normal") or "normal")
        except Exception:
            mode = str(mode or "normal")
        return _admin_mgr_secure_call(
            "RUN_CMD_SAFE",
            {"cmd": str(cmd or ""), "timeout_s": int(timeout_s)},
            timeout_ms=int(max(1500, int(timeout_s) * 1000 + 2000)),
            mode=str(mode or "normal"),
        )
    except Exception as e:
        return {"ok": False, "error": f"admin_run_cmd_sync_error:{e}"}

def _run_privileged_cmd(cmd_list, timeout_s: int = 20, mode: str = "normal") -> tuple[str, str, int, str]:
    cmd_str = " ".join(str(x) for x in (cmd_list or [])).strip()
    if not cmd_str:
        return "", "empty_cmd", 1, "local"
    try:
        if _is_admin():
            r = subprocess.run(
                [str(x) for x in cmd_list],
                capture_output=True, text=True,
                creationflags=0x08000000 if sys.platform == "win32" else 0,
                timeout=int(timeout_s),
                stdin=subprocess.DEVNULL,
            )
            return (r.stdout or ""), (r.stderr or ""), int(getattr(r, "returncode", 1)), "local"
    except Exception as e:
        return "", str(e), 1, "local"
    try:
        if not str(mode or "").strip():
            mode = str(CONFIG.get("admin_manager_default_mode", "normal") or "normal")
    except Exception:
        pass
    res = _admin_run_cmd_sync(cmd_str, timeout_s=int(timeout_s), mode=str(mode or "normal"))
    if not bool(res.get("ok", False)):
        return "", str(res.get("error", "admin_manager_error")), 1, "admin_manager"
    out = ""
    err = ""
    rc = 0
    try:
        result = res.get("result", {}) if isinstance(res.get("result", {}), dict) else {}
        out = str(result.get("stdout", "") or "")
        err = str(result.get("stderr", "") or "")
        rc = int(result.get("returncode", 0) or 0)
    except Exception:
        pass
    return out, err, rc, "admin_manager"

def _ai_deploy_embedded_files():
    import hashlib as _hlib
    failsafe_dir = os.path.join(os.path.dirname(BASE_DIR), "VX_FAILSAFE")
    guardian_dst = os.path.join(_AI_PROTECTED, "vx_ai_guardian.py")
    destruct_dst = os.path.join(failsafe_dir, "vx_autodestruction.py")
    deployed = []
    for dst, src_str, label in [
        (guardian_dst, _VXG_SOURCE.lstrip("\n"), "vx_ai_guardian.py"),
        (destruct_dst, _VXD_SOURCE.lstrip("\n"), "vx_autodestruction.py"),
    ]:
        try:
            os.makedirs(os.path.dirname(dst), exist_ok=True)
            os.makedirs(os.path.dirname(dst), exist_ok=True)
            with open(dst, "w", encoding="utf-8") as f:
                f.write(src_str)
            _sl(f"AI deploy: {label} written ({len(src_str)} bytes)", "INIT")
            deployed.append(label)
            try:
                with open(dst, "rb") as _hf: _hbytes = _hf.read()
                h = _hlib.sha256(_hbytes).hexdigest()
                dst_dir = os.path.dirname(dst)
                vx_hash_path = os.path.join(dst_dir, label.replace(".py","_hash.txt"))
                with open(vx_hash_path, "w") as _hf2: _hf2.write(h)
                if label == "vx_ai_guardian.py":
                    grd_hash_path = os.path.join(dst_dir, "guardian_hash.txt")
                    with open(grd_hash_path, "w") as _hf3: _hf3.write(h)
            except Exception: pass
        except Exception as _de:
            _sl(f"AI deploy ERROR for {label}: {_de}", "ERR")
    return deployed

def _ai_startup_silent_check():
    try:
        deployed = _ai_deploy_embedded_files()
        if deployed:
            _sl(f"AI startup: deployed {deployed}", "INIT")
        installed = False
        try:
            r = subprocess.run(["ollama","--version"], capture_output=True, timeout=5,
                               creationflags=0x08000000 if sys.platform=="win32" else 0,
                               stdin=subprocess.DEVNULL)
            installed = r.returncode == 0
        except Exception: pass
        _sl(f"AI startup check — ollama installed: {installed}", "INIT")
        if os.path.isfile(_AI_LOCKDOWN):
            _sl("AI LOCKDOWN flag present — AI module will be locked on startup", "WARN")
    except Exception as _aisc:
        _sl(f"AI startup check error: {_aisc}", "WARN")

def _ai_launch_guardian():
    guardian_src = os.path.join(_AI_PROTECTED, "vx_ai_guardian.py")
    if not os.path.isfile(guardian_src):
        _sl("vx_ai_guardian.py not found in _protected/ — deploy failed?", "WARN")
        return
    try:
        import psutil as _ps_sg
        _g_abs = os.path.normcase(os.path.abspath(guardian_src))
        for _pr in _ps_sg.process_iter(["pid", "cmdline"]):
            try:
                _cl = _pr.info.get("cmdline") or []
                if not _cl:
                    continue
                for _arg in _cl:
                    if not _arg or not str(_arg).lower().endswith(".py"):
                        continue
                    if os.path.normcase(os.path.abspath(str(_arg))) == _g_abs:
                        if int(_pr.info.get("pid") or 0) != int(os.getpid()):
                            try:
                                _pr.terminate()
                            except Exception:
                                pass
                        break
            except Exception:
                pass
    except Exception:
        pass
    try:
        __import__("time").sleep(0.2)
    except Exception:
        pass
    try:
        import hashlib as _hlib
        with open(guardian_src, "rb") as f: ghash = _hlib.sha256(f.read()).hexdigest()
        sentinel_hash_path = os.path.join(_AI_PROTECTED, "vx_ai_guardian_hash.txt")
        grd_self_hash_path = os.path.join(_AI_PROTECTED, "guardian_hash.txt")
        if os.path.isfile(sentinel_hash_path):
            with open(sentinel_hash_path, "r") as f: stored = f.read().strip()
            if stored and stored != ghash:
                _sl("SECURITY: vx_ai_guardian.py hash mismatch — redeploying", "WARN")
                _ai_deploy_embedded_files()
                with open(guardian_src, "rb") as f: ghash = _hlib.sha256(f.read()).hexdigest()
            with open(sentinel_hash_path, "w") as f: f.write(ghash)
            with open(grd_self_hash_path, "w") as f: f.write(ghash)
        else:
            with open(sentinel_hash_path, "w") as f: f.write(ghash)
            with open(grd_self_hash_path, "w") as f: f.write(ghash)
        _sl(f"Guardian integrity OK — hash: {ghash[:16]}...", "INIT")
        _gp = subprocess.Popen([sys.executable, guardian_src,
                          "--watch", BASE_DIR,
                          "--ai-work", _AI_WORK,
                          "--ai-input", _AI_INPUT_DIR,
                          "--ai-output", _AI_OUTPUT_DIR,
                          "--lockdown-flag", _AI_LOCKDOWN,
                          "--gate-log", _AI_GATE_LOG,
                          "--viols-dir", _AI_VIOLS_DIR,
                          "--main-pid", str(os.getpid()),
                          "--write-token-path", _AI_WRITE_TOKEN,
                          "--startup-grace", "90"],
                          creationflags=0x08000000 if sys.platform=="win32" else 0)
        globals()["_GUARDIAN_PROC"] = _gp
        _sl("vx_ai_guardian.py spawned", "INIT")
        try:
            _apids_path = os.path.join(_AI_PROTECTED, "_authorized_pids.json")
            _apids_data = {"pids": [os.getpid()], "updated": __import__("time").strftime("%Y-%m-%dT%H:%M:%S")}
            with open(_apids_path, "w", encoding="utf-8") as _apf:
                __import__("json").dump(_apids_data, _apf)
        except Exception:
            pass
    except Exception as _ge:
        _sl(f"Guardian launch error: {_ge}", "WARN")

threading.Thread(target=lambda: (_ai_startup_silent_check(), _ai_launch_guardian()), daemon=True).start()


