def _compute_threat_score(stats, yara_hits, iocs, entropy):
    import math as _m
    score = 0
    mal = stats.get("malicious", 0)
    sus = stats.get("suspicious", 0)
    score += min(35, mal * 3 + sus)
    yara_list = yara_hits if isinstance(yara_hits, list) else []
    score += min(25, len(yara_list) * 5)
    if entropy >= 7.5:   score += 15
    elif entropy >= 7.0: score += 10
    elif entropy >= 6.5: score += 5
    ioc_dict = iocs if isinstance(iocs, dict) else {}
    total_iocs = sum(len(v) for v in ioc_dict.values() if isinstance(v, list))
    score += min(15, total_iocs * 2)
    yara_str = " ".join(yara_list).lower()
    _SUSP_KW = ["inject","shellcode","meterpreter","cobalt","ransomware","crypt","encrypt",
                "keylog","rat","stealer","banker","trojan","rootkit","backdoor","dropper"]
    bonus = sum(3 for kw in _SUSP_KW if kw in yara_str)
    score += min(10, bonus)
    return min(100, score)

def _auto_tag_scan(stats, yara_hits, pe_info, iocs, entropy, filename):
    tags = set()
    mal = stats.get("malicious", 0)
    yara_list = yara_hits if isinstance(yara_hits, list) else []
    yara_str  = " ".join(str(y) for y in yara_list).lower()
    pe_str    = json.dumps(pe_info).lower() if pe_info else ""
    fname     = os.path.basename(filename).lower()
    ioc_str   = json.dumps(iocs).lower() if iocs else ""
    if any(k in yara_str for k in ["ransomware","crypt","encrypt","vssadmin","wbadmin","shadow"]):
        tags.add("RANSOMWARE")
    if any(k in yara_str for k in ["rat","remote","async","njrat","quasar","remcos","agentesla"]) or \
       any(k in ioc_str  for k in ["agent","rat","c2","command"]):
        tags.add("RAT")
    if any(k in yara_str for k in ["dropper","downloader","loader","stager","dropp"]):
        tags.add("DROPPER")
    if any(k in pe_str   for k in ["upx","aspack","pecompact","themida","vmprotect","obsidium","nsis"]) or \
       any(k in yara_str for k in ["pack","obfusc","protect"]):
        tags.add("PACKER")
    if any(k in yara_str for k in ["banker","stealer","formgrab","credential","keylog","zbot","zeus","emotet","trickbot"]):
        tags.add("BANKER")
    if any(k in yara_str for k in ["inject","shellcode","hollowing","reflectiv","createremote","writeprocess"]):
        tags.add("INJECTOR")
    if any(k in yara_str for k in ["worm","spreader","propagat","smb","eternalblue","wannacry"]):
        tags.add("WORM")
    if mal == 0 and not tags and entropy > 7.0:
        tags.add("SUSPICIOUS")
    if mal == 0 and not tags:
        tags.add("CLEAN")
    return ",".join(sorted(tags))

def _db_save(file, md5, sha1, sha256, stats, yara_hits, pe_info, iocs, entropy, ftype):
    tags = _auto_tag_scan(stats, yara_hits, pe_info, iocs, entropy, file)
    tscore = _compute_threat_score(stats, yara_hits, iocs, entropy)
    with _db_lock:
        try:
            existing = {row[1] for row in _conn.execute("PRAGMA table_info(scans)").fetchall()}
            ftype_col = "file_type" if "file_type" in existing else "filetype"
            has_tags  = "tags" in existing
            has_score = "threat_score" in existing
            cols = (f"file, md5, sha1, sha256, malicious, suspicious, undetected,"
                    f" yara_hits, pe_info, iocs, entropy, {ftype_col}, timestamp")
            vals = [file, md5, sha1, sha256,
                    stats.get("malicious", 0), stats.get("suspicious", 0), stats.get("undetected", 0),
                    json.dumps(yara_hits),
                    json.dumps({k: v for k, v in pe_info.items() if k != "strings"}),
                    json.dumps(iocs), round(entropy, 3), ftype,
                    time.strftime("%Y-%m-%d %H:%M:%S")]
            if has_tags:
                cols += ", tags"; vals.append(tags)
            if has_score:
                cols += ", threat_score"; vals.append(tscore)
            ph = ",".join(["?"] * len(vals))
            _conn.execute(f"INSERT INTO scans ({cols}) VALUES ({ph})", vals)
            _conn.commit()
            _checkpoint("DB", f"Row INSERT OK — {os.path.basename(file)}  mal={stats.get('malicious',0)} tags={tags} score={tscore}")
        except Exception as e:
            _log_debug(f"[DB INSERT ERROR] {e}", "ERROR")
            _checkpoint("DB", f"INSERT FAILED for {os.path.basename(file)}: {e}")

def _db_query(sql, params=()):
    with _db_lock:
        return _conn.execute(sql, params).fetchall()


