def _github_list_yar(owner, repo, path) -> list:
    url = f"https://api.github.com/repos/{owner}/{repo}/contents/{path}"
    try:
        r = requests.get(url, timeout=20, headers={"Accept":"application/vnd.github.v3+json"})
        if r.status_code == 200:
            return [(f["name"], f["download_url"])
                    for f in r.json()
                    if isinstance(f, dict) and f.get("name","").endswith((".yar",".yara"))]
    except Exception:
        pass
    return []

def _download_yar(name: str, url: str, log_fn) -> bool:
    try:
        r = requests.get(url, timeout=30)
        if r.status_code != 200:
            log_fn(f"HTTP {r.status_code} – {name}", "ERROR"); return False
        source = r.text
        try:
            if yara:
                yara.compile(source=source)
        except (yara.Error if yara else Exception) as e:
            log_fn(f"Invalid YARA ({name}): {e}", "WARNING"); return False
        dest = os.path.join(RULES_EXTERN_DIR, name)
        with open(dest, "w", encoding="utf-8") as f:
            f.write(source)
        log_fn(f"Downloaded: {name}", "INFO"); return True
    except Exception as e:
        log_fn(f"Download error ({name}): {e}", "ERROR"); return False


def _get_api_hdr():
    global _key_index
    if not API_KEYS: return {}, -1
    with _key_lock:
        key = API_KEYS[_key_index]; idx = _key_index
        _key_index = (_key_index + 1) % len(API_KEYS)
    return {"x-apikey": key}, idx

def _hash_file(path):
    md5 = hashlib.md5(); sha1 = hashlib.sha1(); sha256 = hashlib.sha256()
    with open(path, "rb") as f:
        while chunk := f.read(8192):
            md5.update(chunk); sha1.update(chunk); sha256.update(chunk)
    return md5.hexdigest(), sha1.hexdigest(), sha256.hexdigest()

def _vt_hash_lookup(sha256, log_fn):
    if requests is None:
        log_fn("requests not available — VT lookup disabled", "WARN")
        return {}
    try:
        hdr, _ = _get_api_hdr()
        hr = requests.get(f"https://www.virustotal.com/api/v3/files/{sha256}",
                          headers=hdr, timeout=30)
        if hr.status_code == 200:
            attrs   = hr.json().get("data",{}).get("attributes",{})
            stats   = attrs.get("last_analysis_stats",   {})
            engines = attrs.get("last_analysis_results", {})
            if stats:
                log_fn(f"VT (hash) – mal={stats.get('malicious',0)} sus={stats.get('suspicious',0)} clean={stats.get('undetected',0)}", "INFO")
                return stats, engines
    except Exception as e:
        log_fn(f"VT hash lookup: {e}", "DEBUG")
    return None

def _vt_scan(path, log_fn):
    empty = {"malicious":0,"suspicious":0,"undetected":0}
    if requests is None:
        log_fn("requests not available — VT scan disabled", "WARN")
        return empty
    sha256 = hashlib.sha256(open(path,"rb").read()).hexdigest()


    log_fn("Checking VT hash database ...", "DEBUG")
    result = _vt_hash_lookup(sha256, log_fn)
    if result:
        return result


    try:
        hdr, kidx = _get_api_hdr()
        log_fn(f"Not in VT yet - uploading (key #{kidx}) ...", "DEBUG")
        with open(path,"rb") as f:
            r = requests.post("https://www.virustotal.com/api/v3/files",
                              headers=hdr, files={"file":f}, timeout=90)
    except Exception as e:
        log_fn(f"VT upload: {e}", "ERROR"); return empty, {}

    analysis_id = None
    if r.status_code == 200:
        try:
            analysis_id = r.json()["data"]["id"]
            log_fn(f"VT analysis queued - id={analysis_id[:24]}...", "DEBUG")
        except Exception as e:
            log_fn(f"VT parse: {e}", "ERROR"); return empty, {}
    elif r.status_code == 409:
        log_fn("VT 409 - file just indexed, fetching by hash ...", "INFO")
        result = _vt_hash_lookup(sha256, log_fn)
        return result if result else (empty, {})
    else:
        log_fn(f"VT HTTP {r.status_code}", "WARNING"); return empty, {}


    if analysis_id:
        poll          = f"https://www.virustotal.com/api/v3/analyses/{analysis_id}"
        queued_streak = 0
        for attempt in range(20):
            time.sleep(15)
            try:
                hdr2, _ = _get_api_hdr()
                pr = requests.get(poll, headers=hdr2, timeout=30)
                if pr.status_code != 200:
                    log_fn(f"VT poll HTTP {pr.status_code}", "WARNING"); continue
                pdata  = pr.json().get("data",{}).get("attributes",{})
                status = pdata.get("status","")
                log_fn(f"VT poll #{attempt+1}: {status}", "DEBUG")

                if status == "completed":
                    stats   = pdata.get("stats",   empty)
                    engines = pdata.get("results", {})
                    log_fn(f"VT done - mal={stats.get('malicious',0)} sus={stats.get('suspicious',0)} clean={stats.get('undetected',0)}", "INFO")
                    return stats, engines

                if status == "queued":
                    queued_streak += 1


                    if queued_streak >= 3:
                        log_fn("Queue stalled - trying hash lookup ...", "DEBUG")
                        result = _vt_hash_lookup(sha256, log_fn)
                        if result:
                            return result
                        queued_streak = 0
                else:
                    queued_streak = 0

            except Exception as e:
                log_fn(f"VT poll: {e}", "WARNING")

        log_fn("VT poll timeout - final hash attempt ...", "WARNING")


    result = _vt_hash_lookup(sha256, log_fn)
    if result:
        return result
    log_fn("VT: no results (file may be unique/never scanned before)", "WARNING")
    return empty, {}

def _analyze_pe(path, log_fn):
    info = {}
    if not pefile:
        log_fn("pefile not installed — PE analysis skipped", "INFO")
        return info
    try:
        pe = pefile.PE(path)
        info["entry_point"] = hex(pe.OPTIONAL_HEADER.AddressOfEntryPoint)
        info["sections"]    = [s.Name.decode(errors="ignore").strip() for s in pe.sections]
        info["imports"]     = [e.dll.decode(errors="ignore") for e in getattr(pe,"DIRECTORY_ENTRY_IMPORT",[])]
        with open(path,"rb") as f: raw = f.read()
        info["strings"]         = [s.decode(errors="ignore") for s in raw.split(b"\x00") if len(s)>4]
        known_packers           = ["UPX","MPRESS","ASPack","Themida"]
        info["packer_detected"] = any(p in "".join(info["sections"]) for p in known_packers)
        log_fn(f"PE ok – entry={info['entry_point']} packer={info['packer_detected']}", "DEBUG")
    except (pefile.PEFormatError if pefile else Exception):
        log_fn("Not a PE file", "INFO")
    except Exception as e:
        info["error"] = str(e)
        log_fn(f"PE error: {e}", "ERROR")
    return info

def _capture_traffic(pcap_path, log_fn, duration=10):
    if not TSHARK_PATH:
        log_fn("tshark not found — network capture skipped", "WARNING")
        return
    try:
        _cf = {"creationflags": 0x08000000} if sys.platform == "win32" else {}
        subprocess.run([TSHARK_PATH, "-a", f"duration:{duration}", "-w", pcap_path],
                       check=True, capture_output=True, **_cf)
        log_fn(f"Network capture: {os.path.basename(pcap_path)}", "INFO")
    except FileNotFoundError:
        log_fn("tshark not found — network capture skipped", "WARNING")
    except Exception as e:
        log_fn(f"Capture failed: {e}", "WARNING")

