_pre_sl("SCALE  probe start", "SCALE")
_SCALE: float = 1.0
_SCALE_SOURCE: str = "fallback-standard"

try:
    try:
        import ctypes as _sc_ct
        try:
            _sc_ct.windll.shcore.SetProcessDpiAwareness(2)
            _pre_sl("SCALE  SetProcessDpiAwareness(2) OK", "SCALE")
        except Exception as _sc_ea:
            try:
                _sc_ct.windll.user32.SetProcessDPIAware()
                _pre_sl(f"SCALE  DpiAwareness(2) failed ({_sc_ea}) -> SetProcessDPIAware OK", "SCALE")
            except Exception as _sc_eb:
                _pre_sl(f"SCALE  both DPI-aware declarations failed: {_sc_eb}", "SCALE")

        _pre_sl("SCALE  phase1: GetDeviceCaps(LOGPIXELSX)", "SCALE")
        _sc_hdc = _sc_ct.windll.user32.GetDC(0)
        _sc_dpi = _sc_ct.windll.gdi32.GetDeviceCaps(_sc_hdc, 88)
        _sc_ct.windll.user32.ReleaseDC(0, _sc_hdc)
        del _sc_hdc
        if 72 <= _sc_dpi <= 480:
            _SCALE = round(_sc_dpi / 96.0, 3)
            _SCALE_SOURCE = f"ctypes-GetDeviceCaps(LOGPIXELSX={_sc_dpi})"
            _pre_sl(f"SCALE  phase1 OK — raw_dpi={_sc_dpi}  scale={_SCALE}", "SCALE")
        else:
            _pre_sl(f"SCALE  phase1 DPI={_sc_dpi} out of range [72..480], skipping", "SCALE")
            raise ValueError(f"LOGPIXELSX={_sc_dpi} out of range")

    except Exception as _sc_e1:
        _pre_sl(f"SCALE  phase1 failed: {_sc_e1}", "SCALE")

        try:
            _pre_sl("SCALE  phase2: GetDpiForSystem", "SCALE")
            _sc_dpi2 = _sc_ct.windll.user32.GetDpiForSystem()
            if 72 <= _sc_dpi2 <= 480:
                _SCALE = round(_sc_dpi2 / 96.0, 3)
                _SCALE_SOURCE = f"ctypes-GetDpiForSystem({_sc_dpi2})"
                _pre_sl(f"SCALE  phase2 OK — dpi={_sc_dpi2}  scale={_SCALE}", "SCALE")
            else:
                _pre_sl(f"SCALE  phase2 DPI={_sc_dpi2} out of range, skipping", "SCALE")
                raise ValueError(f"GetDpiForSystem={_sc_dpi2} out of range")
        except Exception as _sc_e2:
            _pre_sl(f"SCALE  phase2 failed: {_sc_e2}", "SCALE")

            try:
                _pre_sl("SCALE  phase3: winfo_fpixels('1i')", "SCALE")
                root.update_idletasks()
                _sc_ppi = root.winfo_fpixels("1i")
                if 60.0 <= _sc_ppi <= 480.0:
                    _SCALE = round(_sc_ppi / 96.0, 3)
                    _SCALE_SOURCE = f"tkinter-winfo_fpixels({_sc_ppi:.1f})"
                    _pre_sl(f"SCALE  phase3 OK — ppi={_sc_ppi:.1f}  scale={_SCALE}", "SCALE")
                else:
                    _pre_sl(f"SCALE  phase3 ppi={_sc_ppi:.1f} out of range, skipping", "SCALE")
                    raise ValueError(f"winfo_fpixels={_sc_ppi:.1f} out of range")
            except Exception as _sc_e3:
                _pre_sl(f"SCALE  phase3 failed: {_sc_e3}", "SCALE")

                try:
                    _pre_sl("SCALE  phase4: screen-resolution heuristic vs 1920×1080", "SCALE")
                    _sc_sw = root.winfo_screenwidth()
                    _sc_sh = root.winfo_screenheight()
                    _pre_sl(f"SCALE  phase4 screen={_sc_sw}x{_sc_sh}", "SCALE")
                    _sc_sx = _sc_sw / 1920.0
                    _sc_sy = _sc_sh / 1080.0
                    _sc_raw = min(_sc_sx, _sc_sy)
                    _SCALE = round(max(0.60, min(_sc_raw, 2.50)), 3)
                    _SCALE_SOURCE = f"screen-heuristic({_sc_sw}x{_sc_sh}->raw={_sc_raw:.3f})"
                    _pre_sl(f"SCALE  phase4 OK — raw={_sc_raw:.3f}  clamped={_SCALE}", "SCALE")
                    del _sc_sw, _sc_sh, _sc_sx, _sc_sy, _sc_raw
                except Exception as _sc_e4:
                    _pre_sl(f"SCALE  phase4 failed: {_sc_e4}", "SCALE")
                    _pre_sl("SCALE  phase5: all probes failed — using standard 1.0", "SCALE")
                    _SCALE = 1.0
                    _SCALE_SOURCE = "fallback-all-phases-failed"

    try:
        del _sc_ct
    except Exception:
        pass

except Exception as _sc_e0:
    _pre_sl(f"SCALE  outer exception (ctypes import?): {_sc_e0} — using standard 1.0", "SCALE")
    _SCALE = 1.0
    _SCALE_SOURCE = "fallback-outer-exception"

_pre_sl(f"SCALE  final  _SCALE={_SCALE}  source={_SCALE_SOURCE}", "SCALE")


def _fs(base: int, bold: bool = False, family: str = "Consolas") -> tuple:
    """Return a scaled font tuple.  Always safe — falls back to (family, base)."""
    try:
        sz = max(6, round(base * _SCALE))
        return (family, sz, "bold") if bold else (family, sz)
    except Exception:
        return (family, base, "bold") if bold else (family, base)


def _early_crash_hook(exc_type, exc_val, exc_tb):
    _pre_sl(f"EARLY CRASH: {exc_type.__name__}: {exc_val}", "CRASH")
    try: _sl_copy_to_final()
    except Exception: pass
    import traceback as _etb
    tb = "".join(_etb.format_exception(exc_type, exc_val, exc_tb))
    try:
        with open(os.path.join(DEBUG_DIR, "crash_log", "early_crash.txt"), "a", encoding="utf-8") as _ecf:
            import datetime as _edt
            _ecf.write(f"[{_edt.datetime.now()}] CRASH:\n{tb}\n{'='*60}\n")
    except Exception:
        pass
    try: _session_log(f"CRASH: {exc_type.__name__}: {exc_val}", "ERR")
    except Exception: pass


