def _confirm_exit():
    import time as _ext

    popup = tk.Toplevel(root)
    popup.title("")
    popup.resizable(False, False)
    popup.configure(bg=C["base"])
    popup.attributes("-topmost", True)
    W, H = 480, 300
    popup.update_idletasks()
    sx = popup.winfo_screenwidth(); sy = popup.winfo_screenheight()
    popup.geometry(f"{W}x{H}+{(sx-W)//2}+{(sy-H)//2}")
    popup.lift(); popup.focus_force()
    try: popup.grab_set()
    except Exception: pass

    _hdr = tk.Frame(popup, bg=C["red"], padx=18, pady=9)
    _hdr.pack(fill=tk.X)
    tk.Label(_hdr, text="  ⛔  EXIT V0RTEX",
             font=("Consolas", 12, "bold"), bg=C["red"], fg=C["base"]).pack(anchor="w")

    _body = tk.Frame(popup, bg=C["base"], padx=22, pady=14)
    _body.pack(fill=tk.BOTH, expand=True)

    tk.Label(_body, text="Terminate the session?",
             font=("Consolas", 10, "bold"), bg=C["base"], fg=C["text"]).pack(anchor="w")
    tk.Label(_body, text="All active processes, scans and watchers will be stopped.",
             font=("Consolas", 8), bg=C["base"], fg=C["subtext"]).pack(anchor="w", pady=(2, 12))

    _badges = tk.Frame(_body, bg=C["base"]); _badges.pack(anchor="w", pady=(0, 14))

    def _badge(parent, label, active):
        col = C["red"] if active else C["surface2"]
        txt_col = C["base"] if active else C["overlay0"]
        dot = "●" if active else "○"
        f = tk.Frame(parent, bg=col, padx=7, pady=3)
        f.pack(side=tk.LEFT, padx=(0, 6))
        tk.Label(f, text=f"{dot} {label}", font=("Consolas", 7, "bold"),
                 bg=col, fg=txt_col).pack()

    try:
        import psutil as _psx2
        _child_count = len(_psx2.Process(os.getpid()).children(recursive=True))
    except Exception:
        _child_count = 0

    _scan_active  = bool(globals().get("_sp_current_proc") and globals()["_sp_current_proc"][0])
    _watch_active = bool(globals().get("_watch_active_var") and globals()["_watch_active_var"].get())
    _net_active   = bool(globals().get("_net_capture_proc") and globals()["_net_capture_proc"][0])
    _tray_active  = bool(globals().get("_tray_icon"))

    _badge(_badges, "SCAN",    _scan_active)
    _badge(_badges, "WATCHER", _watch_active)
    _badge(_badges, "CAPTURE", _net_active)
    _badge(_badges, "TRAY",    _tray_active)
    if _child_count:
        _badge(_badges, f"{_child_count} CHILD PROC{'S' if _child_count!=1 else ''}",  True)

    tk.Frame(_body, bg=C["surface1"], height=1).pack(fill=tk.X, pady=(0, 2))

    _status_var = tk.StringVar(value="")
    tk.Label(_body, textvariable=_status_var, font=("Consolas", 7),
             bg=C["base"], fg=C["overlay0"]).pack(anchor="w", pady=(4, 0))

    _btn_row = tk.Frame(popup, bg=C["mantle"], padx=18, pady=10)
    _btn_row.pack(fill=tk.X, side=tk.BOTTOM)

    def _do_exit():
        try: root.withdraw()
        except Exception: pass
        for w in _btn_row.winfo_children():
            try: w.config(state="disabled")
            except Exception: pass

        def _step(msg):
            try:
                _status_var.set(msg)
                popup.update()
                import time as _ext2; _ext2.sleep(0.18)
            except Exception: pass

        _step("Stopping watchers...")
        try:
            _wo = globals().get("_watch_observer")
            if _wo:
                _wo.stop()
        except Exception: pass

        _step("Stopping tray...")
        try:
            _ti = globals().get("_tray_icon")
            if _ti: _ti.stop()
        except Exception: pass

        _step("Killing child processes...")
        try:
            _gp_h = globals().get("_GUARDIAN_PROC")
            if _gp_h:
                try: _gp_h.kill()
                except Exception: pass
        except Exception: pass
        try:
            import psutil as _psx
            for _px in _psx.process_iter(["pid","cmdline"]):
                try:
                    _cmd = " ".join(_px.info.get("cmdline") or [])
                    if "vx_ai_guardian" in _cmd or "vx_autodestruction" in _cmd:
                        _px.kill()
                except Exception: pass
            _me = _psx.Process(os.getpid())
            for ch in _me.children(recursive=True):
                try: ch.kill()
                except Exception: pass
        except Exception: pass

        for _vn in ["_sp_current_proc", "_wd_proc", "_net_capture_proc"]:
            try:
                _pc = globals().get(_vn)
                if _pc and _pc[0]:
                    _pc[0].kill()
            except Exception: pass

        _step("Flushing logs...")
        try:
            import datetime as _dtx
            ts = _dtx.datetime.now().strftime("%Y-%m-%d %H:%M:%S")
            entry = (f"\n{'━'*62}\n  SESSION ENDED — {ts}\n"
                     f"  Exit: user-initiated clean exit\n  PID: {os.getpid()}\n{'━'*62}\n")
            sess_log = globals().get("_SESSION_LOG_PATH")
            if sess_log:
                with open(sess_log, "a", encoding="utf-8") as _sf: _sf.write(entry)
        except Exception: pass

        _step("Destroying UI...")
        try: popup.destroy()
        except Exception: pass
        _safe_destroy_root()

    _exit_btn = tk.Button(_btn_row, text="  ⛔  EXIT  ", command=_do_exit,
                          bg=C["red"], fg=C["base"], font=("Consolas", 10, "bold"),
                          relief="flat", padx=18, pady=8, cursor="hand2", bd=0)
    _exit_btn.pack(side=tk.RIGHT)
    tk.Button(_btn_row, text="  Cancel  ", command=popup.destroy,
              bg=C["surface1"], fg=C["text"], font=("Consolas", 9),
              relief="flat", padx=14, pady=8, cursor="hand2", bd=0).pack(side=tk.RIGHT, padx=(0, 8))

    popup.protocol("WM_DELETE_WINDOW", popup.destroy)

def _show_kill_terminal():
    import signal as _sig
    import time   as _kt
    import threading as _kt_thr

    _KILL_BG  = "#08000a"
    _KILL_RED = "#ff1a33"
    _KILL_DIM = "#4d0015"
    _KILL_YEL = "#ffaa00"
    _KILL_GRN = "#00ff88"
    _KILL_BRT = "#ff4466"
    _KILL_BLU = "#89b4fa"
    _KILL_TXT = "#cdd6f4"

    try:
        import tkinter as _kt_tk
        sw = root.winfo_screenwidth()
        sh = root.winfo_screenheight()

        _KW, _KH = 580, 480
        _kx = (sw - _KW) // 2
        _ky = (sh - _KH) // 2

        win = _kt_tk.Toplevel(root)
        win.title("V0RTEX — Exit")
        win.geometry(f"{_KW}x{_KH}+{_kx}+{_ky}")
        win.configure(bg=_KILL_BG)
        win.resizable(False, False)
        win.attributes("-topmost", True)
        win.grab_set()
        win.protocol("WM_DELETE_WINDOW", lambda: None)

        _kt_tk.Frame(win, bg=_KILL_RED, height=3).pack(fill="x")

        hf = _kt_tk.Frame(win, bg="#110005", pady=8, padx=14)
        hf.pack(fill="x")
        _kt_tk.Label(hf, text="  \u25cf \u25cf \u25cf   V0RTEX",
                     font=("Consolas", 9), bg="#110005", fg=_KILL_DIM).pack(side="left")
        _kt_tk.Label(hf, text=f"  PID {os.getpid()}",
                     font=("Consolas", 8), bg="#110005", fg=_KILL_DIM).pack(side="right")

        _kt_tk.Label(win, text="\u26a0  EXIT V0RTEX",
                     font=("Consolas", 18, "bold"), bg=_KILL_BG, fg=_KILL_RED).pack(pady=(14, 2))
        _kt_tk.Label(win, text="All unsaved changes will be lost. Active scans will be stopped.",
                     font=("Consolas", 9), bg=_KILL_BG, fg=_KILL_YEL,
                     wraplength=520, justify="center").pack(pady=(0, 8))

        _kt_tk.Frame(win, bg="#2a0010", height=1).pack(fill="x", padx=20)

        log_f = _kt_tk.Frame(win, bg="#0a000f"); log_f.pack(fill="both", expand=True, padx=12, pady=8)
        log_sc = _kt_tk.Scrollbar(log_f, orient="vertical", bg="#2a0010",
                                   troughcolor="#0a000f", relief="flat", width=6)
        log_tx = _kt_tk.Text(log_f, bg="#0a000f", fg=_KILL_TXT, font=("Consolas", 8),
                              relief="flat", bd=0, padx=8, pady=6, wrap="none",
                              yscrollcommand=log_sc.set, state="disabled")
        log_sc.config(command=log_tx.yview)
        log_sc.pack(side="right", fill="y")
        log_tx.pack(fill="both", expand=True)
        log_tx.tag_configure("CMD", foreground=_KILL_BLU, font=("Consolas", 8, "bold"))
        log_tx.tag_configure("RED", foreground=_KILL_RED)
        log_tx.tag_configure("GRN", foreground=_KILL_GRN)
        log_tx.tag_configure("YEL", foreground=_KILL_YEL)
        log_tx.tag_configure("DIM", foreground=_KILL_DIM)

        _KILL_CMDS = [
            (f"$ sudo kill -15 $(pgrep -f v0rtex) # PID {os.getpid()}", 0.08, "CMD"),
            (f"[  0.001] SIGTERM \u2192 PID {os.getpid()}", 0.06, "YEL"),
            ("[ 0.008 ] Writing final session log ...", 0.09, "DIM"),
            ("[ 0.014 ] Stopping watchdog observer ...", 0.07, "DIM"),
            ("[ 0.021 ] Joining scan worker threads ...", 0.10, "DIM"),
            ("[ 0.035 ] Flushing scan queue ...", 0.08, "DIM"),
            ("[ 0.042 ] Terminating VirusTotal workers ...", 0.09, "DIM"),
            ("[ 0.051 ] Stopping YARA engine ...", 0.07, "DIM"),
            ("[ 0.058 ] Unloading PE / entropy modules ...", 0.08, "DIM"),
            ("[ 0.064 ] Closing SQLite connections ...", 0.09, "DIM"),
            ("[ 0.073 ] Flushing auto-backup state ...", 0.07, "DIM"),
            ("[ 0.079 ] Closing network sockets ...", 0.08, "DIM"),
            ("[ 0.092 ] Saving notes.txt to disk ...", 0.07, "DIM"),
            ("[ 0.099 ] Unregistering tray icon ...", 0.07, "DIM"),
            ("[ 0.114 ] *** SIGKILL broadcast ***", 0.12, "RED"),
            (f"[ 0.116 ] PID {os.getpid():>6}: SIGKILL \u2713", 0.06, "GRN"),
            ("[ 0.122 ] Removing .lock files ...", 0.08, "DIM"),
            ("[ 0.135 ] Purging tmp scan artifacts ...", 0.07, "DIM"),
            ("[ 0.141 ] Destroying tkinter widget tree ...", 0.10, "DIM"),
            ("[ 0.148 ] All threads joined \u2014 clean shutdown", 0.09, "GRN"),
            ("", 0.05, "DIM"),
            ("[ 0.152 ] \u2550\u2550\u2550 PROCESS EXITED \u2014 code 0 \u2550\u2550\u2550", 0.0, "RED"),
        ]

        _exit_confirmed = [False]
        _seq_done = [False]

        def _write_seq():
            for text, delay, tag in _KILL_CMDS:
                if _exit_confirmed[0]: break
                def _ins(t=text, tg=tag):
                    log_tx.config(state="normal")
                    log_tx.insert("end", t + "\n", tg)
                    log_tx.see("end")
                    log_tx.config(state="disabled")
                try: win.after(0, _ins)
                except Exception: break
                _kt.sleep(delay)
            _seq_done[0] = True

        _kt_thr.Thread(target=_write_seq, daemon=True).start()

        _kt_tk.Frame(win, bg="#2a0010", height=1).pack(fill="x", padx=20)

        bf = _kt_tk.Frame(win, bg=_KILL_BG, pady=10)
        bf.pack()

        def _confirm_exit():
            _exit_confirmed[0] = True
            _APP_DYING[0] = True
            try: win.grab_release()
            except Exception: pass
            try: win.destroy()
            except Exception: pass
            try:
                _session_log("User confirmed exit via EXIT dialog", "INFO")
            except Exception: pass
            _safe_destroy_root()
            _kt.sleep(0.1)
            try: os.kill(os.getpid(), _sig.SIGTERM)
            except Exception: pass
            sys.exit(0)

        def _cancel():
            try: win.grab_release(); win.destroy()
            except Exception: pass

        _kt_tk.Button(bf, text="  \u2716  EXIT NOW  ",
                      font=("Consolas", 11, "bold"), bg=_KILL_RED, fg="#08000a",
                      relief="flat", padx=24, pady=10, cursor="hand2", bd=0,
                      activebackground=_KILL_BRT,
                      command=_confirm_exit).pack(side="left", padx=(0, 12))
        _kt_tk.Button(bf, text="  CANCEL  ",
                      font=("Consolas", 10), bg="#2a0010", fg=_KILL_TXT,
                      relief="flat", padx=18, pady=10, cursor="hand2", bd=0,
                      activebackground="#3a0018",
                      command=_cancel).pack(side="left")

        win.deiconify()
        root.wait_window(win)

    except Exception as _ke:
        try:
            if _vx_msg("Exit V0RTEX",
                       "Are you sure you want to exit?\n\nAll unsaved changes will be lost.",
                       "yesno"):
                _APP_DYING[0] = True
                sys.exit(0)
        except Exception:
            sys.exit(0)

