def _run_startup_health_check():
    _sl("Startup health check started", "INIT")
    issues = []
    try:
        if not os.path.exists(CONFIG_PATH):
            issues.append("config.json missing")
            _sl("Health check: config.json missing", "WARN")
        try:
            import sqlite3 as _sq2
            _c2 = _sq2.connect(DB_PATH, timeout=3); _c2.execute("SELECT 1"); _c2.close()
        except Exception:
            issues.append("DB inaccessible")
            _sl("Health check: DB inaccessible", "WARN")
        if not API_KEYS:
            issues.append("No API keys set")
            _sl("Health check: no API keys configured", "WARN")
        if not globals().get("_yara_rules") and not globals().get("_YARA_AVAILABLE"):
            pass
        for dep, mod in [("psutil","psutil"),("requests","requests"),("pefile","pefile")]:
            try: __import__(mod)
            except ImportError:
                issues.append(f"{dep} missing")
                _sl(f"Health check: {dep} not installed", "WARN")
        _sl(f"Health check done — issues={len(issues)}", "INIT")
        root.after(0, lambda: _dash_show_health_banner(issues))
    except Exception: pass


