_readme_txt.tag_configure("bold",     foreground=C["peach"],  font=("Consolas",8,"bold"))
_readme_txt.tag_configure("url",      foreground=C["sapphire"])
for _line_idx, _line in enumerate(_README_CONTENT.splitlines(), 1):
    _ls = _line.strip()
    _start = f"{_line_idx}.0"; _end = f"{_line_idx}.end"
    if _ls.startswith("## ") or _ls.startswith("# "):
        _readme_txt.tag_add("heading", _start, _end)
    elif _ls.startswith("| ") or _ls.startswith("├") or _ls.startswith("└") or _ls.startswith("│"):
        _readme_txt.tag_add("code", _start, _end)
    elif _ls.startswith("- ") or _ls.startswith("1. "):
        pass
    elif "http" in _ls:
        _readme_txt.tag_add("url", _start, _end)
_readme_txt.config(state="disabled")

