def _ioc_section(parent, title, color, row, col):
    f = tk.Frame(parent, bg=C["surface0"], bd=0, highlightthickness=1,
                 highlightbackground=C["surface2"])
    f.grid(row=row, column=col, sticky="nsew", padx=3, pady=3)
    hdr = tk.Frame(f, bg=C["surface0"]); hdr.pack(fill=tk.X)
    tk.Label(hdr, text=title, font=FB, bg=C["surface0"], fg=color, pady=6, padx=10).pack(side=tk.LEFT)
    _cnt = tk.StringVar(value="0")
    tk.Label(hdr, textvariable=_cnt, font=FS, bg=C["surface0"], fg=C["overlay0"]).pack(side=tk.RIGHT, padx=10)
    tk.Frame(f, bg=C["surface2"], height=1).pack(fill=tk.X)
    sc = tk.Scrollbar(f, bg=C["surface1"], troughcolor=C["mantle"],
                      activebackground=C["surface2"], relief="flat", bd=0, width=7)
    lb = tk.Listbox(f, bg=C["mantle"], fg=color, font=("Consolas",9),
                    relief="flat", bd=0, selectbackground=C["surface1"],
                    highlightthickness=0, activestyle="none", yscrollcommand=sc.set)
    sc.config(command=lb.yview); sc.pack(side=tk.RIGHT, fill=tk.Y); lb.pack(fill=tk.BOTH, expand=True)
    return lb, _cnt

