def _update_ioc_tab(fname, iocs, susp_apis):
    global _vx_last_iocs
    _vx_last_iocs = dict(iocs)
    _vx_last_iocs["susp_apis"] = dict(susp_apis)
    _vx_last_iocs["file"] = fname
    def _do():
        _ioc_fname.set(fname)
        def _fill(lb, cnt_var, items):
            lb.delete(0, tk.END)
            for itm in items: lb.insert(tk.END, f"  {itm}")
            cnt_var.set(str(len(items)))
        _fill(_ioc_ips,      _ioc_ips_cnt,   iocs.get("ips",[]))
        _fill(_ioc_domains,  _ioc_dom_cnt,   iocs.get("domains",[]))
        _fill(_ioc_urls,     _ioc_url_cnt,   iocs.get("urls",[]))
        _fill(_ioc_emails,   _ioc_eml_cnt,   iocs.get("emails",[]))
        _fill(_ioc_registry, _ioc_reg_cnt,   iocs.get("registry",[]))
        api_flat = [f"{cat}: {', '.join(apis)}" for cat,apis in susp_apis.items()]
        _fill(_ioc_apis,     _ioc_api_cnt,   api_flat)
    root.after(0, _do)


