RULES_STATE_PATH = os.path.join(RULES_DIR, "rules_state.json")

def _state_load() -> dict:
    try:
        with open(RULES_STATE_PATH, encoding="utf-8") as f:
            return json.load(f)
    except Exception:
        return {}

_rules_state      = _state_load()
_rules_state_lock = threading.Lock()

def _state_save(state: dict):

    try:
        with open(RULES_STATE_PATH, "w", encoding="utf-8") as f:
            json.dump(state, f, indent=2)
    except Exception as e:
        print(f"[STATE] {e}")

def _state_get_enabled(filename) -> bool:
    with _rules_state_lock:
        return _rules_state.get(filename, {}).get("enabled", True)

def _state_set(filename, enabled: bool, category: str = "local"):
    with _rules_state_lock:
        _rules_state[filename] = {"enabled": enabled, "category": category}
        _state_save(dict(_rules_state))


def _try_compile_file(full_path):
    if not yara:
        return False
    result = [False]
    def _do():
        try:
            yara.compile(filepath=full_path)
            result[0] = True
        except Exception:
            pass
    t = threading.Thread(target=_do, daemon=True)
    t.start(); t.join(timeout=5)
    return result[0]

def _compile_all_rules():
    if not yara:
        _sl("YARA event", "YARA"); _checkpoint("YARA", "yara module not available — skipping compilation")
        _sl("yara module not available — skipping compilation", "YARA")
        return None
    try:
        with _rules_state_lock:
            state_snapshot = dict(_rules_state)
        fps = {}
        for fn in sorted(os.listdir(RULES_DIR)):
            if fn.endswith((".yar", ".yara")) and state_snapshot.get(fn, {}).get("enabled", True):
                full = os.path.join(RULES_DIR, fn)
                if _try_compile_file(full):
                    fps[fn] = full
        for fn in sorted(os.listdir(RULES_EXTERN_DIR)):
            if fn.endswith((".yar", ".yara")) and state_snapshot.get(fn, {}).get("enabled", True):
                full = os.path.join(RULES_EXTERN_DIR, fn)
                if _try_compile_file(full):
                    fps[f"x_{fn}"] = full
        if not fps:
            _checkpoint("YARA", "No enabled/valid rule files found — YARA engine inactive")
            _sl("No enabled/valid rule files found — YARA engine inactive", "YARA")
            return None
        try:
            result = yara.compile(filepaths=fps)
            _checkpoint("YARA", f"Rules compiled OK — {len(fps)} file(s): {', '.join(list(fps.keys())[:5])}{'...' if len(fps)>5 else ''}")
            return result
        except Exception:
            for k, v in fps.items():
                try:
                    result = yara.compile(filepath=v)
                    _checkpoint("YARA", f"Rules compiled (single-file fallback) — {os.path.basename(v)}")
                    return result
                except Exception: pass
            _checkpoint("YARA", f"Rules compilation FAILED for all {len(fps)} file(s)")
            return None
    except (KeyboardInterrupt, SystemExit):
        return None
    except Exception as _ce:
        _checkpoint("YARA", f"Compilation exception: {_ce}")
        return None


_folder_pending      = {}
_folder_pending_lock = threading.Lock()

def _folder_register(fbase, total):
    with _folder_pending_lock:
        _folder_pending[fbase] = {"total": total, "done": 0, "results": []}

def _folder_record(fbase, file_name, vt_stats, yara_hits, entropy, ftype):
    with _folder_pending_lock:
        if fbase not in _folder_pending:
            return False
        _folder_pending[fbase]["done"] += 1
        mal = vt_stats.get("malicious", 0)
        sus = vt_stats.get("suspicious", 0)
        _folder_pending[fbase]["results"].append({
            "file": file_name, "vt": vt_stats,
            "yara": yara_hits, "entropy": entropy,
            "ftype": ftype,
            "verdict": "MALICIOUS" if mal > 0 else ("SUSPICIOUS" if sus > 0 else "CLEAN"),
        })
        done    = _folder_pending[fbase]["done"]
        total   = _folder_pending[fbase]["total"]
        results = list(_folder_pending[fbase]["results"])
    if done >= total:
        _generate_folder_report(fbase, results)
        with _folder_pending_lock:
            _folder_pending.pop(fbase, None)
        return True
    return False

def _generate_folder_report(folder_path, results):
    folder_name = os.path.basename(folder_path)
    n_mal  = sum(1 for r in results if r["verdict"] == "MALICIOUS")
    n_sus  = sum(1 for r in results if r["verdict"] == "SUSPICIOUS")
    n_cln  = len(results) - n_mal - n_sus
    ts     = time.strftime("%Y-%m-%d %H:%M:%S")
    total  = len(results)


    txt_path = os.path.join(folder_path, "folder_report.txt")
    try:
        lines = []
        lines.append("=" * 70)
        lines.append("  FOLDER SCAN REPORT: " + folder_name)
        lines.append("  " + ts)
        lines.append("=" * 70)
        lines.append("")
        lines.append("Total files : " + str(total))
        lines.append("Malicious   : " + str(n_mal))
        lines.append("Suspicious  : " + str(n_sus))
        lines.append("Clean       : " + str(n_cln))
        lines.append("")
        lines.append("-" * 70)
        lines.append("  FILE RESULTS")
        lines.append("-" * 70)
        for r in sorted(results, key=lambda x: (x["verdict"] != "MALICIOUS", x["verdict"] != "SUSPICIOUS")):
            mal = r["vt"].get("malicious", 0)
            sus = r["vt"].get("suspicious", 0)
            line = "  [{:<10}]  mal={} sus={}  ent={:.2f}  {}".format(
                r["verdict"], mal, sus, r["entropy"], r["file"])
            lines.append(line)
            if r["yara"]:
                lines.append("               YARA: " + ", ".join(r["yara"]))
        lines.append("")
        with open(txt_path, "w", encoding="utf-8") as f:
            f.write("\n".join(lines))
    except Exception as e:
        print("[FOLDER RPT TXT]", e)


    html_path = os.path.join(folder_path, "folder_report.html")
    try:
        rows = []
        for r in sorted(results, key=lambda x: (x["verdict"] != "MALICIOUS", x["verdict"] != "SUSPICIOUS")):
            mal = r["vt"].get("malicious", 0)
            sus = r["vt"].get("suspicious", 0)
            vrd = r["verdict"]
            vc  = "#f38ba8" if vrd == "MALICIOUS" else ("#fab387" if vrd == "SUSPICIOUS" else "#a6e3a1")
            ec  = "#f38ba8" if r["entropy"] > 7.0 else ("#fab387" if r["entropy"] > 6.0 else "#a6e3a1")
            yara_str = ", ".join(r["yara"]) if r["yara"] else "—"
            rows.append(
                "<tr>"
                "<td style='color:" + vc + ";font-weight:bold'>" + vrd + "</td>"
                "<td>" + r["file"] + "</td>"
                "<td>" + r["ftype"] + "</td>"
                "<td style='color:" + vc + "'>" + str(mal) + "</td>"
                "<td style='color:#fab387'>" + str(sus) + "</td>"
                "<td style='color:" + ec + "'>" + "{:.3f}".format(r["entropy"]) + "</td>"
                "<td style='color:#cba6f7;font-size:.75rem'>" + yara_str + "</td>"
                "</tr>"
            )
        rows_html = "\n".join(rows)

        html_parts = [
            "<!DOCTYPE html>",
            "<html lang='en'><head><meta charset='UTF-8'>",
            "<title>Folder Scan - " + folder_name + "</title>",
            "<style>",
            "@import url('https://fonts.googleapis.com/css2?family=JetBrains+Mono:wght@400;700&display=swap');",
            "*{box-sizing:border-box;margin:0;padding:0}",
            "body{font-family:'JetBrains Mono',monospace;background:#0d0d14;color:#cdd6f4;padding:32px;line-height:1.6}",
            "h1{font-size:.85rem;color:#89b4fa;letter-spacing:.1em;margin-bottom:4px}",
            ".fname{font-size:1.4rem;font-weight:700;margin-bottom:20px}",
            ".stats{display:flex;gap:20px;margin-bottom:24px}",
            ".chip{border-radius:8px;padding:12px 22px;font-size:1.1rem;font-weight:700}",
            ".mal{background:#3b1a1a;color:#f38ba8}.sus{background:#3b2a10;color:#fab387}",
            ".ok{background:#1a3b22;color:#a6e3a1}.total{background:#1e1e2e;color:#cdd6f4}",
            "table{width:100%;border-collapse:collapse;background:#1e1e2e;border-radius:10px;overflow:hidden}",
            "th{background:#313244;color:#a6adc8;font-size:.75rem;text-transform:uppercase;letter-spacing:.08em;padding:10px 12px;text-align:left}",
            "td{padding:9px 12px;font-size:.82rem;border-bottom:1px solid #181825}",
            "tr:last-child td{border:none} tr:hover td{background:#27273e}",
            "footer{margin-top:20px;font-size:.7rem;color:#45475a;text-align:right}",
            "</style></head><body>",
            "<h1>V0RTEX \u00b7 FOLDER SCAN REPORT</h1>",
            "<div class='fname'>\U0001f4c1 " + folder_name + "</div>",
            "<div class='stats'>",
            "  <div class='chip total'>" + str(total) + " files</div>",
            "  <div class='chip mal'>" + str(n_mal) + " malicious</div>",
            "  <div class='chip sus'>" + str(n_sus) + " suspicious</div>",
            "  <div class='chip ok'>" + str(n_cln) + " clean</div>",
            "</div>",
            "<table><thead><tr>",
            "  <th>Verdict</th><th>File</th><th>Type</th>",
            "  <th>Mal</th><th>Sus</th><th>Entropy</th><th>YARA Hits</th>",
            "</tr></thead>",
            "<tbody>" + rows_html + "</tbody>",
            "</table>",
            "<footer>Generated " + ts + " · " + _VX_FULL + "</footer>",
            "</body></html>",
        ]
        with open(html_path, "w", encoding="utf-8") as f:
            f.write("\n".join(html_parts))
    except Exception as e:
        print("[FOLDER RPT HTML]", e)

    _auto_gc("folder_report")


def _github_list_yar_new(owner, repo, path, _depth=0) -> list:
    if _depth > 1: return []
    url = (f"https://api.github.com/repos/{owner}/{repo}/contents/{path}"
           if path else f"https://api.github.com/repos/{owner}/{repo}/contents")
    results = []
    try:
        r = requests.get(url, timeout=10,
                         headers={"Accept": "application/vnd.github.v3+json", "User-Agent": "V0RTEX-YARA/1.0"})
        if r.status_code != 200: return []
        items = r.json()
        if not isinstance(items, list): return []
        for item in items:
            if not isinstance(item, dict): continue
            t = item.get("type",""); n = item.get("name","")
            if t == "file" and n.lower().endswith((".yar",".yara")) and item.get("download_url"):
                results.append((n, item["download_url"]))
            elif t == "dir" and _depth == 0:
                results.extend(_github_list_yar_new(owner, repo, item.get("path",""), _depth+1))
    except Exception: pass
    return results
def _download_yar_new(name: str, url: str, category: str, log_fn) -> bool:
    dest = os.path.join(RULES_EXTERN_DIR, name)

    if os.path.exists(dest):
        log_fn(f"  SKIP {name} (already exists)", "INFO")
        if name not in _rules_state:
            _state_set(name, True, category)
        return True
    try:
        r = requests.get(url, timeout=40)
        if r.status_code != 200:
            log_fn(f"HTTP {r.status_code} - {name}", "WARNING"); return False
        source = r.text
        try:
            yara.compile(source=source)
        except (yara.Error if yara else Exception) as e:
            log_fn(f"Invalid YARA ({name}): {e}", "WARNING"); return False
        with open(dest, "w", encoding="utf-8") as f:
            f.write(source)
        if name not in _rules_state:
            _state_set(name, True, category)
        log_fn(f"  OK  {name}", "INFO"); return True
    except Exception as e:
        log_fn(f"  ERR {name}: {e}", "WARNING"); return False


