def _ye_test():
    _sl("YARA rule test triggered", "YARA")
    _ye_out_clear()
    code = _ye_ed.get("1.0", tk.END).strip()
    if not code:
        _ye_out_write("No content to compile.", "WARN"); return
    _ye_out_write(f"Compiling... ({len(code.splitlines())} lines)", "INFO")
    def _do():
        try:
            compiled = yara.compile(source=code)

            matches = compiled.match(data=b"")
            root.after(0, lambda: _ye_out_write("✓  Compilation OK — no errors", "OK"))
            root.after(0, lambda: _ye_out_write(f"   Rule(s) compiled successfully.", "INFO"))
        except yara.SyntaxError as e:
            msg = str(e)
            root.after(0, lambda m=msg: _ye_out_write(f"✗  Syntax Error:\n   {m}", "ERR"))

            m2 = re.search(r"line (\d+)", msg)
            if m2:
                ln = int(m2.group(1))
                root.after(0, lambda l=ln: [
                    _ye_ed.tag_add("err", f"{l}.0", f"{l}.end"),
                    _ye_ed.see(f"{l}.0"),
                ])
        except Exception as e:
            root.after(0, lambda: _ye_out_write(f"✗  Error: {e}", "ERR"))
    threading.Thread(target=_do, daemon=True).start()

def _ye_load():
    _sl("YARA rule loaded from file", "YARA")
    from tkinter import filedialog
    path = filedialog.askopenfilename(
        initialdir=RULES_DIR, title="Open YARA rule",
        filetypes=[("YARA rules","*.yar *.yara"),("All","*.*")])
    if not path: return
    with open(path, "r", encoding="utf-8", errors="replace") as f:
        content = f.read()
    _ye_ed.delete("1.0", tk.END)
    _ye_ed.insert("1.0", content)
    _ye_name_var.set(os.path.splitext(os.path.basename(path))[0])
    _ye_highlight()
    _ye_out_write(f"Loaded: {path}", "INFO")

def _ye_new():
    _today = time.strftime("%Y-%m-%d")
    template = (
        'import "pe"\n'
        'import "math"\n'
        '\n'
        'rule MyRule : suspicious\n'
        '{\n'
        '    meta:\n'
        '        author      = "Vider_06"\n'
        '        description = "Describe what this detects"\n'
        f'        date        = "{_today}"\n'
        '        hash        = "optional SHA256"\n'
        '\n'
        '    strings:\n'
        '        $s1 = "suspicious_string" ascii wide nocase\n'
        '        $s2 = { 4D 5A 90 00 }\n'
        '        $r1 = /https?:\\/\\/[\\w.]+\\/[\\w.]+/ nocase\n'
        '\n'
        '    condition:\n'
        '        uint16(0) == 0x5A4D and\n'
        '        filesize < 5MB and\n'
        '        any of ($s*) or $r1\n'
        '}\n'
    )
    _ye_ed.delete("1.0", tk.END)
    _ye_ed.insert("1.0", template)
    _ye_name_var.set("my_rule")
    _ye_highlight()

