_DEBUG_MAX_LINES = 3000
_OPS_MAX_LINES   = 2000

def _log_debug(msg, cat="DEBUG"):
    _session_log(msg, level=cat[:7] if cat else "DEBUG")
    ts = time.strftime("%H:%M:%S"); line = f"[{ts}] [{cat}]  {msg}\n"
    print(line.strip())
    def _do():
        try:
            _debug_txt.config(state="normal")
            _debug_txt.insert(tk.END, line, cat)

            lines = int(_debug_txt.index(tk.END).split(".")[0])
            if lines > _DEBUG_MAX_LINES:
                _debug_txt.delete("1.0", f"{lines - _DEBUG_MAX_LINES}.0")
            _debug_txt.see(tk.END)
        except Exception: pass
    try: root.after(0, _do)
    except Exception: pass

def _log_ops(msg, tag="NORM"):
    _session_log(msg, level=tag[:7] if tag else "NORM")
    ts = time.strftime("%H:%M:%S"); line = f"[{ts}]  {msg}\n"
    def _do():
        try:
            _ops_txt.config(state="normal")
            _ops_txt.insert(tk.END, line, tag)
            lines = int(_ops_txt.index(tk.END).split(".")[0])
            if lines > _OPS_MAX_LINES:
                _ops_txt.delete("1.0", f"{lines - _OPS_MAX_LINES}.0")
            _ops_txt.see(tk.END)
        except Exception: pass
    try: root.after(0, _do)
    except Exception: pass

def _clear_logs():
    _ops_txt.delete("1.0",tk.END); _debug_txt.delete("1.0",tk.END)


_PERF_HIST_MAX = 60
_perf_hist = {"ts":[],"cpu":[],"ram":[],"net_up":[],"net_down":[]}
_perf_hist_lock = threading.Lock()
_perf_net_prev  = {"sent": 0, "recv": 0, "ts": time.time()}

def _get_perf():
    stats = {}
    if _psutil:
        try:
            proc = _psutil.Process()
            stats["cpu_pct"]  = _psutil.cpu_percent(interval=None)
            stats["ram_mb"]   = proc.memory_info().rss / 1024 / 1024
            stats["ram_sys"]  = _psutil.virtual_memory().percent
            net = _psutil.net_io_counters()
            stats["net_sent"] = net.bytes_sent
            stats["net_recv"] = net.bytes_recv
        except Exception: pass
    return stats

_PERF_LOG_INTERVAL = 60000
_PERF_HIST_INTERVAL = 5000

def _perf_hist_tick():
    global _perf_net_prev
    if _psutil:
        try:
            s = _get_perf()
            now = time.time()
            dt = now - _perf_net_prev["ts"]
            net = _psutil.net_io_counters()
            kb_up   = (net.bytes_sent - _perf_net_prev["sent"]) / 1024 / max(dt, 1)
            kb_down = (net.bytes_recv - _perf_net_prev["recv"]) / 1024 / max(dt, 1)
            _perf_net_prev = {"sent": net.bytes_sent, "recv": net.bytes_recv, "ts": now}
            with _perf_hist_lock:
                _perf_hist["ts"].append(now)
                _perf_hist["cpu"].append(s.get("cpu_pct", 0))
                _perf_hist["ram"].append(s.get("ram_mb", 0))
                _perf_hist["net_up"].append(kb_up)
                _perf_hist["net_down"].append(kb_down)
                if len(_perf_hist["ts"]) > _PERF_HIST_MAX:
                    for k in _perf_hist: _perf_hist[k] = _perf_hist[k][-_PERF_HIST_MAX:]
        except Exception: pass
    if not _APP_DYING[0]:
        try: root.after(_PERF_HIST_INTERVAL, _perf_hist_tick)
        except Exception: pass

def _perf_tick():
    if _psutil:
        try:
            s = _get_perf()
            with _perf_hist_lock:
                up   = _perf_hist["net_up"][-1]   if _perf_hist["net_up"]   else 0
                down = _perf_hist["net_down"][-1]  if _perf_hist["net_down"] else 0
            msg = (f"PERF  CPU:{s.get('cpu_pct',0):.0f}%  "
                   f"RAM:{s.get('ram_mb',0):.0f}MB  "
                   f"SysRAM:{s.get('ram_sys',0):.0f}%  "
                   f"Net ↑{up:.1f} ↓{down:.1f} KB/s")
            _log_debug(msg, "DEBUG")
        except Exception: pass
    if not _APP_DYING[0]:
        try: root.after(_PERF_LOG_INTERVAL, _perf_tick)
        except Exception: pass

def _refresh_stats():
    try:
        rows = _db_query("SELECT COUNT(*), SUM(malicious), "
                         "SUM(CASE WHEN malicious=0 THEN 1 ELSE 0 END) FROM scans")
        if rows:
            total, mal, clean = rows[0]
            _sv_scans.set(str(total or 0))
            _sv_mal.set(str(int(mal or 0)))
            _sv_clean_stat.set(str(int(clean or 0)))
        yara_rows = _db_query("SELECT COUNT(*) FROM scans "
                               "WHERE yara_hits != '[]' AND yara_hits IS NOT NULL")
        if yara_rows:
            _sv_yara_stat.set(str(yara_rows[0][0]))
        _sv_keys.set(str(len(API_KEYS)))
        _sv_queue.set(str(_q.qsize()))
    except Exception as _rse:
        _log_debug(f"[STATS] _refresh_stats error: {_rse}", "ERROR")
    if _psutil:
        try:
            _sv_cpu_stat.set(f"{_psutil.cpu_percent(interval=None):.0f}%")
            mb = _psutil.Process().memory_info().rss / 1024 / 1024
            _sv_ram_stat.set(f"{mb:.0f} MB")
        except Exception: pass
    if not _APP_DYING[0]:
        root.after(2000, _refresh_stats)

