def _update_perf_chart():
    with _perf_hist_lock:
        hist = {k: list(v) for k,v in _perf_hist.items()}
    _perf_fig.clear(); _perf_fig.set_facecolor(C["surface0"])
    bg = C["mantle"]
    def _ax_s(ax, t):
        ax.set_facecolor(bg); ax.set_title(t, color=C["subtext"], fontsize=9, pad=5)
        ax.tick_params(colors=C["overlay0"], labelsize=7)
        for sp in ax.spines.values(): sp.set_color(C["surface2"])

    n = len(hist["ts"])
    xs = list(range(n))

    ax1 = _perf_fig.add_subplot(131)
    if hist["cpu"]:
        ax1.fill_between(xs, hist["cpu"], alpha=0.5, color=C["blue"])
        ax1.plot(xs, hist["cpu"], color=C["blue"], linewidth=1.2)
        ax1.set_ylim(0, 100)
    else:
        ax1.text(0.5,0.5,"No data",ha="center",va="center",color=C["overlay0"],transform=ax1.transAxes)
    _ax_s(ax1, "CPU %")

    ax2 = _perf_fig.add_subplot(132)
    if hist["ram"]:
        ax2.fill_between(xs, hist["ram"], alpha=0.5, color=C["green"])
        ax2.plot(xs, hist["ram"], color=C["green"], linewidth=1.2)
    else:
        ax2.text(0.5,0.5,"No data",ha="center",va="center",color=C["overlay0"],transform=ax2.transAxes)
    _ax_s(ax2, "App RAM (MB)")

    ax3 = _perf_fig.add_subplot(133)
    if hist["net_up"]:
        ax3.fill_between(xs, hist["net_up"],   alpha=0.4, color=C["teal"],     label="↑ Up")
        ax3.fill_between(xs, hist["net_down"], alpha=0.4, color=C["sapphire"], label="↓ Down")
        ax3.plot(xs, hist["net_up"],   color=C["teal"],     linewidth=1)
        ax3.plot(xs, hist["net_down"], color=C["sapphire"], linewidth=1)
        ax3.legend(frameon=False, labelcolor=C["text"], fontsize=7)
    else:
        ax3.text(0.5,0.5,"No data",ha="center",va="center",color=C["overlay0"],transform=ax3.transAxes)
    _ax_s(ax3, "Network KB/s")

    _perf_fig.subplots_adjust(left=0.07, right=0.97, top=0.90, bottom=0.12, wspace=0.35)
    _perf_canvas.draw_idle()


    if hist["cpu"]:
        _sv_cpu.set(f"{hist['cpu'][-1]:.0f}%")
        _sv_ram.set(f"{hist['ram'][-1]:.0f} MB")
        _sv_net_up.set(f"{hist['net_up'][-1]:.1f} KB/s")
        _sv_net_dn.set(f"{hist['net_down'][-1]:.1f} KB/s")

