_YE_KEYWORDS  = ["rule","meta","strings","condition","and","or","not","any","all","of","them",
                  "true","false","uint8","uint16","uint32","int8","int16","int32",
                  "filesize","entrypoint","at","in","import","include","for","private","global"]
_YE_MODIFIERS = ["nocase","wide","ascii","fullword","xor","base64","base64wide"]

_ye_highlight_pending = [False]

def _ye_highlight_syntax(event=None):
    if _ye_highlight_pending[0]: return
    _ye_highlight_pending[0] = True
    _ye_editor.after(120, _ye_do_highlight)

def _ye_do_highlight():
    _ye_highlight_pending[0] = False
    src_text = _ye_editor.get("1.0", tk.END)
    for tag in ("kw","mod","str_tag","comment","rule_name","hex_str"):
        _ye_editor.tag_remove(tag, "1.0", tk.END)

    for m in re.finditer(r"//[^\n]*", src_text):
        s = f"1.0 + {m.start()} chars"; e = f"1.0 + {m.end()} chars"
        _ye_editor.tag_add("comment", s, e)

    for m in re.finditer(r'"[^"\n]*"', src_text):
        s = f"1.0 + {m.start()} chars"; e = f"1.0 + {m.end()} chars"
        _ye_editor.tag_add("str_tag", s, e)

    for m in re.finditer(r'\{[0-9A-Fa-f?\s]+\}', src_text):
        s = f"1.0 + {m.start()} chars"; e = f"1.0 + {m.end()} chars"
        _ye_editor.tag_add("hex_str", s, e)

    for kw in _YE_KEYWORDS:
        start = "1.0"
        while True:
            pos = _ye_editor.search(r"\b"+kw+r"\b", start, stopindex=tk.END, regexp=True)
            if not pos: break
            end = f"{pos}+{len(kw)}c"
            _ye_editor.tag_add("kw", pos, end); start = end
    for mod in _YE_MODIFIERS:
        start = "1.0"
        while True:
            pos = _ye_editor.search(r"\b"+mod+r"\b", start, stopindex=tk.END, regexp=True)
            if not pos: break
            end = f"{pos}+{len(mod)}c"
            _ye_editor.tag_add("mod", pos, end); start = end

    for m in re.finditer(r"\brule\s+(\w+)", src_text):
        s = f"1.0 + {m.start(1)} chars"; e = f"1.0 + {m.end(1)} chars"
        _ye_editor.tag_add("rule_name", s, e)

_ye_editor.tag_configure("kw",        foreground=C["mauve"],   font=("Consolas",10,"bold"))
_sl("BOOT: YARA editor — syntax highlight tags configured", "BOOT")
_ye_editor.tag_configure("mod",       foreground=C["peach"])
_ye_editor.tag_configure("str_tag",   foreground=C["green"])
_ye_editor.tag_configure("hex_str",   foreground=C["teal"])
_ye_editor.tag_configure("comment",   foreground=C["overlay1"])
_ye_editor.tag_configure("rule_name", foreground=C["yellow"],  font=("Consolas",10,"bold"))
_ye_editor.bind("<KeyRelease>", _ye_highlight_syntax)


