def _ye_test():
    source = _ye_editor.get("1.0", tk.END).strip()
    if not source:
        _ye_status_var.set("Nothing to test."); return
    try:
        compiled = yara.compile(source=source)
        _ye_status_var.set("✓ Compiled OK")
        _ye_status_lbl.config(fg=C["green"])

        count = 0
        for _ in compiled: count += 1
        _ye_status_var.set(f"✓ Compiled OK  ({count} rule(s))")
    except yara.SyntaxError as e:
        _ye_status_var.set(f"✗ Syntax error:\n{e}")
        _ye_status_lbl.config(fg=C["red"])
    except Exception as e:
        _ye_status_var.set(f"✗ Error: {e}")
        _ye_status_lbl.config(fg=C["red"])

def _ye_test_on_file():
    source = _ye_editor.get("1.0", tk.END).strip()
    if not source: return
    path = filedialog.askopenfilename(title="Choose file to test against")
    if not path: return
    try:
        compiled = yara.compile(source=source)
        matches  = compiled.match(path)
        if matches:
            _ye_status_var.set(f"⚠ MATCH: {[m.rule for m in matches]}")
            _ye_status_lbl.config(fg=C["yellow"])
        else:
            _ye_status_var.set(f"✓ No match on:\n{os.path.basename(path)}")
            _ye_status_lbl.config(fg=C["green"])
    except yara.SyntaxError as e:
        _ye_status_var.set(f"✗ Syntax error:\n{e}")
        _ye_status_lbl.config(fg=C["red"])

def _ye_save():
    _sl("YARA rule saved", "YARA")
    source = _ye_editor.get("1.0", tk.END).strip()
    if not source: return
    dest = filedialog.asksaveasfilename(
        initialdir=RULES_DIR,
        defaultextension=".yar",
        filetypes=[("YARA rules","*.yar *.yara"),("All","*.*")])
    if dest:
        with open(dest,"w",encoding="utf-8") as f: f.write(source)
        _ye_status_var.set(f"Saved:\n{os.path.basename(dest)}")
        _ye_status_lbl.config(fg=C["teal"])
        _ym_library_refresh()

def _ye_open():
    path = filedialog.askopenfilename(
        initialdir=RULES_DIR,
        filetypes=[("YARA rules","*.yar *.yara"),("All","*.*")])
