class _AutoScanHandler(_WatchHandler if _WatchObserver else object):
    def on_created(self, event):
        if event.is_directory: return
        p = event.src_path

        if os.path.basename(p).startswith((".", "~", "$")): return
        _log_ops(f"[AutoScan] New file: {p}", "DIM")
        _notify("AutoScan", os.path.basename(p))
        _enqueue(p)

def _watcher_start():
    global _watch_observer
    if _WatchObserver is None:
        messagebox.showerror("AutoScan", "watchdog not installed. pip install watchdog"); return
    folder = filedialog.askdirectory(title="Choose folder to watch")
    if not folder: return
    _watcher_stop()
    handler  = _AutoScanHandler()
    observer = _WatchObserver()
    observer.schedule(handler, folder, recursive=False)
    observer.start()
    _watch_observer = observer
    _watch_folder_var.set(folder)
    _watch_active_var.set(True)
    _log_ops(f"AutoScan watching: {folder}", "GOOD")
    _notify("AutoScan", f"Watching: {os.path.basename(folder)}")


