def _wd_log(msg, tag="DIM"):
    ts = time.strftime("%H:%M:%S")
    def _do():
        _wd_out.config(state="normal")
        _wd_out.insert(tk.END, f"[{ts}]  {msg}\n", tag)
        _wd_out.see(tk.END)
        _wd_out.config(state="disabled")
    root.after(0, _do)

def _wd_start():
    global _wd_observer
    if _WatchObserver is None:
        messagebox.showerror("Watchdog", "watchdog not installed.\nRun: pip install watchdog")
        return
    folder = _wd_folder_var.get().strip()
    if not folder or not os.path.isdir(folder):
        messagebox.showerror("Watchdog", "Select a valid folder.")
        return
    _wd_stop()


    raw_exts = _wd_ext_var.get().strip()
    ext_set = {e.strip().lower() for e in raw_exts.split(",") if e.strip()} if raw_exts else None

    try:
        min_kb = float(_wd_minsize_var.get())
    except ValueError:
        min_kb = 0.0

    try:
        delay = float(_wd_delay_var.get())
    except ValueError:
        delay = 1.0

    class _WDHandler(_WatchHandler):
        def on_created(self, event):
            if event.is_directory: return
            self._handle(event.src_path, "NEW")
        def on_modified(self, event):
            if event.is_directory: return
            self._handle(event.src_path, "MOD")
        def _handle(self, p, kind):
            bn = os.path.basename(p)

            if _wd_ignore_tmp_var.get() and bn.startswith((".", "~", "$")): return

            ext = os.path.splitext(bn)[1].lower()
            if ext_set and ext not in ext_set: return

            try:
                if os.path.getsize(p) / 1024 < min_kb: return
            except Exception: return
            _wd_log(f"[{kind}] {bn}", "WARN" if kind == "NEW" else "DIM")
            if _wd_autoscan_var.get():
                time.sleep(delay)
                _enqueue(p)
                _wd_log(f"  -> queued for scanning", "OK")

    recursive = _wd_recursive_var.get()
    obs = _WatchObserver()
    obs.schedule(_WDHandler(), folder, recursive=recursive)
    obs.start()
    _wd_observer = obs
    _wd_active_var.set(True)
    _wd_status_sv.set("WATCHING")
    _wd_ind.config(fg=C["green"])
    _wd_folder_disp.config(text=folder[:60])

    root.after(0, lambda: _sv_watcher.set(f"Watch: {os.path.basename(folder)[:18]}"))
    _wd_log(f"Watchdog started: {folder}", "OK")
    _wd_log(f"Filter ext: {raw_exts or 'all'} | Recursive: {recursive} | Min: {min_kb}KB", "DIM")

def _wd_stop():
    global _wd_observer
    if _wd_observer:
        try: _wd_observer.stop(); _wd_observer.join(timeout=2)
        except Exception: pass
        _wd_observer = None
    _wd_active_var.set(False)
    _wd_status_sv.set("IDLE")
    _wd_ind.config(fg=C["overlay0"])
    _wd_folder_disp.config(text="")
    root.after(0, lambda: _sv_watcher.set("Watch: OFF"))
    _wd_log("Watchdog stopped", "WARN")

