def _danger_gate_is_perm_dismissed() -> bool:
    try:
        return bool(CONFIG.get("danger_gate_perm_dismiss", False))
    except Exception:
        return False

def _danger_gate(action_id: str, callback, parent=None):
    """Show per-action danger dialog then call callback() if confirmed."""
    try:
        if _danger_gate_is_perm_dismissed():
            _sl(f"DANGER_GATE: perm-dismissed — executing {action_id} directly", "WARN")
            try: callback()
            except Exception as _dge: _sl(f"DANGER_GATE callback error: {_dge}", "ERR")
            return
        if action_id in _DANGER_ACK_SESSION:
            _sl(f"DANGER_GATE: session-ack — executing {action_id} directly", "WARN")
            try: callback()
            except Exception as _dge: _sl(f"DANGER_GATE callback error: {_dge}", "ERR")
            return
        _sl(f"DANGER_GATE: showing dialog for {action_id}", "WARN")
        cfg = _DANGER_GATE_CFG.get(action_id, _DANGER_GATE_CFG["EXEC"])
        title, icon, summary, bullets, accent = cfg
        _w = tk.Toplevel(parent or root)
        _w.title("⚠  V0RTEX — DANGEROUS ACTION")
        _w.configure(bg=C["base"])
        _w.resizable(False, False)
        _w.attributes("-topmost", True)
        try:
            _w.update_idletasks()
            _ww, _wh = 560, 430
            _sx = _w.winfo_screenwidth(); _sy = _w.winfo_screenheight()
            _w.geometry(f"{_ww}x{_wh}+{(_sx-_ww)//2}+{(_sy-_wh)//2}")
        except Exception:
            _w.geometry("560x430")
        _w.lift()
        _w.focus_force()
        try: _w.grab_set()
        except Exception: pass
        _hdr = tk.Frame(_w, bg=accent, padx=18, pady=10); _hdr.pack(fill=tk.X)
        tk.Label(_hdr, text=f"  {icon}  DANGEROUS ACTION  {icon}",
                 font=("Consolas", 13, "bold"), bg=accent, fg=C["base"]).pack(anchor="w")
        _badge_f = tk.Frame(_w, bg=C["mantle"], pady=6, padx=18); _badge_f.pack(fill=tk.X)
        tk.Label(_badge_f, text=f"  ACTION TYPE:  {action_id}",
                 font=("Consolas", 9, "bold"), bg=C["mantle"], fg=accent).pack(anchor="w")
        _btn_row = tk.Frame(_w, bg=C["surface0"], padx=18, pady=10)
        _btn_row.pack(fill=tk.X, side=tk.BOTTOM)
        _body = tk.Frame(_w, bg=C["base"], padx=20, pady=12); _body.pack(fill=tk.BOTH, expand=True)
        tk.Label(_body, text=summary, font=("Consolas", 9), bg=C["base"], fg=C["text"],
                 wraplength=500, justify="left").pack(anchor="w", pady=(0, 10))
        tk.Frame(_body, bg=C["surface1"], height=1).pack(fill=tk.X, pady=(0, 8))
        tk.Label(_body, text="  This action may:", font=("Consolas", 8, "bold"),
                 bg=C["base"], fg=C["subtext"]).pack(anchor="w")
        for _b in bullets:
            tk.Label(_body, text=f"    ·  {_b}", font=("Consolas", 8),
                     bg=C["base"], fg=C["overlay1"], justify="left").pack(anchor="w", pady=1)
        tk.Frame(_body, bg=C["surface1"], height=1).pack(fill=tk.X, pady=(10, 6))
        _skip_var = tk.BooleanVar(value=False)
        _skip_row = tk.Frame(_body, bg=C["base"]); _skip_row.pack(anchor="w", pady=(0, 4))
        tk.Checkbutton(_skip_row,
                       text=" Don't ask again for this action type  (this session only — resets on restart)",
                       variable=_skip_var, font=("Consolas", 8),
                       bg=C["base"], fg=C["subtext"], activebackground=C["base"],
                       selectcolor=C["mantle"], relief="flat").pack(side=tk.LEFT)
        def _do_cancel():
            _sl(f"DANGER_GATE: user cancelled {action_id}", "INFO")
            try: _w.grab_release()
            except Exception: pass
            _w.destroy()
        def _do_proceed():
            if _skip_var.get():
                _DANGER_ACK_SESSION.add(action_id)
                _sl(f"DANGER_GATE: session-ack set for {action_id}", "WARN")
            try: _w.grab_release()
            except Exception: pass
            _w.destroy()
            _sl(f"DANGER_GATE: user confirmed {action_id}", "WARN")
            try: callback()
            except Exception as _dge: _sl(f"DANGER_GATE callback error: {_dge}", "ERR")
        tk.Button(_btn_row, text="  ✕  CANCEL  ", command=_do_cancel,
                  bg=C["surface1"], fg=C["text"], font=("Consolas", 10, "bold"),
                  relief="flat", padx=18, pady=8, cursor="hand2", bd=0).pack(side=tk.LEFT, padx=(0, 10))
        tk.Button(_btn_row, text=f"  {icon}  PROCEED ANYWAY  ", command=_do_proceed,
                  bg=accent, fg=C["base"], font=("Consolas", 10, "bold"),
                  relief="flat", padx=18, pady=8, cursor="hand2", bd=0).pack(side=tk.RIGHT)
        _w.protocol("WM_DELETE_WINDOW", _do_cancel)
        try: _w.wait_window()
        except Exception: pass
    except Exception as _dg_outer:
        _sl(f"DANGER_GATE: outer error ({_dg_outer}) — executing anyway", "ERR")
        try: callback()
        except Exception: pass

