def _su_bar_widget(parent, svc_name, color, limit):
    f = tk.Frame(parent, bg=C["surface0"], padx=14, pady=10)
    f.pack(fill=tk.X, padx=14, pady=5)
    top = tk.Frame(f, bg=C["surface0"]); top.pack(fill=tk.X)
    tk.Label(top, text=svc_name, font=FB, bg=C["surface0"], fg=color).pack(side=tk.LEFT)
    used_sv  = tk.StringVar(value="—")
    limit_sv = tk.StringVar(value=f"/{limit}/day")
    pct_sv   = tk.StringVar(value="")
    tk.Label(top, textvariable=used_sv,  font=("Consolas",10,"bold"), bg=C["surface0"], fg=C["text"]).pack(side=tk.LEFT, padx=(8,0))
    tk.Label(top, textvariable=limit_sv, font=FS, bg=C["surface0"], fg=C["overlay0"]).pack(side=tk.LEFT)
    tk.Label(top, textvariable=pct_sv,   font=FS, bg=C["surface0"], fg=C["overlay0"]).pack(side=tk.RIGHT)
    bar_bg = tk.Frame(f, bg=C["mantle"], height=10); bar_bg.pack(fill=tk.X, pady=(6,2))
    bar_bg.pack_propagate(False)
    bar_fill = tk.Frame(bar_bg, bg=color, height=10); bar_fill.place(x=0, y=0, relheight=1, relwidth=0)
    status_sv = tk.StringVar(value="")
    tk.Label(f, textvariable=status_sv, font=("Consolas",7), bg=C["surface0"], fg=C["overlay0"]).pack(anchor="w")
    return used_sv, limit_sv, pct_sv, bar_fill, status_sv

for _svc_name, _svc_id, _svc_color, _svc_limit, _svc_key in _SU_SERVICES:
    _su_bar_vars[_svc_id] = _su_bar_widget(_su_body, _svc_name, _svc_color, _svc_limit)

def _su_refresh():
    _su_status_sv.set("Probing API services…")
    def _do():
        results = {}
        vt_keys = CONFIG.get("api_keys", [])
        if isinstance(vt_keys, str): vt_keys = [vt_keys]
        vt_key = vt_keys[0] if vt_keys else None
        try:
            if vt_key:
                r = requests.get("https://www.virustotal.com/api/v3/users/me",
                    headers={"x-apikey": vt_key}, timeout=10)
                if r.status_code == 200:
                    d = r.json().get("data",{}).get("attributes",{})
                    rl = d.get("api_requests_daily",{})
                    used = rl.get("used", 0); lim = rl.get("allowed", 500)
                    results["virustotal"] = (used, lim, f"user: {d.get('email','?')[:30]}")
                else:
                    results["virustotal"] = (None, 500, f"HTTP {r.status_code}")
            else:
                results["virustotal"] = (None, 500, "no key")
        except Exception as e:
            results["virustotal"] = (None, 500, str(e)[:40])

        shodan_key = CONFIG.get("shodan_key","")
        try:
            if shodan_key:
                r2 = requests.get(f"https://api.shodan.io/api-info?key={shodan_key}", timeout=10)
                if r2.status_code == 200:
                    d2 = r2.json()
                    results["shodan"] = (d2.get("usage_limits",{}).get("scan_credits",0),
                                         100, f"plan: {d2.get('plan','?')}")
                else:
                    results["shodan"] = (None, 100, f"HTTP {r2.status_code}")
            else:
                results["shodan"] = (None, 100, "no key")
        except Exception as e2:
            results["shodan"] = (None, 100, str(e2)[:40])

        for svc_id, svc_limit in [("greynoise",1000),("otx",10000),("hybrid_analysis",200)]:
            results[svc_id] = (None, svc_limit, "quota endpoint not available for free tier")

        def _upd():
            ok_count = 0
            for svc_id, (used_sv, limit_sv, pct_sv, bar_fill, status_sv) in _su_bar_vars.items():
                used, lim, note = results.get(svc_id, (None, 500, ""))
                if used is not None:
                    pct = min(used / max(lim, 1), 1.0)
                    used_sv.set(str(used))
                    limit_sv.set(f"/{lim}/day")
                    pct_sv.set(f"  {pct*100:.1f}%")
                    bar_fill.place(relwidth=pct)
                    status_sv.set(note)
                    ok_count += 1
                else:
                    used_sv.set("—")
                    pct_sv.set("")
                    bar_fill.place(relwidth=0)
                    status_sv.set(note)
            _su_status_sv.set(f"Done — {ok_count} service(s) with live quota data")
        root.after(0, _upd)
    threading.Thread(target=_do, daemon=True).start()

