def _ls_extract():
    path = _ls_path_sv.get().strip()
    if not path or not os.path.isfile(path):
        messagebox.showwarning("Strings", "Select a valid file first."); return
    minlen   = _ls_minlen.get()
    pattern  = _ls_pattern.get().strip()
    enc      = _ls_encoding.get()
    min_ent  = _ls_min_ent.get()
    classify = _ls_classify.get()
    def _worker():
        root.after(0, lambda: _ls_count_sv.set("⏳ Extracting..."))
        try:
            with open(path, "rb") as f: data = f.read()
        except Exception as e:
            root.after(0, lambda: _ls_count_sv.set(f"✗ Error: {e}")); return
        strings = []
        import re as _re
        if enc in ("ASCII+Unicode", "ASCII only"):
            for m in _re.finditer(rb"[\x20-\x7e]{%d,}" % minlen, data):
                strings.append(("A", m.start(), m.group().decode("ascii", errors="replace")))
        if enc in ("ASCII+Unicode", "Unicode only"):
            for m in _re.finditer(rb"(?:[\x20-\x7e]\x00){%d,}" % minlen, data):
                try:
                    s = m.group().decode("utf-16-le", errors="replace")
                    if len(s) >= minlen:
                        strings.append(("U", m.start(), s))
                except Exception:
                    pass
        if min_ent > 0.0:
            def _str_ent(s):
                if not s: return 0.0
                freq = {}
                for c in s: freq[c] = freq.get(c, 0) + 1
                n = len(s)
                import math as _m
                return -sum((v/n)*_m.log2(v/n) for v in freq.values())
            strings = [(t, o, s) for t, o, s in strings if _str_ent(s) >= min_ent]
        if pattern:
            try:
                patt = _re.compile(pattern, _re.IGNORECASE)
                strings = [(t, o, s) for t, o, s in strings if patt.search(s)]
            except Exception as _pe:
                root.after(0, lambda: _ls_count_sv.set(f"✗ Regex error: {_pe}")); return
        _TAG_MAP = [
            ("URL",  C["blue"],     lambda s: bool(_re.search(r"https?://|ftp://", s, _re.I))),
            ("IP",   C["red"],      lambda s: bool(_re.match(r"^\d{1,3}(?:\.\d{1,3}){3}$", s.strip()))),
            ("REG",  C["mauve"],    lambda s: bool(_re.search(r"HKLM|HKCU|HKEY_|SOFTWARE\\|CurrentControlSet", s, _re.I))),
            ("CMD",  C["peach"],    lambda s: bool(_re.search(r"cmd\.exe|powershell|wscript|cscript|mshta|certutil|regsvr32|rundll32|bitsadmin|schtasks", s, _re.I))),
            ("INJ",  C["red"],      lambda s: bool(_re.search(r"VirtualAlloc|CreateRemoteThread|WriteProcessMemory|NtMapViewOf|RtlCreateUser|LoadLibrary|GetProcAddress", s, _re.I))),
            ("NET",  C["teal"],     lambda s: bool(_re.search(r"WSAStartup|connect\b|socket\b|recv\b|send\b|InternetOpen|HttpSend|WinHttpOpen", s, _re.I))),
            ("B64",  C["yellow"],   lambda s: bool(_re.match(r"^[A-Za-z0-9+/]{40,}={0,2}$", s.strip()))),
            ("CRED", C["flamingo"], lambda s: bool(_re.search(r"password|passwd|secret\b|token\b|apikey|api_key|credential|private.?key", s, _re.I))),
            ("PATH", C["lavender"], lambda s: bool(_re.search(r"%TEMP%|%APPDATA%|%WINDIR%|C:\\\\|\\\\Windows\\\\|\\\\System32\\\\|\\\\Users\\\\", s, _re.I))),
        ]
        total = len(strings)
        def _update():
            _ls_txt.config(state="normal")
            _ls_txt.delete("1.0", tk.END)
            for typ, offset, s in strings[:5000]:
                prefix = f"[{typ}] 0x{offset:08X}  "
                _ls_txt.insert(tk.END, prefix, "")
                label = ""
                color_tag = ""
                if classify:
                    for lbl, col, fn in _TAG_MAP:
                        try:
                            if fn(s):
                                label = lbl
                                color_tag = lbl.lower()
                                break
                        except Exception:
                            pass
                if label:
                    badge = f"[{label}] "
                    _ls_txt.tag_configure(f"badge_{label}", foreground=C["base"],
                                          background=col, font=("Consolas",7,"bold"))
                    _ls_txt.insert(tk.END, badge, f"badge_{label}")
                    _ls_txt.insert(tk.END, " " + s + "\n", color_tag)
                else:
                    _ls_txt.insert(tk.END, s + "\n", "")
            _ls_txt.config(state="disabled")
            over = "  (showing first 5000)" if total > 5000 else ""
            _ls_count_sv.set(f"✓ {total} strings found{over}  ·  file: {os.path.basename(path)}")
        root.after(0, _update)
    threading.Thread(target=_worker, daemon=True).start()

