def _lsc_scan():
    path = _lsc_path_sv.get().strip()
    if not path or not os.path.isfile(path):
        messagebox.showwarning("Shellcode", "Select a valid file first."); return
    _lsc_status.set("⏳ Scanning...")
    _SC_PATTERNS = [
        ("NOP Sled (≥8)",           rb"\x90{8,}"),
        ("CLD+CALL prologue",        rb"\xfc\xe8[\x00-\xff]{0,4}(\x89|\x8b|\x60|\x56|\x57)"),
        ("PUSHAD+MOV EBP,ESP",       rb"\x60\x89\xe5"),
        ("XOR EAX,EAX",              rb"\x31\xc0"),
        ("XOR ECX,ECX",              rb"\x31\xc9"),
        ("XOR EBX,EBX",              rb"\x31\xdb"),
        ("FPU trick (FLDZ+FSTENV)",  rb"\xd9\xee\xd9\x74"),
        ("Egg hunter (w00t)",        rb"\x77\x30\x30\x74"),
        ("Egg hunter (\\xd9\\xf7)",  rb"\xd9\xf7\xd9\xf7"),
        ("INT3 breakpoint sled",     rb"\xcc{4,}"),
        ("Metasploit SHIKATA prolg", rb"\xd9\x74\x24\xf4"),
        ("CALL-POP (GetPC)",         rb"\xe8\x00\x00\x00\x00[\x58-\x5f]"),
        ("SUB ESP alloca pattern",   rb"\x81\xec[\x00-\xff]{2}\x00\x00"),
        ("PUSH DWORD patterns",      rb"(?:\x68[\x00-\xff]{4}){4,}"),
    ]
    def _worker():
        try:
            with open(path, "rb") as f: data = f.read()
        except Exception as e:
            root.after(0, lambda: _lsc_status.set(f"✗ {e}")); return
        import re as _re
        results = []
        for name, pat in _SC_PATTERNS:
            hits = list(_re.finditer(pat, data))
            if hits:
                results.append((name, hits))
        def _upd():
            _lsc_txt.config(state="normal"); _lsc_txt.delete("1.0", tk.END)
            _lsc_txt.insert(tk.END, f"FILE: {os.path.basename(path)}  ({len(data):,} bytes)\n\n", "hdr")
            if not results:
                _lsc_txt.insert(tk.END, "✓ No known shellcode patterns found.\n", "ok")
            else:
                _lsc_txt.insert(tk.END, f"⚠  {len(results)} pattern type(s) detected:\n\n", "hit")
                for name, hits in results:
                    _lsc_txt.insert(tk.END, f"  ▸ {name}\n", "hit")
                    for h in hits[:8]:
                        ctx = data[max(0,h.start()-4):h.end()+4]
                        hex_ctx = " ".join(f"{b:02x}" for b in ctx)
                        _lsc_txt.insert(tk.END, f"      0x{h.start():08X}  {hex_ctx}\n", "dim")
                    if len(hits) > 8:
                        _lsc_txt.insert(tk.END, f"      ... and {len(hits)-8} more\n", "dim")
                    _lsc_txt.insert(tk.END, "\n", "")
            _lsc_txt.config(state="disabled")
            _lsc_status.set(f"✓ Done — {len(results)} pattern type(s) hit · {len(data):,} bytes scanned")
        root.after(0, _upd)
    threading.Thread(target=_worker, daemon=True).start()
