def _lvss_check():
    _lvss_status.set("⏳ Running (Admin Manager)...")
    def _done(resp, err):
        out = ""
        if err is not None:
            out = f"Error: {err}"
        else:
            try:
                if isinstance(resp, dict) and resp.get("ok") and isinstance(resp.get("result"), dict):
                    rj = resp["result"]
                    out = (str(rj.get("stdout", "")) or "").strip() or (str(rj.get("stderr", "")) or "").strip()
                else:
                    out = str((resp or {}).get("error", "Admin Manager offline"))
            except Exception:
                out = "Admin Manager error"
        _lvss_txt.config(state="normal"); _lvss_txt.delete("1.0", tk.END)
        _lvss_txt.insert(tk.END, "VOLUME SHADOW COPY STATUS\n\n", "hdr")
        copies = [l for l in out.splitlines() if "Shadow Copy ID" in l or "shadow copy" in l.lower()]
        if "No items found" in out or not copies:
            _lvss_txt.insert(tk.END, "⚠  NO shadow copies found.\n", "warn")
            _lvss_txt.insert(tk.END, "    System may be vulnerable or ransomware already wiped them.\n", "dim")
        else:
            _lvss_txt.insert(tk.END, f"✓ {len(copies)} shadow copy reference(s) found.\n\n", "hit")
        _lvss_txt.insert(tk.END, "\n--- RAW OUTPUT ---\n", "hdr")
        _lvss_txt.insert(tk.END, (out or "") + "\n", "dim")
        _lvss_txt.config(state="disabled")
        _lvss_status.set(f"✓ Done — {len(copies)} shadow copy reference(s)" if copies else "⚠ No shadow copies found")
    _admin_run_cmd_safe("VSS Checker", "vssadmin list shadows", timeout_s=20, danger_action_id="EXEC", done_fn=_done)
