_lpipe_pipes_txt = _lpipe_pipes_f.winfo_children()[1]
_lpipe_mutex_txt = _lpipe_mutex_f.winfo_children()[1]
_KNOWN_BAD_PIPES = {r"\\pipe\\mimi", r"\\pipe\\lsadump", r"\\pipe\\ntsvcs",
                    "postex_", "msagent_", "status_", "mojo.", "chrome.exe"}
_KNOWN_BAD_MUTEX = {"asd123", "winmgr", "dce226", "singleinstance", "global\\sync",
                    "agentmutex", "injectionmutex", "rat_mutex", "lockmem"}
def _lpipe_scan():
    _lpipe_status.set("⏳ Enumerating...")
    def _worker():
        import glob
        pipes = []
        mutexes = []
        try:
            if sys.platform == "win32":
                pipe_paths = glob.glob(r"\\.\pipe\*")
                pipes = [p.replace(r"\\.\pipe\\","") for p in pipe_paths]
            else:
                pipes = ["(Named pipes: Windows only)"]
        except Exception as e:
            pipes = [f"Error: {e}"]
        try:
            if sys.platform == "win32":
                r = subprocess.run(
                    ["powershell","-NoProfile","-Command",
                     "Get-Process | ForEach-Object { $_.Modules } 2>$null | Select-Object -ExpandProperty ModuleName -Unique"],
                    capture_output=True, text=True, timeout=15, creationflags=0x08000000)
                r2 = subprocess.run(
                    ["powershell","-NoProfile","-Command",
                     "[System.IO.Directory]::GetFiles('\\\\.\\pipe\\')"],
                    capture_output=True, text=True, timeout=10, creationflags=0x08000000)
                raw_pipes = [l.strip() for l in r2.stdout.splitlines() if l.strip()]
                if raw_pipes:
                    pipes = raw_pipes
                r3 = subprocess.run(
                    ["powershell","-NoProfile","-Command",
                     "Get-WmiObject Win32_Process | Select-Object Name,ProcessId | ConvertTo-Json"],
                    capture_output=True, text=True, timeout=15, creationflags=0x08000000)
        except Exception:
            pass
        def _upd():
            for txt, data_list, known_bad, label in [
                (_lpipe_pipes_txt, pipes, _KNOWN_BAD_PIPES, "PIPE"),
                (_lpipe_mutex_txt, mutexes, _KNOWN_BAD_MUTEX, "MUTEX"),
            ]:
                txt.config(state="normal"); txt.delete("1.0", tk.END)
                hits = 0
                if not data_list:
                    txt.insert(tk.END, f"No {label.lower()}s found or Windows only.\n", "dim")
                else:
                    txt.insert(tk.END, f"{len(data_list)} {label}(s) found:\n\n", "hdr")
                    for item in data_list:
                        is_bad = any(b.lower() in item.lower() for b in known_bad)
                        if is_bad:
                            txt.insert(tk.END, f"  ⚠ {item}\n", "hit"); hits += 1
                        else:
                            txt.insert(tk.END, f"    {item}\n", "dim")
                    if hits == 0:
                        txt.insert(tk.END, "\n✓ No known malicious indicators.\n", "ok")
                txt.config(state="disabled")
            _lpipe_status.set(f"✓ Done — {len(pipes)} pipe(s) found")
        root.after(0, _upd)
    threading.Thread(target=_worker, daemon=True).start()
_lpipe_btn_f = tk.Frame(_lpipe_ctrl, bg=C["surface0"]); _lpipe_btn_f.pack(fill=tk.X, pady=(0,2))
