_lsch_hsc = tk.Scrollbar(_lu_sch_tab, orient="horizontal", command=_lsch_txt.xview,
                          bg=C["surface1"], troughcolor=C["base"], relief="flat", bd=0, width=7)
_lsch_txt.config(xscrollcommand=_lsch_hsc.set); _lsch_sc.config(command=_lsch_txt.yview)
