_lsch_txt.tag_configure("hit",  foreground=C["red"],   font=("Consolas",8,"bold"))
_lsch_txt.tag_configure("dim",  foreground=C["overlay0"])
_lsch_txt.tag_configure("val",  foreground=C["text"])
_lsch_txt.tag_configure("ok",   foreground=C["green"])
_SUSP_TASK_BINS = {"temp\\","appdata\\","downloads\\","desktop\\","public\\",
                   "wscript","cscript","mshta","powershell","cmd.exe","regsvr32",
                   "certutil","bitsadmin","rundll32.exe","wmic.exe"}
_SUSP_TASK_TRIGGERS = {"at logon","at startup","on idle","on event","once"}
def _lsch_query():
    _lsch_status.set("⏳ Querying schtasks...")
    filt = _lsch_filter.get().strip().lower()
    susp_only = _lsch_susp_only.get()
    def _worker_with_raw(raw: str):
        tasks = []
        current = {}
        for line in raw.splitlines():
            line = line.rstrip()
            if line.startswith("TaskName:"):
                if current: tasks.append(current)
                current = {"name": line.split(":",1)[1].strip(), "lines": [], "suspicious": False, "reasons": []}
            elif current:
                current["lines"].append(line)
                ll = line.lower()
                if "run as user:" in ll and "system" not in ll and "service" not in ll:
                    pass
                if "task to run:" in ll:
                    val = line.split(":",1)[1].strip().lower() if ":" in line else ""
                    if any(s in val for s in _SUSP_TASK_BINS):
                        current["suspicious"] = True; current["reasons"].append(f"Suspicious binary path: {val[:80]}")
                if "scheduled task state:" in ll and "disabled" not in ll:
                    pass
                if "trigger:" in ll:
                    val = line.lower()
                    if any(t in val for t in _SUSP_TASK_TRIGGERS):
                        current["reasons"].append(f"Trigger: {line.split(':',1)[-1].strip()}")
                if "status:" in ll and ("running" in ll or "queued" in ll):
                    current["reasons"].append("Status: currently running/queued")
                if "next run time:" in ll and "disabled" not in ll and "n/a" not in ll:
                    pass
        if current: tasks.append(current)
        if filt:
            tasks = [t for t in tasks if filt in t["name"].lower() or
                     any(filt in l.lower() for l in t["lines"])]
        if susp_only:
            tasks = [t for t in tasks if t["suspicious"] or t["reasons"]]
        def _upd():
            _lsch_txt.config(state="normal"); _lsch_txt.delete("1.0", tk.END)
            susp_count = sum(1 for t in tasks if t["suspicious"] or t["reasons"])
            _lsch_txt.insert(tk.END, f"SCHEDULED TASKS — {len(tasks)} shown, {susp_count} suspicious\n\n", "hdr")
            for t in tasks:
                is_s = t["suspicious"] or bool(t["reasons"])
                _lsch_txt.insert(tk.END, f"{'⚠ ' if is_s else '  '}{t['name']}\n",
                                 "hit" if is_s else "val")
                for r in t["reasons"]:
                    _lsch_txt.insert(tk.END, f"      -> {r}\n", "hit")
                for l in t["lines"]:
                    _lsch_txt.insert(tk.END, f"    {l}\n", "dim")
                _lsch_txt.insert(tk.END, "\n", "")
            if not tasks:
                _lsch_txt.insert(tk.END, "No tasks found.\n", "dim")
            _lsch_txt.config(state="disabled")
            _lsch_status.set(f"✓ {len(tasks)} task(s) shown, {susp_count} suspicious")
        root.after(0, _upd)
    def _done(resp, err):
        raw = ""
        if err is not None:
            raw = f"Error: {err}"
        else:
            try:
                if isinstance(resp, dict) and resp.get("ok") and isinstance(resp.get("result"), dict):
                    rj = resp["result"]
                    raw = (str(rj.get("stdout", "")) or "").strip()
                    if not raw:
                        raw = (str(rj.get("stderr", "")) or "").strip()
                else:
                    raw = str((resp or {}).get("error", "Admin Manager offline"))
            except Exception:
                raw = "Admin Manager error"
        threading.Thread(target=lambda: _worker_with_raw(raw), daemon=True).start()
    _admin_run_cmd_safe("Scheduled Tasks", "schtasks /query /fo LIST /v", timeout_s=30, danger_action_id="EXEC", done_fn=_done)
_lsch_btn_f = tk.Frame(_lsch_ctrl, bg=C["surface0"]); _lsch_btn_f.pack(fill=tk.X, pady=(0,2))
