_SUSP_PREFETCH = {"mimikatz","psexec","wce","pwdump","procdump","fgdump","meterpreter",
                  "cobaltstrike","beacon","empire","rubeus","sharphound","bloodhound",
                  "net1.exe","whoami","ipconfig","nltest","certutil"}
def _lpf_read():
    _lpf_status.set("⏳ Reading prefetch files...")
    filt   = _lpf_filter.get().strip().lower()
    sorter = _lpf_sort_sv.get()
    def _done(resp, err):
        out = ""
        if err is not None:
            out = f"Error: {err}"
        else:
            try:
                if isinstance(resp, dict) and resp.get("ok") and isinstance(resp.get("result"), dict):
                    rj = resp["result"]
                    out = (str(rj.get("stdout", "")) or "").strip()
                    if not out:
                        out = (str(rj.get("stderr", "")) or "").strip()
                else:
                    out = str((resp or {}).get("error", "Admin Manager offline"))
            except Exception:
                out = "Admin Manager error"
        def _worker_with_out():
            results = []
            pf_names = []
            try:
                for ln in (out or "").splitlines():
                    s = ln.strip()
                    if s.lower().endswith(".pf"):
                        pf_names.append(s)
            except Exception:
                pass
            for nm in pf_names:
                base = nm.rsplit("-", 1)[0] if "-" in nm else nm
                base = base.replace(".pf", "")
                results.append({"name": base, "run_count": 0, "last_run": "", "mtime": 0})
            if filt:
                results = [r for r in results if filt in r["name"].lower()]
            if sorter == "Name":
                results.sort(key=lambda x: x["name"].lower())
            def _upd():
                _lpf_txt.config(state="normal"); _lpf_txt.delete("1.0", tk.END)
                susp = [r for r in results if any(s in r["name"].lower() for s in _SUSP_PREFETCH)]
                _lpf_txt.insert(tk.END, f"PREFETCH — {len(results)} file(s)  ·  {len(susp)} suspicious\n\n", "hdr")
                hdr_line = f"  {'EXE NAME':<40}\n"
                _lpf_txt.insert(tk.END, hdr_line, "hdr")
                _lpf_txt.insert(tk.END, "  " + "─"*46 + "\n", "dim")
                for r in results:
                    is_s = any(s in r["name"].lower() for s in _SUSP_PREFETCH)
                    prefix = "⚠ " if is_s else "  "
                    line = f"{prefix}{r['name']:<40}\n"
                    _lpf_txt.insert(tk.END, line, "hit" if is_s else "val")
                if not results:
                    _lpf_txt.insert(tk.END, "No prefetch files found.\n", "dim")
                _lpf_txt.insert(tk.END, "\n--- RAW OUTPUT ---\n", "hdr")
                _lpf_txt.insert(tk.END, (out or "") + "\n", "dim")
                _lpf_txt.config(state="disabled")
                _lpf_status.set(f"✓ {len(results)} prefetch file(s) · {len(susp)} suspicious")
            root.after(0, _upd)
        threading.Thread(target=_worker_with_out, daemon=True).start()
    _admin_run_cmd_safe("Prefetch Reader", 'cmd /c dir /b "C:\\Windows\\Prefetch\\*.pf"', timeout_s=25, danger_action_id="EXEC", done_fn=_done)
_lpf_btn_f = tk.Frame(_lpf_ctrl, bg=C["surface0"]); _lpf_btn_f.pack(fill=tk.X, pady=(0,2))
