_ld_txt.tag_configure("added",   foreground=C["green"],   background="#1e3a2e")
_ld_txt.tag_configure("removed", foreground=C["red"],     background="#3a1e1e")
_ld_txt.tag_configure("hdr",     foreground=C["blue"],    font=("Consolas",8,"bold"))
_ld_txt.tag_configure("match",   foreground=C["green"])
_ld_txt.tag_configure("differ",  foreground=C["red"])
_ld_txt.tag_configure("dim",     foreground=C["overlay0"])

def _ld_write(msg, tag=""):
    _ld_txt.config(state="normal")
    _ld_txt.insert(tk.END, msg, tag)
    _ld_txt.config(state="disabled")

def _ld_run():
    a = _ld_file1.get().strip(); b = _ld_file2.get().strip()
    if not a or not b:
        messagebox.showwarning("Diff", "Select both files first."); return
    if not os.path.isfile(a) or not os.path.isfile(b):
        messagebox.showwarning("Diff", "One or both files not found."); return
    mode = _ld_mode.get()
    _ld_status.set("⏳ Comparing...")

    def _worker():
        import hashlib, difflib, time as _t
        _ld_txt.after(0, lambda: (_ld_txt.config(state="normal"),
                                   _ld_txt.delete("1.0", tk.END),
                                   _ld_txt.config(state="disabled")))
        time.sleep(0.05)

        def w(msg, tag=""): root.after(0, lambda m=msg, t=tag: _ld_write(m, t))

        w(f"{'='*70}\n", "hdr")
        w(f"  FILE DIFF  —  {mode}\n", "hdr")
        w(f"{'='*70}\n\n", "hdr")

        try:
            sa = os.stat(a); sb = os.stat(b)
            w(f"  File A : {a}\n", "dim")
            w(f"  File B : {b}\n\n", "dim")


            w("[ HASHES ]\n", "hdr")
            for algo in ("md5","sha1","sha256"):
                h = hashlib.new(algo)
                for path in (a, b):
                    with open(path,"rb") as f:
                        for chunk in iter(lambda: f.read(65536), b""):
                            h.update(chunk)
                    hv = h.hexdigest(); h = hashlib.new(algo)
                    tag = ""
                else:
                    pass
                ha = hashlib.new(algo)
                hb = hashlib.new(algo)
                with open(a,"rb") as f:
                    for chunk in iter(lambda: f.read(65536), b""): ha.update(chunk)
                with open(b,"rb") as f:
                    for chunk in iter(lambda: f.read(65536), b""): hb.update(chunk)
                ha_h = ha.hexdigest(); hb_h = hb.hexdigest()
                match = ha_h == hb_h
                w(f"  {algo.upper():<8}  A: {ha_h}\n", "match" if match else "removed")
                w(f"           B: {hb_h}  {'✓ MATCH' if match else '✗ DIFFER'}\n",
                  "match" if match else "differ")
            w("\n", "")


            w("[ METADATA ]\n", "hdr")
            w(f"  Size A : {sa.st_size:,} bytes\n", "dim")
            w(f"  Size B : {sb.st_size:,} bytes\n", "dim")
            diff_sz = sb.st_size - sa.st_size
            sign = "+" if diff_sz >= 0 else ""
            w(f"  Δ Size : {sign}{diff_sz:,} bytes ({sign}{diff_sz/max(sa.st_size,1)*100:.1f}%)\n",
              "added" if diff_sz > 0 else ("removed" if diff_sz < 0 else "match"))
            w(f"  Mtime A: {_t.strftime('%Y-%m-%d %H:%M:%S', _t.localtime(sa.st_mtime))}\n", "dim")
            w(f"  Mtime B: {_t.strftime('%Y-%m-%d %H:%M:%S', _t.localtime(sb.st_mtime))}\n\n", "dim")

            if mode in ("Text Diff", "Full Report"):
                w("[ TEXT DIFF (unified) ]\n", "hdr")
                try:
                    with open(a,"r",encoding="utf-8",errors="replace") as f: la = f.readlines()
                    with open(b,"r",encoding="utf-8",errors="replace") as f: lb = f.readlines()
                    diff = list(difflib.unified_diff(la, lb,
                                                     fromfile=os.path.basename(a),
                                                     tofile=os.path.basename(b), n=3))
                    if not diff:
                        w("  ✓ Files are textually identical.\n", "match")
                    else:
                        for line in diff[:500]:
                            if line.startswith("+++") or line.startswith("---") or line.startswith("@@"):
                                w(line, "hdr")
                            elif line.startswith("+"):
                                w(line, "added")
                            elif line.startswith("-"):
                                w(line, "removed")
                            else:
                                w(line, "dim")
                        if len(diff) > 500:
                            w(f"\n  ... ({len(diff)-500} more lines truncated)\n", "dim")
                except UnicodeDecodeError:
                    w("  (Binary file — text diff skipped)\n", "dim")
                w("\n", "")

            if mode in ("Hex Diff", "Full Report"):
                w("[ HEX DIFF (first 4096 bytes) ]\n", "hdr")
                with open(a,"rb") as f: ba = f.read(4096)
                with open(b,"rb") as f: bb = f.read(4096)
                differ_count = 0
                for i in range(0, min(len(ba), len(bb)), 16):
                    chunk_a = ba[i:i+16]; chunk_b = bb[i:i+16]
                    if chunk_a != chunk_b:
                        differ_count += 1
                        hex_a = " ".join(f"{x:02x}" for x in chunk_a)
                        hex_b = " ".join(f"{x:02x}" for x in chunk_b)
                        w(f"  0x{i:04X}  A: {hex_a:<47}\n", "removed")
                        w(f"         B: {hex_b:<47}\n", "added")
                        if differ_count >= 50:
                            w("  ... (too many differences — truncated)\n", "dim")
                            break
                if differ_count == 0:
                    w(f"  ✓ First {min(len(ba),len(bb))} bytes identical.\n", "match")
                w("\n", "")

        except Exception as _ex:
            w(f"\n  ✗ Error: {_ex}\n", "removed")

        root.after(0, lambda: _ld_status.set("✓ Done"))

    if _ld_mode.get() == "Session Snapshot Diff":
        _ld_status.set("⏳ Comparing snapshots…")
        def _snap_worker():
            try:
                import json as _js2
                def _load_snap(path):
                    if path.endswith(".json"):
                        with open(path, encoding="utf-8") as f: return _js2.load(f)
                    lines = open(path, encoding="utf-8", errors="replace").read().splitlines()
                    return {l.strip() for l in lines if l.strip()}
                sa2 = _load_snap(a); sb2 = _load_snap(b)
                if isinstance(sa2, dict) and isinstance(sb2, dict):
                    keys_a = set(sa2.keys()); keys_b = set(sb2.keys())
                    appeared = sorted(keys_b - keys_a)
                    disappeared = sorted(keys_a - keys_b)
                    changed = sorted(k for k in keys_a & keys_b if str(sa2[k]) != str(sb2[k]))
                    unchanged = len(keys_a & keys_b) - len(changed)
                else:
                    set_a = set(sa2) if isinstance(sa2, (set,list)) else set(str(sa2).splitlines())
                    set_b = set(sb2) if isinstance(sb2, (set,list)) else set(str(sb2).splitlines())
                    appeared    = sorted(set_b - set_a)
                    disappeared = sorted(set_a - set_b)
                    changed     = []
                    unchanged   = len(set_a & set_b)
                def _show():
                    _ld_txt.config(state="normal"); _ld_txt.delete("1.0", tk.END)
                    _ld_txt.insert(tk.END, f"  SESSION SNAPSHOT DIFF\n", "hdr")
                    _ld_txt.insert(tk.END, f"  A: {os.path.basename(a)}   B: {os.path.basename(b)}\n\n", "dim")
                    _ld_txt.insert(tk.END, f"  {'APPEARED':<14} {len(appeared):>4}   {'DISAPPEARED':<14} {len(disappeared):>4}   {'CHANGED':<10} {len(changed):>4}   UNCHANGED {unchanged}\n\n", "hdr")
                    _ld_txt.insert(tk.END, "  ── APPEARED ──────────────────────────────────────\n", "hdr")
                    for item in appeared[:200]:
                        val = f" = {str(sb2[item])[:60]}" if isinstance(sb2,dict) else ""
                        _ld_txt.insert(tk.END, f"  + {str(item)[:80]}{val}\n", "added")
                    _ld_txt.insert(tk.END, "\n  ── DISAPPEARED ────────────────────────────────────\n", "hdr")
                    for item in disappeared[:200]:
                        val = f" = {str(sa2[item])[:60]}" if isinstance(sa2,dict) else ""
                        _ld_txt.insert(tk.END, f"  - {str(item)[:80]}{val}\n", "removed")
                    if changed:
                        _ld_txt.insert(tk.END, "\n  ── CHANGED ────────────────────────────────────────\n", "hdr")
                        for k in changed[:200]:
                            _ld_txt.insert(tk.END, f"  ~ {k[:60]}\n", "differ")
                            _ld_txt.insert(tk.END, f"      A: {str(sa2[k])[:80]}\n", "removed")
                            _ld_txt.insert(tk.END, f"      B: {str(sb2[k])[:80]}\n", "added")
                    _ld_txt.config(state="disabled")
                    _ld_status.set(f"✓ +{len(appeared)} -{len(disappeared)} ~{len(changed)}")
                root.after(0, _show)
            except Exception as _se:
                root.after(0, lambda: _ld_status.set(f"✗ {_se}"))
        threading.Thread(target=_snap_worker, daemon=True).start()
        return

    threading.Thread(target=_worker, daemon=True).start()

