_SUSP_PROC_NAMES = {"cmd","power" + "shell","wscript","cscript","mshta","rundll32",
                     "regsvr32","certutil","bitsadmin","schtasks","net","whoami","mimikatz","psexec"}
_SUSP_PATHS = {"temp","tmp","appdata\\local\\temp","downloads","\\users\\public"}

