_PRIVATE_PREFIXES = ("10.","172.","192.168.","127.","::1","0.0.0.","fe80")
_SUSPICIOUS_PORTS = {1337,4444,31337,6666,9999,12345,1234,8888,6667,6697}

def _nc_refresh():
    if not _psutil: messagebox.showwarning("Network","psutil not installed\npip install psutil"); return
    ext_only = _nc_ext_only.get()
    _nc_out.config(state="normal"); _nc_out.delete("1.0",tk.END); _nc_out.config(state="disabled")
    def _do():
        try: conns = _psutil.net_connections(kind="inet")
        except Exception as e:
            root.after(0, lambda: _nc_status_sv.set(f"Error (admin?): {e}")); return
        pid_map = {}
        try:
            for p in _psutil.process_iter(["pid","name"]): pid_map[p.info["pid"]] = p.info["name"] or "?"
        except Exception: pass
        shown = 0; hdr = f"{'PROTO':<6}  {'LOCAL':<24}  {'REMOTE':<24}  {'STATE':<13}  {'PORT FLAGS':<16}  PROCESS"
        root.after(0, lambda: [
            _nc_out.config(state="normal"),
            _nc_out.insert(tk.END, hdr+"\n","HEAD"),
            _nc_out.insert(tk.END,"─"*110+"\n","DIM"),
            _nc_out.config(state="disabled"),
        ])
        _nc_proc_flt = _nc_filter_v.get().strip().lower()
        _nc_port_flt = _nc_port_filter_v.get().strip()
        for c in sorted(conns, key=lambda x: x.pid or 0):
            if not c.raddr: continue
            rip = c.raddr.ip; rport = c.raddr.port
            if ext_only and any(rip.startswith(p) for p in _PRIVATE_PREFIXES): continue
            if _nc_proc_flt and _nc_proc_flt not in (pid_map.get(c.pid,"") or "").lower(): continue
            if _nc_port_flt and _nc_port_flt.isdigit() and int(_nc_port_flt) not in (c.laddr.port if c.laddr else 0, rport): continue
            shown += 1
            proto = "TCP" if c.type==1 else "UDP"
            local = f"{c.laddr.ip}:{c.laddr.port}" if c.laddr else "-"
            remote = f"{rip}:{rport}"; state = c.status or "-"
            pname  = pid_map.get(c.pid, f"PID={c.pid}")
            flags = []
            if rport in _SUSPICIOUS_PORTS: flags.append(f"⚠SUSP:{rport}")
            if rport in (80,443,8080,8443): flags.append("WEB")
            if rport in (21,22,23,25,53,110,143): flags.append("STD")
            flag_str = ",".join(flags) or "-"
            tag = ("BAD" if rport in _SUSPICIOUS_PORTS else
                   ("WARN" if any(rip.startswith(p) for p in ["0.","169.254."]) else "OK"))
            line = f"{proto:<6}  {local:<24}  {remote:<24}  {state:<13}  {flag_str:<16}  {pname}"
            if not _APP_DYING[0]:
                try:
                    root.after(0, lambda l=line, t=tag: [
                        _nc_out.config(state="normal"), _nc_out.insert(tk.END, l+"\n", t),
                        _nc_out.config(state="disabled"),
                    ] if not _APP_DYING[0] else None)
                except Exception: pass
        if not _APP_DYING[0]:
            try: root.after(0, lambda: _nc_status_sv.set(f"✓ {shown} connections"))
            except Exception: pass
        if _nc_auto_var.get() and not _APP_DYING[0]:
            try: root.after(30000, _nc_refresh)
            except Exception: pass
    threading.Thread(target=_do, daemon=True).start()

_nc_scan = _nc_refresh

def _nc_copy_sel():
    try:
        sel = _nc_out.get("sel.first","sel.last").strip()
        root.clipboard_clear(); root.clipboard_append(sel)
    except Exception: pass

def _nc_lookup_sel():
    try:
        sel = _nc_out.get("sel.first","sel.last").strip()
        parts = sel.split()
        ip = None
        for p in parts:
            if "." in p and ":" in p:
                ip = p.split(":")[0]
                break
            elif "." in p and p[0].isdigit():
                ip = p; break
        if not ip: messagebox.showwarning("Lookup","No IP found in selection"); return
        import webbrowser
        webbrowser.open(f"https://www.abuseipdb.com/check/{ip}")
    except Exception as e:
        messagebox.showwarning("Lookup", str(e))

def _nc_export():
    path = filedialog.asksaveasfilename(defaultextension=".txt", filetypes=[("Text","*.txt")])
    if not path: return
    try:
        with open(path, "w", encoding="utf-8") as f:
            f.write(_nc_out.get("1.0", tk.END))
        messagebox.showinfo("Export", f"Saved: {path}")
    except Exception as e:
        messagebox.showerror("Export", str(e))

