def _nt_insert_ts():
    _nt_txt.insert(tk.INSERT, f"\n─── {time.strftime('%Y-%m-%d %H:%M:%S')} ───\n")

def _nt_search(*_):
    _nt_txt.tag_remove("search_hl", "1.0", tk.END)
    q = _nt_search_var.get().strip()
    if not q: _nt_search_sv.set(""); return
    count = 0; start = "1.0"
    while True:
        idx = _nt_txt.search(q, start, tk.END, nocase=True)
        if not idx: break
        end = f"{idx}+{len(q)}c"
        _nt_txt.tag_add("search_hl", idx, end)
        start = end; count += 1
    _nt_search_sv.set(f"  {count} match{'es' if count!=1 else ''}" if count else "  No matches")
    if count: _nt_txt.see(_nt_txt.tag_ranges("search_hl")[0])

def _nt_export_md():
    path = filedialog.asksaveasfilename(defaultextension=".md", filetypes=[("Markdown","*.md"),("Text","*.txt")])
    if not path: return
    try:
        with open(path, "w", encoding="utf-8") as f:
            f.write(f"# Analyst Notes\n_Exported {time.strftime('%Y-%m-%d %H:%M:%S')}_\n\n")
            f.write(_nt_txt.get("1.0", tk.END))
        messagebox.showinfo("Export", f"Saved: {path}")
    except Exception as e: messagebox.showerror("Export", str(e))

def _nt_word_count():
    content = _nt_txt.get("1.0", tk.END).strip()
    words = len(content.split()); lines = content.count("\n") + 1; chars = len(content)
    messagebox.showinfo("Stats", f"Lines: {lines}\nWords: {words}\nChars: {chars}")

