_SUSP_STRINGS = [
    b"mimikatz", b"sekurlsa", b"lsadump", b"HKLM\\SAM",
    b"cmd.exe /c", b"powershell -enc", b"powershell -e ",
    b"WScript.Shell", b"CreateObject", b"Shell.Application",
    b"URLDownloadToFile", b"bitsadmin", b"certutil -decode",
    b"regsvr32 /s", b"mshta http", b"schtasks /create",
    b"net user /add", b"netsh advfirewall",
    b"VirtualAlloc", b"WriteProcessMemory", b"CreateRemoteThread",
    b"IsDebuggerPresent", b"NtUnmapViewOfSection",
    b"RtlDecompressBuffer", b"BCryptEncrypt",
]

def _defense_score_file(path: str) -> tuple[int, list[str]]:
    score = 0; reasons = []
    try:
        with open(path, "rb") as f: raw = f.read(min(os.path.getsize(path), 4 * 1024 * 1024))
    except Exception as e:
        return 0, [f"Read error: {e}"]


    if _DEF_SETTINGS["check_entropy"] and len(raw) > 512:
        import math
        counts = [0] * 256
        for b in raw: counts[b] += 1
        n = len(raw)
        ent = -sum((c/n) * math.log2(c/n) for c in counts if c)
        if ent >= _DEF_SETTINGS["entropy_threshold"]:
            score += 2; reasons.append(f"High entropy: {ent:.2f} bits (packed/encrypted)")


    if _DEF_SETTINGS["check_strings"]:
        found = [s.decode("latin-1","ignore") for s in _SUSP_STRINGS if s in raw]
        if found:
            score += len(found); reasons.append(f"Suspicious strings: {', '.join(found[:5])}")


    ext = os.path.splitext(path)[1].lower()
    if _DEF_SETTINGS["check_pe"] and ext in (".exe", ".dll", ".scr", ".com"):
        try:
            import pefile as _pef
            pe = _pef.PE(path, fast_load=True)

            pe.parse_data_directories(
                directories=[_pef.DIRECTORY_ENTRY["IMAGE_DIRECTORY_ENTRY_IMPORT"]])
            imp_names = []
            if hasattr(pe, "DIRECTORY_ENTRY_IMPORT"):
                for e in pe.DIRECTORY_ENTRY_IMPORT:
                    dll = e.dll.decode("ascii","ignore").lower()
                    imp_names.append(dll)
            if not imp_names:
                score += 3; reasons.append("PE: no imports (likely packed)")

            susp_sec = [".thefirm",".adata",".cdata",".packed"]
            for s in pe.sections:
                try:
                    sname = s.Name.decode("ascii","ignore").strip("\x00").lower()
                    if sname in susp_sec:
                        score += 2; reasons.append(f"Suspicious PE section: {sname}")
                except Exception: pass

            last = pe.sections[-1] if pe.sections else None
            if last:
                overlay_start = last.PointerToRawData + last.SizeOfRawData
                fsize = os.path.getsize(path)
                if fsize - overlay_start > 1024:
                    score += 1; reasons.append(f"PE: overlay data {fsize-overlay_start} bytes")
        except Exception as pe_err:
            if "not a valid PE" not in str(pe_err).lower():
                pass


    if _DEF_SETTINGS["check_yara"] and _yara_rules:
        try:
            matches = _yara_rules.match(path)
            if matches:
                score += len(matches) * 2
                reasons.append(f"YARA: {', '.join(m.rule for m in matches[:4])}")
        except Exception: pass


    if _DEF_SETTINGS["check_size"] and ext == ".exe":
        fsize = os.path.getsize(path)
        if fsize < 2048:
            score += 2; reasons.append(f"Tiny EXE: {fsize} bytes (dropper?)")
        elif fsize > 200 * 1024 * 1024:
            score += 1; reasons.append(f"Huge file: {fsize // (1024*1024)} MB")

    return score, reasons

def _defense_action(path: str, score: int, reasons: list, vt_detections: int = -1):
    threshold = _DEF_SETTINGS["auto_quarantine_threshold"]
    action = _DEF_SETTINGS["action_on_detect"]
    if score == 0 and vt_detections <= 0:
        return

    def _do_action(chosen):
        if chosen == "quarantine":
            qid = _quar_store(path, f"Defense score={score} vt={vt_detections}")
            if qid:
                root.after(0, lambda: _defense_log(f"  -> QUARANTINED: {os.path.basename(path)} (qid={qid})", "BAD"))
                root.after(0, _quarantine_refresh)
        elif chosen == "delete":
            try:
                os.remove(path)
                root.after(0, lambda: _defense_log(f"  -> DELETED: {os.path.basename(path)}", "BAD"))
            except Exception as e:
                root.after(0, lambda: _defense_log(f"  -> Delete failed: {e}", "WARN"))
        elif chosen == "log_only":
            root.after(0, lambda: _defense_log(f"  -> Logged only (no action)", "DIM"))

    if action == "log_only":
        _do_action("log_only")
    elif action == "quarantine" or (action == "auto" and (score >= threshold or vt_detections >= threshold)):
        _do_action("quarantine")
    elif action == "delete":
        _do_action("delete")
    elif action == "ask":
        def _ask():
            fname = os.path.basename(path)
            msg = (f"Threat detected!\n\nFile: {fname}\n"
                   f"Score: {score}  VT: {vt_detections if vt_detections >= 0 else 'N/A'}\n\n"
                   f"Reasons:\n" + "\n".join(f"  • {r}" for r in reasons[:6]) +
                   "\n\nWhat do you want to do?")
            from tkinter import simpledialog as _sd
            popup = tk.Toplevel(root)
            popup.title("⚠ Threat Detected"); popup.configure(bg=C["base"])
            popup.geometry("520x420"); popup.grab_set()
            popup.attributes("-topmost", True)
            tk.Label(popup, text="⚠  THREAT DETECTED", font=FB, bg=C["base"], fg=C["red"]).pack(pady=(14,4))
            tk.Frame(popup, bg=C["red"], height=1).pack(fill=tk.X, padx=20)
            info_f = tk.Frame(popup, bg=C["surface0"], padx=16, pady=10); info_f.pack(fill=tk.X, padx=20, pady=8)
            for k, v in [("File:", fname), ("Score:", str(score)),
                          ("VT:", str(vt_detections) if vt_detections >= 0 else "N/A")]:
                r = tk.Frame(info_f, bg=C["surface0"]); r.pack(fill=tk.X)
                tk.Label(r, text=k, width=8, anchor="w", font=("Consolas",9,"bold"),
                         bg=C["surface0"], fg=C["overlay0"]).pack(side=tk.LEFT)
                tk.Label(r, text=v, font=("Consolas",9), bg=C["surface0"], fg=C["red"]).pack(side=tk.LEFT)
            reasons_txt = tk.Text(popup, bg="#0a0a10", fg=C["text"], height=6,
                                   font=("Consolas",8), relief="flat", bd=0, padx=8)
            reasons_txt.pack(fill=tk.X, padx=20, pady=(0,8))
            for r in reasons: reasons_txt.insert(tk.END, f"  • {r}\n")
            reasons_txt.config(state="disabled")
            btn_f = tk.Frame(popup, bg=C["base"]); btn_f.pack(pady=8)
            def _pick(c): popup.destroy(); threading.Thread(target=_do_action, args=(c,), daemon=True).start()
            tk.Button(btn_f, text="🔒 Quarantine", command=lambda: _pick("quarantine"),
                      bg=C["yellow"], fg=C["base"], font=FB, relief="flat", padx=14, pady=6, cursor="hand2").pack(side=tk.LEFT, padx=6)
            tk.Button(btn_f, text="🗑 Delete", command=lambda: _pick("delete"),
                      bg=C["red"], fg=C["base"], font=FB, relief="flat", padx=14, pady=6, cursor="hand2").pack(side=tk.LEFT, padx=6)
            tk.Button(btn_f, text="📝 Log Only", command=lambda: _pick("log_only"),
                      bg=C["overlay0"], fg=C["base"], font=FB, relief="flat", padx=14, pady=6, cursor="hand2").pack(side=tk.LEFT, padx=6)
            tk.Button(btn_f, text="Ignore", command=popup.destroy,
                      bg=C["surface2"], fg=C["text"], font=FS, relief="flat", padx=10, pady=6, cursor="hand2").pack(side=tk.LEFT, padx=6)
        root.after(0, _ask)


