_dsv_scanned  = tk.StringVar(value="0")
_dsv_threats  = tk.StringVar(value="0")
_dsv_quarantine_count = tk.StringVar(value="0")
_dsv_clean    = tk.StringVar(value="0")


def _defense_scan_folder(folder=None):
    if not folder:
        folder = filedialog.askdirectory(title="Choose folder to analyze in Defense mode")
    if not folder: return
    exts = _DEF_SETTINGS["scan_extensions"]
    _defense_set_status("SCANNING")
    _defense_log(f">_ Advanced Defense Scan: {folder}", "PROMPT")
    _defense_log(f"   Extensions: {' '.join(exts)}", "DIM")

    def _worker():
        _bg_nice()
        scanned = threats = clean = 0
        import time as _t2
        _last_ui = [0.0]
        def _throttled_update(s):
            now = _t2.time()
            if now - _last_ui[0] > 0.15:
                _last_ui[0] = now
                root.after(0, lambda sv=s: _dsv_scanned.set(str(sv)))
        for root_dir, dirs, files in os.walk(folder):
            for fn in files:
                fpath = os.path.join(root_dir, fn)
                if os.path.splitext(fn)[1].lower() not in exts:
                    continue
                scanned += 1
                _throttled_update(scanned)
                score, reasons = _defense_score_file(fpath)
                vt_det = -1

                if _DEF_SETTINGS["check_vt"] and API_KEYS:
                    try:
                        import hashlib as _hl2
                        h = _hl2.md5(open(fpath,"rb").read()).hexdigest()
                        k = API_KEYS[0]
                        r = requests.get(f"https://www.virustotal.com/api/v3/files/{h}",
                                          headers={"x-apikey": k}, timeout=10)
                        if r.status_code == 200:
                            stats = r.json().get("data",{}).get("attributes",{}).get("last_analysis_stats",{})
                            vt_det = stats.get("malicious", 0)
                            if vt_det > 0:
                                score += vt_det * 2
                                reasons.append(f"VirusTotal: {vt_det} detections")
                    except Exception: pass

                if score > 0:
                    threats += 1
                    with _defense_lock: _defense_results.append((fpath, score, reasons, vt_det))
                    root.after(0, lambda t=threats: _dsv_threats.set(str(t)))
                    root.after(0, lambda p=fpath, s=score, rs=reasons, v=vt_det:
                        _defense_log(f"  ⚠ {os.path.basename(p)} — score={s}", "BAD"))
                    for reason in reasons:
                        root.after(0, lambda r=reason: _defense_log(f"     • {r}", "WARN"))
                    _defense_action(fpath, score, reasons, vt_det)
                else:
                    clean += 1
                    root.after(0, lambda c=clean: _dsv_clean.set(str(c)))

        root.after(0, lambda: _defense_log(
            f"\n>_ Scan completed: {scanned} files, {threats} threats, {clean} clean", "PROMPT"))
        root.after(0, lambda: _defense_set_status("ARMED" if _DEFENSE_ACTIVE.is_set() else "DISARMED"))
        root.after(0, _quarantine_refresh)
        _auto_gc("defense_scan_folder")

    threading.Thread(target=_worker, daemon=True).start()

def _defense_arm():
    _sl("Defense mode ARMED", "DEFENSE")
