def _gs_browse(var, title):
    d = filedialog.askdirectory(title=title)
    if d: var.set(d)
for lbl, var, title in [
    ("Reports folder:",    _gs_v_reports_dir, "Choose reports folder"),
    ("Quarantine:",         _gs_v_quar_dir,    "Choose quarantine folder"),
    ("Debug log:",          _gs_v_debug_dir,   "Choose debug log folder"),
]:
    r = tk.Frame(_spp2, bg=C["surface0"]); r.pack(fill=tk.X, pady=4)
    tk.Label(r, text=lbl, font=FS, bg=C["surface0"], fg=C["text"], width=20, anchor="w").pack(side=tk.LEFT)
    _v = var
    tk.Entry(r, textvariable=_v, font=("Consolas",8), bg=C["mantle"], fg=C["text"],
             insertbackground=C["text"], relief="flat", bd=3, width=44).pack(side=tk.LEFT)
    tk.Button(r, text="📂", command=lambda v=_v, t=title: _gs_browse(v,t),
              bg=C["surface2"], fg=C["text"], font=FS, relief="flat", padx=6, cursor="hand2").pack(side=tk.LEFT, padx=4)


