def _gs_save_all():
    _sl("Settings saved", "CFG")
    try:
        CONFIG.update({

            "ui_font_size":       _gs_v_font_size.get(),
            "ui_log_maxlines":    int(_gs_v_log_maxlines.get()),
            "ui_confirm_exit":    _gs_v_confirm_exit.get(),
            "ui_show_tray":       _gs_v_show_tray.get(),
            "ui_minimize_tray":   _gs_v_minimize_tray.get(),
            "ui_show_splash":     _gs_v_splash.get(),
            "ui_terminal_bg":     _gs_v_dark_bg.get(),
            "ui_status_animation":_gs_v_status_anim.get(),
            "ui_toast_duration":  int(_gs_v_toast_dur.get()),

            "request_delay":      int(_gs_v_req_delay.get()),
            "vt_timeout":         int(_gs_v_vt_timeout.get()),
            "max_file_mb":        int(_gs_v_max_file_mb.get()),
            "auto_vt_upload":     _gs_v_auto_vt.get(),
            "auto_yara_compile":  _gs_v_auto_yara.get(),
            "auto_report":        _gs_v_auto_report.get(),
            "report_format":      _gs_v_report_fmt.get(),
            "hash_priority":      _gs_v_hash_priority.get(),
            "scan_recursive":     _gs_v_scan_recurse.get(),
            "skip_empty_files":   _gs_v_skip_empty.get(),
            "save_iocs_auto":     _gs_v_save_iocs.get(),
            "compare_with_previous": _gs_v_compare_prev.get(),
            "notify_malicious":   _gs_v_notify_malicious.get(),
            "notify_clean":       _gs_v_notify_clean.get(),
            "vt_rescan_after_days": int(_gs_v_vt_rescan_days.get()),

            "log_retention_days": int(_gs_v_log_retention.get()),
            "db_retention_days":  int(_gs_v_db_retention.get()),
            "store_file_hashes":  _gs_v_store_hashes.get(),
            "store_file_paths":   _gs_v_store_paths.get(),
            "anonymize_paths":    _gs_v_anon_paths.get(),
            "auto_delete_old_logs":_gs_v_auto_del_logs.get(),
            "encrypt_db":         _gs_v_encrypt_db.get(),
            "no_cloud_submit":      _gs_v_no_cloud.get(),
            "log_system_info":      _gs_v_log_sysinfo.get(),
            "log_last_ops":         _gs_v_log_last_ops.get(),
            "log_open_handles":          _gs_v_log_open_handles.get(),
            "crash_zip_include_session_log": _gs_v_zip_sess.get(),
            "crash_zip_include_sysinfo":     _gs_v_zip_sys.get(),
            "crash_zip_include_config":      _gs_v_zip_cfg.get(),
            "crash_zip_include_admin_log":   _gs_v_zip_adm.get(),
            "session_zip_enabled":           _gs_v_szip_en.get(),
            "session_zip_include_debug":     _gs_v_szip_debug.get(),
            "session_zip_include_app_usage": _gs_v_szip_app.get(),
            "session_zip_include_combined":  _gs_v_szip_combined.get(),

            "tshark_path":        _gs_v_tshark.get().strip(),
            "proxy":              _gs_v_proxy.get().strip(),

            "admin_mode_enabled": bool(_gs_v_admin_mgr_admin.get()),
            "admin_manager_admin": bool(_gs_v_admin_mgr_admin.get()),
            "admin_manager_pipe":  str(CONFIG.get("admin_manager_pipe", r"\\.\pipe\V0RTEX_AdminManager") or r"\\.\pipe\V0RTEX_AdminManager"),
            "admin_manager_allowed_processes": list(CONFIG.get("admin_manager_allowed_processes", [])),
            "admin_manager_max_hooks": int(CONFIG.get("admin_manager_max_hooks", 3)),
            "admin_manager_op_timeout_s": int(CONFIG.get("admin_manager_op_timeout_s", 20)),
        })
        _vx_cfg_write(CONFIG)
        _gs_result_sv.set("✓ All settings saved to config.json")
        _session_log("[SETTINGS] Global settings saved", "INFO")
        _checkpoint("SETTINGS", f"Global settings saved to config.json — API keys: {len(CONFIG.get('api_keys',[]))}, delay: {CONFIG.get('request_delay',15)}s, entropy_thr: {CONFIG.get('entropy_threshold',7.0)}")
    except Exception as e:
        _gs_result_sv.set(f"✗ Error: {e}")

def _gs_scrollframe(parent):
    c = tk.Canvas(parent, bg=C["base"], highlightthickness=0)
    sb = tk.Scrollbar(parent, orient="vertical", command=c.yview,
                      bg=C["surface1"], troughcolor=C["mantle"], relief="flat", bd=0, width=7)
    sb.pack(side=tk.RIGHT, fill=tk.Y); c.pack(fill=tk.BOTH, expand=True)
    c.configure(yscrollcommand=sb.set)
    inner = tk.Frame(c, bg=C["base"])
    win = c.create_window((0,0), window=inner, anchor="nw")
    def _cfg(e): c.configure(scrollregion=c.bbox("all")); c.itemconfig(win, width=e.width)
    c.bind("<Configure>", _cfg)
    return inner


