def _request_admin_elevation():
    try:
        import ctypes
        if sys.platform != "win32":
            return
        if _is_admin():
            messagebox.showinfo("Admin", "Already running as administrator.")
            return
        # Deploy admin_manager.py first
        _deploy_admin_manager()
        # Kill existing admin manager process if running (non-admin)
        try:
            _p = _ADMIN_MGR_PROC[0]
            if _p and getattr(_p, "poll", lambda: None)() is None:
                _p.terminate()
                import time
                time.sleep(0.5)
        except Exception:
            pass
        # Restart admin manager with UAC (runas verb) - no --standalone, just normal restart
        try:
            _am_path = os.path.join(os.path.dirname(os.path.abspath(__file__)), "V0rtex_System", "v0rtex_utils", "admin_manager.py")
            if not os.path.isfile(_am_path):
                _am_path = os.path.join(os.path.dirname(os.path.dirname(os.path.abspath(__file__))), "v0rtex_utils", "admin_manager.py")
            if not os.path.isfile(_am_path):
                messagebox.showerror("Admin", f"Admin Manager not found: {_am_path}")
                return
            pipe_name = str(CONFIG.get("admin_manager_pipe", r"\\.\pipe\V0RTEX_AdminManager") or r"\\.\pipe\V0RTEX_AdminManager")
            auth_key = _admin_mgr_get_auth_key()
            _args = [sys.executable, _am_path, "--base-dir", BASE_DIR, "--config-path", CONFIG_PATH,
                     "--pipe-name", pipe_name, "--auth-key", auth_key]
            _args_str = subprocess.list2cmdline(_args)
            ret = ctypes.windll.shell32.ShellExecuteW(None, "runas", sys.executable, _args_str, None, 1)
            if ret <= 32:
                messagebox.showerror("Admin", f"UAC elevation failed (code {ret})")
            else:
                messagebox.showinfo("Admin", "Admin Manager is now running as Administrator.\nUse 'Open ADMIN MANAGER tab' to access the UI.")
        except Exception as _am_e:
            messagebox.showerror("Admin", f"Failed to launch Admin Manager: {_am_e}")
    except Exception as e:
        messagebox.showerror("Admin", f"Elevation error: {e}")

_elev_status = tk.StringVar(value=f"Current: {'Admin' if _is_admin() else 'User mode'}")
tk.Label(sa5b, textvariable=_elev_status, font=("Consolas",9,"bold"), bg=C["surface0"], fg=C["green"] if _is_admin() else C["yellow"]).pack(anchor="w", padx=8, pady=(0,4))

def _refresh_am_status():
    try:
        r = _admin_mgr_request({"type": "PING"}, timeout_ms=500)
        if r.get("ok"):
            _elev_status.set("Admin Manager: Running as Admin")
        else:
            _elev_status.set("Admin Manager: Not running or no admin")
    except Exception:
        _elev_status.set("Admin Manager: Status unknown")

# Call once at startup
root.after(2000, _refresh_am_status)
