def _adm_mgr_auth_refresh_mask():
    try:
        k = str(CONFIG.get("admin_manager_auth_key", "") or "")
        if len(k) >= 12:
            _adm_mgr_auth_masked_sv.set(f"Auth key: {k[:4]}...{k[-4:]}  ({len(k)} chars)")
        elif k:
            _adm_mgr_auth_masked_sv.set(f"Auth key: set ({len(k)} chars)")
        else:
            _adm_mgr_auth_masked_sv.set("Auth key: not set")
    except Exception:
        _adm_mgr_auth_masked_sv.set("Auth key: error")

def _adm_mgr_rotate_auth_key():
    try:
        import secrets as _sec
        CONFIG["admin_manager_auth_key"] = _sec.token_urlsafe(72)[:96]
        _vx_cfg_write(CONFIG)
        _adm_mgr_auth_refresh_mask()
    except Exception:
        pass

def _adm_mgr_open_admin_log():
    try:
        log_dir = os.path.join(os.path.dirname(BASE_DIR), "v0rtex_utils", "debug_log", "admin_log")
        os.makedirs(log_dir, exist_ok=True)
        if sys.platform == "win32":
            os.startfile(log_dir)
        elif sys.platform == "darwin":
            subprocess.Popen(["open", log_dir])
        else:
            subprocess.Popen(["xdg-open", log_dir])
    except Exception:
        pass

_adm_mgr_acl_section = tk.Frame(sa5c, bg=C["surface0"]); _adm_mgr_acl_section.pack(fill=tk.X, padx=4, pady=(4,2))
