def _adm_mgr_acl_refresh():
    try:
        _adm_mgr_acl_lb.delete(0, tk.END)
        _ok = 0
        _missing = 0
        for _p in _gs_admin_mgr_allowed_paths:
            if os.path.isfile(_p):
                _ok += 1
                _adm_mgr_acl_lb.insert(tk.END, f"[EXISTS]  {_p}")
            else:
                _missing += 1
                _adm_mgr_acl_lb.insert(tk.END, f"[MISSING] {_p}")
        _adm_mgr_acl_status_sv.set(f"Entries: {len(_gs_admin_mgr_allowed_paths)}  ·  exists: {_ok}  ·  missing: {_missing}")
    except Exception:
        pass

def _adm_mgr_acl_add_from_picker():
    try:
        p = filedialog.askopenfilename(
            title="Select authorized executable",
            filetypes=[("Executable", "*.exe"), ("All files", "*.*")]
        )
        if not p:
            return
        p = os.path.normcase(os.path.abspath(p))
        if p not in _gs_admin_mgr_allowed_paths:
            _gs_admin_mgr_allowed_paths.append(p)
            _adm_mgr_acl_refresh()
    except Exception:
        pass

def _adm_mgr_acl_add_current():
    try:
        for p in [os.path.normcase(os.path.abspath(sys.executable)),
                  os.path.normcase(os.path.abspath(__file__))]:
            if p not in _gs_admin_mgr_allowed_paths:
                _gs_admin_mgr_allowed_paths.append(p)
        _adm_mgr_acl_refresh()
    except Exception:
        pass

def _adm_mgr_acl_remove_selected():
    try:
        sel = list(_adm_mgr_acl_lb.curselection())
        if not sel:
            return
        for idx in reversed(sel):
            if 0 <= idx < len(_gs_admin_mgr_allowed_paths):
                _gs_admin_mgr_allowed_paths.pop(idx)
        if not _gs_admin_mgr_allowed_paths:
            _adm_mgr_acl_add_current()
        _adm_mgr_acl_refresh()
    except Exception:
        pass

def _adm_mgr_acl_remove_missing():
    try:
        missing = [p for p in _gs_admin_mgr_allowed_paths if not os.path.isfile(p)]
        if not missing:
            _adm_mgr_acl_status_sv.set("Entries: clean — no missing paths")
            return
        if not messagebox.askyesno(
            "Admin Manager Allowlist",
            f"Remove {len(missing)} missing path(s) from allowlist?",
            parent=root
        ):
            return
        _gs_admin_mgr_allowed_paths[:] = [p for p in _gs_admin_mgr_allowed_paths if os.path.isfile(p)]
        if not _gs_admin_mgr_allowed_paths:
            _adm_mgr_acl_add_current()
        _adm_mgr_acl_refresh()
    except Exception:
        pass

def _adm_mgr_acl_export():
    try:
        out = filedialog.asksaveasfilename(
            title="Export Admin Manager allowlist",
            defaultextension=".json",
            filetypes=[("JSON", "*.json"), ("All files", "*.*")]
        )
        if not out:
            return
        blob = {
            "format": "v0rtex.admin_manager.allowlist.v1",
            "created_at": __import__("datetime").datetime.now().isoformat(),
            "paths": list(_gs_admin_mgr_allowed_paths),
        }
        with open(out, "w", encoding="utf-8") as f:
            json.dump(blob, f, indent=2)
        _adm_mgr_acl_status_sv.set(f"Entries: {len(_gs_admin_mgr_allowed_paths)}  ·  exported")
    except Exception as _e:
        _adm_mgr_acl_status_sv.set(f"Export error: {_e}")

def _adm_mgr_acl_import():
    try:
        src = filedialog.askopenfilename(
            title="Import Admin Manager allowlist",
            filetypes=[("JSON", "*.json"), ("All files", "*.*")]
        )
        if not src:
            return
        with open(src, "r", encoding="utf-8", errors="replace") as f:
            obj = json.load(f)
        if not isinstance(obj, dict):
            raise ValueError("invalid json format")
        paths = obj.get("paths", [])
        if not isinstance(paths, list):
            raise ValueError("paths must be a list")
        imported = []
        for p in paths:
            ps = str(p or "").strip()
            if ps:
                ps = os.path.normcase(os.path.abspath(ps))
                if ps not in imported:
                    imported.append(ps)
        if not imported:
            raise ValueError("no valid paths in file")
        _gs_admin_mgr_allowed_paths[:] = imported
        _adm_mgr_acl_refresh()
        _adm_mgr_acl_status_sv.set(f"Entries: {len(_gs_admin_mgr_allowed_paths)}  ·  imported")
    except Exception as _e:
        _adm_mgr_acl_status_sv.set(f"Import error: {_e}")

