def _adm_mgr_ping():
    try:
        CONFIG["admin_manager_pipe"] = _gs_v_admin_mgr_pipe.get().strip() or r"\\.\pipe\V0RTEX_AdminManager"
    except Exception:
        pass
    r = _admin_mgr_request({"type":"PING"})
    if r.get("ok"):
        _adm_mgr_status_sv.set(f"Status: ONLINE  admin={r.get('admin')}  hibernate={r.get('hibernate')}  sessions={r.get('sessions')}  srv_pid={r.get('server_pid','?')}")
    else:
        _adm_mgr_status_sv.set(f"Status: OFFLINE  ({r.get('error','?')})")
def _adm_mgr_restart():
    try:
        if not _gs_admin_mgr_allowed_paths:
            _adm_mgr_status_sv.set("Status: blocked — allowlist cannot be empty")
            return
        CONFIG["admin_manager_admin"] = bool(_gs_v_admin_mgr_admin.get())
        CONFIG["admin_manager_pipe"]  = _gs_v_admin_mgr_pipe.get().strip() or r"\\.\pipe\V0RTEX_AdminManager"
        CONFIG["admin_manager_max_hooks"] = max(1, min(16, int(_gs_v_admin_mgr_max_hooks.get().strip() or "3")))
        CONFIG["admin_manager_op_timeout_s"] = max(5, min(120, int(_gs_v_admin_mgr_timeout.get().strip() or "20")))
        CONFIG["admin_manager_allowed_processes"] = list(_gs_admin_mgr_allowed_paths)
        _vx_cfg_write(CONFIG)
    except Exception:
        pass
    try:
        p = _ADMIN_MGR_PROC[0]
        if p and getattr(p, "poll", lambda: None)() is None:
            try: p.terminate()
            except Exception: pass
    except Exception:
        pass
    try:
        _start_admin_manager()
    except Exception:
        pass
    try:
        root.after(250, _adm_mgr_ping)
    except Exception:
        pass

def _adm_mgr_open_admin_log():
    try:
        log_dir = os.path.join(os.path.dirname(BASE_DIR), "v0rtex_utils", "debug_log", "admin_log")
        os.makedirs(log_dir, exist_ok=True)
        if sys.platform == "win32":
            os.startfile(log_dir)
        elif sys.platform == "darwin":
            subprocess.Popen(["open", log_dir])
        else:
            subprocess.Popen(["xdg-open", log_dir])
    except Exception as _e:
        _adm_mgr_status_sv.set(f"Status: cannot open admin log folder ({_e})")

def _adm_mgr_open_standalone_ui():
    try:
        adm_path = _deploy_admin_manager()
        if not adm_path:
            _adm_mgr_status_sv.set("Status: standalone launch failed (deploy error)")
            return
        try:
            p = _ADMIN_MGR_PROC[0]
            if p and getattr(p, "poll", lambda: None)() is None:
                try:
                    p.terminate()
                except Exception:
                    pass
        except Exception:
            pass
        args = [
            sys.executable, adm_path,
            "--base-dir", BASE_DIR,
            "--config-path", CONFIG_PATH,
            "--pipe-name", _gs_v_admin_mgr_pipe.get().strip() or r"\\.\pipe\V0RTEX_AdminManager",
            "--auth-key", _admin_mgr_get_auth_key(),
            "--standalone",
        ]
        if not bool(_gs_v_admin_mgr_admin.get()):
            args.append("--hibernate")
        _kw = {"creationflags": subprocess.CREATE_NEW_CONSOLE} if sys.platform == "win32" else {}
        _ADMIN_MGR_PROC[0] = subprocess.Popen(args, **_kw)
        _adm_mgr_status_sv.set(f"Status: standalone UI launched (pid={_ADMIN_MGR_PROC[0].pid})")
    except Exception as _e:
        _adm_mgr_status_sv.set(f"Status: standalone launch error ({_e})")

def _adm_mgr_test_authorization():
    try:
        
        CONFIG["admin_manager_pipe"] = _gs_v_admin_mgr_pipe.get().strip() or r"\\.\pipe\V0RTEX_AdminManager"
        CONFIG["admin_manager_allowed_processes"] = list(_gs_admin_mgr_allowed_paths)
        _vx_cfg_write(CONFIG)

        
        _ADMIN_MGR_SESSION["session_id"] = ""
        _ADMIN_MGR_SESSION["token"] = ""
        _ADMIN_MGR_SESSION["expires_at"] = 0.0
        r = _admin_mgr_open_secure_session(ttl_s=60)
        if r.get("ok"):
            _adm_mgr_status_sv.set("Status: AUTH TEST OK — secure session established")
        else:
            _adm_mgr_status_sv.set(f"Status: AUTH TEST FAIL — {r.get('error','unknown')}")
    except Exception as _e:
        _adm_mgr_status_sv.set(f"Status: AUTH TEST ERROR — {_e}")

