            CONFIG["admin_manager_unmanaged_gate_s"] = max(5, min(60, int(_am_v_unmanaged_gate_s.get().strip() or "30")))
            dm = str(_am_v_default_mode.get() or "normal").lower().strip()
            if dm not in ("normal", "unmanaged"):
                dm = "normal"
            CONFIG["admin_manager_default_mode"] = dm
            CONFIG["admin_manager_session_ttl_s"] = max(30, min(300, int(_am_v_session_ttl.get().strip() or "120")))
