def _watchdog_thread():
    while _watchdog_active.is_set():
        _watchdog_ping.clear()
        signaled = _watchdog_ping.wait(timeout=_WATCHDOG_TIMEOUT)
        if not signaled and _watchdog_active.is_set():

            if _WATCHDOG_SUPPRESS.is_set() or _APP_DYING[0]:
                _watchdog_ping.set()
            else:
                try:
                    root.after(0, _show_hang_popup)
                except Exception:
                    pass
        time.sleep(1)


def _schedule_ping():
    if _APP_DYING[0]: return
    _ui_ping()
    if not _APP_DYING[0]:
        try: root.after(2000, _schedule_ping)
        except Exception: pass

