def _mal_run_startup_scan():
    _mal_s_status.set("Status: scanning startup...")
    _mal_s_append("Starting startup scan...")
    def _do_scan():
        try:
            import sqlite3 as _sql
            _found = 0
            _mal_s_append("Checking autostart registry keys...")
            if sys.platform == "win32":
                try:
                    import winreg as _wr
                    _keys = [
                        (_wr.HKEY_CURRENT_USER, r"Software\Microsoft\Windows\CurrentVersion\Run"),
                        (_wr.HKEY_LOCAL_MACHINE, r"SOFTWARE\Microsoft\Windows\CurrentVersion\Run"),
                    ]
                    for _hive, _path in _keys:
                        try:
                            _k = _wr.OpenKey(_hive, _path, 0, _wr.KEY_READ)
                            _i = 0
                            while True:
                                try:
                                    _name, _val, _ = _wr.EnumValue(_k, _i)
                                    _mal_s_append(f"  Found: {_name} -> {_val}")
                                    _found += 1
                                    _i += 1
                                except OSError:
                                    break
                            _wr.CloseKey(_k)
                        except Exception as _re:
                            _mal_s_append(f"  Registry read error: {_re}")
                except Exception as _ie:
                    _mal_s_append(f"  Registry import error: {_ie}")
                _mal_s_append("Checking startup folders...")
                try:
                    _sf = [
                        os.path.expandvars(r"%APPDATA%\Microsoft\Windows\Start Menu\Programs\Startup"),
                        os.path.expandvars(r"%ProgramData%\Microsoft\Windows\Start Menu\Programs\Startup"),
                    ]
                    for _d in _sf:
                        if os.path.isdir(_d):
                            for _f in os.listdir(_d):
                                _mal_s_append(f"  Startup file: {_f}")
                                _found += 1
                except Exception as _fe:
                    _mal_s_append(f"  Startup folder error: {_fe}")
                _mal_s_append("Checking scheduled tasks...")
                try:
                    _out = subprocess.check_output(["schtasks", "/query", "/fo", "CSV", "/nh"], text=True, stderr=subprocess.STDOUT, timeout=15)
                    for _ln in _out.splitlines():
                        if _ln.strip():
                            _mal_s_append(f"  Task: {_ln.strip()[:120]}")
                            _found += 1
                except Exception as _te:
                    _mal_s_append(f"  Scheduled tasks error: {_te}")
            _mal_s_append(f"Startup scan complete. {_found} entries found.")
            _mal_s_status.set(f"Status: complete ({_found} entries)")
            try:
                _db = os.path.join(BASE_DIR, "scan_history.db")
                _con = _sql.connect(_db, timeout=5)
                _con.execute("INSERT INTO scans(file,md5,sha1,sha256,malicious,suspicious,undetected,yara_hits,pe_info,iocs,entropy,filetype,timestamp) VALUES(?,?,?,?,?,?,?,?,?,?,?,?,?)",
                    ("startup_scan","", "", "", 0, 0, _found, "", f"{_found} entries scanned", "", 0.0, "startup", time.strftime("%Y-%m-%d %H:%M:%S")))
                _con.commit()
                _con.close()
            except Exception as _de:
                _mal_s_append(f"DB save error: {_de}")
        except Exception as _e:
            _mal_s_append(f"Error: {_e}")
            _mal_s_status.set(f"Status: error ({_e})")
    threading.Thread(target=_do_scan, daemon=True).start()

