def _mal_run_deep_scan():
    _fp = _mal_d_path_var.get().strip()
    if not _fp:
        _mal_d_status.set("Status: enter a file or directory path")
        return
    if not os.path.exists(_fp):
        _mal_d_status.set("Status: path not found")
        return
    _mal_d_status.set("Status: scanning...")
    _mal_d_append(f"Scanning: {_fp}")
    def _do_deep():
        try:
            import hashlib as _hl
            import sqlite3 as _sql
            _scanned = 0
            _files = [_fp] if os.path.isfile(_fp) else []
            if os.path.isdir(_fp):
                for _root_d, _dirs, _files_d in os.walk(_fp):
                    for _fn in _files_d:
                        _files.append(os.path.join(_root_d, _fn))
            for _f in _files:
                try:
                    _data = open(_f, "rb").read()
                    _md5 = _hl.md5(_data).hexdigest()
                    _sha256 = _hl.sha256(_data).hexdigest()
                    _byts = len(_data)
                    _ent = -sum((_byts2 / _byts) * (math.log2(_byts2 / _byts) if _byts2 > 0 else 0) for _byts2 in __import__("collections").Counter(_data).values()) if _byts else 0.0
                    _mal_d_append(f"  {_f}  md5={_md5[:8]}...  sha256={_sha256[:8]}...  ent={_ent:.2f}")
                    _scanned += 1
                except Exception as _fe:
                    _mal_d_append(f"  Error reading {_f}: {_fe}")
            _mal_d_append(f"Deep scan complete. {_scanned} files processed.")
            _mal_d_status.set(f"Status: complete ({_scanned} files)")
            try:
                _db = os.path.join(BASE_DIR, "scan_history.db")
                _con = _sql.connect(_db, timeout=5)
                _con.execute("INSERT INTO scans(file,md5,sha1,sha256,malicious,suspicious,undetected,yara_hits,pe_info,iocs,entropy,filetype,timestamp) VALUES(?,?,?,?,?,?,?,?,?,?,?,?,?)",
                    (_fp, "", "", "", 0, 0, _scanned, "", f"{_scanned} files scanned", "", 0.0, "deep_scan", time.strftime("%Y-%m-%d %H:%M:%S")))
                _con.commit()
                _con.close()
            except Exception as _de:
                _mal_d_append(f"DB save error: {_de}")
        except Exception as _e:
            _mal_d_append(f"Error: {_e}")
            _mal_d_status.set(f"Status: error ({_e})")
    threading.Thread(target=_do_deep, daemon=True).start()

