def _mal_n_append(msg):
    try:
        _mal_n_log_txt.insert("end", f"[{time.strftime('%H:%M:%S')}] {msg}\n")
        _mal_n_log_txt.see("end")
    except Exception:
        pass

def _mal_run_net_scan():
    _mal_n_status.set("Status: scanning network...")
    _mal_n_log_txt.delete("1.0", "end")
    _mal_n_append("Enumerating network connections...")
    def _do_net():
        try:
            import sqlite3 as _sql
            _conn_count = 0
            if sys.platform == "win32":
                try:
                    _out = subprocess.check_output(["netstat", "-ano"], text=True, stderr=subprocess.STDOUT, timeout=15)
                    for _ln in _out.splitlines():
                        if "ESTABLISHED" in _ln or "LISTENING" in _ln:
                            _mal_n_append(f"  {_ln.strip()}")
                            _conn_count += 1
                except Exception as _ne:
                    _mal_n_append(f"netstat error: {_ne}")
            else:
                try:
                    _out = subprocess.check_output(["ss", "-tunapl"], text=True, stderr=subprocess.STDOUT, timeout=15)
                    for _ln in _out.splitlines():
                        _mal_n_append(f"  {_ln.strip()}")
                        _conn_count += 1
                except Exception:
                    try:
                        _out = subprocess.check_output(["netstat", "-tunapl"], text=True, stderr=subprocess.STDOUT, timeout=15)
                        for _ln in _out.splitlines():
                            _mal_n_append(f"  {_ln.strip()}")
                            _conn_count += 1
                    except Exception as _ne2:
                        _mal_n_append(f"netstat error: {_ne2}")
            _mal_n_append(f"Network scan complete. {_conn_count} connections found.")
            _mal_n_status.set(f"Status: complete ({_conn_count} connections)")
            try:
                _db = os.path.join(BASE_DIR, "scan_history.db")
                _con = _sql.connect(_db, timeout=5)
                _con.execute("INSERT INTO scans(file,md5,sha1,sha256,malicious,suspicious,undetected,yara_hits,pe_info,iocs,entropy,filetype,timestamp) VALUES(?,?,?,?,?,?,?,?,?,?,?,?,?)",
                    ("network_scan","", "", "", 0, 0, _conn_count, "", f"{_conn_count} connections", "", 0.0, "network", time.strftime("%Y-%m-%d %H:%M:%S")))
                _con.commit()
                _con.close()
            except Exception as _de:
                _mal_n_append(f"DB save error: {_de}")
        except Exception as _e:
            _mal_n_append(f"Error: {_e}")
            _mal_n_status.set(f"Status: error ({_e})")
    threading.Thread(target=_do_net, daemon=True).start()

