def _mal_r_load():
    try:
        import sqlite3 as _sql
        _mal_r_tree.delete(*_mal_r_tree.get_children())
        _db = os.path.join(BASE_DIR, "scan_history.db")
        if not os.path.exists(_db):
            _mal_r_status.set("Status: no database found")
            return
        _con = _sql.connect(_db, timeout=5)
        _rows = _con.execute("SELECT file,malicious,suspicious,undetected,yara_hits,filetype,timestamp FROM scans ORDER BY timestamp DESC LIMIT 200").fetchall()
        _con.close()
        for _r in _rows:
            _mal_r_tree.insert("", "end", values=(str(_r[0])[:60], _r[1], _r[2], _r[3], str(_r[4])[:20] or "-", str(_r[5]) or "-", str(_r[6]) or "-"))
        _mal_r_status.set(f"Status: {len(_rows)} records loaded")
    except Exception as _e:
        _mal_r_status.set(f"Status: load error ({_e})")

def _mal_r_refresh():
    _mal_r_load()

