def _ap_bd_write(msg, tag="DIM"):
    import datetime as _dt_ap
    ts = _dt_ap.datetime.now().strftime("%H:%M:%S")
    def _do():
        _ap_bd_log.config(state="normal")
        _ap_bd_log.insert(tk.END, f"[{ts}] {msg}\n", tag)
        _ap_bd_log.see(tk.END); _ap_bd_log.config(state="disabled")
    root.after(0, _do)


