def _panic_state_load():
    try:
        if os.path.isfile(PANIC_STATE_PATH):
            with open(PANIC_STATE_PATH, "r", encoding="utf-8") as _pf:
                return json.load(_pf)
    except Exception:
        pass
    return _panic_init_state()

def _panic_abort():
    _PANIC_CANCEL[0] = True
    panic_broadcast("panic_abort")
    try:
        _st = _panic_state_load()
        _st["active"] = False
        _st["phase"] = "aborted"
        _st["ts"] = time.strftime("%Y-%m-%d %H:%M:%S")
        _panic_save_state(_st)
        _PANIC_ACTIVE[0] = False
    except Exception:
        pass

def _panic_admin_manager_probe():
    r = _admin_mgr_request({"type": "PING"}, timeout_ms=1200)
    status = {"online": bool(r.get("ok")), "admin": bool(r.get("admin")), "hibernate": bool(r.get("hibernate")), "server_pid": int(r.get("server_pid", 0)), "metrics": {}}
    if r.get("ok"):
        m = _admin_mgr_request({"type": "GET_METRICS"}, timeout_ms=800)
        if m.get("ok"):
            status["metrics"] = m.get("metrics", {})
    return status

def _panic_admin_manager_notify(level: int, trigger: str):
    try:
        _am_tok = _panic_token_admin_mgr()
        payload = {"type": "PANIC_NOTIFY", "level": level, "trigger": trigger, "token_prefix": _panic_token_prefix(_am_tok)}
        r = _admin_mgr_request(payload, timeout_ms=1500)
        if r.get("ok"):
            return True, "notified"
        return False, r.get("error", "notify_failed")
    except Exception as e:
        return False, str(e)

def _panic_fallback_cascade(level: int, trigger: str, ai_assist: bool, destruction: bool):
    _PANIC_ACTIVE[0] = True
    _PANIC_CANCEL[0] = False
    _PANIC_CFG["panic_level"] = level
    _PANIC_CFG["trigger_source"] = trigger
    _PANIC_CFG["allow_ai_assist"] = ai_assist
    _PANIC_CFG["allow_destruction"] = destruction
    _PANIC_TOKENS["master"] = _panic_token_master()
    state = _panic_init_state()
    state["active"] = True
    state["level"] = level
    state["trigger_source"] = trigger
    state["allow_ai_assist"] = ai_assist
    state["allow_destruction"] = destruction
    state["ts"] = time.strftime("%Y-%m-%d %H:%M:%S")
    _panic_save_state(state)
    phases = ["announce", "broadcast", "admin_manager_probe", "security_rebuild", "diagnostics", "remediation", "finalize"]
    for phase in phases:
        if _PANIC_CANCEL[0]:
            state["phase"] = "aborted"
            state["actions"].append({"phase": "abort", "action": "cancel_requested", "ts": time.strftime("%Y-%m-%d %H:%M:%S")})
            _panic_save_state(state)
            break
        state["phase"] = phase
        try:
            if phase == "announce":
                state["actions"].append({"phase": "announce", "action": f"Panic L{level} initiated", "ts": time.strftime("%Y-%m-%d %H:%M:%S")})
            elif phase == "broadcast":
                panic_broadcast("panic_start")
                state["actions"].append({"phase": "broadcast", "action": "panic_start signal sent", "ts": time.strftime("%Y-%m-%d %H:%M:%S")})
            elif phase == "admin_manager_probe":
                am = _panic_admin_manager_probe()
                state["admin_manager"] = am
                ok, why = _panic_admin_manager_notify(level, trigger)
                if ok:
                    state["actions"].append({"phase": "admin_mgr", "action": "notified", "ts": time.strftime("%Y-%m-%d %H:%M:%S")})
                else:
                    state["errors"].append({"phase": "admin_mgr", "error": f"notify failed: {why}", "ts": time.strftime("%Y-%m-%d %H:%M:%S")})
            elif phase == "security_rebuild":
                state["actions"].append({"phase": "security_rebuild", "action": "guardian rearm requested", "ts": time.strftime("%Y-%m-%d %H:%M:%S")})
                if level >= 2:
                    try:
                        _out = subprocess.check_output(["sfc", "/verifyonly"], text=True, stderr=subprocess.STDOUT, timeout=120)
                        state["actions"].append({"phase": "sfc", "action": "verify complete", "ts": time.strftime("%Y-%m-%d %H:%M:%S")})
                    except Exception as _se:
                        state["errors"].append({"phase": "sfc", "error": str(_se), "ts": time.strftime("%Y-%m-%d %H:%M:%S")})
                    if level >= 3:
                        try:
                            _out2 = subprocess.check_output(["DISM", "/Online", "/Cleanup-Image", "/CheckHealth"], text=True, stderr=subprocess.STDOUT, timeout=120)
                            state["actions"].append({"phase": "dism", "action": "check complete", "ts": time.strftime("%Y-%m-%d %H:%M:%S")})
                        except Exception as _de:
                            state["errors"].append({"phase": "dism", "error": str(_de), "ts": time.strftime("%Y-%m-%d %H:%M:%S")})
            elif phase == "diagnostics":
                state["actions"].append({"phase": "diagnostics", "action": "env snapshot collected", "ts": time.strftime("%Y-%m-%d %H:%M:%S")})
            elif phase == "remediation":
                if level >= 4 and destruction and _PANIC_CFG["allow_destruction"]:
                    state["actions"].append({"phase": "remediation", "action": "L4 destruction path taken", "ts": time.strftime("%Y-%m-%d %H:%M:%S")})
                else:
                    state["actions"].append({"phase": "remediation", "action": "non-destructive remediation", "ts": time.strftime("%Y-%m-%d %H:%M:%S")})
            elif phase == "finalize":
                try:
                    bp = _panic_export_bundle(state)
                    state["bundle_path"] = bp
                except Exception:
                    pass
                state["active"] = False
                state["phase"] = "completed"
                state["actions"].append({"phase": "finalize", "action": "panic sequence complete", "ts": time.strftime("%Y-%m-%d %H:%M:%S")})
        except Exception as _pe:
            state["errors"].append({"phase": phase, "error": str(_pe), "ts": time.strftime("%Y-%m-%d %H:%M:%S")})
        _panic_save_state(state)
    _PANIC_ACTIVE[0] = False

def _panic_run_orchestrator(level, trigger, ai_assist, destruction):
    t = threading.Thread(target=lambda: _panic_fallback_cascade(level, trigger, ai_assist, destruction), daemon=True)
    t.start()

def _panic_activate():
    lv = _panic_level_var.get()
    ts = _panic_trigger_var.get().strip() or "manual"
    ai = _panic_ai_assist_var.get()
    dest = _panic_destroy_var.get()
    if lv >= 4 and dest:
        if not messagebox.askyesno("Confirm PANIC L4 DESTRUCTION", "This action is IRREVERSIBLE.\n\nAre you sure you want to proceed?"):
            return
    elif not messagebox.askyesno("Confirm Panic", f"Activate PANIC Level {lv}?\n\nTrigger: {ts}\nAI Assist: {'Yes' if ai else 'No'}\nDestruction: {'Yes' if dest else 'No'}"):
        return
    _panic_run_orchestrator(lv, ts, ai, dest)
    _panic_update_status_panel()

def _panic_export_bundle(state: dict) -> str:
    import zipfile
    os.makedirs(PANIC_BUNDLE_DIR, exist_ok=True)
    ts = time.strftime("%Y%m%d_%H%M%S")
    bp = os.path.join(PANIC_BUNDLE_DIR, f"panic_bundle_{ts}.zip")
    with zipfile.ZipFile(bp, "w", zipfile.ZIP_DEFLATED) as zf:
        zf.writestr("panic_state.json", json.dumps(state, indent=2, ensure_ascii=False))
        try:
            redacted = {k: CONFIG[k] for k in ("admin_mode_enabled", "admin_manager_admin", "admin_manager_pipe", "admin_manager_auth_key") if k in CONFIG}
            zf.writestr("config_redacted.json", json.dumps(redacted, indent=2))
        except Exception:
            pass
        for _ld in [DEBUG_DIR, _admin_log_dir()]:
            try:
                if os.path.isdir(_ld):
                    for _fn in os.listdir(_ld):
                        fp = os.path.join(_ld, _fn)
                        if os.path.isfile(fp):
                            zf.write(fp, os.path.join("logs", _fn))
            except Exception:
                pass
        try:
            if os.path.isfile(PANIC_STATE_PATH):
                zf.write(PANIC_STATE_PATH, "panic_state_source.json")
        except Exception:
            pass
    return bp

