_PANIC_TERM_ALLOWED = ["netstat -ano", "tasklist /v", "systeminfo", "ipconfig /all", "wmic process list brief", "driverquery /v"]

def _panic_term_append(msg):
    try:
        _panic_term_log.insert("end", f"[{time.strftime('%H:%M:%S')}] {msg}\n")
        _panic_term_log.see("end")
    except Exception:
        pass

def _panic_term_run():
    cmd = _panic_term_input.get().strip()
    _panic_term_input.delete(0, "end")
    if not cmd:
        return
    if cmd.lower() not in [a.lower() for a in _PANIC_TERM_ALLOWED]:
        _panic_term_append(f"BLOCKED: '{cmd}' not in allowlist")
        _panic_term_append(f"Allowed: {', '.join(_PANIC_TERM_ALLOWED)}")
        return
    _panic_term_append(f"> {cmd}")
    def _do_run():
        try:
            _out = subprocess.check_output(shlex.split(cmd), text=True, stderr=subprocess.STDOUT, timeout=30)
            _panic_term_append(_out[:2000])
            _state = _panic_state_load()
            _state["actions"].append({"phase": "terminal", "action": cmd, "output_len": len(_out), "ts": time.strftime("%Y-%m-%d %H:%M:%S")})
            _panic_save_state(_state)
        except subprocess.TimeoutExpired:
            _panic_term_append("TIMEOUT (30s)")
        except Exception as _te:
            _panic_term_append(f"ERROR: {_te}")
    threading.Thread(target=_do_run, daemon=True).start()

