def _panic_update_status_panel():
    try:
        state = _panic_state_load()
        _panic_status_text.config(state="normal")
        _panic_status_text.delete("1.0", "end")
        info = (
            f"Active: {state.get('active', False)}\n"
            f"Phase: {state.get('phase', 'init').upper()}\n"
            f"Level: {state.get('level', 1)}\n"
            f"Trigger: {state.get('trigger_source', 'none')}\n"
            f"Timestamp: {state.get('ts', '---')}\n\n"
        )
        info += f"Admin Manager: {'ONLINE' if state.get('admin_manager', {}).get('online') else 'OFFLINE'}\n"
        info += f"Admin Mode: {state.get('admin_manager', {}).get('admin', False)}\n"
        info += f"PID: {state.get('admin_manager', {}).get('server_pid', '?')}\n\n"
        with _PANIC_LOCK:
            thr = _PANIC_REGISTRY.get("threads", {})
            if thr:
                info += f"Threads ({len(thr)}):\n"
                for tid, t in thr.items():
                    info += f"  {t.get('label', tid)}: {t.get('state', '?')} (hb:{t.get('last_heartbeat_ts', '-')})\n"
                info += "\n"
        if state.get('bundle_path'):
            info += f"Bundle: {state['bundle_path']}\n\n"
        if state.get('actions'):
            info += f"Actions ({len(state['actions'])}):\n"
            for act in state['actions'][-8:]:
                if isinstance(act, dict):
                    info += f"  - {act.get('phase', '?')}: {act.get('action', '?')}\n"
        if state.get('errors'):
            info += f"\nErrors ({len(state['errors'])}):\n"
            for err in state['errors'][-5:]:
                if isinstance(err, dict):
                    info += f"  x {err.get('phase', '?')}: {err.get('error', '?')}\n"
        _panic_status_text.insert("end", info)
        _panic_status_text.config(state="disabled")
    except Exception:
        pass
    root.after(2000, _panic_update_status_panel)

