_CRYPT_MAGIC = b"SOCENC\x01\x00"
_CRYPT_EXT   = ".soc_enc"

def _crypt_derive_key(password: str, salt: bytes) -> bytes:
    import hashlib as _hc
    return _hc.pbkdf2_hmac("sha256", password.encode("utf-8"), salt, 600_000, dklen=32)

def _crypt_encrypt_bytes(data: bytes, password: str) -> bytes:
    try:
        from cryptography.hazmat.primitives.ciphers.aead import AESGCM
        salt  = os.urandom(16)
        nonce = os.urandom(12)
        key   = _crypt_derive_key(password, salt)
        ct    = AESGCM(key).encrypt(nonce, data, None)
        return _CRYPT_MAGIC + b"AESG" + salt + nonce + ct
    except ImportError:
        import hashlib as _hc2, struct as _st
        salt = os.urandom(16)
        key  = _crypt_derive_key(password, salt)
        ks = bytearray()
        ctr = 0
        while len(ks) < len(data):
            ks += _hc2.sha256(key + _st.pack(">Q", ctr)).digest()
            ctr += 1
        ct = bytes(a ^ b for a, b in zip(data, ks))
        return _CRYPT_MAGIC + b"XOR0" + salt + ct

def _crypt_decrypt_bytes(data: bytes, password: str) -> bytes:
    if not data.startswith(_CRYPT_MAGIC):
        raise ValueError("File not encrypted by V0RTEX CRYPT (magic not found)")
    pos = len(_CRYPT_MAGIC)
    algo  = data[pos:pos+4]; pos += 4
    salt  = data[pos:pos+16]; pos += 16
    rest  = data[pos:]
    key   = _crypt_derive_key(password, salt)
    if algo == b"XOR0":
        import hashlib as _hc3, struct as _st2
        ct = rest
        ks = bytearray()
        ctr = 0
        while len(ks) < len(ct):
            ks += _hc3.sha256(key + _st2.pack(">Q", ctr)).digest()
            ctr += 1
        return bytes(a ^ b for a, b in zip(ct, ks))
    nonce = rest[:12]; ct = rest[12:]
    try:
        from cryptography.hazmat.primitives.ciphers.aead import AESGCM
        return AESGCM(key).decrypt(nonce, ct, None)
    except ImportError:
        raise RuntimeError("Library 'cryptography' required to decrypt AES-GCM")
    except Exception:
        raise ValueError("Wrong password or corrupt file")

def _crypt_encrypt_file(src: str, password: str, delete_src=False) -> str:
    with open(src, "rb") as f: data = f.read()
    enc = _crypt_encrypt_bytes(data, password)
    dst = src + _CRYPT_EXT
    with open(dst, "wb") as f: f.write(enc)
    if delete_src: os.remove(src)
    return dst

def _crypt_decrypt_file(src: str, password: str, delete_src=False) -> str:
    with open(src, "rb") as f: data = f.read()
    dec = _crypt_decrypt_bytes(data, password)
    if src.endswith(_CRYPT_EXT):
        dst = src[:-len(_CRYPT_EXT)]
    else:
        dst = src + ".dec"

    if os.path.exists(dst):
        base, ext = os.path.splitext(dst)
        dst = f"{base}_dec{ext}"
    with open(dst, "wb") as f: f.write(dec)
    if delete_src: os.remove(src)
    return dst


