def _cr_log(msg, tag="DIM"):
    color_map = {"OK": C["green"], "WARN": C["yellow"], "FAIL": C["red"],
                 "HEAD": C["mauve"], "DIM": C["overlay0"], "INFO": C["teal"]}
    color = color_map.get(tag, C["text"])
    import datetime as _dtcr
    ts = _dtcr.datetime.now().strftime("%H:%M:%S")
    def _do():
        _cr_log_txt.config(state="normal")
        tag_name = f"cr_{tag}"
        _cr_log_txt.tag_configure(tag_name, foreground=color)
        _cr_log_txt.insert(tk.END, f"[{ts}] {msg}\n", tag_name)
        _cr_log_txt.see(tk.END)
        _cr_log_txt.config(state="disabled")
    root.after(0, _do)


def _cr_make_target_panel(parent, mode="encrypt"):
    target_path = [""]
    pw_var  = tk.StringVar()
    pw2_var = tk.StringVar()
    pw_show = tk.BooleanVar(value=False)
    del_var = tk.BooleanVar(value=False)
    ow_var  = tk.BooleanVar(value=False)
    status_sv   = tk.StringVar(value="Ready.")
    progress_sv = tk.StringVar(value="")


    tk.Label(parent, text="🎯  TARGET", font=FB, bg=C["surface0"], fg=C["mauve"]).pack(anchor="w", padx=12, pady=(10,2))
    tk.Frame(parent, bg=C["mauve"], height=1).pack(fill=tk.X, padx=12)
    target_lbl = tk.Label(parent, textvariable=tk.StringVar(value="No file selected"),
                           font=("Consolas",8), bg=C["mantle"], fg=C["text"],
                           wraplength=340, justify="left", anchor="w", padx=8, pady=5)
    target_lbl.pack(fill=tk.X, padx=12, pady=4)
    _tsv = tk.StringVar(value="No file selected")
    target_lbl.config(textvariable=_tsv)

    def _pick_file():
        if mode == "decrypt":
            p = filedialog.askopenfilename(title="Select .soc_enc file",
                filetypes=[("V0RTEX Encrypted Files", "*.soc_enc"), ("All Files", "*.*")])
        else:
            p = filedialog.askopenfilename(title="Select file to encrypt")
        if p:
            target_path[0] = p
            _tsv.set(f"📄 {os.path.basename(p)}\n   {p}")

    def _pick_folder():
        p = filedialog.askdirectory(title="Select folder")
        if p:
            target_path[0] = p
            _tsv.set(f"📁 {os.path.basename(p)}/\n   {p}")

    pick_row = tk.Frame(parent, bg=C["surface0"]); pick_row.pack(fill=tk.X, padx=12, pady=(0,6))
    btn_lbl = "📄 .soc_enc File" if mode == "decrypt" else "📄 File"
    tk.Button(pick_row, text=btn_lbl, command=_pick_file,
              bg=C["surface2"], fg=C["text"], font=FS, relief="flat",
              padx=10, pady=5, cursor="hand2", bd=0).pack(side=tk.LEFT, padx=(0,4))
    tk.Button(pick_row, text="📁 Folder", command=_pick_folder,
              bg=C["surface2"], fg=C["text"], font=FS, relief="flat",
              padx=10, pady=5, cursor="hand2", bd=0).pack(side=tk.LEFT)


    pw_color = C["yellow"] if mode == "encrypt" else C["green"]
    tk.Label(parent, text="🔑  PASSWORD", font=FB, bg=C["surface0"], fg=pw_color).pack(anchor="w", padx=12, pady=(10,2))
    tk.Frame(parent, bg=pw_color, height=1).pack(fill=tk.X, padx=12)

    pw_f = tk.Frame(parent, bg=C["surface0"]); pw_f.pack(fill=tk.X, padx=12, pady=4)
    tk.Label(pw_f, text="Password:", font=FS, bg=C["surface0"], fg=C["subtext"], width=12, anchor="w").pack(side=tk.LEFT)
    pw_entry = tk.Entry(pw_f, textvariable=pw_var, font=FM, bg=C["mantle"],
                         fg=C["text"], show="●", insertbackground=C["text"],
                         relief="flat", bd=2, width=24)
    pw_entry.pack(side=tk.LEFT, padx=(4,0))

    if mode == "encrypt":
        pw2_f = tk.Frame(parent, bg=C["surface0"]); pw2_f.pack(fill=tk.X, padx=12)
        tk.Label(pw2_f, text="Confirm:", font=FS, bg=C["surface0"], fg=C["subtext"], width=12, anchor="w").pack(side=tk.LEFT)
        pw2_entry = tk.Entry(pw2_f, textvariable=pw2_var, font=FM, bg=C["mantle"],
                              fg=C["text"], show="●", insertbackground=C["text"],
                              relief="flat", bd=2, width=24)
        pw2_entry.pack(side=tk.LEFT, padx=(4,0))
    else:
        pw2_entry = None

    def _toggle_pw():
        s = "" if pw_show.get() else "●"
        pw_entry.config(show=s)
        if pw2_entry: pw2_entry.config(show=s)

    show_row = tk.Frame(parent, bg=C["surface0"]); show_row.pack(fill=tk.X, padx=12, pady=2)
    tk.Checkbutton(show_row, text="Show password", variable=pw_show,
                   command=_toggle_pw, font=FS, bg=C["surface0"], fg=C["overlay0"],
                   activebackground=C["surface0"], selectcolor=C["mantle"], relief="flat").pack(anchor="w")

    if mode == "encrypt":

        strength_sv = tk.StringVar(value="")
        strength_lbl = tk.Label(parent, textvariable=strength_sv, font=("Consolas",8),
                                 bg=C["surface0"], fg=C["green"], padx=12)
        strength_lbl.pack(anchor="w")

        def _check_strength(*_):
            pw = pw_var.get()
            if not pw: strength_sv.set(""); return
            score = 0
            if len(pw) >= 8:  score += 1
            if len(pw) >= 16: score += 1
            import re as _re3
            if _re3.search(r"[A-Z]", pw): score += 1
            if _re3.search(r"[a-z]", pw): score += 1
            if _re3.search(r"\d", pw): score += 1
            if _re3.search(r"[^A-Za-z0-9]", pw): score += 1
            labels = ["", "⚠ WEAK", "⚠ WEAK", "◑ FAIR", "◑ FAIR", "● STRONG", "● VERY STRONG"]
            colors = [C["overlay0"], C["red"], C["red"], C["yellow"], C["yellow"], C["green"], C["teal"]]
            strength_sv.set(f"Strength: {labels[min(score, 6)]}")
            strength_lbl.config(fg=colors[min(score, 6)])
        pw_var.trace_add("write", _check_strength)

        def _gen_password():
            import secrets, string
            alphabet = string.ascii_letters + string.digits + "!@#$%^&*()-_=+[]{}|;:,.<>?"
            pw = "".join(secrets.choice(alphabet) for _ in range(20))
            pw_var.set(pw); pw2_var.set(pw)
            pw_show.set(True); _toggle_pw()
        tk.Button(parent, text="🎲 Generate Random Password (20 chars)", command=_gen_password,
                  bg=C["surface2"], fg=C["subtext"], font=FS, relief="flat",
                  padx=10, pady=4, cursor="hand2", bd=0, anchor="w").pack(fill=tk.X, padx=12, pady=(0,4))


    tk.Label(parent, text="⚙  OPTIONS", font=FB, bg=C["surface0"], fg=C["peach"]).pack(anchor="w", padx=12, pady=(8,2))
    tk.Frame(parent, bg=C["peach"], height=1).pack(fill=tk.X, padx=12)
    opts = tk.Frame(parent, bg=C["surface0"]); opts.pack(fill=tk.X, padx=12, pady=4)
    tk.Checkbutton(opts, text="🗑 Delete original after operation", variable=del_var, font=FS,
                   bg=C["surface0"], fg=C["text"], activebackground=C["surface0"],
                   selectcolor=C["mantle"], relief="flat").pack(anchor="w", pady=1)
    tk.Checkbutton(opts, text="♻ Overwrite if exists", variable=ow_var, font=FS,
                   bg=C["surface0"], fg=C["text"], activebackground=C["surface0"],
                   selectcolor=C["mantle"], relief="flat").pack(anchor="w", pady=1)


    tk.Label(parent, textvariable=status_sv, font=("Consolas",9),
             bg=C["surface0"], fg=C["teal"], wraplength=340, justify="left", padx=12, pady=4).pack(fill=tk.X)
    tk.Label(parent, textvariable=progress_sv, font=("Consolas",8),
             bg=C["surface0"], fg=C["overlay0"], padx=12).pack(fill=tk.X)


    _sty.configure("Crypt.Horizontal.TProgressbar",
        troughcolor=C["surface1"], background=C["mauve"],
        borderwidth=0, thickness=6, lightcolor=C["mauve"], darkcolor=C["mauve"])
    cr_pbar_val = tk.IntVar(value=0)
    cr_pbar = ttk.Progressbar(parent, variable=cr_pbar_val, maximum=100,
        orient="horizontal", mode="determinate", style="Crypt.Horizontal.TProgressbar")
    cr_pbar.pack(fill=tk.X, padx=12, pady=(0,6))

    return target_path, pw_var, pw2_var, del_var, ow_var, status_sv, progress_sv, cr_pbar_val

def _cr_validate(target_path, pw_var, pw2_var=None, mode="encrypt"):
    if not target_path[0] or not os.path.exists(target_path[0]):
        messagebox.showwarning("CRYPT", "Select a file or folder first."); return False
    pw = pw_var.get()
    if not pw:
        messagebox.showwarning("CRYPT", "Enter a password."); return False
    if mode == "encrypt":
        if pw2_var and pw != pw2_var.get():
            messagebox.showwarning("CRYPT", "Passwords do not match."); return False
        if len(pw) < 6:
            messagebox.showwarning("CRYPT", "Password too short (min 6 chars)."); return False
    return True


