def _dz_export_db_csv():
    from tkinter import filedialog as _fd2
    dest = _fd2.asksaveasfilename(defaultextension=".csv",
        filetypes=[("CSV","*.csv")], initialfile="scan_history_export.csv")
    if not dest: return
    try:
        import csv
        with _db_lock:
            rows = _conn.execute("SELECT * FROM scans ORDER BY timestamp DESC").fetchall()
            cols = [d[0] for d in _conn.execute("SELECT * FROM scans LIMIT 1").description or []]
        if not cols:
            cols = ["file","md5","sha1","sha256","malicious","suspicious","undetected",
                    "yara_hits","pe_info","iocs","entropy","filetype","timestamp"]
        with open(dest, "w", newline="", encoding="utf-8") as f:
            w = csv.writer(f); w.writerow(cols); w.writerows(rows)
        messagebox.showinfo("Export CSV", f"Exported {len(rows)} records to:\n{dest}")
    except Exception as e: messagebox.showerror("Error", str(e))

def _dz_export_db_json():
    from tkinter import filedialog as _fd3
    dest = _fd3.asksaveasfilename(defaultextension=".json",
        filetypes=[("JSON","*.json")], initialfile="scan_history.json")
    if not dest: return
    try:
        import json as _jj
        with _db_lock:
            rows = _conn.execute("SELECT * FROM scans ORDER BY timestamp DESC").fetchall()
            try: cols = [d[0] for d in _conn.execute("SELECT * FROM scans LIMIT 1").description]
            except Exception: cols = ["file","md5","sha1","sha256","malicious","suspicious",
                "undetected","yara_hits","pe_info","iocs","entropy","filetype","timestamp"]
        data = [dict(zip(cols, r)) for r in rows]
        with open(dest, "w", encoding="utf-8") as f:
            _jj.dump(data, f, indent=2, ensure_ascii=False, default=str)
        messagebox.showinfo("Export JSON", f"Exported {len(rows)} records.")
    except Exception as e: messagebox.showerror("Error", str(e))

def _dz_import_db():
    from tkinter import filedialog as _fd4
    src = _fd4.askopenfilename(filetypes=[("SQLite DB","*.db"),("All","*.*")])
    if not src: return
    if not messagebox.askyesno("Import DB","This will merge records from the selected DB into your current one. Continue?"): return
    try:
        import sqlite3 as _sq
        other = _sq.connect(src); other.row_factory = _sq.Row
        rows = other.execute("SELECT * FROM scans").fetchall()
        other.close()
        with _db_lock:
            for r in rows:
                try:
                    _conn.execute(
                        "INSERT OR IGNORE INTO scans VALUES (?,?,?,?,?,?,?,?,?,?,?,?,?)",
                        tuple(r))
                except Exception: pass
            _conn.commit()
        _refresh_stats(); _update_charts()
        messagebox.showinfo("Import", f"Imported {len(rows)} record(s).")
    except Exception as e: messagebox.showerror("Error", str(e))

def _dz_db_stats():
    try:
        with _db_lock:
            total = _conn.execute("SELECT COUNT(*) FROM scans").fetchone()[0]
            mal   = _conn.execute("SELECT COUNT(*) FROM scans WHERE malicious>0").fetchone()[0]
            clean = _conn.execute("SELECT COUNT(*) FROM scans WHERE malicious=0").fetchone()[0]
            size  = os.path.getsize(DB_PATH) / 1024 if os.path.exists(DB_PATH) else 0
        messagebox.showinfo("DB Stats",
            f"Total records: {total}\nMalicious: {mal}\nClean: {clean}\n"
            f"DB size: {size:.1f} KB")
    except Exception as e: messagebox.showerror("Error", str(e))

def _dz_delete_malicious():
    def _do():
        if not messagebox.askyesno("Delete Malicious","Delete all malicious records from DB?"): return
        try:
            with _db_lock:
                n = _conn.execute("SELECT COUNT(*) FROM scans WHERE malicious>0").fetchone()[0]
                _conn.execute("DELETE FROM scans WHERE malicious>0"); _conn.commit()
            _refresh_stats(); _update_charts()
            messagebox.showinfo("Done", f"Deleted {n} malicious record(s).")
        except Exception as e: messagebox.showerror("Error", str(e))
    _danger_gate("DELETE", _do)

