def _dz_quar_restore_all():
    from tkinter import filedialog as _fd5
    q = os.path.join(BASE_DIR, "quarantine")
    if not os.path.exists(q) or not os.listdir(q):
        messagebox.showinfo("Quarantine","No files in quarantine."); return
    dest = _fd5.askdirectory(title="Where to restore all files?")
    if not dest: return
    if not messagebox.askyesno("Restore All",f"Restore all files to:\n{dest}?"): return
    import shutil; count = 0
    for fn in os.listdir(q):
        try: shutil.copy2(os.path.join(q, fn), os.path.join(dest, fn)); count += 1
        except Exception: pass
    messagebox.showinfo("Restore", f"Restored {count} files to {dest}")

def _dz_quar_export_report():
    from tkinter import filedialog as _fd6
    q = os.path.join(BASE_DIR, "quarantine")
    dest = _fd6.asksaveasfilename(defaultextension=".txt",
        filetypes=[("Text","*.txt")], initialfile="quarantine_report.txt")
    if not dest: return
    import time as _qt2
    lines = [f"QUARANTINE REPORT — {_qt2.strftime('%Y-%m-%d %H:%M:%S')}", "="*60]
    if os.path.exists(q):
        for fn in sorted(os.listdir(q)):
            fp = os.path.join(q, fn)
            try:
                sz = os.path.getsize(fp)
                ts = _qt2.strftime('%Y-%m-%d %H:%M', _qt2.localtime(os.path.getmtime(fp)))
                lines.append(f"  {fn:<50} {sz:>8} bytes  {ts}")
            except Exception: pass
    with open(dest, "w", encoding="utf-8") as f: f.write("\n".join(lines))
    messagebox.showinfo("Report", f"Report saved:\n{dest}")

