def _dz_flush_api_cache():
    cleared = 0
    for k in list(globals().keys()):
        if k.startswith("_vt_cache_"):
            del globals()[k]; cleared += 1
    import gc; gc.collect()
    messagebox.showinfo("Cache", f"VT API cache cleared ({cleared} entries).")

def _dz_test_all_keys():
    if not API_KEYS:
        messagebox.showwarning("API Keys","No API keys configured."); return
    from tkinter import Toplevel as _TL, Text as _TX, Scrollbar as _SB
    pop = _TL(root); pop.title("Test API Keys"); pop.configure(bg=C["surface0"])
    pop.geometry("600x400"); pop.transient(root)
    sc = _SB(pop, orient="vertical", bg=C["surface1"], troughcolor=C["mantle"],
              relief="flat", bd=0, width=7)
    txt = _TX(pop, bg="#0a0a10", fg=C["text"], font=("Consolas",9), relief="flat", bd=0,
               padx=10, pady=8, yscrollcommand=sc.set, state="disabled")
    sc.config(command=txt.yview)
    sc.pack(side="right", fill="y"); txt.pack(fill="both", expand=True)
    def log(m, c=C["text"]):
        txt.config(state="normal")
        tag = f"t{id(c)}"
        txt.tag_configure(tag, foreground=c)
        txt.insert("end", m+"\n", tag); txt.see("end")
        txt.config(state="disabled")
        pop.update()
    def _run():
        log(">_ Testing API Keys...\n", C["teal"])
        for i, key in enumerate(API_KEYS):
            log(f"  [{i+1}] {key[:8]}...{key[-4:]}", C["overlay0"])
            try:
                r = requests.get("https://www.virustotal.com/api/v3/files/"+
                    "44d88612fea8a8f36de82e1278abb02f",
                    headers={"x-apikey":key}, timeout=8)
                if r.status_code == 200:
                    log(f"       ✓ VALIDA (quota OK)", C["green"])
                elif r.status_code == 401:
                    log(f"       ✗ NON VALIDA (401 Unauthorized)", C["red"])
                elif r.status_code == 429:
                    log(f"       ⚠ RATE LIMITED (429)", C["yellow"])
                else:
                    log(f"       ? HTTP {r.status_code}", C["peach"])
            except Exception as e:
                log(f"       ✗ ERROR: {e}", C["red"])
        log("\n>_ Test complete.", C["teal"])
    threading.Thread(target=_run, daemon=True).start()

def _dz_ping_vt():
    def _run():
        try:
            r = requests.get("https://www.virustotal.com/api/v3/metadata", timeout=5)
            messagebox.showinfo("VT Ping", f"VirusTotal reachable — HTTP {r.status_code}")
        except Exception as e:
            messagebox.showwarning("VT Ping", f"VirusTotal unreachable:\n{e}")
    threading.Thread(target=_run, daemon=True).start()

