def _ent_draw_gauge(entropy):
    _ent_gauge_canvas.delete("all")
    w = 440
    for col, lo, hi in [(C["green"],0,4),(C["yellow"],4,6),(C["peach"],6,7),(C["red"],7,8)]:
        _ent_gauge_canvas.create_rectangle(int(lo/8*w),4,int(hi/8*w),24,fill=col,outline="")
    tick = int(entropy/8*w)
    _ent_gauge_canvas.create_rectangle(tick-2,0,tick+2,28,fill="white",outline="")
    for v in [0,2,4,6,7.2,8]:
        x = int(v/8*w)
        _ent_gauge_canvas.create_text(x,28,text=str(v),font=("Consolas",7),fill=C["overlay0"],anchor="s")

def _ent_analyze():
    p = _ent_path_var.get().strip()
    if not p or not os.path.isfile(p):
        messagebox.showwarning("Entropy","Select a valid file first."); return
    _checkpoint("ENTROPY", f"Manual entropy analysis started — file: {os.path.basename(p)}  size: {os.path.getsize(p)} bytes")
    def _do():
        try:
            with open(p,"rb") as f: data = f.read()
            if not data:
                root.after(0,lambda: _ent_verdict_lbl.config(text="Empty file",fg=C["overlay0"])); return
            from collections import Counter
            freq = Counter(data); total = len(data)
            entropy = -sum((c/total)*math.log2(c/total) for c in freq.values() if c>0)
            entropy = round(entropy,4)
            hist = [freq.get(i,0) for i in range(256)]
            chunk_size = max(256, total//200)
            chunk_entropies = []
            for i in range(0,min(total,chunk_size*200),chunk_size):
                ch = data[i:i+chunk_size]; ct=len(ch)
                if ct>0:
                    cf=Counter(ch)
                    chunk_entropies.append(round(-sum((cv/ct)*math.log2(cv/ct) for cv in cf.values() if cv>0),4))
            pe_sections=[]
            if data[:2]==b"MZ":
                try:
                    import pefile as _pef
                    pef=_pef.PE(data=data,fast_load=False)
                    for sec in pef.sections:
                        sd=bytes(sec.get_data())
                        if sd:
                            scf=Counter(sd); sct=len(sd)
                            se=-sum((sv2/sct)*math.log2(sv2/sct) for sv2 in scf.values() if sv2>0)
                            pe_sections.append((sec.Name.rstrip(b"\x00").decode(errors="replace"),round(se,3),len(sd)))
                except Exception: pass
            root.after(0,lambda: _ent_render(entropy,hist,chunk_entropies,pe_sections,p,total))
            _checkpoint("ENTROPY", f"{os.path.basename(p)} — entropy: {entropy:.4f}/8.0  {'PACKED/ENCRYPTED' if entropy>7.2 else ('SUSPICIOUS' if entropy>6 else 'NORMAL')}  PE sections: {len(pe_sections)}")
        except Exception as e:
            _checkpoint("ENTROPY", f"Entropy analysis ERROR for {os.path.basename(p)}: {e}")
            root.after(0,lambda err=str(e): messagebox.showerror("Entropy Error",err))
    threading.Thread(target=_do,daemon=True).start()

def _ent_render(entropy,hist,chunk_entropies,pe_sections,fpath,fsize):
    _ent_draw_gauge(entropy)
    ecol = C["red"] if entropy>7.2 else (C["yellow"] if entropy>6 else C["green"])
    _ent_val_lbl.config(text=f"{entropy:.4f}",fg=ecol)
    if   entropy>=7.5: verdict,vc="🔴 LIKELY PACKED/ENCRYPTED",C["red"]
    elif entropy>=7.2: verdict,vc="🟠 HIGH ENTROPY — suspicious",C["peach"]
    elif entropy>=6.0: verdict,vc="🟡 ELEVATED — compressed data",C["yellow"]
    else:              verdict,vc="🟢 NORMAL entropy",C["green"]
    _ent_verdict_lbl.config(text=f"{verdict}  |  {fsize:,} bytes  |  {os.path.basename(fpath)}",fg=vc)
    for w2 in _ent_chart_frame.winfo_children(): w2.destroy()
    try:
        cols = 3 if pe_sections else 2
        fig = mplfig.Figure(figsize=(13,4.5),facecolor=C["base"],tight_layout=True)
        ax1=fig.add_subplot(1,cols,1)
        ax1.set_facecolor(C["mantle"]); ax1.tick_params(colors=C["overlay0"])
        ax1.bar(range(256),hist,color=C["blue"],width=1.0,linewidth=0)
        ax1.set_title("Byte Frequency",color=C["text"],fontsize=9)
        ax1.set_xlabel("Byte Value",color=C["overlay0"],fontsize=8); ax1.set_xlim(0,255)
        for sp in ax1.spines.values(): sp.set_color(C["surface2"])
        ax2=fig.add_subplot(1,cols,2)
        ax2.set_facecolor(C["mantle"]); ax2.tick_params(colors=C["overlay0"])
        cc=[C["red"] if e>7.2 else (C["yellow"] if e>6 else C["green"]) for e in chunk_entropies]
        ax2.bar(range(len(chunk_entropies)),chunk_entropies,color=cc,width=1.0,linewidth=0)
        ax2.axhline(7.2,color=C["red"],linestyle="--",linewidth=0.8,alpha=0.7)
        ax2.set_ylim(0,8); ax2.set_title("Entropy by Block",color=C["text"],fontsize=9)
        ax2.set_xlabel("File Position ->",color=C["overlay0"],fontsize=8)
        for sp in ax2.spines.values(): sp.set_color(C["surface2"])
        if pe_sections:
            ax3=fig.add_subplot(1,cols,3)
            ax3.set_facecolor(C["mantle"]); ax3.tick_params(colors=C["overlay0"])
            names=[s[0] for s in pe_sections]; ents=[s[1] for s in pe_sections]
            ax3.barh(names,ents,color=[C["red"] if e>7.2 else C["blue"] for e in ents])
            ax3.axvline(7.2,color=C["red"],linestyle="--",linewidth=0.8)
            ax3.set_xlim(0,8); ax3.set_title("PE Sections",color=C["text"],fontsize=9)
            ax3.tick_params(axis="y",colors=C["subtext"]); ax3.tick_params(axis="x",colors=C["overlay0"])
            for sp in ax3.spines.values(): sp.set_color(C["surface2"])
        cv=FigureCanvasTkAgg(fig,master=_ent_chart_frame)
        cv.get_tk_widget().configure(bg=C["base"]); cv.get_tk_widget().pack(fill=tk.BOTH,expand=True)
        cv.draw()
    except Exception as e:
        tk.Label(_ent_chart_frame,text=f"Chart error: {e}",bg=C["base"],fg=C["red"],font=FS).pack()


