_HEX_BPR = 16
_HEX_FILE = [None]
_HEX_MAGIC = [(b"MZ","PE Executable"),(b"\x7fELF","ELF Binary"),(b"PK\x03\x04","ZIP/Office"),
              (b"%PDF","PDF"),(b"\x1f\x8b","GZip"),(b"Rar!\x1a","RAR"),
              (b"\xd0\xcf\x11\xe0","OLE2/Office97"),(b"\xcf\xfa\xed\xfe","Mach-O")]

def _hex_browse():
    p = filedialog.askopenfilename(title="Open in Hex Viewer")
    if p: _hex_path_var.set(p); _hex_offset_var.set("0"); _hex_load(p,0)

def _hex_load(path, offset=0):
    def _do():
        try:
            with open(path,"rb") as f:
                f.seek(offset); data=f.read(_HEX_BPR*4096)
            fsize=os.path.getsize(path)
            root.after(0,lambda: _hex_render(data,offset,fsize,path))
        except Exception as e:
            root.after(0,lambda err=str(e): messagebox.showerror("Hex Viewer",err))
    threading.Thread(target=_do,daemon=True).start()

def _hex_render(data,start,fsize,path):
    magic="Unknown"
    for sig,name in _HEX_MAGIC:
        if data[:len(sig)]==sig: magic=name; break
    _hex_txt.config(state="normal"); _hex_txt.delete("1.0",tk.END)
    _hex_txt.insert(tk.END,f"  {os.path.basename(path)}  │  {fsize:,} bytes  │  {magic}  │  offset:{start:#010x}\n","ADDR")
    _hex_txt.insert(tk.END,"  "+"─"*87+"\n","ADDR")
    _hex_txt.insert(tk.END,f"  {'Offset':<12} {'00 01 02 03 04 05 06 07  08 09 0a 0b 0c 0d 0e 0f':<51}  ASCII\n","ADDR")
    _hex_txt.insert(tk.END,"  "+"─"*87+"\n","ADDR")
    offset=start
    for i in range(0,len(data),_HEX_BPR):
        row=data[i:i+_HEX_BPR]
        _hex_txt.insert(tk.END,f"  {offset:08x}  ","ADDR")
        for j,b in enumerate(row):
            tag="NULL" if b==0 else ("TXT" if 0x20<=b<0x7f else None)
            _hex_txt.insert(tk.END,f"{b:02x} ",tag)
            if j==7: _hex_txt.insert(tk.END," ")
        if len(row)<_HEX_BPR:
            pad=(_HEX_BPR-len(row))*3+(1 if len(row)<=8 else 0)
            _hex_txt.insert(tk.END," "*pad)
        _hex_txt.insert(tk.END,"  ")
        for b in row:
            _hex_txt.insert(tk.END,chr(b) if 0x20<=b<0x7f else "·","TXT" if 0x20<=b<0x7f else "NULL")
        _hex_txt.insert(tk.END,"\n")
        offset+=len(row)
    _hex_txt.config(state="disabled"); _hex_txt.see("1.0")
    _HEX_FILE[0]=path
    _hex_info_lbl.config(text=f"{fsize:,} bytes  │  {magic}",fg=C["teal"])

def _hex_goto():
    p=_hex_path_var.get().strip()
    if not p or not os.path.isfile(p): messagebox.showwarning("Hex","Load a file first."); return
    try:
        s=_hex_offset_var.get().strip()
        off=int(s,16) if s.lower().startswith("0x") else int(s)
        fsize=os.path.getsize(p)
        _hex_load(p,max(0,min(off,fsize-1)))
    except ValueError: messagebox.showerror("Hex","Invalid offset.")

def _hex_find():
    p=_hex_path_var.get().strip()
    if not p or not os.path.isfile(p): messagebox.showwarning("Hex","Load a file first."); return
    q=_hex_search_var.get().strip()
    if not q: return
    def _do():
        try:
            with open(p,"rb") as f: data=f.read()
            try: pattern=bytes.fromhex(q.replace(" ",""))
            except ValueError: pattern=q.encode("utf-8",errors="replace")
            idx=data.find(pattern)
            if idx==-1:
                root.after(0,lambda: _hex_info_lbl.config(text="Pattern not found.",fg=C["red"]))
            else:
                aligned=(idx//_HEX_BPR)*_HEX_BPR
                root.after(0,lambda: _hex_info_lbl.config(text=f"Found at {idx:#010x}",fg=C["green"]))
                root.after(0,lambda: _hex_offset_var.set(str(aligned)))
                root.after(50,lambda: _hex_load(p,aligned))
        except Exception as e:
            root.after(0,lambda err=str(e): messagebox.showerror("Hex Find",err))
    threading.Thread(target=_do,daemon=True).start()


