def _rx_load_file():
    p = filedialog.askopenfilename(filetypes=[("Text/Log","*.txt *.log *.json *.xml *.html *.csv"),("All","*.*")])
    if not p: return
    try:
        with open(p,encoding="utf-8",errors="replace") as f: content=f.read(2_000_000)
        _rx_in_txt.delete("1.0",tk.END); _rx_in_txt.insert(tk.END,content)
    except Exception as e: messagebox.showerror("Load",str(e))

def _rx_extract():
    text = _rx_in_txt.get("1.0",tk.END)
    results={}; total=0
    for name,pat in _RX_PATTERNS.items():
        if not _rx_pat_vars[name].get(): continue
        try:
            matches=list(dict.fromkeys(re.findall(pat,text)))
            if matches: results[name]=matches; total+=len(matches)
        except Exception: pass
    _rx_last[0]=results
    _rx_res_txt.config(state="normal"); _rx_res_txt.delete("1.0",tk.END)
    if not results:
        _rx_res_txt.insert(tk.END,"No IOCs found in the provided text.\n","NONE")
        _rx_count_sv.set("0 matches")
    else:
        _rx_count_sv.set(f"{total} matches, {len(results)} types")
        for cat,matches in results.items():
            _rx_res_txt.insert(tk.END,f"\n── {cat} ({len(matches)}) ──\n","CAT")
            for m in matches: _rx_res_txt.insert(tk.END,f"  {m}\n","MATCH")
    _rx_res_txt.config(state="disabled"); _rx_res_txt.see("1.0")

def _rx_copy():
    r=_rx_last[0]
    if not r: return
    lines=[]
    for cat,matches in r.items(): lines.append(f"=== {cat} ==="); lines.extend(matches)
    root.clipboard_clear(); root.clipboard_append("\n".join(lines))
    messagebox.showinfo("Copied",f"{sum(len(v) for v in r.values())} IOCs copied.")

def _rx_export():
    dest=filedialog.asksaveasfilename(defaultextension=".csv",filetypes=[("CSV","*.csv")],initialfile="ioc_extract.csv")
    if not dest: return
    import csv
    with open(dest,"w",newline="",encoding="utf-8") as f:
        w=csv.writer(f); w.writerow(["type","value"])
        for cat,matches in _rx_last[0].items():
            for m in matches: w.writerow([cat,m])
    messagebox.showinfo("Export",f"Exported to:\n{dest}")


