def _doc_browse():
    p=filedialog.askopenfilename(title="Select document",
        filetypes=[("Documents","*.pdf *.doc *.docx *.xls *.xlsx *.ppt *.pptx *.rtf"),("All","*.*")])
    if p: _doc_path_var.set(p)

def _doc_analyze():
    p=_doc_path_var.get().strip()
    if not p or not os.path.isfile(p): messagebox.showwarning("Doc","Select a valid file."); return
    _checkpoint("DOC", f"Document analysis started — file: {os.path.basename(p)}  size: {os.path.getsize(p):,} bytes")
    _doc_out.config(state="normal"); _doc_out.delete("1.0",tk.END); _doc_out.config(state="disabled")
    def _do():
        try:
            fname=os.path.basename(p); ext=os.path.splitext(fname)[1].lower()
            root.after(0,lambda: _doc_log(f"\n{'━'*60}","HEAD"))
            root.after(0,lambda: _doc_log(f"  FILE: {fname}  │  {os.path.getsize(p):,} bytes  │  {ext}","HEAD"))
            root.after(0,lambda: _doc_log(f"{'━'*60}","HEAD"))
            with open(p,"rb") as f: raw=f.read()
            findings=[]; score=0
            if ext==".pdf":
                for pattern,sev,desc in [
                    (b"/JavaScript","HIGH","Embedded JavaScript action"),
                    (b"/JS ","HIGH","JS stream reference"),
                    (b"/Launch","HIGH","Launch action — can execute files"),
                    (b"/EmbeddedFile","MED","Embedded file attachment"),
                    (b"/OpenAction","MED","OpenAction triggered on open"),
                    (b"/RichMedia","MED","Rich media (Flash/3D)"),
                    (b"/XFA","MED","XFA form — complex scripting"),
                    (b"eval(","HIGH","eval() — JS obfuscation"),
                    (b"unescape(","HIGH","unescape() — obfuscation indicator"),
                    (b"/URI","LOW","Outbound URI reference"),
                    (b"/AcroForm","LOW","AcroForm present"),
                ]:
                    if pattern in raw:
                        findings.append((sev,desc))
                        score+={"HIGH":3,"MED":1,"LOW":0}.get(sev,0)
                pages=raw.count(b"/Type /Page")+raw.count(b"/Type/Page")
                findings.append(("LOW",f"Page count ≈ {pages}"))
            elif ext in (".doc",".xls",".ppt"):
                if raw[:8]==b"\xd0\xcf\x11\xe0\xa1\xb1\x1a\xe1":
                    findings.append(("LOW","OLE2 magic bytes detected"))
                    if b"VBA" in raw or b"vba" in raw:
                        findings.append(("HIGH","VBA string found in binary — likely macros")); score+=4
                    try:
                        import olefile as _ole2
                        ole2=_ole2.OleFileIO(p); streams=["/".join(s) for s in ole2.listdir()]
                        vba_streams=[s for s in streams if "vba" in s.lower() or "macro" in s.lower()]
                        if vba_streams:
                            findings.append(("HIGH",f"VBA streams: {', '.join(vba_streams[:3])}")); score+=2
                        findings.append(("LOW",f"OLE streams: {len(streams)}"))
                        ole2.close()
                    except ImportError: findings.append(("LOW","Install 'olefile' for deep OLE analysis"))
                    except Exception: pass
                else: findings.append(("LOW","File does not match OLE2 magic"))
            elif ext in (".docx",".xlsx",".pptx"):
                import zipfile, io
                try:
                    zf=zipfile.ZipFile(io.BytesIO(raw)); names=zf.namelist()
                    macros=[n for n in names if "vbaproject" in n.lower()]
                    if macros: findings.append(("HIGH",f"VBA macro project: {', '.join(macros)}")); score+=4
                    for rf in [n for n in names if n.endswith(".rels")]:
                        try:
                            c7=zf.read(rf).decode("utf-8",errors="replace")
                            if "http://" in c7 or "https://" in c7:
                                findings.append(("MED",f"External relationship in {rf}")); score+=1; break
                        except Exception: pass
                    for xname in names:
                        if xname.endswith(".xml"):
                            try:
                                c8=zf.read(xname).decode("utf-8",errors="replace")
                                if "ddeField" in c8 or "DDE(" in c8.upper():
                                    findings.append(("HIGH",f"DDE field in {xname}")); score+=3; break
                                if "cmd.exe" in c8.lower() or "power" + "shell" in c8.lower():
                                    findings.append(("HIGH",f"Shell ref in {xname}")); score+=3; break
                                if "javascript:" in c8.lower():
                                    findings.append(("HIGH",f"JavaScript URI in {xname}")); score+=2; break
                            except Exception: pass
                    findings.append(("LOW",f"ZIP members: {len(names)} files")); zf.close()
                except zipfile.BadZipFile: findings.append(("LOW","Not a valid ZIP/OOXML"))
            elif ext==".rtf":
                text8=raw[:500_000].decode("latin-1",errors="replace")
                for pat8,sev8,desc8 in [(r"\\object","HIGH","Embedded OLE object"),
                                        (r"\\objocx","HIGH","ActiveX control"),
                                        (r"\\objhtml","HIGH","HTML object"),
                                        (r"\\bin","MED","Binary data blob")]:
                    if re.search(pat8,text8,re.IGNORECASE):
                        findings.append((sev8,desc8)); score+={"HIGH":3,"MED":1}.get(sev8,0)
                obc=text8.count("{"); cbc=text8.count("}")
                if abs(obc-cbc)>100: findings.append(("MED",f"Unbalanced braces ({obc}/{cbc}) — evasion?")); score+=1
            else: findings.append(("LOW",f"No deep analyzer for {ext}"))
            if not findings:
                root.after(0,lambda: _doc_log("\n  ✓ No suspicious indicators found.","OK"))
            else:
                for sev9,msg9 in findings:
                    root.after(0,lambda s=sev9,m=msg9: _doc_log(f"  [{s}]  {m}","CRIT" if s=="HIGH" else ("WARN" if s=="MED" else "INFO")))
            verdict9="HIGH RISK" if score>=4 else ("SUSPICIOUS" if score>=2 else "CLEAN")
            vtag9="CRIT" if score>=4 else ("WARN" if score>=2 else "OK")
            root.after(0,lambda: _doc_log(f"\n  ▶ VERDICT: {verdict9}  (risk score: {score})",vtag9))
            root.after(0,lambda: _doc_log(f"{'━'*60}","DIM"))
        except Exception as e:
            root.after(0,lambda err=str(e): _doc_log(f"Analysis error: {err}","CRIT"))
    threading.Thread(target=_do,daemon=True).start()


