def _secure_wipe_reports():
    import shutil
    if not messagebox.askyesno("Secure Wipe",
        "Overwrite (3 passes) and delete all reports?\nNot recoverable."): return
    count = 0
    for rt, dirs, files in os.walk(REPORTS_DIR):
        for fn in files:
            fp = os.path.join(rt, fn)
            try:
                sz = os.path.getsize(fp)
                if sz > 0:
                    with open(fp, "r+b") as _f:
                        for _ in range(3): _f.seek(0); _f.write(os.urandom(sz))
                os.remove(fp); count += 1
            except Exception: pass
    shutil.rmtree(REPORTS_DIR, ignore_errors=True)
    os.makedirs(REPORTS_DIR, exist_ok=True)
    _rep_refresh()
    messagebox.showinfo("Secure Wipe", f"Securely wiped {count} file(s).")

