def _dz_secure_delete_file():
    path = filedialog.askopenfilename(title="Select file for secure deletion")
    if not path: return
    passes_map = {"DoD 5220.22-M (3 pass)": 3, "Gutmann (35 pass)": 35, "Single pass (fast)": 1}
    import tkinter.simpledialog as _sd
    choice = None
    _pd = tk.Toplevel(root); _pd.title("Secure Delete"); _pd.configure(bg=C["base"]); _pd.resizable(False,False)
    _pd.grab_set()
    tk.Label(_pd, text=f"Secure Delete: {os.path.basename(path)}", font=("Consolas",9,"bold"),
             bg=C["base"], fg=C["red"], padx=14, pady=8).pack(anchor="w")
    _sd_mode = tk.StringVar(value="DoD 5220.22-M (3 pass)")
    for opt in passes_map:
        tk.Radiobutton(_pd, text=opt, variable=_sd_mode, value=opt, font=("Consolas",8),
                       bg=C["base"], fg=C["text"], selectcolor=C["surface1"],
                       activebackground=C["base"], activeforeground=C["text"]).pack(anchor="w", padx=14)
    _sd_status = tk.StringVar(value="")
    tk.Label(_pd, textvariable=_sd_status, font=("Consolas",8), bg=C["base"], fg=C["teal"]).pack(anchor="w", padx=14)
    def _do_wipe():
        mode = _sd_mode.get(); n_passes = passes_map[mode]
        _sd_status.set(f"⏳ Wiping ({mode})...")
        _pd.update_idletasks()
        def _worker():
            import math as _m
            try:
                fsize = os.path.getsize(path)
                if mode == "Gutmann (35 pass)":
                    patterns = [
                        b'\x55',b'\xaa',b'\x92\x49\x24',b'\x49\x24\x92',b'\x24\x92\x49',
                        b'\x00',b'\x11',b'\x22',b'\x33',b'\x44',b'\x55',b'\x66',b'\x77',
                        b'\x88',b'\x99',b'\xaa',b'\xbb',b'\xcc',b'\xdd',b'\xee',b'\xff',
                        b'\x92\x49\x24',b'\x49\x24\x92',b'\x24\x92\x49',b'\x6d\xb6\xdb',
                        b'\xb6\xdb\x6d',b'\xdb\x6d\xb6',None,None,None,None,None,None,None,None,None
                    ]
                else:
                    patterns = [b'\x00', b'\xff', None] if n_passes == 3 else [None]
                for i, pat in enumerate(patterns[:n_passes]):
                    with open(path, "r+b") as f:
                        written = 0
                        chunk_size = 65536
                        while written < fsize:
                            to_write = min(chunk_size, fsize - written)
                            if pat:
                                chunk = (pat * (chunk_size // len(pat) + 1))[:to_write]
                            else:
                                import os as _os2
                                chunk = _os2.urandom(to_write)
                            f.write(chunk); written += to_write
                        f.flush(); os.fsync(f.fileno())
                    root.after(0, lambda i=i, n=n_passes: _sd_status.set(f"⏳ Pass {i+1}/{n}..."))
                os.remove(path)
                root.after(0, lambda: _sd_status.set(f"✓ Securely deleted ({n_passes} pass{'es' if n_passes>1 else ''})"))
                root.after(0, lambda: messagebox.showinfo("Secure Delete",
                    f"File securely wiped and deleted:\n{os.path.basename(path)}\nMethod: {mode}"))
            except Exception as e:
                root.after(0, lambda: _sd_status.set(f"✗ {e}"))
                root.after(0, lambda: messagebox.showerror("Secure Delete Error", str(e)))
        threading.Thread(target=_worker, daemon=True).start()
    btn_row = tk.Frame(_pd, bg=C["base"], padx=14, pady=8); btn_row.pack(fill=tk.X)
    tk.Button(btn_row, text="🔥 Wipe", command=_do_wipe, bg=C["red"], fg=C["base"],
              font=("Consolas",9,"bold"), relief="flat", padx=10, pady=4, cursor="hand2", bd=0).pack(side=tk.LEFT, padx=(0,8))
    tk.Button(btn_row, text="Cancel", command=_pd.destroy, bg=C["surface2"], fg=C["text"],
              font=("Consolas",9), relief="flat", padx=8, pady=4, cursor="hand2", bd=0).pack(side=tk.LEFT)
