def _factory_reset():
    import shutil
    if not messagebox.askyesno("FACTORY RESET",
        "DELETE EVERYTHING:\n  • Scan database\n  • All reports\n  • All YARA rules\n  • Config\n  • All logs\n  • Whitelist\n\nIRREVERSIBLE."): return
    if not messagebox.askyesno("FINAL CONFIRM","Are you absolutely sure?\n\nThis cannot be undone."): return
    try:
        with _db_lock: _conn.execute("DELETE FROM scans"); _conn.commit()
        for d in os.listdir(REPORTS_DIR):
            full = os.path.join(REPORTS_DIR, d)
            if os.path.isdir(full): shutil.rmtree(full)
        shutil.rmtree(RULES_EXTERN_DIR); os.makedirs(RULES_EXTERN_DIR, exist_ok=True)
        for fn in os.listdir(RULES_DIR):
            if fn.lower().endswith((".yar",".yara")): os.remove(os.path.join(RULES_DIR, fn))
        with _rules_state_lock: _rules_state.clear(); _state_save({})
        default = {"api_keys":[], "request_delay":15, "tshark_path":"tshark"}
        _vx_cfg_write(default)
        for fn in os.listdir(DEBUG_DIR):
            try: os.remove(os.path.join(DEBUG_DIR, fn))
            except Exception: pass
        if os.path.exists(WHITELIST_PATH): os.remove(WHITELIST_PATH)
        global _yara_rules; _yara_rules = None
        _clear_logs(); _refresh_stats(); _update_charts(); _rep_refresh(); _ym_library_refresh()
        messagebox.showinfo("Factory Reset","Completed. All data deleted.")
    except Exception as e: messagebox.showerror("Error", str(e))
