def _df_write(msg, tag="INF"):
    _df_out.config(state="normal")
    _df_out.insert("end", msg + "\n", tag)
    _df_out.config(state="disabled")

def _df_run():
    import difflib
    f1, f2 = _df_f1.get().strip(), _df_f2.get().strip()
    if not f1 or not f2 or not os.path.isfile(f1) or not os.path.isfile(f2):
        messagebox.showerror("Diff", "Select two valid files."); return
    mode = _df_mode_v.get()
    _df_out.config(state="normal"); _df_out.delete("1.0","end"); _df_out.config(state="disabled")

    if mode == "text":
        try:
            lines_a = open(f1,"r",errors="replace").readlines()
            lines_b = open(f2,"r",errors="replace").readlines()
        except Exception as e:
            messagebox.showerror("Diff", str(e)); return
        d = list(difflib.unified_diff(lines_a, lines_b,
                 fromfile=os.path.basename(f1), tofile=os.path.basename(f2), lineterm=""))
        adds = sum(1 for l in d if l.startswith("+") and not l.startswith("+++"))
        dels = sum(1 for l in d if l.startswith("-") and not l.startswith("---"))
        _df_stats.set(f"  +{adds} lines added   -{dels} lines removed   {len(d)} diff lines total")
        for line in d:
            if line.startswith("@@"):    _df_write(line, "HDR")
            elif line.startswith("+"): _df_write(line, "ADD")
            elif line.startswith("-"): _df_write(line, "DEL")
            else:                       _df_write(line, "INF")
        _df_html_diff[0] = difflib.HtmlDiff().make_file(lines_a, lines_b,
                               fromdesc=os.path.basename(f1), todesc=os.path.basename(f2))

    elif mode == "hex":
        try:
            raw_a = open(f1,"rb").read()
            raw_b = open(f2,"rb").read()
        except Exception as e:
            messagebox.showerror("Diff", str(e)); return
        sz_a, sz_b = len(raw_a), len(raw_b)
        diffs = 0
        _df_stats.set(f"  A: {sz_a:,} B  B: {sz_b:,} B  size delta: {sz_b-sz_a:+,} B")
        _df_write(f"{'Offset':<10}  {'File A bytes':<40}  {'File B bytes':<40}  Status", "HDR")
        _df_write("─"*100, "INF")
        chunk = 16
        limit = min(max(sz_a, sz_b), 0x10000)
        for off in range(0, limit, chunk):
            ba = raw_a[off:off+chunk]
            bb = raw_b[off:off+chunk]
            if ba == bb:
                continue
            hex_a = " ".join(f"{b:02x}" for b in ba).ljust(47)
            hex_b = " ".join(f"{b:02x}" for b in bb).ljust(47)
            tag = "ADD" if not ba else ("DEL" if not bb else "MOD")
            _df_write(f"0x{off:08x}  {hex_a}  {hex_b}", tag)
            diffs += 1
            if diffs >= 2000:
                _df_write(f"  ... truncated at 2000 differing chunks (use Export for full report)", "HDR"); break
        if diffs == 0:
            _df_write("  Files are byte-identical ✓", "ADD")
        else:
            _df_write(f"\n  {diffs} differing 16-byte chunk(s)", "HDR")

    elif mode == "pe":
        def _pe_sections(path):
            try:
                import pefile as _pe2
                pe = _pe2.PE(path, fast_load=False)
                secs = []
                for s in pe.sections:
                    name = s.Name.decode("latin-1","replace").rstrip("\x00")
                    secs.append({
                        "name": name,
                        "vaddr": s.VirtualAddress,
                        "vsize": s.Misc_VirtualSize,
                        "rsize": s.SizeOfRawData,
                        "entropy": s.get_entropy(),
                        "chars": s.Characteristics,
                    })
                return secs, None
            except ImportError:
                return None, "pefile not installed"
            except Exception as _e2:
                return None, str(_e2)
        secs_a, err_a = _pe_sections(f1)
        secs_b, err_b = _pe_sections(f2)
        if err_a or err_b:
            _df_write(f"  A: {err_a or 'OK'}  B: {err_b or 'OK'}", "DEL"); return
        _df_stats.set(f"  A: {len(secs_a)} sections    B: {len(secs_b)} sections")
        _df_write(f"{'Section':<12}  {'VAddr':<12}  {'VSize':<12}  {'RSize':<12}  {'Entropy':>8}  Status", "HDR")
        _df_write("─"*80, "INF")
        names_a = {s["name"] for s in secs_a}
        names_b = {s["name"] for s in secs_b}
        sec_map_a = {s["name"]: s for s in secs_a}
        sec_map_b = {s["name"]: s for s in secs_b}
        for name in sorted(names_a | names_b):
            sa = sec_map_a.get(name)
            sb = sec_map_b.get(name)
            if sa and not sb:
                _df_write(f"  {name:<12}  {sa['vaddr']:<12x}  {sa['vsize']:<12}  {sa['rsize']:<12}  {sa['entropy']:8.2f}  REMOVED", "DEL")
            elif sb and not sa:
                _df_write(f"  {name:<12}  {sb['vaddr']:<12x}  {sb['vsize']:<12}  {sb['rsize']:<12}  {sb['entropy']:8.2f}  ADDED", "ADD")
            else:
                ent_delta = sb["entropy"] - sa["entropy"]
                changed = (sa["rsize"] != sb["rsize"] or abs(ent_delta) > 0.3)
                tag = "MOD" if changed else "EQ"
                status = f"delta entropy={ent_delta:+.2f}" if changed else "unchanged"
                _df_write(f"  {name:<12}  {sb['vaddr']:<12x}  {sb['vsize']:<12}  {sb['rsize']:<12}  {sb['entropy']:8.2f}  {status}", tag)
                if sb["entropy"] > 7.2:
                    _df_write(f"    ⚠ High entropy in {name} — likely packed/encrypted", "SECD")

def _df_export_html():
    if not _df_html_diff[0]:
        messagebox.showinfo("Diff","Run a text comparison first."); return
    p = filedialog.asksaveasfilename(defaultextension=".html",filetypes=[("HTML","*.html")])
    if not p: return
    with open(p,"w",encoding="utf-8") as f: f.write(_df_html_diff[0])
    messagebox.showinfo("Diff","HTML report saved.")


