def _tf_fetch_feeds(silent=False):
    import requests as _rq
    selected = [f for f in _FREE_FEEDS if _tf_feed_vars[f[0]].get()]
    if not selected:
        if not silent: messagebox.showinfo("Feeds","Select at least one feed.")
        return
    if not silent: _tf_status_sv.set(f"Fetching {len(selected)} feed(s)…")
    def _do():
        total = 0
        for fname, furl, ftype in selected:
            try:
                r = _rq.get(furl, timeout=20, headers={"User-Agent":"V0RTEX/1.0"})
                if r.ok:
                    entries = set()
                    for line in r.text.splitlines():
                        line = line.strip()
                        if not line or line.startswith("#"): continue
                        entries.add(line.split()[0].lower())
                    _tf_cache[fname] = entries
                    total += len(entries)
                    if not silent:
                        root.after(0,lambda fn=fname,n=len(entries): _tf_log(f"[OK] {fn}: {n} entries","OK"))
                else:
                    if not silent:
                        root.after(0,lambda fn=fname,s=r.status_code: _tf_log(f"[FAIL] {fn}: HTTP {s}","ERR"))
            except Exception as ex:
                if not silent:
                    root.after(0,lambda fn=fname,e=str(ex): _tf_log(f"[ERR] {fn}: {e}","ERR"))
        root.after(0,lambda t=total: _tf_status_sv.set(f"Feeds loaded — {t} total entries cached"))
        root.after(0, _tf_crossref_session_iocs)
    threading.Thread(target=_do,daemon=True).start()

def _tf_collect_session_iocs():
    iocs = set()
    try:
        for lb in (_ioc_ips, _ioc_domains, _ioc_urls):
            for i in range(lb.size()):
                val = lb.get(i).strip()
                if val: iocs.add(val.lower())
    except Exception: pass
    return iocs

def _tf_crossref_session_iocs():
    if not _tf_cache: return
    iocs = _tf_collect_session_iocs()
    if not iocs: return
    matches = []
    for ioc in iocs:
        for fname, entries in _tf_cache.items():
            if ioc in entries:
                matches.append((ioc, fname))
    if matches:
        _tf_log(f"\n⚑ AUTO CROSS-REF: {len(matches)} match(es) found in session IOCs!", "ERR")
        for ioc, fname in matches[:20]:
            _tf_log(f"  ⚠ {ioc}  ->  {fname}", "ERR")
        try:
            root.after(0, lambda m=matches: messagebox.showwarning(
                "Feed Monitor — IOC Match!",
                f"{len(m)} session IOC(s) found in threat feeds!\n\n" +
                "\n".join(f"  {i}  ->  {f}" for i,f in m[:10])
            ))
        except Exception: pass
    else:
        _tf_log(f"  ✓ Auto cross-ref: {len(iocs)} session IOC(s) — no matches", "OK")

def _tf_schedule_auto():
    if _tf_auto_timer[0]:
        try: root.after_cancel(_tf_auto_timer[0])
        except Exception: pass
        _tf_auto_timer[0] = None
    if not _tf_auto_enabled.get() or _APP_DYING[0]: return
    interval_ms = _tf_interval_v.get() * 60 * 1000
    import datetime as _dt_tf
    next_t = _dt_tf.datetime.now() + _dt_tf.timedelta(minutes=_tf_interval_v.get())
    _tf_next_sv.set(f"next: {next_t.strftime('%H:%M')}")
    def _tick():
        if _APP_DYING[0] or not _tf_auto_enabled.get(): return
        _tf_log(f"[AUTO] Background refresh triggered", "INFO")
        _tf_fetch_feeds(silent=True)
        _tf_schedule_auto()
    _tf_auto_timer[0] = root.after(interval_ms, _tick)

_tf_auto_enabled.trace_add("write", lambda *_: _tf_schedule_auto())
_tf_interval_v.trace_add("write", lambda *_: _tf_schedule_auto() if _tf_auto_enabled.get() else None)

def _tf_check_ioc():
    ioc = _tf_ioc_var.get().strip().lower()
    if not ioc: return
    if not _tf_cache:
        messagebox.showinfo("Feeds","Fetch feeds first."); return
    hits = []
    for fname, entries in _tf_cache.items():
        if ioc in entries:
            hits.append(fname)
        else:
            for e in entries:
                if ioc in e or e in ioc:
                    hits.append(f"{fname} (partial: {e})")
                    break
    if hits:
        _tf_log(f"⚑ MATCH for '{ioc}': {', '.join(hits)}", "ERR")
    else:
        _tf_log(f"✓ '{ioc}' not found in cached feeds.", "OK")

