def _b64_encode():
    import base64 as _bm
    txt = _b64_inp.get("1.0", tk.END).strip()
    if not txt: return
    try:
        d = txt.encode("utf-8"); m = _b64_mode.get()
        if m == "Base64": r = _bm.b64encode(d).decode()
        elif m == "Base64 URL": r = _bm.urlsafe_b64encode(d).decode()
        elif m == "Base32": r = _bm.b32encode(d).decode()
        else: r = d.hex()
    except Exception as e: r = f"Error: {e}"
    _b64_out.config(state="normal"); _b64_out.delete("1.0",tk.END); _b64_out.insert(tk.END, r); _b64_out.config(state="disabled")
def _b64_decode():
    import base64 as _bm
    txt = _b64_inp.get("1.0", tk.END).strip()
    if not txt: return
    try:
        m = _b64_mode.get()
        if m == "Base64": d = _bm.b64decode(txt + "==")
        elif m == "Base64 URL": d = _bm.urlsafe_b64decode(txt + "==")
        elif m == "Base32": d = _bm.b32decode(txt.upper() + "="*((8-len(txt)%8)%8))
        else: d = bytes.fromhex(txt.replace(" ",""))
        try: r = d.decode("utf-8")
        except: r = d.decode("latin-1")
    except Exception as e: r = f"Error: {e}"
    _b64_out.config(state="normal"); _b64_out.delete("1.0",tk.END); _b64_out.insert(tk.END, r); _b64_out.config(state="disabled")
def _b64_swap():
    val = _b64_out.get("1.0",tk.END).strip()
    _b64_inp.delete("1.0",tk.END); _b64_inp.insert("1.0", val)
    _b64_out.config(state="normal"); _b64_out.delete("1.0",tk.END); _b64_out.config(state="disabled")
