def _xor_run():
    txt = _xor_inp.get("1.0", tk.END).strip()
    if not txt: return
    try:
        key_s = _xor_key_v.get().strip()
        if key_s.lower().startswith("0x"): key = bytes.fromhex(key_s[2:])
        else: key = key_s.encode("utf-8")
        if not key: raise ValueError("empty key")
        data = bytes.fromhex(txt.replace(" ","")) if _xor_inhex.get() else txt.encode("utf-8")
        out = bytes(b ^ key[i % len(key)] for i, b in enumerate(data))
        if _xor_outhex.get(): r = out.hex()
        else:
            try: r = out.decode("utf-8")
            except: r = out.decode("latin-1")
    except Exception as e: r = f"Error: {e}"
    _xor_out.config(state="normal"); _xor_out.delete("1.0",tk.END)
    _xor_out.insert(tk.END, r); _xor_out.config(state="disabled")
_mkbtn(_xor_btnrow,"⚡ XOR",lambda:_xor_run(),C["maroon"])
