def _whois_run():
    query = _whois_v.get().strip()
    if not query: return
    _whois_out.config(state="normal"); _whois_out.delete("1.0",tk.END)
    _whois_out.insert(tk.END, f"  Querying WHOIS for: {query} ...\n")
    _whois_out.config(state="disabled")
    def _do():
        import socket as _sock
        try:
            try:
                import whois as _wlib; raw = str(_wlib.whois(query))
            except ImportError:
                tld = query.split(".")[-1].lower() if "." in query else ""
                srvs = {"com":"whois.verisign-grs.com","net":"whois.verisign-grs.com",
                        "org":"whois.pir.org","io":"whois.iana.org"}
                srv = srvs.get(tld,"whois.iana.org")
                s = _sock.create_connection((srv,43), timeout=10)
                s.sendall((query+"\r\n").encode())
                raw = b""; chunk = s.recv(4096)
                while chunk: raw += chunk; chunk = s.recv(4096)
                s.close(); raw = raw.decode("utf-8","replace")
        except Exception as e:
            raw = f"Error: {e}"
        root.after(0, lambda: (_whois_out.config(state="normal"),
                               _whois_out.delete("1.0",tk.END),
                               _whois_out.insert(tk.END, raw),
                               _whois_out.config(state="disabled")))
    threading.Thread(target=_do, daemon=True).start()

