def _ioex_scan():
    import re as _re_ex
    _ioex_out.config(state="normal"); _ioex_out.delete("1.0",tk.END)
    collected = {"IP":set(),"URL":set(),"Hash":set(),"Email":set()}
    logs_dir = DEBUG_DIR
    if os.path.isdir(logs_dir):
        for fn in sorted(os.listdir(logs_dir), reverse=True):
            fp = os.path.join(logs_dir, fn)
            if not os.path.isfile(fp): continue
            try:
                with open(fp,"r",encoding="utf-8",errors="replace") as f: c = f.read()
                if _ioex_ips.get():
                    for ip in _re_ex.findall(r'\b(?:\d{1,3}\.){3}\d{1,3}\b',c):
                        if not ip.startswith(("127.","0.","255.")):
                            collected["IP"].add(ip)
                if _ioex_urls.get():
                    for u in _re_ex.findall(r'https?://[^\s"\'<>]{8,}',c):
                        collected["URL"].add(u)
                if _ioex_hashes.get():
                    for h in _re_ex.findall(
                        r'\b[0-9a-fA-F]{32}\b|\b[0-9a-fA-F]{40}\b|\b[0-9a-fA-F]{64}\b', c):
                        collected["Hash"].add(h)
                if _ioex_emails.get():
                    for e in _re_ex.findall(r'[a-zA-Z0-9_.+-]+@[a-zA-Z0-9-]+\.[a-zA-Z]{2,}',c):
                        collected["Email"].add(e)
            except: pass
    total = sum(len(v) for v in collected.values())
    _ioex_out.insert(tk.END, f"  Logs dir: {logs_dir}\n  Found {total} unique IOCs\n\n")
    for cat, items in collected.items():
        if items:
            _ioex_out.insert(tk.END, f"  [{cat}] {len(items)}\n")
            for item in sorted(items)[:10]:
                _ioex_out.insert(tk.END, f"    {item}\n")
            if len(items)>10:
                _ioex_out.insert(tk.END, f"    ... and {len(items)-10} more\n")
    _ioex_out.config(state="disabled")
    return collected
def _ioex_export():
    import csv, json as _j
    collected = _ioex_scan()
    fmt = _ioex_fmt.get()
    ext = {"CSV":".csv","JSON":".json","TXT":".txt"}[fmt]
    p = filedialog.asksaveasfilename(defaultextension=ext, filetypes=[(fmt,f"*{ext}")])
    if not p: return
    try:
        if fmt=="CSV":
            with open(p,"w",newline="",encoding="utf-8") as f:
                w = csv.writer(f); w.writerow(["Type","IOC"])
                for cat,items in collected.items():
                    for item in items: w.writerow([cat,item])
        elif fmt=="JSON":
            with open(p,"w",encoding="utf-8") as f:
                _j.dump({cat:sorted(items) for cat,items in collected.items()},f,indent=2)
        else:
            with open(p,"w",encoding="utf-8") as f:
                for cat,items in collected.items():
                    for item in sorted(items): f.write(f"{item}\n")
        messagebox.showinfo("Export",f"Exported to {os.path.basename(p)}")
    except Exception as e:
        messagebox.showerror("Export",str(e))
_mkbtn(_ioex_btnrow,"🔍 Scan Logs",lambda:_ioex_scan(),C["surface2"],C["text"])
_mkbtn(_ioex_btnrow,"💾 Export",lambda:_ioex_export(),C["teal"])

