def _ts_level(score):
    if score >= 75: return "CRITICAL", C["red"]
    if score >= 50: return "HIGH",     C["peach"]
    if score >= 25: return "MEDIUM",   C["yellow"]
    return "LOW", C["green"]
def _ts_compute():
    _ts_status.set("⏳ Computing...")
    mode = _ts_mode.get()
    def _worker():
        try:
            if mode == "Latest Scan":
                rows = _db_query("SELECT file, malicious, suspicious, undetected, yara_hits, iocs, entropy, threat_score, tags FROM scans ORDER BY timestamp DESC LIMIT 1")
            elif mode == "Last 10 Scans":
                rows = _db_query("SELECT file, malicious, suspicious, undetected, yara_hits, iocs, entropy, threat_score, tags FROM scans ORDER BY timestamp DESC LIMIT 10")
            else:
                rows = _db_query("SELECT file, malicious, suspicious, undetected, yara_hits, iocs, entropy, threat_score, tags FROM scans ORDER BY timestamp DESC LIMIT 100")
        except Exception as e:
            root.after(0, lambda: _ts_status.set(f"✗ DB error: {e}")); return
        def _upd():
            _ts_txt.config(state="normal"); _ts_txt.delete("1.0", tk.END)
            if not rows:
                _ts_badge_var.set("N/A"); _ts_score_var.set("—")
                _ts_txt.insert(tk.END, "No scan data in DB.\n", "dim")
                _ts_txt.config(state="disabled"); _ts_status.set("No data"); return
            if mode in ("Latest Scan",):
                r = rows[0]
                fname = os.path.basename(r[0]) if r[0] else "unknown"
                stats = {"malicious": r[1], "suspicious": r[2], "undetected": r[3]}
                try: yara = json.loads(r[4]) if r[4] else []
                except: yara = []
                try: iocs = json.loads(r[5]) if r[5] else {}
                except: iocs = {}
                entropy = r[6] or 0.0
                saved_score = r[7]
                tags = r[8] or ""
                score = saved_score if saved_score else _compute_threat_score(stats, yara, iocs, entropy)
                level, col = _ts_level(score)
                _ts_badge_var.set(level); _ts_score_var.set(str(score))
                _ts_badge_lbl.config(fg=col); _ts_score_lbl.config(fg=col)
                total_iocs = sum(len(v) for v in iocs.values() if isinstance(v, list))
                _ts_txt.insert(tk.END, f"FILE: {fname}\n\n", "hdr")
                _ts_txt.insert(tk.END, f"  VT Malicious       : {r[1]}\n", "val")
                _ts_txt.insert(tk.END, f"  VT Suspicious      : {r[2]}\n", "val")
                _ts_txt.insert(tk.END, f"  YARA Hits          : {len(yara)}\n", "val")
                _ts_txt.insert(tk.END, f"  Entropy            : {entropy:.3f}\n", "val")
                _ts_txt.insert(tk.END, f"  IOC Count          : {total_iocs}\n", "val")
                _ts_txt.insert(tk.END, f"  Auto-Tags          : {tags or 'none'}\n", "val")
                _ts_txt.insert(tk.END, f"\n  THREAT SCORE       : {score}/100  [{level}]\n",
                               level.lower() if level != "N/A" else "dim")
            else:
                all_scores = []
                for r in rows:
                    try: y = json.loads(r[4]) if r[4] else []
                    except: y = []
                    try: ic = json.loads(r[5]) if r[5] else {}
                    except: ic = {}
                    st = {"malicious": r[1], "suspicious": r[2], "undetected": r[3]}
                    sc = r[7] if r[7] else _compute_threat_score(st, y, ic, r[6] or 0.0)
                    all_scores.append((os.path.basename(r[0] or ""), sc, r[8] or ""))
                avg = sum(s for _, s, _ in all_scores) // len(all_scores)
                level, col = _ts_level(avg)
                _ts_badge_var.set(level); _ts_score_var.set(f"avg {avg}")
                _ts_badge_lbl.config(fg=col); _ts_score_lbl.config(fg=col)
                _ts_txt.insert(tk.END, f"SCAN BATCH — {len(all_scores)} files  |  avg score: {avg}\n\n", "hdr")
                for fname, sc, tgs in sorted(all_scores, key=lambda x: -x[1]):
                    lv, lc = _ts_level(sc)
                    _ts_txt.insert(tk.END, f"  [{sc:>3}] {lv:<8}  {fname:<45}  {tgs}\n", lv.lower())
            _ts_txt.config(state="disabled")
            _ts_status.set(f"✓ Done — {len(rows)} record(s)")
        root.after(0, _upd)
    threading.Thread(target=_worker, daemon=True).start()
