def _ic_correlate():
    _ic_status.set("⏳ Correlating...")
    min_sess = _ic_min_sv.get()
    ioc_type = _ic_type_sv.get()
    def _worker():
        try:
            rows = _db_query("SELECT file, iocs, md5, sha256, timestamp FROM scans ORDER BY timestamp ASC")
        except Exception as e:
            root.after(0, lambda: _ic_status.set(f"✗ DB error: {e}")); return
        from collections import defaultdict
        ioc_map = defaultdict(list)
        for row in rows:
            fname = os.path.basename(row[0] or "?")
            ts    = row[4] or ""
            try: ioc_dict = json.loads(row[1]) if row[1] else {}
            except: ioc_dict = {}
            md5    = row[2] or ""
            sha256 = row[3] or ""
            key_ts = f"{ts}|{fname}"
            if ioc_type in ("All","IPs"):
                for ip in ioc_dict.get("ips", []):
                    ioc_map[("IP", ip)].append(key_ts)
            if ioc_type in ("All","Domains"):
                for d in ioc_dict.get("domains", []):
                    ioc_map[("Domain", d)].append(key_ts)
            if ioc_type in ("All","URLs"):
                for u in ioc_dict.get("urls", []):
                    ioc_map[("URL", u)].append(key_ts)
            if ioc_type in ("All","Hashes"):
                if md5:    ioc_map[("MD5",    md5)].append(key_ts)
                if sha256: ioc_map[("SHA256", sha256)].append(key_ts)
        correlated = {k: v for k, v in ioc_map.items() if len(set(v)) >= min_sess}
        sorted_corr = sorted(correlated.items(), key=lambda x: -len(x[1]))
        def _upd():
            _ic_txt.config(state="normal"); _ic_txt.delete("1.0", tk.END)
            _ic_txt.insert(tk.END, f"IOC CORRELATION — {len(rows)} sessions scanned\n"
                           f"Found {len(correlated)} IOC(s) appearing in ≥{min_sess} sessions\n\n", "hdr")
            if not sorted_corr:
                _ic_txt.insert(tk.END, "No correlated IOCs found at this threshold.\n", "dim")
            for (typ, ioc), sessions in sorted_corr[:200]:
                uniq = list(dict.fromkeys(sessions))
                _ic_txt.insert(tk.END, f"  [{typ}] ", "dim")
                _ic_txt.insert(tk.END, f"{ioc}\n", "hit")
                _ic_txt.insert(tk.END, f"    Seen in ", "dim")
                _ic_txt.insert(tk.END, f"{len(uniq)}", "cnt")
                _ic_txt.insert(tk.END, " session(s):\n", "dim")
                for s in uniq[:5]:
                    _ic_txt.insert(tk.END, f"      {s}\n", "dim")
                if len(uniq) > 5:
                    _ic_txt.insert(tk.END, f"      ... and {len(uniq)-5} more\n", "dim")
                _ic_txt.insert(tk.END, "\n", "")
            _ic_txt.config(state="disabled")
            _ic_status.set(f"✓ {len(correlated)} correlated IOC(s) across {len(rows)} sessions")
        root.after(0, _upd)
    threading.Thread(target=_worker, daemon=True).start()
