def _ce_extract():
    path = _ce_path_sv.get().strip()
    if not path or not os.path.isfile(path):
        messagebox.showwarning("Config Extractor","Select a valid file first."); return
    _ce_status.set("⏳ Analyzing...")
    def _worker():
        import re as _re, base64 as _b64, struct as _st
        try:
            with open(path,"rb") as f: data = f.read()
        except Exception as e:
            root.after(0, lambda: _ce_status.set(f"✗ {e}")); return
        results = {}
        s = data.decode("latin-1","ignore")
        def _try_b64(v):
            try:
                padded = v + "=" * (-len(v) % 4)
                decoded = _b64.b64decode(padded).decode("utf-8","ignore").strip()
                if decoded and decoded.isprintable() and len(decoded) > 1: return decoded
            except Exception: pass
            return v
        agenttesla_patterns = [
            ("C2 Host",    _re.compile(r"(?:host|server|smtp[._-]?host)[\x00-\x20]*[:=][\x00-\x20]*([a-zA-Z0-9.\-]{4,80})", _re.I)),
            ("C2 Port",    _re.compile(r"(?:port|smtp[._-]?port)[\x00-\x20]*[:=][\x00-\x20]*(\d{2,5})", _re.I)),
            ("Username",   _re.compile(r"(?:username|from|sender)[\x00-\x20]*[:=][\x00-\x20]*([a-zA-Z0-9@._\-]{4,80})", _re.I)),
            ("Password",   _re.compile(r"(?:password|pass)[\x00-\x20]*[:=][\x00-\x20]*([^\x00-\x20]{4,64})", _re.I)),
            ("Mutex",      _re.compile(r"(?:mutex|mutexname)[\x00-\x20]*[:=][\x00-\x20]*([^\x00-\x20]{4,64})", _re.I)),
        ]
        asyncrat_patterns = [
            ("C2 Host",    _re.compile(r"Hosts\x00{1,4}([a-zA-Z0-9.\-]{4,80})", _re.I)),
            ("C2 Port",    _re.compile(r"Port\x00{1,4}(\d{2,5})", _re.I)),
            ("Mutex",      _re.compile(r"Mutex\x00{1,4}([^\x00]{4,64})")),
            ("Install Dir",_re.compile(r"InstallDir\x00{1,4}([^\x00]{2,64})")),
            ("Version",    _re.compile(r"Version\x00{1,4}([^\x00]{1,32})")),
            ("Pastebin",   _re.compile(r"(https?://pastebin\.com/[A-Za-z0-9]+)")),
        ]
        njrat_patterns = [
            ("C2 Host",    _re.compile(r"((?:\d{1,3}\.){3}\d{1,3}|[a-zA-Z0-9\-]+\.(?:tk|ml|ga|cf|gq|xyz|top|online|fun|info|biz|site|net|org|com))", _re.I)),
            ("C2 Port",    _re.compile(r"\|(\d{3,5})\|")),
            ("Version",    _re.compile(r"im523|kilerrat|njq8|H-Worm|njRat", _re.I)),
            ("Campaign",   _re.compile(r"MUTEX_([A-Za-z0-9_\-]{4,32})")),
        ]
        redline_patterns = [
            ("C2 Host",    _re.compile(r"Connection\x00{1,4}([a-zA-Z0-9.\-]{4,80}:\d{2,5})")),
            ("C2 Port",    _re.compile(r"<IP>([^<]{4,80})</IP>")),
            ("Campaign",   _re.compile(r"<ID>([^<]{1,64})</ID>")),
            ("Key",        _re.compile(r"<Key>([^<]{4,64})</Key>")),
        ]
        families = [
            ("AgentTesla", agenttesla_patterns, ["SMTP","EmailCredential","AgentTesla","Spy.Agent"]),
            ("AsyncRAT",   asyncrat_patterns,   ["AsyncRAT","AsyncClient","Async","asynrat"]),
            ("njRAT",      njrat_patterns,       ["njRat","njq8","H-Worm","kilerrat","im523"]),
            ("RedLine",    redline_patterns,     ["RedLine","Stealer","RecordBreaker"]),
        ]
        detected = []
        for family, patterns, markers in families:
            marker_hit = any(m.lower() in s.lower() for m in markers)
            found_fields = {}
            for fname2, pat in patterns:
                m = pat.search(s)
                if m:
                    val = m.group(1) if m.lastindex else m.group(0)
                    found_fields[fname2] = _try_b64(val.strip())
            if marker_hit or found_fields:
                detected.append((family, found_fields, marker_hit))
        def _upd():
            _ce_txt.config(state="normal"); _ce_txt.delete("1.0", tk.END)
            _ce_txt.insert(tk.END, f"CONFIG EXTRACTION — {os.path.basename(path)}\n\n", "hdr")
            if not detected:
                _ce_txt.insert(tk.END, "No known RAT config patterns detected.\n", "none")
            for family, fields, marker in detected:
                conf_lv = "✓ CONFIRMED" if marker else "~ POSSIBLE"
                _ce_txt.insert(tk.END, f"  [{conf_lv}] {family}\n", "hit" if marker else "dim")
                if fields:
                    for k, v in fields.items():
                        _ce_txt.insert(tk.END, f"      {k:<16}: ", "key")
                        _ce_txt.insert(tk.END, f"{v}\n", "val")
                else:
                    _ce_txt.insert(tk.END, "      Marker found but no fields extracted.\n", "dim")
                _ce_txt.insert(tk.END, "\n", "")
            _ce_txt.config(state="disabled")
            n = len(detected)
            _ce_status.set(f"✓ Done — {n} family match{'es' if n!=1 else ''} found")
        root.after(0, _upd)
    threading.Thread(target=_worker, daemon=True).start()
_ce_btn_f = tk.Frame(_ce_ctrl, bg=C["surface0"]); _ce_btn_f.pack(fill=tk.X, pady=(0,2))
