def _ta_lookup():
    ioc = _ta_ioc_sv.get().strip()
    if not ioc: messagebox.showwarning("Actor Lookup","Enter an IOC first."); return
    _ta_status.set("⏳ Querying...")
    import re as _re
    ioc_type = _ta_type_sv.get()
    if ioc_type == "Auto":
        if _re.match(r"^\d{1,3}(?:\.\d{1,3}){3}$", ioc): ioc_type = "IP"
        elif _re.match(r"^[0-9a-fA-F]{64}$", ioc): ioc_type = "SHA256"
        elif _re.match(r"^[0-9a-fA-F]{32}$", ioc): ioc_type = "MD5"
        else: ioc_type = "Domain"
    def _worker():
        import urllib.request, urllib.error
        results = []
        try:
            cfg = {}
            try:
                with open(os.path.join(BASE_DIR, "config.json"), "r") as f:
                    cfg = json.load(f)
            except Exception: pass
            otx_key   = cfg.get("otx_key","") or cfg.get("alienvault_key","")
            abuse_key = cfg.get("abuseipdb_key","")
            if otx_key:
                ep_map = {"IP":"IPv4","Domain":"domain","MD5":"file","SHA256":"file"}
                ep = ep_map.get(ioc_type,"domain")
                ioc_path = ioc if ioc_type != "MD5" else ioc
                url = f"https://otx.alienvault.com/api/v1/indicators/{ep}/{ioc_path}/general"
                req = urllib.request.Request(url, headers={"X-OTX-API-KEY": otx_key})
                try:
                    with urllib.request.urlopen(req, timeout=12) as r:
                        d = json.loads(r.read())
                    pulse_count = d.get("pulse_info",{}).get("count",0)
                    pulses = d.get("pulse_info",{}).get("pulses",[])
                    country = d.get("country_name","") or d.get("country","")
                    rep = d.get("reputation", None)
                    results.append(("OTX AlienVault", {
                        "Pulses": str(pulse_count),
                        "Country": country or "N/A",
                        "Reputation": str(rep) if rep is not None else "N/A",
                        "Campaigns": ", ".join(p.get("name","") for p in pulses[:5]) or "None",
                        "Tags": ", ".join(t for p in pulses[:3] for t in p.get("tags",[]))[:120] or "None",
                    }, pulse_count > 0))
                except urllib.error.HTTPError as he:
                    results.append(("OTX AlienVault", {"Error": f"HTTP {he.code}"}, False))
                except Exception as oe:
                    results.append(("OTX AlienVault", {"Error": str(oe)[:80]}, False))
            else:
                results.append(("OTX AlienVault", {"Status": "No API key configured (otx_key in config.json)"}, False))
            if ioc_type == "IP" and abuse_key:
                url2 = f"https://api.abuseipdb.com/api/v2/check?ipAddress={ioc}&maxAgeInDays=90"
                req2 = urllib.request.Request(url2, headers={"Key": abuse_key, "Accept": "application/json"})
                try:
                    with urllib.request.urlopen(req2, timeout=10) as r2:
                        d2 = json.loads(r2.read()).get("data",{})
                    score2 = d2.get("abuseConfidenceScore",0)
                    results.append(("AbuseIPDB", {
                        "Abuse Score": f"{score2}%",
                        "Total Reports": str(d2.get("totalReports",0)),
                        "Country": d2.get("countryCode","N/A"),
                        "ISP": d2.get("isp","N/A")[:60],
                        "Usage Type": d2.get("usageType","N/A"),
                    }, score2 > 25))
                except Exception as ae:
                    results.append(("AbuseIPDB", {"Error": str(ae)[:80]}, False))
            elif ioc_type == "IP" and not abuse_key:
                results.append(("AbuseIPDB", {"Status": "No API key configured (abuseipdb_key)"}, False))
        except Exception as e:
            results.append(("Error", {"Fatal": str(e)}, False))
        def _upd():
            _ta_txt.config(state="normal"); _ta_txt.delete("1.0", tk.END)
            _ta_txt.insert(tk.END, f"THREAT ACTOR LOOKUP  —  {ioc}  [{ioc_type}]\n\n", "hdr")
            any_hit = False
            for source, fields, is_hit in results:
                any_hit = any_hit or is_hit
                _ta_txt.insert(tk.END, f"  ◈ {source}\n", "hit" if is_hit else "key")
                for k, v in fields.items():
                    _ta_txt.insert(tk.END, f"    {k:<18}: ", "dim")
                    _ta_txt.insert(tk.END, f"{v}\n", "hit" if (is_hit and k in ("Pulses","Abuse Score","Campaigns")) else "val")
                _ta_txt.insert(tk.END, "\n", "")
            if not any_hit:
                _ta_txt.insert(tk.END, "✓ No threat actor associations found.\n", "ok")
            _ta_txt.config(state="disabled")
            _ta_status.set(f"✓ Done — {'KNOWN THREAT' if any_hit else 'clean/unknown'}")
        root.after(0, _upd)
    threading.Thread(target=_worker, daemon=True).start()
_ta_btn_f = tk.Frame(_ta_ctrl, bg=C["surface0"]); _ta_btn_f.pack(fill=tk.X, pady=(0,2))
_mkbtn(_ta_btn_f, "▶ Lookup", _ta_lookup, C["sapphire"])
_mkbtn(_ta_btn_f, "✕ Clear",
       lambda: (_ta_txt.config(state="normal"), _ta_txt.delete("1.0",tk.END),
                _ta_txt.config(state="disabled"), _ta_status.set("")), C["surface2"], C["text"])

