_ptree_tree.tag_configure("SUSP", foreground=C["red"])
_ptree_tree.tag_configure("WARN", foreground=C["yellow"])
_ptree_tree.tag_configure("NORM", foreground=C["text"])
_SUSP_NAMES = {"cmd.exe","power" + "shell.exe","wscript.exe","cscript.exe","mshta.exe",
               "regsvr32.exe","rundll32.exe","schtasks.exe","wmic.exe","bitsadmin.exe"}
def _ptree_refresh():
    for r in _ptree_tree.get_children(): _ptree_tree.delete(r)
    if _psutil is None:
        _ptree_tree.insert("","end",values=("—","—","psutil not installed","—","—","—")); return
    flt = _ptree_flt_v.get().strip().lower()
    susp_only = _ptree_susp_v.get()
    def _do():
        try:
            procs = {}
            for p in _psutil.process_iter(["pid","ppid","name","cpu_percent","memory_info","cmdline"]):
                try:
                    info = p.info
                    cmd = " ".join(info.get("cmdline") or [])[:80] if info.get("cmdline") else ""
                    mem = round(info["memory_info"].rss/1048576,1) if info.get("memory_info") else 0
                    is_susp = (info.get("name","").lower() in _SUSP_NAMES or
                               any(kw in cmd.lower() for kw in ["-enc","-encoded","downloadstring","invoke-expression","bypass","hidden"]))
                    procs[info["pid"]] = {"pid":info["pid"],"ppid":info.get("ppid",0),
                                          "name":info.get("name","?"),"cpu":info.get("cpu_percent",0),
                                          "mem":mem,"cmd":cmd,"susp":is_susp}
                except (_psutil.NoSuchProcess, _psutil.AccessDenied): pass
            children = {}
            for pid, p in procs.items():
                ppid = p["ppid"]
                if ppid not in children: children[ppid] = []
                children[ppid].append(pid)
            def _insert_tree(parent_iid, pid, depth=0):
                p = procs.get(pid)
                if p is None: return
                nm = p["name"]
                if flt and flt not in nm.lower() and flt not in p["cmd"].lower(): pass
                else:
                    if susp_only and not p["susp"]: pass
                    else:
                        tag = "SUSP" if p["susp"] else "NORM"
                        indent = "  " * depth
                        iid = f"proc_{pid}"
                        try:
                            _ptree_tree.insert(parent_iid, "end", iid=iid,
                                               text=f"{indent}⬡ {nm}",
                                               values=(p["pid"],p["ppid"],nm,
                                                       f"{p['cpu']:.1f}",f"{p['mem']:.1f}",p["cmd"]),
                                               tags=(tag,))
                            for child_pid in sorted(children.get(pid,[])):
                                _insert_tree(iid, child_pid, depth+1)
                        except tk.TclError: pass
            def _show():
                for r in _ptree_tree.get_children(): _ptree_tree.delete(r)
                roots = [pid for pid in procs if procs[pid]["ppid"] not in procs or procs[pid]["ppid"]==0]
                for rpid in sorted(roots):
                    _insert_tree("", rpid, 0)
            root.after(0, _show)
        except Exception as e:
            root.after(0, lambda: _ptree_tree.insert("","end",values=("—","—",f"Error: {e}","—","—","—")))
    threading.Thread(target=_do, daemon=True).start()
_mkbtn(_ptree_ctrl,"🔄 Refresh",lambda:_ptree_refresh(),C["teal"])
_mkbtn(_ptree_ctrl,"▶ Expand All",lambda: [_ptree_tree.item(i,open=True) for i in _ptree_tree.get_children()],C["surface2"],C["text"])
