def _lol_on_select(evt=None):
    sel = _lol_tree.selection()
    if not sel or not _lol_db[0]: return
    name = _lol_tree.item(sel[0])["values"][0]
    for entry in _lol_db[0]:
        n = (entry.get("Name") or entry.get("name","")).lower()
        if n == str(name).lower():
            cmds = entry.get("Commands",[]) or []
            desc = entry.get("Description","")
            cmd_str = "  |  ".join(c.get("Command","")[:80] for c in cmds[:3] if isinstance(c,dict))
            _lol_detail_sv.set(f"{desc}\n  Example: {cmd_str[:200]}" if cmd_str else desc[:200])
            slug = str(name).lower().replace(".exe","").replace(".","")
            _lol_link_sv.set(f"https://lolbas-project.github.io/#{slug}")
            break
_lol_tree.bind("<<TreeviewSelect>>", _lol_on_select)

def _lol_render(db, flt=""):
    _lol_tree.delete(*_lol_tree.get_children())
    flt = flt.strip().lower()
    for entry in (db or []):
        name = entry.get("Name") or entry.get("name","")
        typ  = entry.get("Type","")
        desc = (entry.get("Description","") or "")[:120]
        if flt and flt not in name.lower() and flt not in desc.lower(): continue
        _lol_tree.insert("", "end", values=(name, typ, desc))

def _lol_fetch():
    _lol_status_sv.set("Fetching LOLBAS database…")
    def _do():
        try:
            import urllib.request as _ur2
            url = "https://lolbas-project.github.io/api/lolbas.json"
            with _ur2.urlopen(_ur2.Request(url, headers={"User-Agent":"V0RTEX/1.0"}), timeout=15) as r:
                raw = r.read().decode("utf-8","replace")
            import json as _jl
            db = _jl.loads(raw)
            _lol_db[0] = db
            root.after(0, lambda: _lol_status_sv.set(f"DB loaded — {len(db)} entries"))
            root.after(0, lambda: _lol_render(db, _lol_flt_v.get()))
        except Exception as _le:
            root.after(0, lambda: _lol_status_sv.set(f"Fetch failed: {_le}"))
    threading.Thread(target=_do, daemon=True).start()

_lol_flt_v.trace_add("write", lambda *_: _lol_render(_lol_db[0], _lol_flt_v.get()) if _lol_db[0] else None)
_mkbtn(_lol_db_ctrl, "🔄 Fetch DB", _lol_fetch, C["flamingo"], C["base"])

