def _lol_live_scan():
    if not _lol_db[0]:
        _lol_live_status_sv.set("⚠ Fetch LOLBAS DB first (DATABASE tab)"); return
    if not _psutil:
        _lol_live_status_sv.set("⚠ psutil not available"); return
    _lol_live_status_sv.set("Scanning…")
    def _do():
        lol_names = {(e.get("Name") or e.get("name","")).lower() for e in (_lol_db[0] or [])}
        rows = []
        try:
            for proc in _psutil.process_iter(["pid","name","exe"]):
                try:
                    pid  = proc.info["pid"]
                    name = proc.info.get("name","") or ""
                    exe  = proc.info.get("exe","") or ""
                    match = ""
                    nm_lo = name.lower()
                    if nm_lo in lol_names:
                        match = name
                    rows.append((pid, name, exe[:80], match, bool(match)))
                except Exception: pass
        except Exception: pass
        hits = sum(1 for r in rows if r[4])
        def _show():
            _lol_live_tree.delete(*_lol_live_tree.get_children())
            for pid, name, exe, match, is_hit in rows:
                tag = "HIT" if is_hit else "OK"
                _lol_live_tree.insert("", "end", values=(pid, name, exe, match or "—"), tags=(tag,))
            _lol_live_status_sv.set(f"  {len(rows)} processes scanned — {hits} LOLBAS match(es)")
        root.after(0, _show)
