def _sgt_write(msg, tag="MISS"):
    _sgt_out.config(state="normal")
    _sgt_out.insert(tk.END, msg + "\n", tag)
    _sgt_out.see(tk.END)
    _sgt_out.config(state="disabled")

def _sgt_run():
    _sgt_out.config(state="normal"); _sgt_out.delete("1.0", tk.END); _sgt_out.config(state="disabled")
    raw_rule = _sig_path_v.get().strip()
    if not raw_rule or not os.path.isfile(raw_rule):
        _sgt_result_sv.set("⚠ Load a Sigma rule first (use Open button above)")
        return
    try:
        import yaml as _yaml2
        with open(raw_rule, "r", encoding="utf-8") as _rf: rule = _yaml2.safe_load(_rf.read())
    except ImportError:
        _sgt_result_sv.set("⚠ PyYAML not installed"); return
    except Exception as _e:
        _sgt_result_sv.set(f"⚠ Rule parse error: {_e}"); return
    try:
        event = json.loads(_sgt_json_txt.get("1.0", tk.END).strip())
    except Exception as _e:
        _sgt_result_sv.set(f"⚠ Invalid JSON: {_e}"); return

    _sgt_write(f"Rule  : {rule.get('title','?')}", "HEAD")
    _sgt_write(f"Level : {rule.get('level','?')}  |  Status: {rule.get('status','?')}", "HEAD")
    _sgt_write("", "MISS")

    detection = rule.get("detection", {})
    condition = str(detection.get("condition", "")).strip().lower()
    _sgt_write(f"Condition : {condition}", "HEAD")
    _sgt_write("", "MISS")

    hits = []
    misses = []
    for sel_key, sel_val in detection.items():
        if sel_key == "condition": continue
        if not isinstance(sel_val, dict): continue
        _sgt_write(f"  Selection [{sel_key}]:", "HEAD")
        sel_matched = True
        for field, patterns in sel_val.items():
            field_clean = field.split("|")[0]
            modifier = field.split("|")[1].lower() if "|" in field else "exact"
            event_val = str(event.get(field_clean, event.get(field_clean.lower(), "")))
            pat_list = patterns if isinstance(patterns, list) else [patterns]
            field_hit = False
            for pat in pat_list:
                pat_s = str(pat)
                if modifier in ("contains", "contains|all"):
                    matched = pat_s.lower() in event_val.lower()
                elif modifier == "startswith":
                    matched = event_val.lower().startswith(pat_s.lower())
                elif modifier == "endswith":
                    matched = event_val.lower().endswith(pat_s.lower())
                elif modifier == "re":
                    import re as _re2
                    matched = bool(_re2.search(pat_s, event_val, _re2.IGNORECASE))
                else:
                    matched = event_val.lower() == pat_s.lower() or pat_s == "*"
                if matched:
                    field_hit = True
                    _sgt_write(f"    ✓ {field_clean}: '{event_val}' matched '{pat_s}'", "OK")
                    break
            if not field_hit:
                sel_matched = False
                _sgt_write(f"    ✗ {field_clean}: '{event_val}' — no match in {pat_list[:3]}", "MISS")
        if sel_matched:
            hits.append(sel_key)
        else:
            misses.append(sel_key)

    _sgt_write("", "MISS")
    all_hit = len(hits) > 0 and ("all of them" in condition or all(k in hits for k in detection if k != "condition"))
    any_hit = len(hits) > 0
    final_match = all_hit if "all of" in condition or "and" in condition else any_hit

    if final_match:
        _sgt_result_sv.set(f"🔴  HIT — Rule matched ({len(hits)}/{len(hits)+len(misses)} selections)")
        _sgt_write(f"  ══ RULE MATCHED ══  selections hit: {hits}", "HIT")
    else:
        _sgt_result_sv.set(f"🟢  MISS — Rule did not match ({len(misses)} selections failed)")
        _sgt_write(f"  ══ NO MATCH ══  selections missed: {misses}", "MISS")

_mkbtn(_sgt_ctrl, "▶ Run Test", _sgt_run, C["blue"])
