def _crh_display(data):
    import zlib
    verify = _crh_verify_v.get().strip().lower()
    algos = [("MD5","md5",C["red"]),("SHA-1","sha1",C["peach"]),
             ("SHA-256","sha256",C["green"]),("SHA-512","sha512",C["blue"])]
    _crh_out.config(state="normal"); _crh_out.delete("1.0",tk.END)
    for name, algo, col in algos:
        try:
            h = hashlib.new(algo, data).hexdigest()
            _crh_out.tag_configure(algo,      foreground=col)
            _crh_out.tag_configure(algo+"L",  foreground=C["overlay0"])
            _crh_out.insert(tk.END, f"  {name:<12}", algo+"L")
            _crh_out.insert(tk.END, h, algo)
            if verify and h.lower() == verify:
                _crh_out.tag_configure("MATCH", foreground=C["green"])
                _crh_out.insert(tk.END, "  ✓ MATCH","MATCH")
            _crh_out.insert(tk.END, "\n")
        except Exception: pass
    try:
        crc = zlib.crc32(data) & 0xFFFFFFFF
        _crh_out.tag_configure("crcL", foreground=C["overlay0"])
        _crh_out.tag_configure("crcV", foreground=C["yellow"])
        _crh_out.insert(tk.END, "  CRC32       ","crcL")
        _crh_out.insert(tk.END, f"{crc:08x}\n","crcV")
    except: pass
    _crh_out.config(state="disabled")
def _crh_run_file():
    p = _crh_path_v.get().strip()
    if not p or not os.path.isfile(p):
        messagebox.showwarning("Hash","No valid file."); return
    def _do():
        try:
            with open(p,"rb") as f: data = f.read()
            root.after(0, lambda: _crh_display(data))
        except Exception as e:
            root.after(0, lambda: messagebox.showerror("Hash",str(e)))
    threading.Thread(target=_do, daemon=True).start()
def _crh_run_text():
    t = _crh_txt.get("1.0",tk.END).rstrip("\n")
    if not t: return
    _crh_display(t.encode("utf-8"))

