def _vig_cipher(plaintext, key, encrypt=True):
    key_upper = key.upper(); result = []; ki = 0
    for char in plaintext:
        if char.isalpha():
            base  = ord('A') if char.isupper() else ord('a')
            shift = ord(key_upper[ki % len(key_upper)]) - ord('A')
            if not encrypt: shift = -shift
            result.append(chr((ord(char) - base + shift) % 26 + base))
            ki += 1
        else:
            result.append(char)
    return "".join(result)
def _vig_enc():
    t = _vig_inp.get("1.0",tk.END).rstrip("\n")
    k = _vig_key_v.get().strip()
    if not t or not k or not k.isalpha():
        messagebox.showwarning("Vigenere","Key must be alphabetic."); return
    r = _vig_cipher(t, k, True)
    _vig_out.config(state="normal"); _vig_out.delete("1.0",tk.END)
    _vig_out.insert(tk.END, r); _vig_out.config(state="disabled")
def _vig_dec():
    t = _vig_inp.get("1.0",tk.END).rstrip("\n")
    k = _vig_key_v.get().strip()
    if not t or not k or not k.isalpha():
        messagebox.showwarning("Vigenere","Key must be alphabetic."); return
    r = _vig_cipher(t, k, False)
    _vig_out.config(state="normal"); _vig_out.delete("1.0",tk.END)
    _vig_out.insert(tk.END, r); _vig_out.config(state="disabled")
