def _unc_run():
    import urllib.parse as _ulp, html as _html_lib, unicodedata as _ucd
    txt = _unc_inp.get("1.0",tk.END).rstrip("\n")
    m = _unc_mode.get()
    try:
        if m == "Code Points":
            lines = []
            for c in txt[:200]:
                try: name = _ucd.name(c)
                except: name = "?"
                lines.append(f"  U+{ord(c):04X}  {repr(c):<10}  {name}")
            r = "\n".join(lines)
        elif m == "URL Encode":  r = _ulp.quote(txt, safe="")
        elif m == "URL Decode":  r = _ulp.unquote(txt)
        elif m == "HTML Entities": r = _html_lib.escape(txt)
        else:
            try:
                import chardet as _cd
                enc = _cd.detect(txt.encode("raw_unicode_escape"))
                r = (f"Detected encoding: {enc.get('encoding','?')}\n"
                     f"Confidence:        {enc.get('confidence',0):.0%}")
            except ImportError:
                r = "chardet not installed.\npip install chardet"
    except Exception as e: r = f"Error: {e}"
    _unc_out.config(state="normal"); _unc_out.delete("1.0",tk.END)
    _unc_out.insert(tk.END, r); _unc_out.config(state="disabled")
_mkbtn(_unc_btnrow,"⚡ Run",lambda:_unc_run(),C["sapphire"])
