def _pcap_push_to_ioc_extract():
    ips_list     = sorted(_pcap_extracted_iocs["ips"])
    domains_list = sorted(_pcap_extracted_iocs["domains"])
    urls_list    = sorted(_pcap_extracted_iocs["urls"])
    total = len(ips_list) + len(domains_list) + len(urls_list)
    if not total:
        messagebox.showinfo("PCAP->IOC", "No IOCs extracted yet — run analysis first."); return
    def _do():
        _ioc_ips.delete(0, tk.END)
        for ip in ips_list:     _ioc_ips.insert(tk.END, f"  {ip}")
        _ioc_ips_cnt.set(str(len(ips_list)))
        _ioc_domains.delete(0, tk.END)
        for d in domains_list:  _ioc_domains.insert(tk.END, f"  {d}")
        _ioc_dom_cnt.set(str(len(domains_list)))
        _ioc_urls.delete(0, tk.END)
        for u in urls_list:     _ioc_urls.insert(tk.END, f"  {u}")
        _ioc_url_cnt.set(str(len(urls_list)))
        _ioc_fname.set(f"PCAP: {os.path.basename(_pcap_path_v.get())}")
        try: _nb.select(_tab_ioc_host)
        except Exception: pass
    root.after(0, _do)
    messagebox.showinfo("PCAP->IOC",
        f"Pushed {len(ips_list)} IPs, {len(domains_list)} domains, {len(urls_list)} URLs to IOC EXTRACT tab.")

