def _nst_log_add(msg, tag="DIM"):
    import datetime as _nd9
    ts = _nd9.datetime.now().strftime("%H:%M:%S")
    def _d():
        _nst_log2.config(state="normal")
        _nst_log2.insert(tk.END, f"[{ts}] {msg}\n", tag)
