def _el_on_select(event):
    sel = _el_tree.selection()
    if not sel: return
    vals = _el_tree.item(sel[0], "values")
    _el_detail.config(state="normal"); _el_detail.delete("1.0", tk.END)
    _el_detail.insert(tk.END, f"Event ID: {vals[0]}  |  Level: {vals[1]}  |  Source: {vals[2]}  |  Time: {vals[3]}\n\n", "hdr")
    _el_detail.insert(tk.END, vals[4] if len(vals) > 4 else "")
    _el_detail.config(state="disabled")
_el_tree.bind("<<TreeviewSelect>>", _el_on_select)
_EL_SUSP_IDS = {4624,4625,4648,4672,4688,4698,4702,4719,4720,4726,4732,4756,
                7045,1102,7034,7036,4657,4663,4670,4697}
def _el_query():
    _el_status.set("⏳ Querying event log...")
    log   = _el_log_sv.get()
    evtid = _el_evtid_sv.get().strip()
    count = _el_count_sv.get()
    level = _el_level_sv.get()
    level_map = {"Critical":"1","Error":"2","Warning":"3","Information":"4"}
    cmd = f'wevtutil qe "{log}" /c:{int(count)} /rd:true /f:text'
    if evtid:
        try:
            _eid = int(evtid)
            cmd = f'wevtutil qe "{log}" /q:"*[System[(EventID={_eid})]]" /c:{int(count)} /rd:true /f:text'
        except Exception:
            pass
    def _done(resp, err):
        out = ""
        if err is not None:
            out = f"Error: {err}"
        else:
            try:
                if isinstance(resp, dict) and resp.get("ok") and isinstance(resp.get("result"), dict):
                    rj = resp["result"]
                    out = (str(rj.get("stdout", "")) or "").strip()
                    if not out:
                        out = (str(rj.get("stderr", "")) or "").strip()
                else:
                    out = str((resp or {}).get("error", "Admin Manager offline"))
            except Exception:
                out = "Admin Manager error"
        events = []
        try:
            cur = {"id":"", "level":"", "source":"", "time":"", "msg":""}
            msg_lines = []
            for ln in (out or "").splitlines():
                s = ln.strip()
                if s.startswith("Event["):
                    if cur.get("id") or msg_lines:
                        cur["msg"] = " ".join(msg_lines)[:300]
                        events.append(cur)
                    cur = {"id":"", "level":"", "source":"", "time":"", "msg":""}
                    msg_lines = []
                    continue
                if s.lower().startswith("event id:"):
                    cur["id"] = s.split(":",1)[-1].strip()
                elif s.lower().startswith("level:"):
                    cur["level"] = s.split(":",1)[-1].strip()
                elif s.lower().startswith("provider name:"):
                    cur["source"] = s.split(":",1)[-1].strip()[:60]
                elif s.lower().startswith("date:"):
                    cur["time"] = s.split(":",1)[-1].strip()
                elif s and not any(s.lower().startswith(x) for x in ("log name:", "task:", "opcode:", "keywords:", "computer:", "description:")):
                    if len(msg_lines) < 6:
                        msg_lines.append(s.replace("\t"," ").replace("\r"," "))
            if cur.get("id") or msg_lines:
                cur["msg"] = " ".join(msg_lines)[:300]
                events.append(cur)
        except Exception:
            events = [{"id":"ERR","level":"Error","source":"Parse","time":"","msg":"Failed to parse wevtutil output"}]
        if not events:
            events = [{"id":"ERR","level":"Warning","source":"System","time":"","msg":(out or "No events returned.")[:200]}]
        def _upd():
            for row in _el_tree.get_children(): _el_tree.delete(row)
            for ev in events:
                lv = (ev.get("level","") or "").lower()
                tag = "critical" if "critical" in lv else ("error" if "error" in lv else ("warning" if "warning" in lv else "info"))
                try: eid_int = int(ev.get("id") or 0)
                except: eid_int = 0
                if eid_int in _EL_SUSP_IDS: tag = "error"
                _el_tree.insert("", tk.END, values=(ev.get("id",""), ev.get("level",""), ev.get("source",""), ev.get("time",""), ev.get("msg","")), tags=(tag,))
            _el_status.set(f"✓ {len(events)} event(s) — {log}")
        root.after(0, _upd)
    if level in level_map:
        pass
    _admin_run_cmd_safe(f"Event Log — {log}", cmd, timeout_s=35, danger_action_id="EXEC", done_fn=_done)
