def _ct_query():
    domain = _ct_domain_sv.get().strip()
    for pfx in ("https://","http://"):
        if domain.startswith(pfx): domain = domain[len(pfx):]
    domain = domain.split("/")[0].strip()
    if not domain: messagebox.showwarning("Cert CT","Enter a domain first."); return
    _ct_status.set("⏳ Querying crt.sh...")
    def _worker():
        import urllib.request, urllib.error, time as _t
        certs = None
        last_err = ""
        for attempt in range(3):
            try:
                url = f"https://crt.sh/?q={domain}&output=json"
                req = urllib.request.Request(url, headers={"User-Agent":"Mozilla/5.0 V0RTEX/1.0"})
                with urllib.request.urlopen(req, timeout=18) as r:
                    raw = r.read()
                certs = json.loads(raw)
                last_err = ""
                break
            except urllib.error.HTTPError as he:
                last_err = f"HTTP {he.code} ({he.reason}) — crt.sh server error, try again later."
                if he.code in (502, 503, 504): _t.sleep(2)
                else: break
            except urllib.error.URLError as ue:
                last_err = f"Network error: {ue.reason}"
                break
            except json.JSONDecodeError:
                last_err = "crt.sh returned non-JSON (may be rate-limited or down)."
                break
            except Exception as e:
                last_err = str(e)[:120]
                break
        if certs is None:
            root.after(0, lambda: _ct_status.set(f"✗ {last_err}"))
            root.after(0, lambda: (_ct_txt.config(state="normal"),
                                    _ct_txt.delete("1.0", tk.END),
                                    _ct_txt.insert(tk.END, f"Query failed: {last_err}\n\ncrt.sh sometimes returns 502 Bad Gateway under high load.\nWait a few seconds and try again.\n", "dim"),
                                    _ct_txt.config(state="disabled")))
            return
        seen = set()
        unique_certs = []
        for c in certs:
            key = c.get("serial_number","") or str(c.get("id",""))
            if key not in seen:
                seen.add(key)
                unique_certs.append(c)
        unique_certs.sort(key=lambda x: x.get("not_before",""), reverse=True)
        def _upd():
            _ct_txt.config(state="normal"); _ct_txt.delete("1.0", tk.END)
            _ct_txt.insert(tk.END, f"CERTIFICATE TRANSPARENCY — {domain}\n{len(unique_certs)} unique cert(s)\n\n", "hdr")
            for c in unique_certs[:100]:
                cn   = c.get("common_name","?")
                name = c.get("name_value","").replace("\n"," ")
                issuer = c.get("issuer_name","?")[:60]
                nb   = c.get("not_before","?")[:10]
                na   = c.get("not_after","?")[:10]
                is_wild = cn.startswith("*") or name.startswith("*")
                _ct_txt.insert(tk.END, f"  {'⚠ ' if is_wild else '  '}{cn}\n", "wild" if is_wild else "hit")
                _ct_txt.insert(tk.END, f"    SANs   : {name[:100]}\n", "val")
                _ct_txt.insert(tk.END, f"    Issuer : {issuer}\n", "dim")
                _ct_txt.insert(tk.END, f"    Valid  : {nb} -> {na}\n\n", "dim")
            if len(unique_certs) > 100:
                _ct_txt.insert(tk.END, f"  ... and {len(unique_certs)-100} more.\n", "dim")
            _ct_txt.config(state="disabled")
            wilds = sum(1 for c in unique_certs if c.get("common_name","").startswith("*"))
            _ct_status.set(f"✓ {len(unique_certs)} cert(s) — {wilds} wildcard(s)")
        root.after(0, _upd)
    threading.Thread(target=_worker, daemon=True).start()
