_usn_txt.tag_configure("mod",  foreground=C["yellow"])
_usn_txt.tag_configure("dim",  foreground=C["overlay0"])
_SUSP_USN_EXT = {".exe",".dll",".bat",".ps1",".vbs",".js",".hta",".tmp",".scr",".pif",".com"}
def _usn_read():
    _usn_status.set("⏳ Reading recent file activity...")
    drive  = _usn_drive_sv.get().strip() or "C:"
    filt   = _usn_filter_sv.get().strip().lower()
    def _worker():
        entries = []
        raw_err = ""
        try:
            import datetime as _dt_usn
            cutoff = time.time() - (7 * 24 * 3600)
            letter = drive.rstrip(":\\").upper()
            base_paths = [
                f"{letter}:\\Windows\\Temp",
                f"{letter}:\\ProgramData",
                os.environ.get("TEMP", ""),
                os.path.join(os.environ.get("USERPROFILE", ""), "Desktop"),
                os.path.join(os.environ.get("USERPROFILE", ""), "Downloads"),
                os.environ.get("APPDATA", ""),
                os.environ.get("LOCALAPPDATA", ""),
            ]
            base_paths = [p for p in base_paths if p and os.path.isdir(p)]
            def _walk_depth(root_dir: str, max_depth: int = 4):
                root_dir = os.path.abspath(root_dir)
                root_parts = root_dir.rstrip("\\/").split(os.sep)
                for rt, dirs, files in os.walk(root_dir):
                    try:
                        parts = rt.rstrip("\\/").split(os.sep)
                        depth = max(0, len(parts) - len(root_parts))
                        if depth >= max_depth:
                            dirs[:] = []
                    except Exception:
                        pass
                    yield rt, files
            for bp in base_paths:
                for rt, files in _walk_depth(bp, 4):
                    for fn in files:
                        try:
                            fp = os.path.join(rt, fn)
                            mt = os.path.getmtime(fp)
                            if mt < cutoff:
                                continue
                            try:
                                ct = os.path.getctime(fp)
                            except Exception:
                                ct = 0
                            reason = "CREATE" if (ct and ct >= cutoff) else "MODIFY"
                            entries.append({
                                "file_name": fn,
                                "full_path": fp,
                                "time_stamp": _dt_usn.datetime.fromtimestamp(mt).strftime("%Y-%m-%d %H:%M:%S"),
                                "reason": reason,
                            })
                        except Exception:
                            pass
            entries.sort(key=lambda e: e.get("time_stamp",""), reverse=True)
            entries = entries[:400]
        except Exception as e:
            raw_err = f"Error: {e}"
        if filt:
            entries = [e for e in entries if filt in (e.get("file_name","") + e.get("full_path","")).lower()]
        def _upd():
            _usn_txt.config(state="normal"); _usn_txt.delete("1.0", tk.END)
            _usn_txt.insert(tk.END, f"RECENT FILE ACTIVITY — {drive}  last 7 days  ({len(entries)} entries)\n\n", "hdr")
            if not entries:
                _usn_txt.insert(tk.END, raw_err + "\n" if raw_err else "No recent file activity found.\n", "dim")
            else:
                _usn_txt.insert(tk.END, f"  {'TIME':<22}  {'CHANGE':<8}  {'FILE'}\n", "hdr")
                _usn_txt.insert(tk.END, "  " + "─"*80 + "\n", "dim")
                for e in entries:
                    fname2  = e.get("file_name","?") or "?"
                    reason  = e.get("reason","MODIFY")
                    ts      = e.get("time_stamp","")
                    fpath   = e.get("full_path","")
                    ext     = os.path.splitext(fname2)[1].lower()
                    is_del  = "delete" in reason.lower()
                    is_new  = "create" in reason.lower()
                    is_susp = ext in _SUSP_USN_EXT
                    tag = "del" if is_del else ("new" if is_new else "mod")
                    prefix = "⚠ " if is_susp else "  "
                    _usn_txt.insert(tk.END, f"{prefix}{ts:<22}  {reason:<8}  {fname2}\n", tag)
                    if fpath and fpath != fname2:
                        _usn_txt.insert(tk.END, f"    {fpath}\n", "dim")
            _usn_txt.config(state="disabled")
            _usn_status.set(f"✓ {len(entries)} entries — last 7 days")
        root.after(0, _upd)
    threading.Thread(target=_worker, daemon=True).start()
