_MAGIC_SIGS = {
    "MZ (PE)":   bytes([0x4d,0x5a]),
    "ELF":       bytes([0x7f,0x45,0x4c,0x46]),
    "PDF":       b"%PDF",
    "ZIP":       bytes([0x50,0x4b,0x03,0x04]),
    "GZIP":      bytes([0x1f,0x8b,0x08]),
    "RAR":       b"Rar!",
    "7-ZIP":     bytes([0x37,0x7a,0xbc,0xaf]),
    "PNG":       bytes([0x89,0x50,0x4e,0x47]),
    "JPEG":      bytes([0xff,0xd8,0xff]),
    "OLE2":      bytes([0xd0,0xcf,0x11,0xe0]),
}
def _bpan_run():
    p = _bpan_file_v.get().strip()
    pat_s = _bpan_pat_v.get().strip()
    if not p or not os.path.isfile(p):
        messagebox.showwarning("BinPat","No file selected."); return
    _bpan_out.config(state="normal"); _bpan_out.delete("1.0",tk.END); _bpan_out.config(state="disabled")
    def _do():
        try:
            with open(p,"rb") as f: data = f.read()
            hits = []
            if pat_s:
                needle = bytes.fromhex(pat_s.replace(" ","")) if _bpan_is_hex.get() else pat_s.encode("utf-8")
                off = 0
                while True:
                    idx = data.find(needle, off)
                    if idx == -1: break
                    hits.append((idx, needle, "USER PATTERN")); off = idx+1
                    if len(hits) >= 500: break
            else:
                for name, sig in _MAGIC_SIGS.items():
                    off = 0
                    while True:
                        idx = data.find(sig, off)
                        if idx == -1: break
                        hits.append((idx, sig, name)); off = idx+1
            def _show():
                _bpan_out.config(state="normal")
                _bpan_out.insert(tk.END, f"  File: {os.path.basename(p)}  ({len(data):,} bytes)\n","HEAD")
                _bpan_out.insert(tk.END, f"  Hits: {len(hits)}\n\n","HEAD")
                for off2, needle2, label in hits[:300]:
                    ctx = data[off2:off2+16].hex()
                    _bpan_out.insert(tk.END, f"  @0x{off2:08x}  [{label}]  ","CTX")
                    _bpan_out.insert(tk.END, ctx+"\n","HIT")
                _bpan_out.config(state="disabled")
            root.after(0, _show)
        except Exception as e:
            root.after(0, lambda: (_bpan_out.config(state="normal"),
                                   _bpan_out.insert(tk.END,f"  Error: {e}\n"),
                                   _bpan_out.config(state="disabled")))
    threading.Thread(target=_do, daemon=True).start()
_mkbtn(_bpan_prow,"🔍 Search",lambda:_bpan_run(),C["red"])
_mkbtn(_bpan_prow,"🔍 Magic Sigs",lambda:(_bpan_pat_v.set(""),_bpan_run()),C["surface2"],C["text"])
_bpan_pat_e.bind("<Return>", lambda e: _bpan_run())


