_MATPLOTLIB_CANVAS_IDS = set()
try:
    for _mc in [_chart_canvas, _perf_canvas, _tl_canvas]:
        try: _MATPLOTLIB_CANVAS_IDS.add(str(_mc.get_tk_widget()))
        except Exception: pass
except Exception: pass


_tab_scroll_registry: dict = {}
_last_scrolled_widget = [None]

def _is_scrollable_canvas(widget) -> bool:
    try:
        if str(widget) in _MATPLOTLIB_CANVAS_IDS:
            return False
        if widget.winfo_class() != "Canvas":
            return False
        sc = str(widget.cget("yscrollcommand"))
        if sc and sc not in ("", "{}"):
            return True
        sr = widget.cget("scrollregion")
        if sr and str(sr) not in ("", "{}", "0 0 0 0"):
            return True
    except Exception:
        pass
    return False

def _find_scrollable_in_subtree(widget, depth=0) -> list:
    if depth > 12:
        return []
    results = []
    try:
        cls = widget.winfo_class()
        if cls in ("Text", "Listbox"):
            if widget.winfo_viewable():
                results.append(widget)
            return results
        elif cls == "Canvas" and _is_scrollable_canvas(widget):
            if widget.winfo_viewable():
                results.append(widget)
            return results
        elif cls == "TNotebook":
            try:
                sel = widget.select()
                if sel:
                    child_frame = widget.nametowidget(sel)
                    results.extend(_find_scrollable_in_subtree(child_frame, depth + 1))
            except Exception:
                pass
            return results
        for child in widget.winfo_children():
            results.extend(_find_scrollable_in_subtree(child, depth + 1))
    except Exception:
        pass
    return results

def _find_scrollable_ancestor(widget):
    w = widget
    for _ in range(25):
        try:
            cls = w.winfo_class()
            if cls in ("Text", "Listbox"):
                return w
            if cls == "Canvas" and _is_scrollable_canvas(w):
                return w
            w = w.nametowidget(w.winfo_parent())
        except Exception:
            break
    return None

def _get_visible_notebook_frame(nb):
    try:
        sel = nb.select()
        if not sel: return None
        return nb.nametowidget(sel)
    except Exception:
        return None

def _find_visible_scrollable(widget, depth=0):
    if depth > 12:
        return []
    results = []
    try:
        cls = widget.winfo_class()
        if cls == "TNotebook":
            visible = _get_visible_notebook_frame(widget)
            if visible:
                return _find_visible_scrollable(visible, depth + 1)
            return []
        if cls in ("Text", "Listbox"):
            try:
                if widget.winfo_viewable():
                    results.append(widget)
            except Exception:
                results.append(widget)
            return results
        if cls == "Canvas" and _is_scrollable_canvas(widget):
            try:
                if widget.winfo_viewable():
                    results.append(widget)
            except Exception:
                results.append(widget)
            return results
        for child in widget.winfo_children():
            results.extend(_find_visible_scrollable(child, depth + 1))
    except Exception:
        pass
    return results

def _get_tab_scrollable():
    try:
        tab_idx = _nb.index(_nb.select())
        cached  = _tab_scroll_registry.get(tab_idx)
        if cached:
            try:
                if cached.winfo_viewable():
                    return cached
            except Exception:
                pass
            _tab_scroll_registry.pop(tab_idx, None)

        tab_frame = _get_visible_notebook_frame(_nb)
        if not tab_frame:
            return None
        candidates = _find_visible_scrollable(tab_frame)
        if candidates:
            texts    = [w for w in candidates if w.winfo_class() == "Text"]
            canvases = [w for w in candidates if w.winfo_class() == "Canvas"]
            best = texts[0] if texts else (canvases[0] if canvases else candidates[0])
            _tab_scroll_registry[tab_idx] = best
            return best
    except Exception:
        pass
    return None

def _global_scroll_handler(event):
    try:

        delta = 0
        if event.delta:
            delta = -1 if event.delta > 0 else 1
            units = max(1, abs(event.delta) // 120)
            delta *= units

        if not delta:
            return


        target = event.widget
        scrollable = None

        try:
            cls = target.winfo_class()
            if cls in ("Text", "Listbox"):
                scrollable = target
            elif cls == "Canvas" and _is_scrollable_canvas(target):
                scrollable = target
        except Exception:
            pass


        if not scrollable:
            scrollable = _find_scrollable_ancestor(target)


        if not scrollable:
            scrollable = _get_tab_scrollable()


        if not scrollable:
            scrollable = _last_scrolled_widget[0]

        if not scrollable:
            return


        if scrollable.winfo_class() == "Canvas":
            try:
                bb = scrollable.bbox("all")
                if bb:
                    scrollable.configure(scrollregion=bb)
            except Exception:
                pass

            try:
                yv = scrollable.yview()
                if delta < 0 and yv[0] <= 0.001: return
                if delta > 0 and yv[1] >= 0.999: return
            except Exception:
                pass

        scrollable.yview_scroll(delta, "units")
        _last_scrolled_widget[0] = scrollable
    except Exception:
        pass

def _on_tab_changed(event=None):
    _tab_scroll_registry.clear()
    _last_scrolled_widget[0] = None

_nb.bind("<<NotebookTabChanged>>", _on_tab_changed)

root.bind_all("<MouseWheel>", _global_scroll_handler)

def _bind_sub_nbs(*_):
    _ALL_SUB_NBS = [
        "_dash_nb", "_ioc_nb", "_yara_nb", "_ym_nb", "_sb_host_nb", "_sb_nb",
        "_look_nb", "_lu_nb", "_lpipe_nb", "_proc_nb", "_net_nb", "_nt_nb",
        "_gs_nb", "_ap_nb", "_pd_nb", "_ap_syschk_nb", "_cr_nb", "_lol_nb",
        "_ai_nb", "_set_nb", "_grd_cfg_nb", "_chrt_nb", "_stg_nb",
        "_lpipe_nb",
    ]
    for _snb_name in _ALL_SUB_NBS:
        try:
            _snb = globals().get(_snb_name)
            if _snb and hasattr(_snb, "bind"):
                _snb.bind("<<NotebookTabChanged>>", _on_tab_changed, add=True)
        except Exception:
            pass
    _bind_scrollables_recursively(root)

root.after(500, _bind_sub_nbs)

def _bind_scrollables_recursively(widget, depth=0):
    if depth > 15:
        return
    try:
        cls = widget.winfo_class()
        if cls in ("Text", "Listbox"):
            widget.bind("<MouseWheel>", _global_scroll_handler, add=True)
        elif cls == "Canvas" and _is_scrollable_canvas(widget):
            widget.bind("<MouseWheel>", _global_scroll_handler, add=True)
        for child in widget.winfo_children():
            _bind_scrollables_recursively(child, depth + 1)
    except Exception:
        pass

def _refresh_all_canvas_scrollregions(widget=None):
    if widget is None:
        widget = root
    try:
        if widget.winfo_class() == "Canvas" and _is_scrollable_canvas(widget):
            try:
                bb = widget.bbox("all")
                if bb:
                    widget.configure(scrollregion=bb)
            except Exception:
                pass
        for child in widget.winfo_children():
            _refresh_all_canvas_scrollregions(child)
    except Exception:
        pass

root.after(600,  _refresh_all_canvas_scrollregions)
