_BK_FILE = os.path.join(BASE_DIR, "bookmarks.json")
def _bk_load_list():
    _bk_lb.delete(0, tk.END)
    try:
        bks = json.load(open(_BK_FILE, encoding="utf-8")) if os.path.isfile(_BK_FILE) else []
        for b in bks: _bk_lb.insert(tk.END, b.get("name","?"))
        return bks
    except Exception: return []
def _bk_save():
    name = _bk_name_sv.get().strip()
    if not name: messagebox.showwarning("Bookmarks","Enter a name first."); return
    try:
        bks = json.load(open(_BK_FILE, encoding="utf-8")) if os.path.isfile(_BK_FILE) else []
    except Exception: bks = []
    snap = {
        "name": name,
        "timestamp": time.strftime("%Y-%m-%d %H:%M:%S"),
        "notes": "",
    }
    try: snap["active_tab"] = str(_nb.tab(_nb.select(), "text")).strip()
    except Exception: pass
    try: snap["ioc_tab"] = str(_ioc_nb.tab(_ioc_nb.select(), "text")).strip()
    except Exception: pass
    try: snap["net_tab"] = str(_net_nb.tab(_net_nb.select(), "text")).strip()
    except Exception: pass
    bks = [b for b in bks if b.get("name") != name]
    bks.insert(0, snap)
    bks = bks[:50]
    with open(_BK_FILE, "w", encoding="utf-8") as f: json.dump(bks, f, indent=2)
    _bk_load_list(); _bk_status.set(f"✓ Saved bookmark: {name}")
    _sl(f"Bookmark saved: {name}", "EVT")
def _bk_restore():
    sel = _bk_lb.curselection()
    if not sel: messagebox.showwarning("Bookmarks","Select a bookmark first."); return
    bks = _bk_load_list()
    if not bks or sel[0] >= len(bks): return
    bk = bks[sel[0]]
    try:
        for tab_id in _nb.tabs():
            if str(_nb.tab(tab_id,"text")).strip() == bk.get("active_tab",""):
                _nb.select(tab_id); break
    except Exception: pass
    try:
        for tab_id in _ioc_nb.tabs():
            if str(_ioc_nb.tab(tab_id,"text")).strip() == bk.get("ioc_tab",""):
                _ioc_nb.select(tab_id); break
    except Exception: pass
    try:
        for tab_id in _net_nb.tabs():
            if str(_net_nb.tab(tab_id,"text")).strip() == bk.get("net_tab",""):
                _net_nb.select(tab_id); break
    except Exception: pass
    _bk_status.set(f"✓ Restored: {bk.get('name','')}  ({bk.get('timestamp','')})")
    _sl(f"Bookmark restored: {bk.get('name','')}", "EVT")
def _bk_delete():
    sel = _bk_lb.curselection()
    if not sel: return
    bks = _bk_load_list()
    if not bks or sel[0] >= len(bks): return
    name = bks[sel[0]].get("name","")
    if not messagebox.askyesno("Delete Bookmark", f"Delete bookmark '{name}'?"): return
    bks.pop(sel[0])
    with open(_BK_FILE, "w", encoding="utf-8") as f: json.dump(bks, f, indent=2)
    _bk_load_list(); _bk_status.set(f"✓ Deleted: {name}")
def _bk_on_select(event):
    sel = _bk_lb.curselection()
    if not sel: return
    bks = _bk_load_list()
    if not bks or sel[0] >= len(bks): return
    bk = bks[sel[0]]
    _bk_det.config(state="normal"); _bk_det.delete("1.0", tk.END)
    _bk_det.insert(tk.END, f"{bk.get('name','')}\n\n", "hdr")
    for k, v in bk.items():
        if k == "name": continue
        _bk_det.insert(tk.END, f"  {k:<14}: ", "key")
        _bk_det.insert(tk.END, f"{v}\n", "val")
    _bk_det.config(state="disabled")
_bk_lb.bind("<<ListboxSelect>>", _bk_on_select)
_bk_btn_f = tk.Frame(_bk_ctrl, bg=C["surface0"]); _bk_btn_f.pack(fill=tk.X, pady=(0,2))
