def _th_update_preview(*_):
    theme = _th_sel.get()
    if theme == "Custom":
        colors = {k: v.get() for k, v in _th_custom_vars.items()}
    else:
        colors = _CATPPUCCIN_THEMES.get(theme, _CATPPUCCIN_THEMES["Mocha (default)"])
    for k, sw in _th_swatches.items():
        sw.config(bg=colors.get(k, "#888888"))
    try:
        _th_custom_frame.pack_forget() if theme != "Custom" else _th_custom_frame.pack(fill=tk.X, padx=16, pady=4)
    except NameError:
        pass

