def _th_pick_color(key):
    import tkinter.colorchooser as _tcc
    current = _th_custom_vars[key].get()
    try:
        result = _tcc.askcolor(color=current, title=f"Pick color — {key}")
        if result and result[1]:
            _th_custom_vars[key].set(result[1])
            _th_custom_btns[key].config(bg=result[1])
            _th_update_preview()
    except Exception:
        pass

