def _th_walk_recolor(widget, colors):
    try:
        cls = widget.winfo_class()
        if cls in ("Frame", "Label", "Button", "Text", "Entry", "Listbox", "Canvas"):
            cur_bg = widget.cget("bg") if cls != "Canvas" else widget.cget("background")
            for old_key, new_hex in colors.items():
                old_hex = C.get(old_key, "")
                if old_hex and cur_bg.lower() == old_hex.lower():
                    try:
                        widget.config(bg=new_hex)
                    except Exception:
                        pass
                    break
            if cls in ("Label", "Button"):
                cur_fg = widget.cget("fg")
                for old_key, new_hex in colors.items():
                    old_hex = C.get(old_key, "")
                    if old_hex and cur_fg.lower() == old_hex.lower():
                        try:
                            widget.config(fg=new_hex)
                        except Exception:
                            pass
                        break
    except Exception:
        pass
    try:
        for child in widget.winfo_children():
            _th_walk_recolor(child, colors)
    except Exception:
        pass

def _th_apply():
    theme = _th_sel.get()
    new_colors = _CATPPUCCIN_THEMES.get(theme, _CATPPUCCIN_THEMES["Mocha (default)"])
    if theme == "Custom":
        new_colors = dict(new_colors)
        for _ck, _cv in _th_custom_vars.items():
            new_colors[_ck] = _cv.get()
    CONFIG["theme"] = theme
    if theme == "Custom":
        CONFIG["theme_custom"] = {k: v.get() for k, v in _th_custom_vars.items()}
    try:
        _vx_cfg_write(CONFIG)
        _sl(f"Theme set: {theme}", "CFG")
    except Exception as e:
        _th_status.set(f"✗ Could not save: {e}")
        return
    try:
        _th_walk_recolor(root, new_colors)
        C.update(new_colors)
        _th_status.set(f"✓ Theme '{theme}' saved and applied live.")
    except Exception:
        _th_status.set(f"✓ Theme '{theme}' saved.")
_th_btn_f = tk.Frame(_th_ctrl, bg=C["surface0"]); _th_btn_f.pack(side=tk.LEFT, padx=(16,0))
_mkbtn(_th_btn_f, "💾 Save Theme", _th_apply, C["mauve"])

