def _gi_draw_map(results):
    _gi_map_canvas.delete("all")
    w = _gi_map_canvas.winfo_width() or 600
    h = _gi_map_canvas.winfo_height() or 200
    _gi_map_canvas.create_rectangle(0, 0, w, h, fill="#1a1a2e", outline="")
    _gi_map_canvas.create_text(w//2, 10, text="GEO IP MAP  (equirectangular)", fill=C["overlay0"],
                                font=("Consolas",7), anchor="n")
    for r in results:
        try:
            lat = float(r.get("lat", 0)); lon = float(r.get("lon", 0))
            x = int((lon + 180) / 360 * w)
            y = int((90 - lat) / 180 * h)
            ip = r.get("query","")
            country = r.get("country","?")
            col = C["red"] if r.get("_threat") else C["teal"]
            _gi_map_canvas.create_oval(x-5, y-5, x+5, y+5, fill=col, outline=C["base"], width=1)
            _gi_map_canvas.create_text(x+8, y, text=f"{ip}\n{country}", fill=col,
                                        font=("Consolas",6), anchor="w")
        except Exception: pass
def _gi_lookup():
    raw = _gi_ip_txt.get("1.0", tk.END).strip()
    import re as _re
    ips = list(set(_re.findall(r'\b(?:\d{1,3}\.){3}\d{1,3}\b', raw)))
    if not ips: messagebox.showwarning("Geo IP","No valid IPs found."); return
    if len(ips) > 30: ips = ips[:30]
    _gi_status.set(f"⏳ Geolocating {len(ips)} IP(s)...")
    def _worker():
        import urllib.request
        results = []
        for ip in ips:
            try:
                url = f"http://ip-api.com/json/{ip}?fields=status,country,countryCode,city,isp,org,as,lat,lon,query"
                with urllib.request.urlopen(url, timeout=8) as r:
                    d = json.loads(r.read())
                    d["_threat"] = False
                    results.append(d)
            except Exception as e:
                results.append({"query": ip, "country":"Error","city":"","isp":str(e)[:40],
                                 "as":"","lat":0,"lon":0,"_threat":False})
            import time as _t2; _t2.sleep(0.15)
        def _upd():
            for row in _gi_tree.get_children(): _gi_tree.delete(row)
            for r in results:
                _gi_tree.insert("", tk.END,
                    values=(r.get("query",""), r.get("country","?"), r.get("city",""),
                            r.get("isp","")[:50], r.get("as","")[:30],
                            r.get("lat",""), r.get("lon","")),
                    tags=("threat" if r.get("_threat") else "ok",))
            _gi_draw_map(results)
            _gi_status.set(f"✓ {len(results)} IP(s) geolocated")
        root.after(0, _upd)
    threading.Thread(target=_worker, daemon=True).start()
