def _tl2_draw():
    _tl2_status.set("⏳ Building timeline...")
    def _worker():
        try:
            rows = _db_query("SELECT file, timestamp, threat_score, malicious, yara_hits, iocs, tags FROM scans ORDER BY timestamp ASC LIMIT 200")
        except Exception as e:
            root.after(0, lambda: _tl2_status.set(f"✗ DB error: {e}")); return
        if not rows:
            root.after(0, lambda: (_tl2_canvas.delete("all"),
                                    _tl2_canvas.create_text(200,60,text="No scan data yet.",fill=C["overlay0"],font=("Consolas",9)),
                                    _tl2_status.set("No data"))); return
        COLORS = {"CRITICAL":C["red"],"HIGH":C["peach"],"MEDIUM":C["yellow"],"LOW":C["green"],"CLEAN":C["teal"]}
        BAR_W = 32; PAD = 10; H = 200; BOTTOM = 230
        total_w = max(600, len(rows) * (BAR_W + PAD) + PAD * 2)
        def _upd():
            _tl2_canvas.delete("all")
            _tl2_canvas.config(scrollregion=(0, 0, total_w, BOTTOM + 40))
            _tl2_canvas.create_text(PAD, 10, text="BEHAVIORAL TIMELINE — threat score per scan session",
                                     fill=C["overlay0"], font=("Consolas",7), anchor="w")
            _tl2_canvas.create_line(PAD, BOTTOM, total_w - PAD, BOTTOM, fill=C["surface2"], width=1)
            for i, (fname, ts, score, mal, yara_j, ioc_j, tags) in enumerate(rows):
                sc = score or 0
                bar_h = int(sc / 100 * H)
                x = PAD + i * (BAR_W + PAD)
                level = "CRITICAL" if sc >= 75 else ("HIGH" if sc >= 50 else ("MEDIUM" if sc >= 25 else "LOW"))
                col = COLORS.get(level, C["teal"])
                _tl2_canvas.create_rectangle(x, BOTTOM - bar_h, x + BAR_W, BOTTOM, fill=col, outline="")
                _tl2_canvas.create_text(x + BAR_W//2, BOTTOM - bar_h - 4, text=str(sc),
                                         fill=col, font=("Consolas",6), anchor="s")
                label = os.path.basename(fname or "?")[:8]
                _tl2_canvas.create_text(x + BAR_W//2, BOTTOM + 8, text=label,
                                         fill=C["overlay0"], font=("Consolas",5), anchor="n", angle=45)
            _tl2_status.set(f"✓ {len(rows)} session(s) shown")
        root.after(0, _upd)
    threading.Thread(target=_worker, daemon=True).start()
