def _fr_start():
    if _fr_running[0]: return
    try: port = int(_fr_port_sv.get().strip())
    except ValueError: messagebox.showwarning("Fake C2","Invalid port."); return
    resp_body = _fr_resp_entry.get("1.0", tk.END).encode("latin-1", "replace")
    _fr_running[0] = True
    _fr_status.set(f"● LISTENING  127.0.0.1:{port}")
    _fr_log(f"Fake C2 responder started on 127.0.0.1:{port}", "hdr")
    import socket as _sock
    def _server_loop():
        try:
            srv = _sock.socket(_sock.AF_INET, _sock.SOCK_STREAM)
            srv.setsockopt(_sock.SOL_SOCKET, _sock.SO_REUSEADDR, 1)
            srv.bind(("127.0.0.1", port))
            srv.listen(10)
            srv.settimeout(1.0)
            _fr_server[0] = srv
            while _fr_running[0]:
                try:
                    conn, addr = srv.accept()
                    data = b""
                    try:
                        conn.settimeout(2.0)
                        while True:
                            chunk = conn.recv(4096)
                            if not chunk: break
                            data += chunk
                            if len(data) > 8192 or b"\r\n\r\n" in data: break
                    except Exception: pass
                    ts = time.strftime("%H:%M:%S")
                    preview = data[:200].decode("latin-1","replace").replace("\r","").replace("\n"," ")
                    _fr_log(f"[{ts}] {addr[0]}:{addr[1]}  ->  {preview}", "req")
                    _sl(f"Fake C2 connection from {addr[0]}:{addr[1]}", "NET")
                    try: conn.sendall(resp_body)
                    except Exception: pass
                    try: conn.close()
                    except Exception: pass
                except _sock.timeout: continue
                except Exception as _se: _fr_log(f"Server error: {_se}", "dim")
            try: srv.close()
            except Exception: pass
        except Exception as e:
            root.after(0, lambda: _fr_status.set(f"✗ {e}"))
            _fr_log(f"Failed to bind port {port}: {e}", "dim")
            _fr_running[0] = False
    threading.Thread(target=_server_loop, daemon=True).start()
def _fr_stop():
    _fr_running[0] = False
    _fr_status.set("● STOPPED")
    _fr_log("Responder stopped.", "dim")
