def _sbio_record():
    if _sbio_running[0]: return
    target = _sbio_pid_sv.get().strip()
    if not target: messagebox.showwarning("I/O Recorder","Enter a PID or executable path."); return
    duration = _sbio_dur_sv.get()
    _sbio_running[0] = True
    _sbio_status.set(f"⏳ Recording for {duration}s...")
    for _sn in _sbio_tabs:
        _sbio_tabs[_sn].config(state="normal"); _sbio_tabs[_sn].delete("1.0",tk.END); _sbio_tabs[_sn].config(state="disabled")
    def _worker():
        import time as _t3
        start = _t3.time()
        proc = None
        pid = None
        if target.isdigit():
            pid = int(target)
        else:
            try:
                proc = subprocess.Popen([target], creationflags=0x08000000 if sys.platform=="win32" else 0)
                pid = proc.pid
            except Exception as e:
                root.after(0, lambda: _sbio_status.set(f"✗ Launch failed: {e}"))
                _sbio_running[0] = False; return
        _sbio_log("LOG", f"Recording PID {pid} for {duration}s", "hit")
        snap_before = {}
        snap_before_reg = {}
        if _psutil:
            try:
                p = _psutil.Process(pid)
                snap_before["files"] = set(str(f.path) for f in p.open_files())
                snap_before["conns"] = set(str(c) for c in p.connections())
            except Exception: pass
        try:
            import winreg as _wr
            for _hk, _hkn in [(_wr.HKEY_CURRENT_USER,"HKCU"),(_wr.HKEY_LOCAL_MACHINE,"HKLM")]:
                for _sk in ["SOFTWARE","SYSTEM\\CurrentControlSet"]:
                    try:
                        with _wr.OpenKey(_hk, _sk) as k: pass
                        snap_before_reg[f"{_hkn}\\{_sk}"] = True
                    except Exception: pass
        except ImportError: pass
        _t3.sleep(duration)
        if _psutil:
            try:
                p = _psutil.Process(pid)
                after_files = set(str(f.path) for f in p.open_files())
                after_conns = set(str(c) for c in p.connections())
                new_files = after_files - snap_before.get("files", set())
                new_conns = after_conns - snap_before.get("conns", set())
                for f in new_files: _sbio_log("FILES", f"  OPEN  {f}", "hit")
                for c in new_conns: _sbio_log("NETWORK", f"  CONN  {c}", "hit")
                if not new_files: _sbio_log("FILES", "  No new file handles detected.", "dim")
                if not new_conns: _sbio_log("NETWORK", "  No new connections detected.", "dim")
            except Exception as e: _sbio_log("LOG", f"psutil error: {e}", "dim")
        else:
            _sbio_log("LOG", "psutil not available — install for full I/O recording.", "dim")
            try:
                r = subprocess.run(["powershell","-NoProfile","-Command",
                    f"Get-Process -Id {pid} -ErrorAction SilentlyContinue | Select-Object Modules | ConvertTo-Json -Depth 1 -Compress"],
                    capture_output=True, text=True, timeout=10,
                    creationflags=0x08000000 if sys.platform=="win32" else 0)
                if r.stdout.strip(): _sbio_log("LOG", r.stdout.strip()[:500], "dim")
            except Exception: pass
        if proc:
            try: proc.terminate()
            except Exception: pass
        _sbio_running[0] = False
        root.after(0, lambda: _sbio_status.set(f"✓ Recording complete — PID {pid}"))
        _sbio_log("LOG", f"Recording ended — elapsed {_t3.time()-start:.1f}s", "hit")
    threading.Thread(target=_worker, daemon=True).start()
