_mx_txt.tag_configure("hdr",   foreground=C["red"],     font=("Consolas",8,"bold"))
_mx_txt.tag_configure("taken", foreground=C["red"],     font=("Consolas",8,"bold"))
_mx_txt.tag_configure("free",  foreground=C["green"])
