_PL_FETCH_HOST_SUFFIXES = ("raw.githubusercontent.com",)

def _pl_remote_url_ok(url: str) -> bool:
    from urllib.parse import urlparse
    try:
        u = urlparse(str(url or "").strip())
    except Exception:
        return False
    if u.scheme.lower() != "https" or not u.netloc:
        return False
    host = u.netloc.lower()
    if "@" in host:
        host = host.split("@", 1)[-1]
    if host.startswith("["):
        _end = host.find("]")
        host = host[1:_end] if _end > 0 else host
    elif host.count(":") == 1:
        host = host.rsplit(":", 1)[0]
    return any(host == s or host.endswith("." + s) for s in _PL_FETCH_HOST_SUFFIXES)

_PL_VALID_CLASSES    = {"Unverified", "Verified", "Elevated", "V0RTEX-Made"}
_PL_VALID_PERMS      = {
    "fs.read.external", "fs.write.zip", "fs.write.json", "fs.write.xml",
    "fs.write.csv", "fs.write.html", "fs.write.pdf",
    "fs.read.v0rtex.logs", "fs.read.v0rtex.reports",
    "net.background", "net.listen", "proc.read",
    "sys.read.registry", "sys.read.env",
}
_PL_HEADER_FIELDS    = [
    "V0RTEX Plugin", "Name", "Version", "Author",
    "Description", "Dependencies", "Class",
    "Elevated-Permissions", "Background-Network",
    "Background-Endpoints", "Min-V0RTEX-Version",
]
_PL_SIM_WARN  = 0.60
_PL_SIM_BAN   = 0.80
_PL_FETCH_JSON_MAX_BYTES = 8 * 1024 * 1024

def _pl_read_json_response(resp, max_bytes: int):
    buf = bytearray()
    while True:
        chunk = resp.read(65536)
        if not chunk:
            break
        if len(buf) + len(chunk) > max_bytes:
            raise ValueError("response_too_large")
        buf.extend(chunk)
    return json.loads(buf.decode("utf-8"))

