class PluginPermissionError(Exception):
    pass


def _pl_fetch_json(url, cache_path, timeout=8):
    if not _pl_remote_url_ok(url):
        reason = "url_host_not_allowed"
        if os.path.exists(cache_path):
            try:
                with open(cache_path, "r", encoding="utf-8") as f:
                    return json.load(f), True, reason
            except Exception:
                pass
        return None, True, reason
    try:
        req = _pl_urllib.Request(url, headers={"User-Agent": "V0RTEX/" + _VX_VER, "Accept": "application/json"})
        _ssl_ctx = _pl_ssl.create_default_context()
        with _pl_urllib.urlopen(req, timeout=timeout, context=_ssl_ctx) as r:
            data = _pl_read_json_response(r, _PL_FETCH_JSON_MAX_BYTES)
        with open(cache_path, "w", encoding="utf-8") as f:
            json.dump(data, f, indent=2)
        return data, False, None
    except _pl_urlerr.HTTPError as e:
        reason = f"HTTP {e.code} from repository"
    except _pl_urlerr.URLError as e:
        reason = f"Network error: {e.reason}"
    except OSError:
        reason = "No network"
    except Exception as e:
        reason = f"Fetch error: {e}"
    if os.path.exists(cache_path):
        try:
            with open(cache_path, "r", encoding="utf-8") as f:
                return json.load(f), True, reason
        except Exception:
            pass
    return None, True, reason


def _pl_load_remote_data():
    global _pl_banned_data, _pl_manifest, _pl_offline, _pl_offline_reason
    bd, off1, reason1 = _pl_fetch_json(_PL_BANNED_URL,   _PL_BANNED_CACHE)
    md, off2, reason2 = _pl_fetch_json(_PL_MANIFEST_URL,  _PL_MANIFEST_CACHE)
    _pl_offline = off1 or off2
    _pl_offline_reason = reason1 or reason2 or ""
    if bd: _pl_banned_data = bd
    if md: _pl_manifest    = md


