def _pl_save_local_ban(fname, plugin_id, similar_to, score):
    entry = {"file": fname, "id": plugin_id, "similar_to": similar_to, "score": round(score, 3)}
    _pl_local_bans.append(entry)
    try:
        with open(_PL_LOCAL_BAN, "w", encoding="utf-8") as f:
            json.dump(_pl_local_bans, f, indent=2)
    except Exception:
        pass


def _pl_parse_header(path):
    hdr = {}
    try:
        with open(path, "r", encoding="utf-8", errors="replace") as f:
            lines = [f.readline() for _ in range(15)]
        first_line = lines[0].strip()
        if first_line != "# V0RTEX Plugin":
            return None, "First line must be '# V0RTEX Plugin'"
        for line in lines[1:]:
            line = line.strip()
            if not line.startswith("#"):
                break
            if ":" in line:
                key, _, val = line[1:].partition(":")
                hdr[key.strip()] = val.strip()
        required = ["Name", "Version", "Author", "Description", "Dependencies",
                    "Class", "Elevated-Permissions", "Background-Network",
                    "Background-Endpoints", "Min-V0RTEX-Version"]
        for field in required:
            if field not in hdr:
                return None, f"Missing header field: {field}"
        if hdr["Class"] not in _PL_VALID_CLASSES:
            return None, f"Invalid Class: '{hdr['Class']}'"
        if hdr["Background-Network"].lower() not in ("yes", "no"):
            return None, "Background-Network must be 'yes' or 'no'"
        if hdr["Background-Network"].lower() == "yes" and hdr.get("Background-Endpoints", "none").lower() == "none":
            return None, "Background-Endpoints required when Background-Network is 'yes'"
        ep = hdr.get("Elevated-Permissions", "none")
        if ep.lower() != "none":
            declared = {p.strip() for p in ep.split(",")}
            invalid = declared - _PL_VALID_PERMS
            if invalid:
                return None, f"Unknown elevated permissions: {', '.join(invalid)}"
        try:
            def _parse_ver(v):
                parts = []
                for x in v.split("."):
                    try: parts.append(int(x))
                    except ValueError: break
                return tuple(parts) if parts else (0,)
            min_ver = _parse_ver(hdr["Min-V0RTEX-Version"])
            cur_ver = _parse_ver(_VX_VER)
            if not min_ver:
                return None, "Min-V0RTEX-Version must be a valid semver (e.g. 1.0.0)"
            if cur_ver < min_ver:
                return None, f"Requires V0RTEX {hdr['Min-V0RTEX-Version']} (running {_VX_VER})"
        except Exception:
            return None, "Min-V0RTEX-Version must be a valid semver (e.g. 1.0.0)"
        return hdr, None
    except Exception as e:
        return None, f"Header read error: {e}"


def _pl_hash_full(path):
    with open(path, "rb") as f:
        data = f.read()
    data = data.replace(b"\r\n", b"\n").replace(b"\r", b"\n")
    return _pl_hashlib.sha256(data).hexdigest()


def _pl_hash_structural(path):
    try:
        with open(path, "r", encoding="utf-8", errors="replace") as f:
            source = f.read()
        tokens = _pl_tokenize.generate_tokens(_pl_io.StringIO(source).readline)
        clean_lines = {}
        for tok_type, tok_str, (srow, _), _, _ in tokens:
            if tok_type in (_pl_tokenize.COMMENT, _pl_tokenize.NL, _pl_tokenize.NEWLINE):
                continue
            clean_lines.setdefault(srow, []).append(tok_str)
        try:
            tree = _pl_ast.parse(source)
            for node in _pl_ast.walk(tree):
                if isinstance(node, _pl_ast.Expr) and isinstance(node.value, _pl_ast.Constant) and isinstance(node.value.value, str):
                    for ln in range(getattr(node, "lineno", 0), getattr(node, "end_lineno", 0) + 1):
                        clean_lines.pop(ln, None)
        except Exception:
            pass
        structural = "\n".join(" ".join(v) for k, v in sorted(clean_lines.items()))
        return _pl_hashlib.sha256(structural.encode("utf-8")).hexdigest(), structural
    except Exception:
        return None, ""


def _pl_hash_ast(path):
    try:
        with open(path, "r", encoding="utf-8", errors="replace") as f:
            source = f.read()
        tree = _pl_ast.parse(source)
        counters = {"var": 0, "func": 0, "cls": 0}
        name_map = {}
        for node in _pl_ast.walk(tree):
            if isinstance(node, _pl_ast.FunctionDef):
                if node.name not in name_map:
                    name_map[node.name] = f"FUNC_{counters['func']}"; counters["func"] += 1
                node.name = name_map[node.name]
            elif isinstance(node, _pl_ast.ClassDef):
                if node.name not in name_map:
                    name_map[node.name] = f"CLS_{counters['cls']}"; counters["cls"] += 1
                node.name = name_map[node.name]
            elif isinstance(node, _pl_ast.Name):
                if node.id not in name_map and not node.id.startswith("__"):
                    name_map[node.id] = f"VAR_{counters['var']}"; counters["var"] += 1
                if node.id in name_map:
                    node.id = name_map[node.id]
        token_count = sum(1 for _ in _pl_ast.walk(tree))
        dump = _pl_ast.dump(tree)
        return _pl_hashlib.sha256(dump.encode("utf-8")).hexdigest(), token_count
    except Exception:
        return None, 0


def _pl_hamming_similarity(h1, h2):
    try:
        b1 = bytes.fromhex(h1[:32])
        b2 = bytes.fromhex(h2[:32])
        diff = sum(bin(a ^ b).count("1") for a, b in zip(b1, b2))
        return 1.0 - (diff / (len(b1) * 8))
    except Exception:
        return 0.0


def _pl_similarity_score(h_struct_local, tok_local, h_struct_banned, tok_banned):
    if not h_struct_local or not h_struct_banned:
        return 0.0
    hamming = _pl_hamming_similarity(h_struct_local, h_struct_banned)
    if tok_local == 0 or tok_banned == 0:
        tok_ratio = 0.0
    else:
        tok_ratio = min(tok_local, tok_banned) / max(tok_local, tok_banned)
    return (hamming * 0.6) + (tok_ratio * 0.4)


def _pl_check_banned(fname, hdr, h_full, h_struct, h_ast, tok_count):
    plugin_id = hdr.get("Name", fname).lower().replace(" ", "_")
    author    = hdr.get("Author", "")
    for entry in _pl_local_bans:
        if entry.get("file") == fname:
            return "local_ban", f"Blocked locally (similarity {entry['score']*100:.0f}% with '{entry['similar_to']}')", None
    for acct in _pl_banned_data.get("banned_accounts", []):
        if acct.get("github_username", "").lower() == author.lower():
            return "ban", f"Author '{author}' is permanently banned (Level 4 — {acct.get('reason_category','?')})", None
    best_score  = 0.0
    best_match  = None
    for entry in _pl_banned_data.get("banned_plugins", []):
        if h_full and h_full in entry.get("hash_full", []):
            return "ban", f"Exact match with banned plugin '{entry.get('id','?')}' (hash_full)", entry
        if h_struct and h_struct in entry.get("hash_structural", []):
            return "ban", f"Structural match with banned plugin '{entry.get('id','?')}' (comments stripped)", entry
        if h_ast and h_ast in entry.get("hash_ast", []):
            return "ban", f"AST match with banned plugin '{entry.get('id','?')}' (refactoring detected)", entry
        for hs in entry.get("hash_structural", []):
            score = _pl_similarity_score(h_struct, tok_count, hs, entry.get("ast_token_count", 0))
            if score > best_score:
                best_score = score
                best_match = entry
    if best_score >= _PL_SIM_BAN and best_match:
        _pl_save_local_ban(fname, plugin_id, best_match.get("id", "?"), best_score)
        return "local_ban", f"High similarity ({best_score*100:.0f}%) with banned plugin '{best_match.get('id','?')}' — blocked locally", best_match
    if best_score >= _PL_SIM_WARN and best_match:
        return "warn_sim", f"Suspicious similarity ({best_score*100:.0f}%) with banned plugin '{best_match.get('id','?')}'", best_match
    return "ok", "", None


def _pl_check_manifest(fname, hdr, h_full):
    global _pl_violations
    declared_class = hdr.get("Class", "Unverified")
    author         = hdr.get("Author", "")
    plugin_id      = hdr.get("Name", fname).lower().replace(" ", "_")
    for entry in _pl_manifest.get("plugins", []):
        if entry.get("id") == plugin_id or entry.get("author", "").lower() == author.lower():
            official_class = entry.get("class", "Unverified")
            if declared_class != official_class:
                return "block", f"Class mismatch \u2014 header says '{declared_class}' but repository says '{official_class}'"
            official_hash = entry.get("hash_full", "")
            if official_hash and h_full and h_full != official_hash:
                return "block", "File hash mismatch \u2014 plugin may have been tampered with"
            violation = entry.get("violation")
            if violation:
                lvl   = violation.get("level", 1)
                reason = violation.get("reason", "")
                deadline = violation.get("fix_deadline", "")
                _pl_violations[fname] = {"level": lvl, "reason": reason, "deadline": deadline}
                badge = f"\U0001f7e1 S.E.A. LEVEL {lvl} VIOLATION: {reason}" + (f" (fix by {deadline})" if deadline else "")
                return "violation", badge
            return "ok", ""
    if declared_class in ("Verified", "Elevated", "V0RTEX-Made"):
        return "block", f"Class '{declared_class}' claimed but no official repository record found \u2014 possible impersonation"
    return "ok", ""


def _pl_malware_scan(path):
    SUSPICIOUS_STRINGS = [
        "subprocess.call", "os.system", "eval(", "exec(", "compile(",
        "__import__", "ctypes", "socket.connect", "urllib.request.urlopen",
        "requests.post", "requests.get", "base64.b64decode",
        "marshal.loads", "pickle.loads", "shutil.rmtree",
        "os.remove", "winreg", "DeleteFile", "FormatDisk",
    ]
    HIGH_ENTROPY_THRESH = 5.5
    findings = []
    try:
        with open(path, "r", encoding="utf-8", errors="replace") as f:
            source = f.read()
        for s in SUSPICIOUS_STRINGS:
            if s in source:
                findings.append(f"Suspicious pattern: '{s}'")
        import math
        def _entropy(data):
            if not data: return 0.0
            freq = {}
            for c in data: freq[c] = freq.get(c, 0) + 1
            length = len(data)
            return -sum((v / length) * math.log2(v / length) for v in freq.values())
        for i, line in enumerate(source.splitlines(), 1):
            if len(line) > 80:
                ent = _entropy(line)
                if ent > HIGH_ENTROPY_THRESH:
                    findings.append(f"High entropy line {i} (entropy={ent:.2f}) — possible encoded payload")
                    break
        return findings
    except Exception as e:
        return [f"Scan error: {e}"]


def _pl_check_deps(path, hdr):
    warnings = []
    declared_raw = hdr.get("Dependencies", "none")
    if declared_raw.lower() == "none":
        declared = set()
    else:
        declared = {d.strip().lower() for d in declared_raw.split(",") if d.strip()}
    try:
        with open(path, "r", encoding="utf-8", errors="replace") as f:
            source = f.read()
        tree = _pl_ast.parse(source)
        imported = set()
        for node in _pl_ast.walk(tree):
            if isinstance(node, _pl_ast.Import):
                for alias in node.names:
                    imported.add(alias.name.split(".")[0].lower())
            elif isinstance(node, _pl_ast.ImportFrom) and node.module:
                imported.add(node.module.split(".")[0].lower())
        stdlib = {
            "os", "sys", "re", "io", "ast", "math", "json", "time", "copy",
            "enum", "abc", "hmac", "uuid", "zlib", "gzip", "struct", "array",
            "queue", "heapq", "bisect", "decimal", "fractions", "random",
            "string", "textwrap", "difflib", "fnmatch", "glob", "shutil",
            "pathlib", "tempfile", "stat", "signal", "threading", "multiprocessing",
            "subprocess", "socket", "ssl", "hashlib", "base64", "binascii",
            "codecs", "csv", "configparser", "logging", "unittest", "traceback",
            "inspect", "functools", "itertools", "operator", "contextlib",
            "dataclasses", "typing", "collections", "weakref", "gc",
            "tkinter", "tkinter.ttk", "datetime", "calendar", "locale",
            "platform", "ctypes", "winreg", "urllib", "http", "email",
            "html", "xml", "sqlite3", "pickle", "shelve", "marshal",
            "importlib", "tokenize", "dis", "py_compile", "zipfile", "tarfile",
            "vx",
        }
        third_party = imported - stdlib - {os.path.splitext(os.path.basename(path))[0].lower()}
        undeclared = third_party - declared
        unused     = declared - third_party
        for u in undeclared:
            warnings.append(f"Undeclared dependency: '{u}'")
        for u in unused:
            warnings.append(f"Declared but unused dependency: '{u}'")
    except Exception as e:
        warnings.append(f"Dependency audit error: {e}")
    return warnings


def _pl_build_vx_api(fname, hdr):
    plugin_class = hdr.get("Class", "Unverified")
    perms_raw    = hdr.get("Elevated-Permissions", "none")
    perms        = set() if perms_raw.lower() == "none" else {p.strip() for p in perms_raw.split(",")}
    ALLOWED_VERIFIED = {
        "vx.ui.add_tab", "vx.ui.add_menu_entry", "vx.ui.notify", "vx.ui.get_theme",
        "vx.scan.get_last_result", "vx.scan.on_scan_complete", "vx.scan.get_history",
        "vx.ioc.get_last_extracted", "vx.notes.append", "vx.version.get",
    }
    ALLOWED_ELEVATED = {
        "vx.fs.read_external", "vx.fs.write_file", "vx.fs.read_logs", "vx.fs.read_reports",
        "vx.net.background_request", "vx.net.listen",
        "vx.proc.list_processes",
        "vx.sys.read_registry", "vx.sys.read_env",
    }
    ALLOWED = ALLOWED_VERIFIED | (ALLOWED_ELEVATED if plugin_class in ("Elevated", "V0RTEX-Made") else set())
    _scan_callbacks = []

    class _VxUI:
        def add_tab(self, name, frame):
            if plugin_class == "Unverified": raise PluginPermissionError("Unverified plugins cannot use vx.ui.add_tab")
            try: _nb.add(frame, text=f" {name} ")
            except Exception: pass
        def add_menu_entry(self, label, callback):
            if plugin_class == "Unverified": raise PluginPermissionError("Unverified plugins cannot use vx.ui.add_menu_entry")
        def notify(self, message, level="info"):
            if plugin_class == "Unverified": raise PluginPermissionError("Unverified plugins cannot use vx.ui.notify")
            try: _sl(f"[PLUGIN:{fname}] {message}", "EVT")
            except Exception: pass
            try:
                urgent = level == "error"
                root.after(0, lambda m=message, u=urgent, lv=level: _notify(f"Plugin — {lv.upper()}", m, urgent=u))
            except Exception: pass
        def get_theme(self):
            if plugin_class == "Unverified": raise PluginPermissionError("Unverified plugins cannot use vx.ui.get_theme")
            theme = dict(C)
            theme["font"] = FB[0] if isinstance(FB, (tuple, list)) else "Consolas"
            theme["font_bold"] = FB
            theme["font_small"] = FS
            return theme

    class _VxScan:
        def get_last_result(self):
            if plugin_class == "Unverified": raise PluginPermissionError("Unverified plugins cannot use vx.scan")
            try:
                conn = __import__("sqlite3").connect(DB_PATH)
                cur = conn.execute("SELECT * FROM scans ORDER BY rowid DESC LIMIT 1")
                cols = [d[0] for d in cur.description] if cur.description else []
                row = cur.fetchone()
                conn.close()
                return dict(zip(cols, row)) if row and cols else ({"file": row[0]} if row else None)
            except Exception: return None
        def on_scan_complete(self, callback):
            if plugin_class == "Unverified": raise PluginPermissionError("Unverified plugins cannot use vx.scan")
            _scan_callbacks.append(callback)
        def get_history(self, limit=10):
            if plugin_class == "Unverified": raise PluginPermissionError("Unverified plugins cannot use vx.scan")
            try:
                conn = __import__("sqlite3").connect(DB_PATH)
                cur = conn.execute("SELECT * FROM scans ORDER BY rowid DESC LIMIT ?", (limit,))
                cols = [d[0] for d in cur.description] if cur.description else []
                rows = [dict(zip(cols, r)) for r in cur.fetchall()]
                conn.close(); return rows
            except Exception: return []

    class _VxIoc:
        def get_last_extracted(self):
            if plugin_class == "Unverified": raise PluginPermissionError("Unverified plugins cannot use vx.ioc")
            return dict(_vx_last_iocs)

    class _VxNotes:
        def append(self, text):
            if plugin_class == "Unverified": raise PluginPermissionError("Unverified plugins cannot use vx.notes")
            try:
                notes_path = os.path.join(BASE_DIR, "notes.txt")
                with open(notes_path, "a", encoding="utf-8") as f:
                    f.write(text + "\n")
            except Exception: pass

    class _VxVersion:
        def get(self):
            return _VX_VER

    

    class _VxFs:
        def read_external(self, path):
            if "fs.read.external" not in perms:
                raise PluginPermissionError("fs.read.external not granted")
            try:
                with open(path, "rb") as f: return f.read()
            except Exception as e: raise PluginPermissionError(f"fs.read.external error: {e}")

        def write_file(self, filename, data, fmt):
            allowed_fmts = {
                "zip":  "fs.write.zip",  "json": "fs.write.json",
                "xml":  "fs.write.xml",  "csv":  "fs.write.csv",
                "html": "fs.write.html", "pdf":  "fs.write.pdf",
            }
            perm = allowed_fmts.get(fmt.lower())
            if not perm:
                raise PluginPermissionError(f"Format '{fmt}' is not a writable Elevated format")
            if perm not in perms:
                raise PluginPermissionError(f"{perm} not granted")
            safe_name = os.path.basename(filename)
            if not safe_name.lower().endswith(f".{fmt.lower()}"):
                safe_name = f"{safe_name}.{fmt.lower()}"
            plugin_folder = os.path.join(_PL_DIR, os.path.splitext(os.path.basename(fname))[0])
            os.makedirs(plugin_folder, exist_ok=True)
            dest = os.path.join(plugin_folder, safe_name)
            try:
                mode = "wb" if isinstance(data, bytes) else "w"
                enc  = None if isinstance(data, bytes) else "utf-8"
                with open(dest, mode, **({"encoding": enc} if enc else {})) as f:
                    f.write(data)
                return dest
            except Exception as e: raise PluginPermissionError(f"fs.write.{fmt} error: {e}")

        def read_logs(self):
            if "fs.read.v0rtex.logs" not in perms:
                raise PluginPermissionError("fs.read.v0rtex.logs not granted")
            try:
                result = {}
                if os.path.isdir(DEBUG_DIR):
                    for fn in os.listdir(DEBUG_DIR):
                        fp = os.path.join(DEBUG_DIR, fn)
                        if os.path.isfile(fp) and fn.endswith((".log", ".txt")):
                            try:
                                with open(fp, "r", encoding="utf-8", errors="replace") as f:
                                    result[fn] = f.read()
                            except Exception: pass
                return result
            except Exception as e: raise PluginPermissionError(f"fs.read.v0rtex.logs error: {e}")

        def read_reports(self):
            if "fs.read.v0rtex.reports" not in perms:
                raise PluginPermissionError("fs.read.v0rtex.reports not granted")
            try:
                result = {}
                if os.path.isdir(REPORTS_DIR):
                    for root_d, _, files in os.walk(REPORTS_DIR):
                        for fn in files:
                            if fn.endswith((".html", ".txt", ".json")):
                                fp = os.path.join(root_d, fn)
                                rel = os.path.relpath(fp, REPORTS_DIR)
                                try:
                                    with open(fp, "r", encoding="utf-8", errors="replace") as f:
                                        result[rel] = f.read()
                                except Exception: pass
                return result
            except Exception as e: raise PluginPermissionError(f"fs.read.v0rtex.reports error: {e}")

    class _VxNet:
        def background_request(self, method, url, **kwargs):
            if "net.background" not in perms:
                raise PluginPermissionError("net.background not granted")
            import threading as _t, urllib.request as _ur, urllib.error as _ue
            result_box = [None]
            def _do():
                try:
                    req = _ur.Request(url, method=method.upper(),
                                      headers=kwargs.get("headers", {}),
                                      data=kwargs.get("data"))
                    with _ur.urlopen(req, timeout=kwargs.get("timeout", 15)) as r:
                        result_box[0] = {"status": r.status, "body": r.read()}
                except Exception as e:
                    result_box[0] = {"error": str(e)}
            _t.Thread(target=_do, daemon=True).start()
            return result_box

        def listen(self, host, port, handler):
            if "net.listen" not in perms:
                raise PluginPermissionError("net.listen not granted")
            import socket as _s, threading as _t
            srv = _s.socket(_s.AF_INET, _s.SOCK_STREAM)
            srv.setsockopt(_s.SOL_SOCKET, _s.SO_REUSEADDR, 1)
            srv.bind((host, port))
            srv.listen(5)
            def _accept():
                try:
                    while True:
                        conn, addr = srv.accept()
                        _t.Thread(target=handler, args=(conn, addr), daemon=True).start()
                except Exception: pass
            _t.Thread(target=_accept, daemon=True).start()
            return srv

    class _VxProc:
        def list_processes(self):
            if "proc.read" not in perms:
                raise PluginPermissionError("proc.read not granted")
            try:
                import subprocess as _sp
                if sys.platform == "win32":
                    r = _sp.run(["tasklist", "/fo", "csv", "/nh"],
                                capture_output=True, text=True, timeout=10)
                    procs = []
                    for line in r.stdout.strip().splitlines():
                        parts = [p.strip('"') for p in line.split('","')] 
                        if len(parts) >= 2:
                            procs.append({"name": parts[0], "pid": parts[1],
                                          "mem": parts[4] if len(parts) > 4 else ""})
                    return procs
                else:
                    r = _sp.run(["ps", "aux"], capture_output=True, text=True, timeout=10)
                    procs = []
                    for line in r.stdout.strip().splitlines()[1:]:
                        cols = line.split(None, 10)
                        if len(cols) >= 11:
                            procs.append({"user": cols[0], "pid": cols[1],
                                          "cpu": cols[2], "mem": cols[3], "cmd": cols[10]})
                    return procs
            except Exception as e: raise PluginPermissionError(f"proc.read error: {e}")

    class _VxSys:
        def read_registry(self, key_path, value_name=None):
            if "sys.read.registry" not in perms:
                raise PluginPermissionError("sys.read.registry not granted")
            if sys.platform != "win32":
                raise PluginPermissionError("sys.read.registry is Windows only")
            try:
                import winreg as _wr
                hives = {
                    "HKEY_LOCAL_MACHINE":  _wr.HKEY_LOCAL_MACHINE,
                    "HKEY_CURRENT_USER":   _wr.HKEY_CURRENT_USER,
                    "HKEY_CLASSES_ROOT":   _wr.HKEY_CLASSES_ROOT,
                    "HKEY_USERS":          _wr.HKEY_USERS,
                    "HKEY_CURRENT_CONFIG": _wr.HKEY_CURRENT_CONFIG,
                }
                parts   = key_path.split("\\", 1)
                hive    = hives.get(parts[0])
                if hive is None: raise PluginPermissionError(f"Unknown hive: {parts[0]}")
                subkey  = parts[1] if len(parts) > 1 else ""
                key     = _wr.OpenKey(hive, subkey, 0, _wr.KEY_READ)
                if value_name is not None:
                    val, vtype = _wr.QueryValueEx(key, value_name)
                    _wr.CloseKey(key)
                    return {"value": val, "type": vtype}
                else:
                    result = {}
                    i = 0
                    while True:
                        try:
                            name, data, vtype = _wr.EnumValue(key, i)
                            result[name] = {"value": data, "type": vtype}
                            i += 1
                        except OSError: break
                    _wr.CloseKey(key)
                    return result
            except PluginPermissionError: raise
            except Exception as e: raise PluginPermissionError(f"sys.read.registry error: {e}")

        def read_env(self):
            if "sys.read.env" not in perms:
                raise PluginPermissionError("sys.read.env not granted")
            return dict(os.environ)

    class _VxApi:
        def __init__(self):
            self.ui      = _VxUI()
            self.scan    = _VxScan()
            self.ioc     = _VxIoc()
            self.notes   = _VxNotes()
            self.version = _VxVersion()
            if plugin_class in ("Elevated", "V0RTEX-Made"):
                self.fs   = _VxFs()
                self.net  = _VxNet()
                self.proc = _VxProc()
                self.sys  = _VxSys()
        def __getattr__(self, name):
            _sub_apis = {"ui", "scan", "ioc", "notes", "version", "fs", "net", "proc", "sys"}
            if name in _sub_apis:
                raise AttributeError(name)
            endpoint = f"vx.{name}"
            if endpoint not in ALLOWED:
                raise PluginPermissionError(f"vx.{name} is not a permitted API endpoint")
            raise AttributeError(name)

    return _VxApi(), _scan_callbacks


def _pl_run_security_check(fname):
    path = os.path.join(_PL_DIR, fname.replace("/", os.sep))
    result = {
        "fname": fname, "header": None, "class": "Unverified",
        "status": "unknown", "blocked": False, "warnings": [],
        "details": [], "sim_score": 0.0, "sim_target": None,
    }
    hdr, hdr_err = _pl_parse_header(path)
    if hdr is None:
        result["status"]  = "blocked"
        result["blocked"] = True
        result["details"].append(f"✗ Invalid header: {hdr_err}")
        return result
    result["header"] = hdr
    result["class"]  = hdr.get("Class", "Unverified")
    h_full          = _pl_hash_full(path)
    h_struct, _     = _pl_hash_structural(path)
    h_ast, tok      = _pl_hash_ast(path)
    ban_status, ban_msg, ban_entry = _pl_check_banned(fname, hdr, h_full, h_struct, h_ast, tok)
    if ban_status == "ban":
        result["status"]  = "blocked"
        result["blocked"] = True
        result["details"].append(f"✗ BANNED: {ban_msg}")
        return result
    if ban_status == "local_ban":
        result["status"]  = "blocked"
        result["blocked"] = True
        result["details"].append(f"✗ LOCAL BAN: {ban_msg}")
        return result
    if ban_status == "warn_sim":
        result["warnings"].append(f"⚠ Similarity warning: {ban_msg}")
        result["sim_score"] = float(ban_msg.split("(")[1].split("%")[0]) / 100 if "(" in ban_msg else 0.0
        result["sim_target"] = ban_entry.get("id") if ban_entry else None
    if not _pl_offline:
        manifest_status, manifest_msg = _pl_check_manifest(fname, hdr, h_full)
        if manifest_status == "block":
            result["status"]  = "blocked"
            result["blocked"] = True
            result["details"].append(f"✗ Repository check failed: {manifest_msg}")
            return result
        elif manifest_status == "violation":
            result["violation"] = _pl_violations.get(fname, {})
            result["warnings"].append(manifest_msg)
    else:
        result["warnings"].append("⚠ Offline mode — repository checks skipped (using cached data)")
    malware_findings = _pl_malware_scan(path)
    if malware_findings:
        if result["class"] in ("Verified", "Elevated", "V0RTEX-Made"):
            result["status"]  = "blocked"
            result["blocked"] = True
            for f_ in malware_findings:
                result["details"].append(f"✗ Malware scan: {f_}")
            return result
        else:
            for f_ in malware_findings:
                result["warnings"].append(f"⚠ Malware scan: {f_}")
    dep_warnings = _pl_check_deps(path, hdr)
    if dep_warnings:
        if result["class"] in ("Verified", "Elevated", "V0RTEX-Made"):
            result["status"]  = "blocked"
            result["blocked"] = True
            for w in dep_warnings:
                result["details"].append(f"✗ Dependency audit: {w}")
            return result
        else:
            for w in dep_warnings:
                result["warnings"].append(f"⚠ Dependency audit: {w}")
    result["status"] = "ok"
    result["details"].append(f"✓ Header valid — Class: {result['class']}")
    if not malware_findings:
        result["details"].append("✓ Malware scan: clean")
    if not dep_warnings:
        result["details"].append("✓ Dependency audit: clean")
    if not _pl_offline:
        result["details"].append("✓ Repository check: passed")
    return result


def _pl_get_class_icon(cls):
    return {"V0RTEX-Made": "🔴", "Elevated": "⚡", "Verified": "✅", "Unverified": "⚠️"}.get(cls, "❓")


def _pl_get_status_color(result):
    if result["blocked"]: return C["red"]
    viol = result.get("violation")
    if viol:
        return C["peach"] if viol.get("level", 1) >= 2 else C["yellow"]
    if result["warnings"]: return C["yellow"]
    return C["green"]


