def _pl_det_write(text, tag=""):
    _pl_det.config(state="normal")
    _pl_det.insert(tk.END, text, tag)
    _pl_det.config(state="disabled")


def _pl_det_clear():
    _pl_det.config(state="normal")
    _pl_det.delete("1.0", tk.END)
    _pl_det.config(state="disabled")


def _pl_listbox_label(fname, result):
    if result["blocked"]:
        icon = "🚫"
    elif result.get("violation"):
        lvl = result["violation"].get("level", 1)
        icon = "🟡" if lvl == 1 else "🟠"
    elif result["warnings"]:
        icon = "⚠"
    else:
        icon = "✓"
    cls      = result.get("class", "Unverified")
    cls_icon = _pl_get_class_icon(cls)
    en = "●" if _pl_enabled.get(fname) else "○"
    return f"{en} {icon} {cls_icon}  {fname}"


def _pl_refresh_list():
    global _pl_keys
    sel_fname = None
    if _pl_lb.curselection():
        idx = _pl_lb.curselection()[0]
        sel_fname = _pl_keys[idx] if idx < len(_pl_keys) else None
    _pl_lb.delete(0, tk.END)
    _pl_keys = list(_pl_scan_results.keys())
    for fname, result in _pl_scan_results.items():
        label = _pl_listbox_label(fname, result)
        _pl_lb.insert(tk.END, label)
        fg = _pl_get_status_color(result)
        _pl_lb.itemconfig(tk.END, fg=fg)
    if sel_fname and sel_fname in _pl_scan_results:
        if sel_fname in _pl_keys:
            _pl_lb.selection_set(_pl_keys.index(sel_fname))


def _pl_show_detail(fname):
    result = _pl_scan_results.get(fname)
    if not result: return
    hdr = result.get("header") or {}
    _pl_det_clear()
    cls      = result.get("class", "Unverified")
    cls_icon = _pl_get_class_icon(cls)
    cls_tag  = {"V0RTEX-Made": "cls_vxm", "Elevated": "cls_elv", "Verified": "cls_ver"}.get(cls, "cls_unv")
    _pl_det_write(f"{cls_icon}  {hdr.get('Name', fname)}  v{hdr.get('Version','?')}\n", cls_tag)
    _pl_det_write(f"Author: {hdr.get('Author','?')}    Class: {cls}\n", "dim")
    if hdr.get("Description"): _pl_det_write(f"{hdr['Description']}\n", "dim")
    _pl_det_write("\n── S.E.A. Security Report ──────────────────\n", "sea")
    for line in result.get("details", []):
        tag = "ok" if line.startswith("✓") else "err"
        _pl_det_write(f"  {line}\n", tag)
    for line in result.get("warnings", []):
        _pl_det_write(f"  {line}\n", "warn")
    if result["blocked"]:
        _pl_det_write("\n  🚫 PLUGIN BLOCKED — cannot be enabled\n", "ban")
    else:
        viol = result.get("violation")
        if viol:
            lvl    = viol.get("level", 1)
            reason = viol.get("reason", "")
            dl     = viol.get("deadline", "")
            badge  = "🟡" if lvl == 1 else "🟠"
            _pl_det_write("\n── S.E.A. Violation Record ──────────────────\n", "sea")
            _pl_det_write(f"  {badge} LEVEL {lvl} VIOLATION\n", "ban")
            _pl_det_write(f"  Reason   : {reason}\n", "warn")
            if dl: _pl_det_write(f"  Fix by   : {dl}\n", "warn")
            _pl_det_write("  Plugin remains loadable. Repeated violations escalate.\n", "dim")
        if _pl_enabled.get(fname):
            _pl_det_write("\n  ● Plugin is ENABLED\n", "ok")
        else:
            _pl_det_write("\n  ○ Plugin is disabled\n", "dim")
    if hdr.get("Elevated-Permissions", "none").lower() != "none":
        _pl_det_write("\n── Elevated Permissions ─────────────────────\n", "sea")
        for p in hdr["Elevated-Permissions"].split(","):
            _pl_det_write(f"  ⚡ {p.strip()}\n", "warn")
    if hdr.get("Dependencies", "none").lower() != "none":
        _pl_det_write(f"\n── Dependencies ─────────────────────────────\n", "sea")
        _pl_det_write(f"  {hdr['Dependencies']}\n", "dim")
    if _pl_offline:
        _pl_det_write("\n⚠ OFFLINE MODE — some checks used cached data\n", "warn")
    _pl_det.see("1.0")


def _pl_on_select(event=None):
    sel = _pl_lb.curselection()
    if not sel: return
    idx = sel[0]
    if idx < len(_pl_keys):
        _pl_show_detail(_pl_keys[idx])


_pl_lb.bind("<<ListboxSelect>>", _pl_on_select)


def _pl_check_version_update(fname, hdr):
    plugin_id = hdr.get("Name", fname).lower().replace(" ", "_")
    local_ver  = hdr.get("Version", "0.0.0")
    for entry in _pl_manifest.get("plugins", []):
        if entry.get("id") == plugin_id:
            repo_ver = entry.get("current_version", local_ver)
            if repo_ver != local_ver:
                return repo_ver
    return None


def _pl_scan_worker():
    global _pl_scan_results, _pl_offline
    root.after(0, lambda: _pl_status.set("\u23f3 Loading S.E.A. data..."))
    _pl_load_remote_data()
    _pl_load_local_bans()
    def _pl_set_offline_label():
        if not _pl_offline:
            _pl_offline_var.set("")
        elif _pl_offline_reason:
            short = _pl_offline_reason[:40]
            _pl_offline_var.set(f"[ OFFLINE — {short} ]")
        else:
            _pl_offline_var.set("[ OFFLINE — using cached data ]")
    root.after(0, _pl_set_offline_label)
    try:
        discovered = []
        for entry in os.listdir(_PL_DIR):
            entry_path = os.path.join(_PL_DIR, entry)
            if entry.endswith(".py") and os.path.isfile(entry_path):
                discovered.append(entry)
            elif os.path.isdir(entry_path):
                candidate = os.path.join(entry_path, entry + ".py")
                if os.path.isfile(candidate):
                    discovered.append(entry + "/" + entry + ".py")
        files = sorted(discovered)
    except Exception as e:
        root.after(0, lambda msg=f"\u2717 Scan error: {e}": _pl_status.set(msg))
        root.after(0, lambda: _pl_scan_btn.config(state="normal"))
        return
    new_results = {}
    for fname in files:
        root.after(0, lambda f=fname: _pl_status.set(f"\u27f3 Checking {f}..."))
        result = _pl_run_security_check(fname)
        hdr = result.get("header") or {}
        new_ver = _pl_check_version_update(fname, hdr)
        if new_ver:
            result["warnings"].append(f"\u26a0 Update available: v{new_ver} in official repository")
            mod = _pl_loaded.get(fname)
            if mod and hasattr(mod, "on_update"):
                try: mod.on_update(hdr.get("Version", "?"), new_ver)
                except Exception: pass
        new_results[fname] = result
    _pl_scan_results.clear()
    _pl_scan_results.update(new_results)
    blocked = sum(1 for r in _pl_scan_results.values() if r["blocked"])
    warned  = sum(1 for r in _pl_scan_results.values() if r["warnings"] and not r["blocked"])
    msg = f"\u2713 {len(files)} plugin(s) \u2014 {blocked} blocked, {warned} with warnings"
    root.after(0, lambda: _pl_status.set(msg))
    root.after(0, lambda: _sl(f"Plugin scan: {len(files)} found, {blocked} blocked", "EVT"))
    root.after(0, _pl_refresh_list)
    if _pl_scan_results:
        root.after(0, lambda: (_pl_lb.selection_set(0), _pl_on_select()))
    root.after(0, lambda: _pl_scan_btn.config(state="normal"))


def _pl_scan():
    _pl_scan_btn.config(state="disabled")
    threading.Thread(target=_pl_scan_worker, daemon=True).start()


def _pl_toggle_enable():
    print("[DBG] _pl_toggle_enable called")
    sel = _pl_lb.curselection()
    if not sel:
        print("[DBG] toggle: no selection")
        return
    idx = sel[0]
    if idx >= len(_pl_keys):
        print(f"[DBG] toggle: idx={idx} out of range, _pl_keys len={len(_pl_keys)}")
        return
    fname  = _pl_keys[idx]
    result = _pl_scan_results.get(fname)
    if not result:
        print(f"[DBG] toggle: no result for fname={fname!r}")
        return
    print(f"[DBG] toggle: fname={fname!r} blocked={result['blocked']} enabled={_pl_enabled.get(fname)}")
    if result["blocked"]:
        messagebox.showwarning("Plugin Blocked", f"'{fname}' is blocked by S.E.A. and cannot be enabled.")
        return
    if _pl_enabled.get(fname):
        _pl_do_disable(fname)
    else:
        _pl_do_enable(fname)


def _pl_do_enable(fname):
    print(f"[DBG] _pl_do_enable called: fname={fname!r}")
    result = _pl_scan_results.get(fname)
    if not result:
        messagebox.showwarning("Plugin Not Scanned", f"'{fname}' has no scan result.\nRun 'Scan & Verify' first.")
        return
    hdr    = result.get("header") or {}
    cls    = hdr.get("Class", "Unverified")
    print(f"[DBG] do_enable: cls={cls!r} hdr={list(hdr.keys())}")
    if cls == "Elevated":
        perms = hdr.get("Elevated-Permissions", "none")
        msg = (f"Plugin '{hdr.get('Name', fname)}' requires Elevated permissions:\n\n"
               f"{perms}\n\nDo you want to allow these permissions and enable this plugin?")
        print("[DBG] do_enable: showing elevated dialog...")
        _elev_ans = [False]
        _cx = root.winfo_x() + root.winfo_width()//2 - 240
        _cy = root.winfo_y() + root.winfo_height()//2 - 130
        _dlg = tk.Toplevel(root)
        _dlg.title("Elevated Permissions — S.E.A.")
        _dlg.resizable(False, False)
        _dlg.configure(bg=C["base"])
        _perms_count = len([p.strip() for p in perms.split(",") if p.strip()])
        _dlg_h = max(260, 180 + _perms_count * 28)
        _cy2 = root.winfo_y() + root.winfo_height()//2 - _dlg_h//2
        _dlg.geometry(f"480x{_dlg_h}+{_cx}+{_cy2}")
        _dlg.transient(root)
        _dlg.attributes("-topmost", True)
        _dlg_topbar = tk.Frame(_dlg, bg=C["surface0"], height=32)
        _dlg_topbar.pack(fill="x")
        _dlg_topbar.pack_propagate(False)
        tk.Label(_dlg_topbar, text="⚡  ELEVATED PERMISSIONS — S.E.A.",
                 font=("Consolas", 9, "bold"), bg=C["surface0"], fg=C["yellow"]).pack(side="left", padx=12, pady=6)
        tk.Frame(_dlg, bg=C["yellow"], height=1).pack(fill="x")
        _dlg_body = tk.Frame(_dlg, bg=C["base"], padx=18, pady=14)
        _dlg_body.pack(fill="both", expand=True)
        _pname = hdr.get("Name", fname)
        _perms_list = [p.strip() for p in perms.split(",") if p.strip()]
        tk.Label(_dlg_body, text=f"Plugin  '{_pname}'  requests elevated access:",
                 font=("Consolas", 9), bg=C["base"], fg=C["subtext"], anchor="w").pack(fill="x", pady=(0, 8))
        _pf = tk.Frame(_dlg_body, bg=C["surface1"], bd=0, highlightthickness=1,
                       highlightbackground=C["surface2"])
        _pf.pack(fill="x", pady=(0, 12))
        for _p in _perms_list:
            tk.Label(_pf, text=f"  ⚠  {_p}", font=("Consolas", 9), bg=C["surface1"],
                     fg=C["yellow"], anchor="w", pady=3).pack(fill="x", padx=8)
        tk.Label(_dlg_body, text="Allow these permissions and enable this plugin?",
                 font=("Consolas", 8), bg=C["base"], fg=C["muted"]).pack(anchor="w", pady=(0, 4))
        tk.Frame(_dlg, bg=C["surface2"], height=1).pack(fill="x")
        _bf = tk.Frame(_dlg, bg=C["surface0"], pady=10)
        _bf.pack(fill="x")
        def _elev_yes():
            _elev_ans[0] = True
            _dlg.destroy()
        def _elev_no():
            _elev_ans[0] = False
            _dlg.destroy()
        tk.Button(_bf, text="✓  Allow", font=("Consolas", 9, "bold"),
                  bg=C["green"], fg=C["base"], activebackground=C["green"],
                  relief="flat", bd=0, padx=18, pady=5,
                  cursor="hand2", command=_elev_yes).pack(side="left", padx=(18, 8))
        tk.Button(_bf, text="✕  Deny", font=("Consolas", 9, "bold"),
                  bg=C["red"], fg=C["base"], activebackground=C["maroon"],
                  relief="flat", bd=0, padx=18, pady=5,
                  cursor="hand2", command=_elev_no).pack(side="left")
        _dlg.protocol("WM_DELETE_WINDOW", _elev_no)
        _dlg.grab_set()
        _dlg.focus_force()
        root.wait_window(_dlg)
        ans = _elev_ans[0]
        print(f"[DBG] do_enable: dialog answer={ans}")
        if not ans:
            return
    if result.get("warnings") and cls == "Unverified":
        msg = (f"Plugin '{hdr.get('Name', fname)}' has security warnings:\n\n"
               + "\n".join(result["warnings"])
               + "\n\nLoad anyway at your own risk?")
        if not messagebox.askyesno("Security Warning — S.E.A.", msg, default=messagebox.YES, parent=root):
            return
    print("[DBG] do_enable: past dialogs, loading module...")
    path = os.path.join(_PL_DIR, fname.replace("/", os.sep))
    mod_name = fname.replace("/", ".").replace(os.sep, ".")[:-3]
    try:
        spec = _pl_ilu.spec_from_file_location(mod_name, path)
        mod  = _pl_ilu.module_from_spec(spec)
        vx_api, _ = _pl_build_vx_api(fname, hdr)
        mod.vx       = vx_api
        mod.root     = root
        mod.C        = C
        mod.FB       = FB
        mod.FS       = FS
        mod._nb      = _nb
        mod.BASE_DIR = BASE_DIR
        mod.PluginPermissionError = PluginPermissionError
        spec.loader.exec_module(mod)
        if hasattr(mod, "on_load"):
            mod.on_load()
        _pl_loaded[fname]  = mod
        _pl_enabled[fname] = True
        _sl(f"Plugin enabled: {fname} (class={cls})", "EVT")
        root.after(0, _pl_refresh_list)
        root.after(0, lambda f=fname: _pl_show_detail(f))
        if hasattr(mod, "run"):
            def _safe_run(m=mod, fn=fname):
                try:
                    m.run()
                except PluginPermissionError as _e:
                    messagebox.showerror("Permission Denied — S.E.A.", str(_e))
                    root.after(0, lambda f=fn: _pl_do_disable(f))
                except Exception as _e:
                    import traceback; traceback.print_exc()
                    messagebox.showerror("Plugin Error", f"'{fn}' run() failed:\n{_e}")
                    root.after(0, lambda f=fn: _pl_do_disable(f))
            root.after(10, _safe_run)
        def _pl_watch_window(fn=fname, m=mod):
            import time as _time
            dead_since = None
            while _pl_enabled.get(fn):
                try:
                    win = getattr(m, "_win", None)
                    if win is not None:
                        alive = False
                        try: alive = win.winfo_exists()
                        except Exception: pass
                        if not alive:
                            if dead_since is None:
                                dead_since = _time.monotonic()
                            elif _time.monotonic() - dead_since >= 10:
                                root.after(0, lambda f=fn: _pl_do_disable(f))
                                return
                        else:
                            dead_since = None
                            try:
                                win.protocol("WM_DELETE_WINDOW",
                                    lambda f=fn, w=win: (w.destroy(), root.after(0, lambda: _pl_do_disable(f))))
                            except Exception: pass
                except Exception: pass
                _time.sleep(1)
        threading.Thread(target=_pl_watch_window, daemon=True).start()
    except PluginPermissionError as e:
        import traceback; traceback.print_exc()
        messagebox.showerror("Permission Denied — S.E.A.", str(e))
        _pl_enabled[fname] = False
        root.after(0, _pl_refresh_list)
        root.after(0, lambda f=fname: _pl_show_detail(f))
        return
    except Exception as e:
        import traceback; traceback.print_exc()
        messagebox.showerror("Plugin Error", f"Failed to load '{fname}':\n{e}")
        _pl_enabled[fname] = False
        root.after(0, _pl_refresh_list)
        root.after(0, lambda f=fname: _pl_show_detail(f))
        return


def _pl_do_disable(fname):
    mod = _pl_loaded.get(fname)
    if mod and hasattr(mod, "on_unload"):
        try: mod.on_unload()
        except Exception: pass
    _pl_enabled[fname] = False
    _pl_loaded.pop(fname, None)
    _sl(f"Plugin disabled: {fname}", "EVT")
    _pl_refresh_list()
    _pl_show_detail(fname)


