def _sbar_tick():
    if _APP_DYING[0]: return
    try:
        import datetime as _dtsb
        _sb_time_sv.set(_dtsb.datetime.now().strftime("%H:%M:%S"))

        if _DEFENSE_ACTIVE.is_set():
            _sb_defense_sv.set("⚔ DEFENSE: ARMED")
        else:
            _sb_defense_sv.set("⬛ DEFENSE: OFF")

        with _defense_lock:
            _sb_threats_sv.set(f"threats: {len(_defense_results)}")
        _sb_scanned_sv.set(f"scanned: {_dsv_scanned.get()}")
        _sb_queue_sv.set(f"queue: {_sv_queue.get()}")

        cur_admin = _is_admin()
        with _ADMIN_STATUS_LOCK:
            prev = _ADMIN_STATUS[0]
            if cur_admin != prev:
                _ADMIN_STATUS[0] = cur_admin
                _log_admin_event(f"Admin status changed: {prev} -> {cur_admin}")
        if cur_admin:
            _sb_admin_sv.set(_ADM_BADGE_S + " !")
            _sb_admin_lbl.config(bg="#2a0010")
            try: root.title(_ADM_BADGE_W)
            except Exception: pass
        else:
            _sb_admin_sv.set("")
            _sb_admin_lbl.config(bg=C["crust"])
            try: root.title(f"{_VX_NAME}  v{_VX_VER}  by {_VX_AUTH}")
            except Exception: pass
    except Exception:
        pass
    if not _APP_DYING[0]:
        root.after(1000, _sbar_tick)

root.after(1200, _sbar_tick)


def _write_startup_scripts():
    _sl("Writing startup scripts", "SYS")
    """Generate (or regenerate) utility scripts on startup.
    Also copies v0rtex_log_censor.py to v0rtex_utils if found near the install dir.
    Files are always rewritten to stay in sync with the current version.
    They are deleted ONLY by the uninstall/reinstall/update/recovery process."""
    try:
        _tram = _build_trampoline_script()
        _media = os.path.join(os.path.dirname(BASE_DIR), "v0rtex_utils")
        os.makedirs(_media, exist_ok=True)
        for _name, _builder, _ba in [
            ("v0rtex_uninstall.py",   _build_uninstall_script,   (BASE_DIR, sys.executable, _tram)),
            ("v0rtex_reinstall.py",   _build_reinstall_script,   (BASE_DIR, sys.executable, _tram)),
            ("v0rtex_updater.py",     _build_updater_script,     (BASE_DIR, sys.executable)),
            ("v0rtex_recovery_ui.py", _build_recovery_ui_script, (BASE_DIR, sys.executable)),
            ("v0rtex_log_censor.py",  _build_censor_script,      ()),
        ]:
            _p = os.path.join(_media, _name)
            try:
                with open(_p, "w", encoding="utf-8") as _f:
                    _f.write(_builder(*_ba))
                _sl(f"write_startup_scripts: wrote {_name}", "SYS")
            except Exception as _we:
                _sl(f"write_startup_scripts: could not write {_name}: {_we}", "ERR")
    except Exception as _e:
        _sl(f"write_startup_scripts failed: {_e}", "ERR")

_sl("Scheduled: write startup scripts at +1200ms", "BOOT"); root.after(1200, _write_startup_scripts)
root.after(400, _take_startup_snapshot)
root.after(1800, lambda: threading.Thread(target=_run_startup_health_check, daemon=True).start())
