def _ai_gate_log(entry: dict):
    with _AI_GATE_LOCK:
        try:
            existing = []
            if os.path.isfile(_AI_GATE_LOG):
                try:
                    with open(_AI_GATE_LOG, "r", encoding="utf-8") as f:
                        existing = json.load(f)
                except Exception: existing = []
            existing.append(entry)
            existing = existing[-500:]
            with open(_AI_GATE_LOG, "w", encoding="utf-8") as f:
                json.dump(existing, f, indent=2)
            _ai_log_guardian_event("GATE_LOG", entry.get("action_type","?"))
        except Exception: pass

def _ai_log_guardian_event(event_type: str, detail: str = ""):
    try:
        day = time.strftime("%Y%m%d")
        p = os.path.join(_AI_GUARDIAN_LOG_DIR, f"guardian_{day}.log")
        with open(p, "a", encoding="utf-8") as f:
            f.write(f"[{time.strftime("%H:%M:%S")}] {event_type}"
                    + (f": {detail}" if detail else "") + "\n")
    except Exception: pass

