def _ai_chat_log_exchange(role: str, text: str, elapsed: float = 0.0,
                           action: dict | None = None):
    _f = _AI_CURRENT_CHAT_FILE[0]
    if not _f: return
    try:
        with _AI_CHAT_SESSION_LOCK:
            with open(_f, "a", encoding="utf-8") as f:
                ts = time.strftime("%H:%M:%S")
                pfx = "USER" if role == "user" else "AI  "
                f.write(f"[{ts}] {pfx}: {text}\n")
                if elapsed > 0:
                    f.write(f"         response_time={elapsed:.2f}s\n")
                if action:
                    f.write(f"         ACTION: {action.get('action','?')} -> "
                            f"{action.get('label', action.get('target','?'))}\n")
                if role == "assistant":
                    params = {k: CONFIG.get(k, d) for k, d in [
                        ("ai_temperature", 0.7), ("ai_top_p", 0.9), ("ai_top_k", 40),
                        ("ai_repeat_penalty", 1.1), ("ai_num_ctx", 4096), ("ai_seed", -1)]}
                    f.write(f"         [PARAMS SNAPSHOT]\n")
                    for k, v in params.items():
                        old = _AI_LAST_PARAMS.get(k)
                        chg = "  ← CHANGED" if (old is not None and old != v) else ""
                        f.write(f"           {k:22s} = {v}{chg}\n")
                    _AI_LAST_PARAMS.update(params)
                    hist_len = len(_AI_CHAT_HISTORY)
                    ctx_tokens_est = sum(len(m.get("content","")) // 4 for m in _AI_CHAT_HISTORY)
                    f.write(f"         [MEMORY SNAPSHOT]\n")
                    f.write(f"           history_messages   = {hist_len}\n")
                    f.write(f"           ctx_tokens_est     = {ctx_tokens_est}\n")
                    f.write(f"           model              = {CONFIG.get('ai_model','?')}\n")
                    f.write(f"           session_uptime_s   = {int(time.time()-_AI_START_TIME[0]) if _AI_START_TIME[0] else 0}\n")
                f.write("\n")
    except Exception: pass

