def _ai_argv_has_shell_tokens(parts: list) -> bool:
    bad = {"&", "|", ";", "&&", "||", "`"}
    return any(p in bad for p in parts)

def _ai_terminal_first_stem(tok: str) -> str:
    import pathlib as _plp
    p = _plp.Path(tok.strip().strip('"').strip("'"))
    if p.suffix.lower() == ".exe":
        return p.stem.lower()
    return p.name.lower()

def _ai_terminal_python_self_ok(first_tok: str) -> bool:
    try:
        return (os.path.normcase(os.path.abspath(first_tok))
                == os.path.normcase(os.path.abspath(sys.executable)))
    except Exception:
        return False

def _ai_terminal_check_cmd(cmd: str) -> tuple:
    import re as _re_t
    import shlex as _shx_t
    raw = (cmd or "").strip()
    if not raw:
        return False, "empty"
    if "\x00" in raw or "\r" in raw:
        return False, "invalid_cmd"
    cmd_stripped = raw.lower()
    for pat in _AI_TERMINAL_BLOCKED_PATTERNS:
        if _re_t.search(pat, cmd_stripped, _re_t.IGNORECASE):
            return False, f"Blocked pattern: {pat[:40]}"
    try:
        parts = _shx_t.split(raw, posix=(os.name != "nt"))
    except ValueError:
        return False, "cmd_parse_error"
    if not parts:
        return False, "empty"
    if _ai_argv_has_shell_tokens(parts):
        return False, "shell_chaining_not_allowed"
    platform_key = "win32" if sys.platform == "win32" else "linux"
    stem = _ai_terminal_first_stem(parts[0])
    allowed = _AI_TERMINAL_ALLOWED_FIRST[platform_key]
    if not (_ai_terminal_python_self_ok(parts[0]) or stem in allowed):
        return False, f"Command '{stem}' not in allowlist"
    return True, "ok"

def _ai_terminal_execute(cmd: str, source: str = "USER"):
    ok, reason = _ai_terminal_check_cmd(cmd)
    ts = time.strftime("%H:%M:%S")
    log_line = f"[{ts}] [{source}] {'OK' if ok else 'BLOCKED'}: {cmd}\n"
    try:
        day = time.strftime("%Y%m%d")
        with open(os.path.join(_AI_TERMINAL_LOG_DIR, f"terminal_{day}.log"), "a", encoding="utf-8") as f:
            f.write(log_line)
            if not ok: f.write(f"           REASON: {reason}\n")
    except Exception: pass
    if not ok:
        _ai_log_guardian_event("TERMINAL_BLOCKED", f"cmd={cmd[:60]} reason={reason}")
        return None, f"[GUARDIAN BLOCKED]: {reason}"
    try:
        import subprocess as _sp_t
        import shlex as _shx_t2
        parts = _shx_t2.split(cmd.strip(), posix=(os.name != "nt"))
        if not parts:
            return None, "empty_cmd"
        r = _sp_t.run(
            parts, shell=False, capture_output=True, text=True, timeout=15,
            creationflags=0x08000000 if sys.platform == "win32" else 0,
            stdin=_sp_t.DEVNULL,
        )
        out = (r.stdout + r.stderr).strip()[:4000]
        _ai_log_action("TERMINAL_EXEC", cmd[:80], after=out[:200])
        result = {"action": "TERMINAL", "cmd": cmd, "status": "ok",
                  "output": out, "timestamp": time.strftime("%Y-%m-%dT%H:%M:%S")}
        _ai_write_action_result(result)
        return out, None
    except Exception as _te:
        return None, str(_te)

def _ai_parse_action(text: str) -> dict | None:
    import re as _re
    m = _re.search(r'\{[^}]*"action"\s*:\s*"[A-Z_]+"[^}]*\}', text)
    if not m: return None
    try: return json.loads(m.group(0))
    except Exception: return None

def _ai_execute_nav(target: str) -> bool:
    nav_map = {
        "HOME": "_tab_home", "LOGS": "_tab_logs", "IOC": "_tab_ioc_host",
        "YARA": "_tab_yara_host", "SCANNER": "_tab_scan_host",
        "LOOKUP": "_tab_look_host", "PROCESS": "_tab_sb_host",
        "NETWORK": "_tab_net", "NOTES": "_tab_notes", "CRYPTO": "_tab_crypt",
        "CONFIG": "_tab_cfg", "SETTINGS": "_tab_globset",
        "PROTECTION": "_tab_prot", "DZ": "_tab_dz",
        "IOC/EXTRACT": "_lu_ioc_tab", "IOC/REPUT": "_tab_reput",
        "IOC/MITRE": "_tab_mitre", "IOC/SCORE": "_tab_threat_score",
        "IOC/CORRELATE": "_tab_ioc_corr", "IOC/ACTOR": "_tab_actor",
        "IOC/GEOIP": "_tab_geoip",
        "NETWORK/CONNECTIONS": "_net_conn_tab", "NETWORK/PORTSCAN": "_tab_portscan",
        "NETWORK/DNS": "_tab_dns", "NETWORK/EVTLOG": "_tab_evtlog",
        "LOOKUP/STRINGS": "_lu_str_tab", "LOOKUP/SHELLCODE": "_lu_sc_tab",
        "LOOKUP/HEX": "_tab_hex", "LOOKUP/REGEX": "_tab_regex",
        "LOOKUP/PREFETCH": "_lu_pf_tab", "LOOKUP/SCHTASKS": "_lu_sch_tab",
        "LOOKUP/VSS": "_lu_vss_tab", "LOOKUP/PIPES": "_lu_pipe_tab",
    }
    ref = nav_map.get(target.upper())
    if ref:
        try: _smart_nav(ref); return True
        except Exception: pass
    return False

def _ai_danger_gate(action: dict, callback):
    atype = action.get("action","").upper()
    label = action.get("label", action.get("target","?"))
    if atype == "NAV":
        callback(); return
    if atype == "READ":
        callback(); return
    if atype == "WRITE_SAFE":
        if messagebox.askyesno("AI Action", f"Allow AI to write:\n{label}?"):
            _ai_gate_log({"timestamp": time.strftime("%Y-%m-%dT%H:%M:%S"),
                          "action_type": atype, "label": label, "authorized": True})
            callback()
        else:
            _ai_gate_log({"timestamp": time.strftime("%Y-%m-%dT%H:%M:%S"),
                          "action_type": atype, "label": label, "authorized": False})
        return
    if atype in ("EXEC","SYSTEM"):
        _gw = tk.Toplevel(root); _gw.title("AI Action Authorization")
        _gw.configure(bg="#0a0a10"); _gw.resizable(False, False)
        _gw.geometry("520x240"); _gw.grab_set(); _gw.attributes("-topmost", True)
        tk.Frame(_gw, bg="#f38ba8", height=3).pack(fill="x")
        tk.Label(_gw, text=f"⚠  AI wants to: {atype}", font=("Consolas",11,"bold"),
                 bg="#0a0a10", fg="#f38ba8", padx=20, pady=12).pack(anchor="w")
        tk.Label(_gw, text=label, font=("Consolas",9), bg="#0a0a10",
                 fg="#cdd6f4", padx=20, wraplength=460).pack(anchor="w")
        if atype == "SYSTEM" and not _is_admin():
            tk.Label(_gw, text="⚠ Requires administrator mode", font=("Consolas",8),
                     bg="#0a0a10", fg="#f9e2af", padx=20).pack(anchor="w", pady=4)
        _cd_sv = tk.StringVar(value="5")
        _auth_btn = [None]
        def _tick_cd(n=5):
            if n > 0:
                _cd_sv.set(str(n))
                _gw.after(1000, lambda: _tick_cd(n-1))
            else:
                _cd_sv.set("AUTHORIZE")
                if _auth_btn[0]: _auth_btn[0].config(state="normal", bg="#f38ba8", fg="#0d0d14")
        _btn_row = tk.Frame(_gw, bg="#0a0a10", padx=20, pady=12); _btn_row.pack(fill="x")
        _ab = tk.Button(_btn_row, textvariable=_cd_sv, state="disabled",
                         bg="#313244", fg="#6c7086", font=("Consolas",10,"bold"),
                         relief="flat", bd=0, padx=16, pady=8, cursor="hand2",
                         command=lambda: (_ai_gate_log({"timestamp": time.strftime("%Y-%m-%dT%H:%M:%S"),
                             "action_type": atype, "label": label, "authorized": True}),
                             _gw.destroy(), callback()))
        _ab.pack(side="left", padx=(0,10))
        _auth_btn[0] = _ab
        tk.Button(_btn_row, text="Deny", bg="#313244", fg="#6c7086",
                  font=("Consolas",9), relief="flat", bd=0, padx=14, pady=8,
                  command=lambda: (_ai_gate_log({"timestamp": time.strftime("%Y-%m-%dT%H:%M:%S"),
                      "action_type": atype, "label": label, "authorized": False}),
                      _gw.destroy())).pack(side="left")
        _gw.after(100, _tick_cd)

def _ai_add_bubble(role: str, text: str, action: dict | None = None,
                   tech_info: dict | None = None):
    if _AI_CHAT_FRAME is None: return
    is_user = role == "user"
    bg_col  = C["surface0"] if is_user else C["mantle"]
    fg_col  = C["text"]
    align   = "e" if is_user else "w"
    frm = tk.Frame(_AI_CHAT_FRAME, bg=C["base"], pady=3)
    frm.pack(fill="x", padx=8)
    bubble = tk.Frame(frm, bg=bg_col, padx=10, pady=8)
    bubble.pack(anchor=align, fill="none")
    prefix = "You:  " if is_user else "AI:   "
    lbl = tk.Label(bubble, text=prefix + text, font=("Consolas",8), bg=bg_col, fg=fg_col,
                   wraplength=580, justify="left", anchor="w")
    lbl.pack(anchor="w")
    if action:
        atype_lbl = action.get("action","").upper()
        albl = action.get("label", action.get("target","?"))
        acolor = {"NAV": C["blue"], "EXEC": C["peach"], "WRITE_SAFE": C["teal"],
                  "SYSTEM": C["red"], "READ": C["sapphire"], "TERMINAL": C["green"],
                  "AUTOMATE": C["mauve"], "FILE_MOVE": C["yellow"],
                  "ENABLE_FEATURE": C["teal"]}.get(atype_lbl, C["overlay0"])
        tk.Label(bubble, text=f"⚡ {atype_lbl}: {albl}",
                 font=("Consolas",7,"bold"), bg=bg_col, fg=acolor,
                 anchor="w").pack(anchor="w", pady=(2,0))
    if not is_user and (action or tech_info):
        _tech_visible = [False]
        _tech_frame   = [None]
        def _toggle_tech(btn=None, _act=action, _ti=tech_info):
            if _tech_visible[0]:
                if _tech_frame[0]:
                    try: _tech_frame[0].destroy()
                    except Exception: pass
                    _tech_frame[0] = None
                _tech_visible[0] = False
                if btn: btn.config(text="▶ TECHNICAL INFO")
            else:
                tf = tk.Frame(bubble, bg="#11111b", padx=8, pady=6)
                tf.pack(anchor="w", fill="x", pady=(4,0))
                _tech_frame[0] = tf
                lines_out = []
                if _act:
                    lines_out.append(f"ACTION JSON:\n{json.dumps(_act, indent=2)}")
                if _ti:
                    for k, v in _ti.items():
                        if k in ("gate_result","danger_result") and isinstance(v, dict):
                            lines_out.append(f"{k.upper().replace(chr(95),' ')}:\n{json.dumps(v, indent=2)}")
                        elif k == "guardian_events" and isinstance(v, list):
                            lines_out.append("GUARDIAN EVENTS:\n" + "\n".join(f"  • {e}" for e in v))
                        elif k == "terminal_result":
                            lines_out.append(f"TERMINAL OUTPUT:\n{v}")
                        elif k == "elapsed":
                            lines_out.append(f"RESPONSE TIME: {float(v):.2f}s")
                        elif k == "scrubbed":
                            lines_out.append(f"SCRUBBED: {v}")
                        else:
                            lines_out.append(f"{k.upper()}: {v}")
                content = "\n\n".join(lines_out) if lines_out else "(no technical data)"
                n_lines = min(12, content.count("\n") + 2)
                txt = tk.Text(tf, font=("Consolas",7), bg="#11111b", fg="#6c7086",
                              relief="flat", bd=0, padx=4, pady=4,
                              wrap="word", state="normal", height=n_lines)
                txt.insert("1.0", content)
                txt.config(state="disabled")
                txt.pack(fill="x")
                _tech_visible[0] = True
                if btn: btn.config(text="▼ TECHNICAL INFO")
            try:
                _AI_CHAT_FRAME.update_idletasks()
                _AI_CHAT_FRAME.master.yview_moveto(1.0)
            except Exception: pass
        btn_row = tk.Frame(bubble, bg=bg_col); btn_row.pack(anchor="w", pady=(3,0))
        tech_btn = tk.Button(btn_row, text="▶ TECHNICAL INFO",
                             font=("Consolas",6), bg=bg_col, fg=C["overlay0"],
                             relief="flat", bd=0, padx=0, pady=0, cursor="hand2")
        tech_btn.config(command=lambda b=tech_btn: _toggle_tech(b))
        tech_btn.pack(side="left")
    try:
        _AI_CHAT_FRAME.update_idletasks()
        _AI_CHAT_FRAME.master.yview_moveto(1.0)
    except Exception: pass

def _ai_send_message(user_text: str):
    if not user_text.strip(): return
    if not _AI_THREAD_ALIVE[0]:
        _ai_add_bubble("assistant", "AI is not running. Press START first."); return
    try:
        with open(_AI_CURRENT_INPUT, "w", encoding="utf-8") as _cf: _cf.write(user_text)
    except Exception: pass
    if CONFIG.get("ai_guardian_input", True):
        user_clean, violations = _ai_guardian_check_input(user_text)
        if violations:
            _ai_log_guardian_event("INPUT_SANITISED", f"{len(violations)} violation(s)")
            root.after(0, lambda v=list(violations): _ai_show_input_blocked_popup(v))
            try:
                with open(_AI_CURRENT_INPUT, "w", encoding="utf-8") as _cf: _cf.write(user_clean)
            except Exception: pass
    else:
        user_clean = user_text; violations = []
    _AI_CHAT_HISTORY.append({"role": "user", "content": user_clean})
    _ai_add_bubble("user", user_text + (" [🛡 sanitised]" if violations else ""))
    _ai_chat_log_exchange("user", user_clean)
    _ai_ext_log_entry("user", user_clean, violations=violations)
    _ai_write_input_file(user_clean)
    ctx = _ai_build_context()
    ctx_str = json.dumps(ctx, indent=2)
    recent_results = _ai_read_action_results()
    results_str = ""
    if recent_results:
        last = recent_results[-1]
        results_str = f"\n\nLAST ACTION RESULT:\n{json.dumps(last, indent=2)}\n"
    sys_prompt = _AI_SYSTEM_PROMPT + f"\n\nCURRENT CONTEXT:\n{ctx_str}\n{results_str}"
    messages = [{"role": "system", "content": sys_prompt}]
    messages += _AI_CHAT_HISTORY[-int(CONFIG.get("ai_history_len", 20)):]
    def _worker():
        _ai_debug("Sending request to Ollama...")
        model = CONFIG.get("ai_model", "phi3:mini")
        t0 = time.time()
        thinking_text = ""
        try:
            import urllib.request as _ulr3
            opts = {
                "model": model, "messages": messages, "stream": False,
                "options": {
                    "temperature":    CONFIG.get("ai_temperature", 0.7),
                    "top_p":          CONFIG.get("ai_top_p", 0.9),
                    "top_k":          int(CONFIG.get("ai_top_k", 40)),
                    "repeat_penalty": CONFIG.get("ai_repeat_penalty", 1.1),
                    "num_ctx":        int(CONFIG.get("ai_num_ctx", 4096)),
                    "seed":           int(CONFIG.get("ai_seed", -1)),
                }
            }
            payload = json.dumps(opts).encode()
            req = _ulr3.Request(
                f"{_AI_OLLAMA_URL}/api/chat",
                data=payload,
                headers={"Content-Type": "application/json"},
                method="POST"
            )
            with _ai_urlopen_request(req, int(CONFIG.get("ai_request_timeout", CONFIG.get("ai_timeout", 180)))) as r:
                resp = _ai_read_limited_json_body(r, _AI_OLLAMA_CHAT_JSON_MAX_BYTES)
            elapsed = time.time() - t0
            raw = resp.get("message",{}).get("content","").strip()
            thinking_text = resp.get("message",{}).get("thinking","").strip()
            prompt_t = resp.get("prompt_eval_count", len(sys_prompt)//4)
            resp_t   = resp.get("eval_count", len(raw)//4)
            _ai_debug(f"Response received ({len(raw)} chars, {elapsed:.1f}s)")
            _ai_log_model_perf(model, elapsed, prompt_t, resp_t)
            try:
                with open(_AI_CURRENT_OUTPUT, "w", encoding="utf-8") as _ocf: _ocf.write(raw)
            except Exception: pass
            text, scrubbed = _ai_scrub_response(raw)
            if scrubbed:
                _ai_gate_log({"timestamp": time.strftime("%Y-%m-%dT%H:%M:%S"),
                              "action_type": "MEMORY_SCRUB", "authorized": False})
                _ai_debug("MEMORY_SCRUB: forbidden term or path in response, sanitised")
                _ai_log_guardian_event("RESPONSE_SCRUBBED", f"original_len={len(raw)}")
                try:
                    with open(_AI_CURRENT_OUTPUT, "w", encoding="utf-8") as _ocf: _ocf.write(text)
                except Exception: pass
                scrubbed_parts = [s for s in raw.split() if s.lower() not in text.lower()][:5]
                def _scrub_popup():
                    import tkinter.messagebox as _mb
                    _mb.showwarning("V0RTEX Security — Response Filtered",
                        "Part of the AI response was removed by V0RTEX Security.\n\n"
                        "Reason: Response contained sensitive path references or forbidden terms.\n"
                        "The cleaned response has been shown instead.\n\n"
                        "Check the guardian log for details.")
                root.after(500, _scrub_popup)
            action = _ai_parse_action(text)
            clean_text = text
            if action:
                import re as _re3
                clean_text = _re3.sub(r'\{[^}]*"action"\s*:\s*"[A-Z_]+"[^}]*\}', "", text).strip()
                atype = action.get("action","").upper()
                _ai_debug(f"Action parsed: {atype} -> {action.get('target','')}")
                _ai_log_action(atype, action.get("label", action.get("target","?")))
            _AI_CHAT_HISTORY.append({"role": "assistant", "content": clean_text})
            _ai_chat_log_exchange("assistant", clean_text, elapsed=elapsed, action=action)
            _ai_ext_log_entry("assistant", clean_text, thinking=thinking_text,
                               elapsed=elapsed, action=action)
            current_params = {k: CONFIG.get(k, d) for k, d in [
                ("ai_temperature", 0.7), ("ai_top_p", 0.9), ("ai_top_k", 40),
                ("ai_repeat_penalty", 1.1), ("ai_num_ctx", 4096), ("ai_seed", -1)]}
            if current_params != _AI_LAST_PARAMS:
                _ai_chat_log_params_snapshot("auto_change")
            _ai_write_output_file(clean_text)
            def _run_bg_checks(_raw=raw):
                _ai_neuron_check(_raw)
                if callable(globals().get("_ai_context_watchdog")):
                    _ai_context_watchdog(_raw)
            threading.Thread(target=_run_bg_checks, daemon=True).start()
            def _upd():
                _ai_add_bubble("assistant", clean_text, action)
                if action:
                    root.after(300, lambda a=action: _ai_action_verification(
                        a, clean_text, lambda: None))
                if _AI_STATUS_SV: _AI_STATUS_SV.set("● READY")
            root.after(0, _upd)
        except Exception as e:
            elapsed = time.time() - t0
            _ai_debug(f"Request error: {e}")
            _ai_log_session_event("REQUEST_ERROR", f"{e}")
            root.after(0, lambda: _ai_add_bubble("assistant", f"[Error: {e}]"))
            if _AI_STATUS_SV:
                root.after(0, lambda: _AI_STATUS_SV.set("● ERROR"))
    threading.Thread(target=_worker, daemon=True).start()
    if _AI_STATUS_SV: _AI_STATUS_SV.set("● THINKING...")

def _ai_write_input_file(text: str):
    try:
        with open(_AI_CURRENT_INPUT, "w", encoding="utf-8") as f: f.write(text)
        p = os.path.join(_AI_INPUT_DIR, f"input_{time.strftime('%H%M%S')}.txt")
        with open(p, "w", encoding="utf-8") as f: f.write(text)
        old = sorted([x for x in os.listdir(_AI_INPUT_DIR) if x.startswith("input_")])
        for fn in old[:-20]:
            try: os.remove(os.path.join(_AI_INPUT_DIR, fn))
            except Exception: pass
    except Exception: pass

def _ai_write_output_file(text: str):
    try:
        with open(_AI_CURRENT_OUTPUT, "w", encoding="utf-8") as f: f.write(text)
        p = os.path.join(_AI_OUTPUT_DIR, f"response_{time.strftime('%H%M%S')}.txt")
        with open(p, "w", encoding="utf-8") as f: f.write(text)
        old = sorted(os.listdir(_AI_OUTPUT_DIR))
        for fn in [x for x in old if x.startswith("response_")][:-10]:
            try: os.remove(os.path.join(_AI_OUTPUT_DIR, fn))
            except Exception: pass
    except Exception: pass

def _ai_read_and_apply_scrubbed_input() -> str:
    try:
        if os.path.isfile(_AI_CURRENT_INPUT):
            with open(_AI_CURRENT_INPUT, "r", encoding="utf-8") as f:
                return f.read()
    except Exception: pass
    return ""


