_AI_LOCKDOWN_OVERLAY = [None]

def _ai_check_lockdown():
    if os.path.isfile(_AI_LOCKDOWN):
        _AI_LOCKDOWN_SV.set("⛔ AI LOCKED — Security violation detected")
        try:
            if _AI_BANNER_FRAME and _AI_BANNER_FRAME.winfo_ismapped():
                _ai_lockdown_bar.pack(fill=tk.X, after=_AI_BANNER_FRAME)
            else:
                _ai_lockdown_bar.pack(fill=tk.X, before=_ai_ctrl_row)
        except Exception:
            try: _ai_lockdown_bar.pack(fill=tk.X)
            except Exception: pass
        try: _ai_ld_view_btn.pack(side=tk.LEFT, padx=4)
        except Exception: pass
        try: _ai_ld_unlock_btn.pack(side=tk.LEFT, padx=4)
        except Exception: pass
        if _AI_INPUT_ENTRY: _AI_INPUT_ENTRY.config(state="disabled")
        if _AI_SEND_BTN:    _AI_SEND_BTN.config(state="disabled")
        if _AI_STATUS_SV:   _AI_STATUS_SV.set("⛔ LOCKED")
        if _AI_LOCKDOWN_OVERLAY[0] is None and _AI_CHAT_FRAME is not None:
            try:
                ov = tk.Frame(_AI_CHAT_FRAME, bg="#1a0000")
                ov.place(relx=0, rely=0, relwidth=1, relheight=1)

                tk.Frame(ov, bg="#f38ba8", height=4).pack(fill="x")
                tk.Label(ov, text="\n⛔", font=("Consolas",52),
                         bg="#1a0000", fg="#f38ba8").pack(pady=(12,0))
                tk.Label(ov, text="AI MODULE LOCKED",
                         font=("Consolas",18,"bold"), bg="#1a0000", fg="#f38ba8").pack()
                tk.Frame(ov, bg="#3a0000", height=2).pack(fill="x", padx=40, pady=10)
                tk.Label(ov, text="A security violation was detected.\nThe Guardian has locked the AI module.",
                         font=("Consolas",9), bg="#1a0000", fg="#cdd6f4",
                         justify="center").pack(pady=(0,4))
                tk.Label(ov, text="Review the GUARDIAN -> VIOLATIONS tab before unlocking.",
                         font=("Consolas",8), bg="#1a0000", fg="#6c1a1a",
                         justify="center").pack()
                tk.Frame(ov, bg="#3a0000", height=1).pack(fill="x", padx=40, pady=(14,8))

                _ov_cd_sv  = tk.StringVar(value="5")
                _ov_btn_rf = [None]
                def _ov_tick(n=5):
                    if n > 0:
                        _ov_cd_sv.set(str(n))
                        try: ov.after(1000, lambda: _ov_tick(n-1))
                        except Exception: pass
                    else:
                        _ov_cd_sv.set("UNLOCK AI")
                        if _ov_btn_rf[0]:
                            try: _ov_btn_rf[0].config(state="normal", bg="#8b0000", fg="#f38ba8",
                                                        font=("Consolas",11,"bold"))
                            except Exception: pass
                def _ov_do_unlock():
                    try:
                        if _ov_btn_rf[0]: _ov_btn_rf[0].config(state="disabled")
                    except Exception: pass
                    _ai_unlock()
                _ov_btn = tk.Button(ov, textvariable=_ov_cd_sv, state="disabled",
                                     command=_ov_do_unlock,
                                     bg="#3a0000", fg="#6c1a1a",
                                     font=("Consolas",11), relief="flat", bd=0,
                                     padx=28, pady=12, cursor="watch")
                _ov_btn.pack(pady=4)
                _ov_btn_rf[0] = _ov_btn
                tk.Button(ov, text="-> View Violation Report", command=_ai_view_lockdown_report,
                          bg="#1a0000", fg="#6c1a1a", font=("Consolas",8),
                          relief="flat", bd=0, padx=12, pady=6, cursor="hand2").pack(pady=(4,0))
                tk.Frame(ov, bg="#f38ba8", height=4).pack(fill="x", side=tk.BOTTOM)
                ov.after(200, _ov_tick)
                _AI_LOCKDOWN_OVERLAY[0] = ov
            except Exception: pass
    else:
        try: _ai_lockdown_bar.pack_forget()
        except Exception: pass
        if _AI_LOCKDOWN_OVERLAY[0] is not None:
            try: _AI_LOCKDOWN_OVERLAY[0].destroy()
            except Exception: pass
            _AI_LOCKDOWN_OVERLAY[0] = None

def _ai_view_lockdown_report():
    import glob as _gl2
    zips = sorted(_gl2.glob(os.path.join(_AI_VIOLS_DIR, "*.zip")), reverse=True)
    if zips:
        try:
            if sys.platform == "win32": os.startfile(os.path.dirname(zips[0]))
            else: subprocess.Popen(["xdg-open", os.path.dirname(zips[0])])
        except Exception: pass
    else:
        messagebox.showinfo("Lockdown Report", f"No violation ZIPs found in:\n{_AI_VIOLS_DIR}")

def _ai_unlock():
    viol_info = ""
    try:
        logs = json.load(open(_AI_GATE_LOG, encoding="utf-8")) if os.path.isfile(_AI_GATE_LOG) else []
        viols = [l for l in logs if l.get("action_type") == "VIOLATION"]
        if viols: viol_info = f"\nLast violation: {viols[-1].get('label','unknown')}"
    except Exception: pass
    _uw = tk.Toplevel(root); _uw.title("Unlock AI"); _uw.configure(bg="#0a0a10")
    _uw.resizable(False,False); _uw.grab_set(); _uw.attributes("-topmost", True)
    tk.Frame(_uw, bg="#f38ba8", height=3).pack(fill="x")
    tk.Label(_uw, text="⛔  UNLOCK AI MODULE", font=("Consolas",12,"bold"),
             bg="#0a0a10", fg="#f38ba8", padx=20, pady=12).pack(anchor="w")
    tk.Label(_uw, text=f"A security violation was detected.{viol_info}\n\nUnlocking allows the AI to run again. Proceed only if you understand the risk.",
             font=("Consolas",8), bg="#0a0a10", fg="#cdd6f4", padx=20,
             wraplength=420, justify="left").pack(anchor="w")
    _ucd = tk.StringVar(value="10")
    _ubtn = [None]
    def _utick(n=10):
        if n > 0: _ucd.set(str(n)); _uw.after(1000, lambda: _utick(n-1))
        else:
            _ucd.set("CONFIRM UNLOCK")
            if _ubtn[0]: _ubtn[0].config(state="normal", bg="#f38ba8", fg="#0d0d14")
    def _do_unlock():
        try: os.remove(_AI_LOCKDOWN)
        except Exception: pass
        _ai_gate_log({"timestamp": time.strftime("%Y-%m-%dT%H:%M:%S"),
                      "action_type": "UNLOCK", "authorized": True})
        _uw.destroy(); _ai_check_lockdown()
    _ubr = tk.Frame(_uw, bg="#0a0a10", padx=20, pady=12); _ubr.pack(fill="x")
    _ub = tk.Button(_ubr, textvariable=_ucd, state="disabled",
                    bg="#313244", fg="#6c7086", font=("Consolas",10,"bold"),
                    relief="flat", bd=0, padx=16, pady=8, cursor="hand2", command=_do_unlock)
    _ub.pack(side="left", padx=(0,8)); _ubtn[0] = _ub
    tk.Button(_ubr, text="Cancel", bg="#313244", fg="#6c7086", font=("Consolas",9),
              relief="flat", bd=0, padx=14, pady=8, command=_uw.destroy).pack(side="left")
    _uw.after(100, _utick)

_ai_ld_view_btn   = tk.Button(_ai_lockdown_bar, text="-> VIEW REPORT",
                               command=_ai_view_lockdown_report,
                               bg="#f38ba8", fg="#0d0d14", font=("Consolas",8,"bold"),
                               relief="flat", bd=0, padx=8, pady=3, cursor="hand2")
_ai_ld_unlock_btn = tk.Button(_ai_lockdown_bar, text="UNLOCK AI — I understand the risk",
                               command=_ai_unlock,
                               bg="#313244", fg="#cdd6f4", font=("Consolas",8),
                               relief="flat", bd=0, padx=8, pady=3, cursor="hand2")

_ai_ctrl_row = tk.Frame(_tab_ai_main, bg=C["surface0"], padx=10, pady=6); _ai_ctrl_row.pack(fill=tk.X)

_AI_ARMED = [False]

def _ai_start():
    if os.path.isfile(_AI_LOCKDOWN):
        _AI_STATUS_SV.set("⛔ AI LOCKED — unlock first"); return
    installed, running, has_model, model = _ai_check_ollama()
    if not installed:
        _ai_banner_var.set("⚠ Ollama not found — install it or run the Setup wizard")
        _AI_BANNER_FRAME.pack(fill=tk.X, before=_ai_ctrl_row)
        _AI_STATUS_SV.set("● OFFLINE — Ollama missing"); return
    if not running:
        _ai_banner_var.set("⚠ Ollama not running — starting service...")
        _AI_BANNER_FRAME.pack(fill=tk.X, before=_ai_ctrl_row)
        try:
            subprocess.Popen(["ollama", "serve"],
                             creationflags=0x08000000 if sys.platform == "win32" else 0)
            import time as _t4; _t4.sleep(2)
        except Exception as e:
            _AI_STATUS_SV.set(f"● ERROR — {e}"); return
    if not has_model:
        _ai_banner_var.set(f"⚠ Model '{model}' not found — go to AI -> MODELS tab to pull it")
        _AI_BANNER_FRAME.pack(fill=tk.X, before=_ai_ctrl_row)
        _AI_STATUS_SV.set(f"● OFFLINE — model missing"); return
    try: _AI_BANNER_FRAME.pack_forget()
    except Exception: pass
    _AI_STATUS_SV.set("● INITIALIZING SECURITY...")
    if _AI_INPUT_ENTRY: _AI_INPUT_ENTRY.config(state="disabled")
    if _AI_SEND_BTN:    _AI_SEND_BTN.config(state="disabled")
    root.after(50, lambda: _ai_guardian_splash(model))

def _ai_guardian_splash(model: str):
    BG_G = "#0a0008"; RED_G = "#f38ba8"; GRN_G = "#a6e3a1"; DIM_G = "#6c7086"
    sw = tk.Toplevel(root); sw.title("V0RTEX Security — Initializing")
    sw.configure(bg=BG_G); sw.resizable(False, False); sw.attributes("-topmost", True)
    W, H = 540, 340
    sw.geometry(f"{W}x{H}+{(sw.winfo_screenwidth()-W)//2}+{(sw.winfo_screenheight()-H)//2}")
    tk.Frame(sw, bg=RED_G, height=3).pack(fill="x")
    tk.Label(sw, text="🛡  V0RTEX SECURITY", font=("Consolas",13,"bold"),
             bg=BG_G, fg=RED_G, pady=10).pack()
    tk.Label(sw, text="Initializing security layer...",
             font=("Consolas",8), bg=BG_G, fg=DIM_G).pack()
    tk.Frame(sw, bg=RED_G, height=1).pack(fill="x", padx=16, pady=6)
    pf = tk.Frame(sw, bg=BG_G, padx=20); pf.pack(fill="x")
    PROCS = ["Loading security policy","Starting filesystem monitor",
             "Initializing input validation","Arming response scrubber",
             "Violation reports handler ready","Establishing action gate",
             "Security layer ACTIVE"]
    lbls = []
    for p in PROCS:
        l = tk.Label(pf, text=f"  [ ] {p}", font=("Consolas",8), bg=BG_G, fg=DIM_G, anchor="w")
        l.pack(anchor="w", pady=1); lbls.append(l)
    st_sv = tk.StringVar(value="")
    tk.Label(sw, textvariable=st_sv, font=("Consolas",8,"bold"), bg=BG_G, fg=GRN_G, pady=6).pack()
    def _step(i=0):
        if i < len(lbls):
            lbls[i].config(text=f"  [✓] {PROCS[i]}", fg=GRN_G)
            sw.update_idletasks(); sw.after(160, lambda: _step(i+1))
        else:
            st_sv.set("✓ V0RTEX Security initialized")
            sw.after(550, _finish)
    def _finish():
        try: sw.grab_release(); sw.destroy()
        except Exception: pass
        _ai_autodestruct_splash(model)
    sw.after(150, _step)
    try: sw.grab_set()
    except Exception: pass

def _ai_autodestruct_splash(model: str):
    BG_G = "#0a0008"; RED_G = "#f38ba8"; GRN_G = "#a6e3a1"; DIM_G = "#6c7086"
    sw2 = tk.Toplevel(root); sw2.title("V0RTEX Security — Failsafe")
    sw2.configure(bg=BG_G); sw2.resizable(False, False); sw2.attributes("-topmost", True)
    W, H = 540, 230
    sw2.geometry(f"{W}x{H}+{(sw2.winfo_screenwidth()-W)//2}+{(sw2.winfo_screenheight()-H)//2}")
    tk.Frame(sw2, bg=RED_G, height=3).pack(fill="x")
    tk.Label(sw2, text="⛔  FAILSAFE MODULE", font=("Consolas",12,"bold"),
             bg=BG_G, fg=RED_G, pady=8).pack()
    pf2 = tk.Frame(sw2, bg=BG_G, padx=20); pf2.pack(fill="x")
    PROCS2 = ["Loading failsafe configuration","Setting Armed = False (standby)","Failsafe standing by"]
    lbls2 = []
