def _ai_cfg_save():
    m = _ai_model_sv2.get().strip()
    for k, v in [
        ("ai_model", m),
        ("ai_ollama_url", _ai_cfg_url_sv.get().strip()),
        ("ai_timeout", int(_ai_cfg_timeout_sv.get().strip() or "120")),
        ("ai_history_len", int(_ai_cfg_history_sv.get().strip() or "20")),
        ("ai_autostart", _ai_cfg_autostart_bv.get()),
        ("ai_scrub_paths", _ai_cfg_scrub_bv.get()),
        ("ai_scrub_response", _ai_cfg_scrub_resp_bv.get()),
        ("ai_guardian_input", _ai_cfg_guardian_bv.get()),
        ("ai_extended_log", _ai_cfg_extlog_bv.get()),
        ("ai_extended_thinking", _ai_cfg_thinking_bv.get()),
        ("ai_use_action_results", _ai_cfg_results_bv.get()),
        ("ai_stream", _ai_cfg_stream_bv.get()),
    ]: CONFIG[k] = v
    _ai_active_model_sv.set(m)
    globals()["_AI_OLLAMA_URL"] = CONFIG["ai_ollama_url"]
    try:
        with open(CONFIG_PATH, "r", encoding="utf-8") as f: cfg = json.load(f)
    except Exception: cfg = {}
    cfg.update({k: CONFIG[k] for k in [
        "ai_model","ai_ollama_url","ai_timeout","ai_history_len","ai_autostart",
        "ai_scrub_paths","ai_scrub_response","ai_guardian_input","ai_extended_log",
        "ai_extended_thinking","ai_use_action_results","ai_stream"]})
    _vx_cfg_write(cfg)
    _ai_cfg_status.set(f"✓ Saved — model: {m}  guardian: {'on' if CONFIG['ai_guardian_input'] else 'OFF'}")
