_MDL_PULL_PROCS   = {}
_MDL_ROW_WIDGETS  = {}
_MDL_INSTALLED    = []

def _mdl_refresh_installed():
    def _fetch():
        installed = []
        try:
            import urllib.request as _ureq2
            _tags_req = _ureq2.Request(f"{_AI_OLLAMA_URL}/api/tags")
            with _ai_urlopen_request(_tags_req, 4) as _r:
                tags = _ai_read_limited_json_body(_r, _AI_OLLAMA_TAGS_JSON_MAX_BYTES)
            installed = [m.get("name","") for m in tags.get("models",[])]
        except Exception:
            pass
        def _apply(inst=installed):
            _MDL_INSTALLED.clear()
            _MDL_INSTALLED.extend(inst)
            if inst:
                _mdl_installed_sv.set("Installed: " + "  ·  ".join(inst))
            else:
                _mdl_installed_sv.set("Installed: none (Ollama not running or no models)")
            _known_names = [n for n, _, _ in _AI_KNOWN_MODELS]
            _base_vals   = ["phi3:mini","llama3.2:1b","llama3.2:3b","llama3.1:8b",
                             "mistral","gemma2:2b","qwen2.5:0.5b","deepseek-r1:1.5b"]
            _extra = [m for m in inst if m not in _base_vals]
            _combo_vals = _base_vals + _extra
            try: _ai_model_combo_main["values"] = _combo_vals
            except Exception: pass
            try: _ai_cfg_combo["values"] = _combo_vals
            except Exception: pass
            active = CONFIG.get("ai_model","phi3:mini")
            for name, widgets in _MDL_ROW_WIDGETS.items():
                is_inst = any(name in m for m in inst)
                is_act  = name == active
                try:
                    widgets["ind"].config(
                        text="●" if is_inst else "○",
                        fg=C["green"] if is_act else (C["teal"] if is_inst else C["overlay0"]))
                    widgets["pull_btn"].config(state="disabled" if is_inst else "normal",
                                               text="✓ installed" if is_inst else "⬇ Pull")
                    widgets["del_btn"].config(state="normal" if is_inst else "disabled")
                    widgets["use_btn"].config(
                        state="normal" if is_inst else "disabled",
                        bg=C["mauve"] if is_act else C["surface2"],
                        fg=C["base"] if is_act else C["text"],
                        text="✓ active" if is_act else "Use")
                except Exception:
                    pass
        try: root.after(0, _apply)
        except Exception: pass
    threading.Thread(target=_fetch, daemon=True).start()

def _mdl_pull(name):
    if name in _MDL_PULL_PROCS and _MDL_PULL_PROCS[name] is not None:
        return
    w = _MDL_ROW_WIDGETS.get(name, {})
    try:
        w["pull_btn"].config(state="disabled", text="⏳ pulling…")
        w["prog_var"].set(0)
        w["prog_lbl"].config(text="starting…")
        w["prog_row"].pack(fill=tk.X, pady=(2,0))
    except Exception:
        pass
    _mdl_status_sv.set(f"Pulling {name}…")
    def _worker():
        try:
            import subprocess as _sub2
            flags = 0x08000000 if sys.platform == "win32" else 0
            proc = _sub2.Popen(
                ["ollama", "pull", name],
                stdout=_sub2.PIPE, stderr=_sub2.STDOUT,
                creationflags=flags)
            _MDL_PULL_PROCS[name] = proc
            for raw in iter(proc.stdout.readline, b""):
                line = raw.decode("utf-8","ignore").strip()
                if not line: continue
                import re as _re2
                m = _re2.search(r'(\d+)%', line)
                if m:
                    pct = int(m.group(1))
                    def _upd(p=pct, l=line[:50]):
                        try:
                            w["prog_var"].set(p)
                            w["prog_lbl"].config(text=f"{p}%  {l}")
                        except Exception: pass
                    root.after(0, _upd)
            proc.wait()
            ok = proc.returncode == 0
            def _done(o=ok):
                try:
                    if o:
                        w["prog_lbl"].config(text="✓ done")
                        w["prog_var"].set(100)
                    else:
                        w["prog_lbl"].config(text="✗ failed")
                    _MDL_PULL_PROCS[name] = None
                    root.after(500, _mdl_refresh_installed)
                    _mdl_status_sv.set(f"{'✓ Pulled' if o else '✗ Failed'}: {name}")
                    root.after(3000, lambda: w["prog_row"].pack_forget() if w.get("prog_row") else None)
                except Exception: pass
            root.after(0, _done)
        except FileNotFoundError:
            def _err():
                try:
                    w["prog_lbl"].config(text="✗ ollama not found")
                    _mdl_status_sv.set("✗ ollama not in PATH")
                except Exception: pass
            root.after(0, _err)
        except Exception as _e2:
            def _err2(e=str(_e2)):
                try:
                    w["prog_lbl"].config(text=f"✗ {e[:40]}")
                    _mdl_status_sv.set(f"✗ Pull error: {e[:60]}")
                except Exception: pass
            root.after(0, _err2)
    threading.Thread(target=_worker, daemon=True).start()

def _mdl_delete(name):
    if not messagebox.askyesno("Remove Model",
            f"Remove model '{name}' from Ollama?\n\nThis will free disk space but the model will need to be re-pulled.",
            parent=root):
        return
    def _worker():
        try:
            import subprocess as _sub3
            flags = 0x08000000 if sys.platform == "win32" else 0
            r = _sub3.run(["ollama", "rm", name], capture_output=True, timeout=30, creationflags=flags)
            ok = r.returncode == 0
            def _done(o=ok):
                _mdl_status_sv.set(f"{'✓ Removed' if o else '✗ Failed to remove'}: {name}")
                root.after(200, _mdl_refresh_installed)
                if CONFIG.get("ai_model") == name:
                    CONFIG["ai_model"] = "phi3:mini"
                    _ai_active_model_sv.set("phi3:mini")
                    _ai_model_sv2.set("phi3:mini")
                    try:
                        with open(CONFIG_PATH, "r", encoding="utf-8") as _fc: _cfd = json.load(_fc)
                    except Exception: _cfd = {}
                    _cfd["ai_model"] = "phi3:mini"
                    try:
                        _vx_cfg_write(_cfd)
                    except Exception: pass
            root.after(0, _done)
        except Exception as _e3:
            root.after(0, lambda e=str(_e3): _mdl_status_sv.set(f"✗ Error: {e[:60]}"))
    threading.Thread(target=_worker, daemon=True).start()

