def _set_param_save_all():
    for key, _, default, _, _, _, desc in _AI_PARAM_DEFAULTS:
        sv = _SET_PARAM_SVS.get(key)
        if sv is None: continue
        try:
            raw = sv.get().strip()
            old = CONFIG.get(key, default)
            val = float(raw) if "." in raw or key in ("ai_temperature","ai_top_p","ai_repeat_penalty") else int(raw)
            CONFIG[key] = val
            _ai_log_settings_change(key, old, val, desc)
        except Exception: pass
    try:
        with open(CONFIG_PATH, "r", encoding="utf-8") as _f: _cfg_s = json.load(_f)
    except Exception: _cfg_s = {}
    for key, _, default, *_ in _AI_PARAM_DEFAULTS:
        _cfg_s[key] = CONFIG.get(key, default)
    _vx_cfg_write(_cfg_s)
    _ai_chat_log_params_snapshot("manual_save")
    _set_save_lbl.config(text="✓ Saved", fg=C["green"])
    _tab_ai_set.after(2000, lambda: _set_save_lbl.config(text="", fg=C["overlay0"]))

def _set_param_reset():
    for key, _, default, _, _, _, _ in _AI_PARAM_DEFAULTS:
        sv = _SET_PARAM_SVS.get(key)
        if sv: sv.set(str(default))
        old = CONFIG.get(key, default)
        CONFIG[key] = default
        _ai_log_settings_change(key, old, default, "reset to default")
    _set_param_save_all()

