def _bench_run():
    _bench_prog_sv.set("⏳ Detecting hardware...")
    _bench_result_sv.set("Running benchmark...")
    _bench_rec_sv.set("")
    def _worker():
        try:
            import platform as _pl
            cpu_name    = _pl.processor() or _pl.machine()
            cpu_count   = os.cpu_count() or 1
            ram_gb      = 0
            gpu_name    = "Unknown"
            gpu_vram_gb = 0
            try:
                import psutil as _psu2
                ram_gb = round(_psu2.virtual_memory().total / (1024**3), 1)
            except Exception: pass
            if sys.platform == "win32":
                try:
                    import subprocess as _sp_b
                    r = _sp_b.run(
                        ["wmic", "path", "win32_VideoController", "get", "name,AdapterRAM", "/format:csv"],
                        capture_output=True, text=True, timeout=8,
                        creationflags=0x08000000)
                    for line in r.stdout.splitlines():
                        parts = line.strip().split(",")
                        if len(parts) >= 3 and parts[2].strip().isdigit():
                            vram = int(parts[2]) // (1024**3)
                            if vram > gpu_vram_gb:
                                gpu_vram_gb = vram
                                gpu_name    = parts[1].strip() if parts[1].strip() else gpu_name
                except Exception: pass
            elif sys.platform == "linux":
                try:
                    import subprocess as _sp_b2
                    r2 = _sp_b2.run(["nvidia-smi", "--query-gpu=name,memory.total",
                                     "--format=csv,noheader"],
                                    capture_output=True, text=True, timeout=5)
                    if r2.returncode == 0:
                        ln = r2.stdout.strip().split("\n")[0].split(",")
                        gpu_name = ln[0].strip()
                        gpu_vram_gb = int(ln[1].replace("MiB","").strip()) // 1024
                except Exception: pass
            rec_model   = "phi3:mini"
            rec_reason  = ""
            if gpu_vram_gb >= 8:
                rec_model  = "llama3.1:8b"
                rec_reason = f"GPU {gpu_name} has {gpu_vram_gb}GB VRAM — 8B model runs fully on GPU"
            elif gpu_vram_gb >= 4 or ram_gb >= 12:
                rec_model  = "mistral"
                rec_reason = f"{'GPU' if gpu_vram_gb>=4 else 'RAM'} is sufficient for 7B Mistral"
            elif ram_gb >= 8:
                rec_model  = "llama3.2:3b"
                rec_reason = f"{ram_gb}GB RAM — 3B model recommended"
            elif ram_gb >= 5:
                rec_model  = "phi3:mini"
                rec_reason = f"{ram_gb}GB RAM — Phi3-Mini is the sweet spot"
            elif ram_gb >= 3:
                rec_model  = "llama3.2:1b"
                rec_reason = f"Only {ram_gb}GB RAM detected — 1B model recommended"
            else:
                rec_model  = "qwen2.5:0.5b"
                rec_reason = f"Very low RAM ({ram_gb}GB) — 0.5B only option"
            result_txt = (
                f"CPU   : {cpu_name or 'N/A'}  ({cpu_count} cores)\n"
                f"RAM   : {ram_gb} GB\n"
                f"GPU   : {gpu_name}\n"
                f"VRAM  : {gpu_vram_gb} GB\n"
                f"OS    : {sys.platform}  {_pl.release()}\n\n"
                f"Reason: {rec_reason}"
            )
            def _apply(rec=rec_model, txt=result_txt):
                _bench_result_sv.set(txt)
                _bench_rec_sv.set(rec)
                _bench_prog_sv.set("")
            root.after(0, _apply)
        except Exception as _be:
            root.after(0, lambda e=str(_be): (_bench_result_sv.set(f"Error: {e}"),
                                               _bench_prog_sv.set("")))
    threading.Thread(target=_worker, daemon=True).start()

def _bench_apply_rec():
    rec = _bench_rec_sv.get().strip()
    if rec:
        _mdl_set_active(rec)
        _bench_prog_sv.set(f"✓ Model set to {rec}")

