_GRD_GUARDIAN_ALIVE = [False]

def _grd_check_guardian_alive_bg():
    alive = False
    try:
        import psutil as _psu3
        for _p3 in _psu3.process_iter(["cmdline"]):
            try:
                if any("vx_ai_guardian" in a for a in (_p3.info["cmdline"] or [])):
                    alive = True; break
            except Exception: pass
    except Exception: pass
    _GRD_GUARDIAN_ALIVE[0] = alive
    root.after(0, _grd_apply_lock_status)

def _grd_apply_lock_status():
    guardian_alive = _GRD_GUARDIAN_ALIVE[0]
    adm  = "✓" if _AI_GRD_ADMIN_OK[0] else "✗"
    risk = "✓" if _AI_GRD_SESSION_UNLOCKED[0] else "✗"
    grd  = "✓ running" if guardian_alive else "✗ not running"
    if not guardian_alive and not _AI_GRD_SESSION_UNLOCKED[0]:
        _grd_lock_status_sv.set("Guardian: ✗ not running — cannot unlock Guardian tab")
    else:
        _grd_lock_status_sv.set(f"Admin: {adm}   Risk accepted: {risk}   Guardian: {grd}")

def _grd_update_lock_status():
    _grd_lock_status_sv.set("Checking guardian status...")
    threading.Thread(target=_grd_check_guardian_alive_bg, daemon=True).start()
    return _GRD_GUARDIAN_ALIVE[0]

def _grd_grant_admin():
    if not _is_admin():
        messagebox.showwarning("Admin Required",
            "V0RTEX is not running as administrator.\n\n"
            "Restart V0RTEX as admin (right-click -> Run as administrator) "
            "to access Guardian settings.", parent=root)
        return
    _AI_GRD_ADMIN_OK[0] = True
    _grd_admin_btn.config(text="✓ Admin granted", state="disabled",
                           bg="#003a00", fg=C["green"])
    _grd_risk_btn.config(state="normal")
    _grd_update_lock_status()
    _ai_log_guardian_event("GUARDIAN_TAB_ADMIN_GRANTED")

def _grd_accept_risk():
    guardian_alive = _grd_update_lock_status()
    if not guardian_alive:
        messagebox.showwarning("Guardian Not Running",
            "The Guardian process is not running.\n\n"
            "The Guardian tab cannot be unlocked while the guardian is stopped.\n"
            "Start V0RTEX normally to launch the guardian.", parent=root)
        return
    _rw = tk.Toplevel(root); _rw.title("Accept Risk"); _rw.configure(bg="#0d0000")
    _rw.resizable(False, False); _rw.grab_set(); _rw.attributes("-topmost", True)
    tk.Frame(_rw, bg=C["red"], height=3).pack(fill="x")
    tk.Label(_rw, text="⚠  ACCEPT RISK — GUARDIAN SETTINGS",
             font=("Consolas",12,"bold"), bg="#0d0000", fg=C["red"], padx=20, pady=12).pack(anchor="w")
    tk.Label(_rw, text=(
        "You are about to access Guardian configuration.\n\n"
        "Modifying these settings can:\n"
        "  • Disable or weaken security monitoring\n"
        "  • Allow the AI to bypass containment checks\n"
        "  • Prevent the guardian from detecting violations\n\n"
        "This unlock is valid for THIS SESSION ONLY.\n"
        "It resets when V0RTEX is closed."),
        font=("Consolas",8), bg="#0d0000", fg="#cdd6f4", padx=20,
        justify="left", wraplength=440).pack(anchor="w")
    _rcd = tk.StringVar(value="10")
    _rbtn = [None]
    def _rtick(n=10):
        if n > 0: _rcd.set(str(n)); _rw.after(1000, lambda: _rtick(n-1))
        else:
            _rcd.set("I UNDERSTAND THE RISK — UNLOCK")
            if _rbtn[0]: _rbtn[0].config(state="normal", bg=C["red"], fg="#0d0000")
    def _do_unlock_grd():
        _AI_GRD_SESSION_UNLOCKED[0] = True
        _rw.destroy()
        _grd_lock_frame.pack_forget()
        _grd_content.pack(fill=tk.BOTH, expand=True)
        _grd_update_lock_status()
        _ai_log_guardian_event("GUARDIAN_TAB_UNLOCKED", "session risk accepted")
    _rbr = tk.Frame(_rw, bg="#0d0000", padx=20, pady=12); _rbr.pack(fill="x")
    _rb  = tk.Button(_rbr, textvariable=_rcd, state="disabled",
                     bg="#3a0000", fg="#6c1a1a", font=("Consolas",10,"bold"),
                     relief="flat", bd=0, padx=16, pady=8, cursor="hand2",
                     command=_do_unlock_grd)
    _rb.pack(side="left", padx=(0,8)); _rbtn[0] = _rb
    tk.Button(_rbr, text="Cancel", bg="#1a0000", fg="#6c1a1a", font=("Consolas",9),
              relief="flat", bd=0, padx=14, pady=8, command=_rw.destroy).pack(side="left")
    _rw.after(100, _rtick)

