def _grd_make_listbox_editor(parent, label, hint, initial_items, add_cb, del_cb):
    tk.Frame(parent, bg="#3a0000", height=1).pack(fill=tk.X, padx=12, pady=(10,4))
    _grd_label(parent, label, bold=True, color="#f9e2af")
    if hint:
        tk.Label(parent, text=hint, font=("Consolas",7), bg="#0d0000",
                 fg="#6c7086", padx=12).pack(anchor="w")
    _fr = tk.Frame(parent, bg="#0d0000", padx=12); _fr.pack(fill=tk.X, pady=(2,0))
    _sc = tk.Scrollbar(_fr, orient="vertical", bg="#1a0000", troughcolor="#0d0000", relief="flat", bd=0, width=6)
    _lb = tk.Listbox(_fr, font=("Consolas",7), bg="#11111b", fg="#cdd6f4",
                     selectbackground="#f38ba8", selectforeground="#0d0d14",
                     relief="flat", bd=0, height=5, yscrollcommand=_sc.set)
    _sc.config(command=_lb.yview); _sc.pack(side=tk.RIGHT, fill=tk.Y); _lb.pack(fill=tk.X)
    for _item in initial_items: _lb.insert(tk.END, _item)
    _ctrl = tk.Frame(parent, bg="#0d0000", padx=12); _ctrl.pack(fill=tk.X, pady=(0,2))
    _sv = tk.StringVar()
    tk.Entry(_ctrl, textvariable=_sv, font=("Consolas",7),
             bg="#1a0000", fg="#cdd6f4", insertbackground="#cdd6f4",
             relief="flat", bd=2).pack(side=tk.LEFT, fill=tk.X, expand=True, padx=(0,4))
    def _add():
        v = _sv.get().strip()
        if v: _lb.insert(tk.END, v); _sv.set(""); add_cb(_lb)
    def _del():
        sel = _lb.curselection()
        if sel: _lb.delete(sel[0]); del_cb(_lb)
    tk.Button(_ctrl, text="Add",    command=_add, font=("Consolas",7),
              bg="#1a2e1a", fg="#a6e3a1", relief="flat", bd=0, padx=6, pady=3, cursor="hand2").pack(side=tk.LEFT, padx=2)
    tk.Button(_ctrl, text="Remove", command=_del, font=("Consolas",7),
              bg="#1a0000", fg="#f38ba8", relief="flat", bd=0, padx=6, pady=3, cursor="hand2").pack(side=tk.LEFT)
    return _lb


