def _grd_save_config():
    cfg = {}
    try:
        with open(_AI_GUARDIAN_CFG, "r", encoding="utf-8") as _fgc: cfg = json.load(_fgc)
    except Exception: pass

    for sv, ck, default in _grd_svs:
        try:
            old = CONFIG.get(ck, default)
            val = float(sv.get()) if "." in sv.get() else int(sv.get())
            CONFIG[ck] = val; cfg[ck] = val
            _ai_log_settings_change(ck, old, val, "guardian config")
            _ai_log_guardian_event("CONFIG_CHANGE", f"{ck}: {old!r} -> {val!r}")
        except Exception: pass

    for rk, rbv in _grd_rule_svs.items():
        old = CONFIG.get(rk, True)
        val = rbv.get(); CONFIG[rk] = val; cfg[rk] = val
        _ai_log_guardian_event("RULE_CHANGE", f"{rk}: {old!r} -> {val!r}")

    CONFIG["grd_fs_monitor"]             = _grd_fsmon_bv.get()
    CONFIG["grd_restart_on_save"]        = _grd_restart_bv.get()
    CONFIG["grd_write_prefix_overrides"] = list(_grd_wpfx_lb.get(0, tk.END))
    CONFIG["grd_extra_protected_files"]  = list(_grd_epf_lb.get(0, tk.END))
    cfg["grd_fs_monitor"]             = CONFIG["grd_fs_monitor"]
    cfg["grd_restart_on_save"]        = CONFIG["grd_restart_on_save"]
    cfg["grd_write_prefix_overrides"] = CONFIG["grd_write_prefix_overrides"]
    cfg["grd_extra_protected_files"]  = CONFIG["grd_extra_protected_files"]

    cfg["grd_injection_patterns"]    = list(_grd_inj_lb.get(0, tk.END))
    cfg["grd_forbidden_output_terms"]= list(_grd_out_lb.get(0, tk.END))
    cfg["grd_forbidden_input_terms"] = list(_grd_in_lb.get(0, tk.END))
    try:
        os.makedirs(os.path.dirname(_AI_GUARDIAN_CFG), exist_ok=True)
        with open(_AI_GUARDIAN_CFG, "w", encoding="utf-8") as _fgw:
            json.dump(cfg, _fgw, indent=2)
        _grd_save_lbl.config(text="✓ guardian_config.json written", fg=C["green"])
        _tab_ai_grd.after(3000, lambda: _grd_save_lbl.config(text="", fg="#6c1a1a"))
        if CONFIG.get("grd_restart_on_save"):
            _grd_restart_guardian()
    except Exception as _gse:
        _grd_save_lbl.config(text=f"✗ {_gse}", fg=C["red"])

