def _grd_refresh_status():
    import datetime as _dt_gs
    def _worker():

        pid_str, uptime_str, hash_str = "not running", "—", "—"
        try:
            import psutil as _psu4
            for _p4 in _psu4.process_iter(["pid","name","cmdline","create_time"]):
                try:
                    cmd = " ".join(_p4.info["cmdline"] or [])
                    if "vx_ai_guardian" in cmd:
                        pid_str = str(_p4.info["pid"])
                        ct = _dt_gs.datetime.fromtimestamp(_p4.info["create_time"])
                        delta = _dt_gs.datetime.now() - ct
                        h, rem = divmod(int(delta.total_seconds()), 3600)
                        m, s   = divmod(rem, 60)
                        uptime_str = f"{h:02d}:{m:02d}:{s:02d}"
                        break
                except Exception: pass
        except Exception: pid_str = "psutil missing"
        lockdown_str  = "⚠ ACTIVE" if os.path.isfile(_AI_LOCKDOWN) else "✓ clear"
        try:
            gate_count = len(json.load(open(_AI_GATE_LOG, encoding="utf-8"))) if os.path.isfile(_AI_GATE_LOG) else 0
        except Exception: gate_count = "err"
        viols_count = len(os.listdir(_AI_VIOLS_DIR)) if os.path.isdir(_AI_VIOLS_DIR) else 0
        config_str  = "✓ exists" if os.path.isfile(_AI_GUARDIAN_CFG) else "✗ not written"
        logdir_str  = "✓ exists" if os.path.isdir(_AI_GUARDIAN_LOG_DIR) else "✗ missing"
        hash_path   = os.path.join(_AI_PROTECTED, "guardian_hash.txt")
        hash_str    = "✓ present" if os.path.isfile(hash_path) else "✗ missing"


        mini_lines = []
        try:
            if os.path.isfile(_AI_GATE_LOG):
                entries = json.load(open(_AI_GATE_LOG, encoding="utf-8"))
                mini_lines = entries[-10:] if len(entries) >= 10 else entries
        except Exception: pass

        def _update():
            _grd_stat_vars["pid"].set(pid_str)
            _grd_stat_vars["uptime"].set(uptime_str)
            _grd_stat_vars["hash"].set(hash_str)
            _grd_stat_vars["lockdown"].set(lockdown_str)
            _grd_stat_vars["gate_entries"].set(str(gate_count))
            _grd_stat_vars["viols"].set(str(viols_count))
            _grd_stat_vars["config"].set(config_str)
            _grd_stat_vars["logdir"].set(logdir_str)

            _grd_mini_txt.config(state="normal")
            _grd_mini_txt.delete("1.0", tk.END)
            if mini_lines:
                for _entry in mini_lines:
                    _at = _entry.get("action_type","INFO")
                    _ts = _entry.get("timestamp","")[-8:] if _entry.get("timestamp") else ""
                    _lb = _entry.get("label","") or _entry.get("detail","")
                    _line = f"[{_ts}] {_at:<20} {_lb}\n"
                    _tag = _at if _at in ("VIOLATION","INPUT_SANITISED","CONFIG_CHANGE","TERMINAL_BLOCKED") else "default"
                    _grd_mini_txt.insert(tk.END, _line, _tag)
                _grd_mini_txt.see(tk.END)
            else:
                _grd_mini_txt.insert(tk.END, "(gate log empty or not found)", "default")
            _grd_mini_txt.config(state="disabled")
        root.after(0, _update)
    threading.Thread(target=_worker, daemon=True).start()

def _grd_autoref_loop():
    try:
        if _grd_autoref_bv.get():
            _grd_refresh_status()
    except Exception: pass
    try: root.after(5000, _grd_autoref_loop)
    except Exception: pass

