def _grd_kill_guardian():
    if not messagebox.askyesno("Kill Guardian",
        "⚠ Kill the Guardian process now?\n\nThe AI will be unmonitored until restarted."):
        return
    killed = False
    try:
        import psutil as _psu_k
        for _p in _psu_k.process_iter(["pid","cmdline"]):
            try:
                if "vx_ai_guardian" in " ".join(_p.info["cmdline"] or []):
                    _p.kill(); killed = True
            except Exception: pass
    except Exception as e: messagebox.showerror("Error", f"psutil error: {e}"); return
    if killed:
        _ai_log_guardian_event("GUARDIAN_KILLED", "user action via LOCKDOWN tab")
        messagebox.showinfo("Guardian Killed", "Guardian process terminated.")
    else:
        messagebox.showinfo("Not Found", "Guardian process not found.")

def _grd_restart_guardian():
    guardian_src = os.path.join(_AI_PROTECTED, "vx_ai_guardian.py")
    if not os.path.isfile(guardian_src):
        messagebox.showerror("Restart", f"Guardian script not found:\n{guardian_src}"); return
    try:
        import psutil as _psu_r
        for _p in _psu_r.process_iter(["pid","cmdline"]):
            try:
                if "vx_ai_guardian" in " ".join(_p.info["cmdline"] or []):
                    _p.kill()
            except Exception: pass
    except Exception: pass
    import time as _t_r; _t_r.sleep(0.3)
    try:
        subprocess.Popen([sys.executable, guardian_src,
                          "--watch", BASE_DIR,
                          "--lockdown-flag", _AI_LOCKDOWN,
                          "--gate-log", _AI_GATE_LOG,
                          "--viols-dir", _AI_VIOLS_DIR,
                          "--main-pid", str(os.getpid()),
                          "--write-token-path", _AI_WRITE_TOKEN],
                         creationflags=subprocess.CREATE_NO_WINDOW if sys.platform=="win32" else 0)
        _ai_log_guardian_event("GUARDIAN_RESTARTED", "user action via LOCKDOWN tab")
        messagebox.showinfo("Guardian Restarted", "Guardian process restarted.")
    except Exception as e:
        messagebox.showerror("Restart Error", str(e))

def _grd_force_lockdown():
    if not messagebox.askyesno("Force Lockdown",
        "⚠ Force AI lockdown now?\n\nThis will lock the AI immediately and kill Ollama.",
        parent=root):
        return
    try: open(_AI_LOCKDOWN, "w").close()
    except Exception: pass
    _ai_gate_log({"timestamp": __import__("time").strftime("%Y-%m-%dT%H:%M:%S"),
                  "action_type": "VIOLATION", "label": "MANUAL_LOCKDOWN", "authorized": False})
    _ai_log_guardian_event("MANUAL_LOCKDOWN", "forced by user via LOCKDOWN tab")
    _ai_check_lockdown()
    messagebox.showwarning("Lockdown Active", "AI lockdown flag set. AI is now locked.", parent=root)

def _grd_remove_lockdown():
    if not os.path.isfile(_AI_LOCKDOWN):
        messagebox.showinfo("Lockdown", "No active lockdown.", parent=root); return
    if not messagebox.askyesno("Remove Lockdown",
        "Remove the AI lockdown flag?\nThis allows the AI to run again.", parent=root):
        return
    try: os.remove(_AI_LOCKDOWN)
    except Exception as e: messagebox.showerror("Error", str(e), parent=root); return
    _ai_gate_log({"timestamp": __import__("time").strftime("%Y-%m-%dT%H:%M:%S"),
                  "action_type": "UNLOCK", "authorized": True})
    _ai_log_guardian_event("LOCKDOWN_REMOVED", "via LOCKDOWN tab")
    _ai_check_lockdown()
    messagebox.showinfo("Lockdown Removed", "Lockdown flag deleted. AI is now unlocked.", parent=root)

def _grd_redeploy_guardian():
    if not messagebox.askyesno("Redeploy Guardian",
        "Overwrite vx_ai_guardian.py from embedded source and rewrite hash?\n\n"
        "Guardian will be killed and restarted."):
        return
    try:
        guardian_dst = os.path.join(_AI_PROTECTED, "vx_ai_guardian.py")
        os.makedirs(_AI_PROTECTED, exist_ok=True)
        with open(guardian_dst, "w", encoding="utf-8") as _gf:
            _gf.write(_VXG_SOURCE.lstrip("\n"))
        import hashlib as _hl_r
        h = _hl_r.sha256(open(guardian_dst, "rb").read()).hexdigest()
        with open(os.path.join(_AI_PROTECTED, "vx_ai_guardian_hash.txt"), "w") as _hf:
            _hf.write(h)
        with open(os.path.join(_AI_PROTECTED, "guardian_hash.txt"), "w") as _hf:
            _hf.write(h)
        _ai_log_guardian_event("GUARDIAN_REDEPLOYED", "source + hash rewritten from embedded")
        _grd_restart_guardian()
    except Exception as e:
        messagebox.showerror("Redeploy Error", str(e))


