def _grd_load_gate_log():
    flt = _grd_gl_filter_sv.get()
    def _worker():
        entries = []
        try:
            if os.path.isfile(_AI_GATE_LOG):
                entries = json.load(open(_AI_GATE_LOG, encoding="utf-8"))
        except Exception as e: entries = [{"action_type":"ERROR","label":str(e),"timestamp":""}]
        if flt != "All":
            entries = [e for e in entries if e.get("action_type","") == flt]
        def _update():
            _grd_gl_txt.config(state="normal"); _grd_gl_txt.delete("1.0", tk.END)
            _grd_gl_count_lbl.config(text=f"{len(entries)} entries")
            for _e in entries:
                _at  = _e.get("action_type","INFO")
                _ts  = _e.get("timestamp","")
                _lb  = _e.get("label","") or _e.get("detail","")
                _line= f"[{_ts}] {_at:<22} {_lb}\n"
                _tag = _at if _at in ("VIOLATION","INPUT_SANITISED","CONFIG_CHANGE","TERMINAL_BLOCKED","UNLOCK") else "default"
                _grd_gl_txt.insert(tk.END, _line, _tag)
            _grd_gl_txt.see(tk.END); _grd_gl_txt.config(state="disabled")
        root.after(0, _update)
    threading.Thread(target=_worker, daemon=True).start()

def _grd_gl_export_csv():
    import csv as _csv_g
    try:
        entries = json.load(open(_AI_GATE_LOG, encoding="utf-8")) if os.path.isfile(_AI_GATE_LOG) else []
    except Exception as e: messagebox.showerror("Error", str(e)); return
    out = os.path.join(_AI_SECTOR, "gate_log_export.csv")
    try:
        with open(out, "w", newline="", encoding="utf-8") as _cf:
            w = _csv_g.DictWriter(_cf, fieldnames=["timestamp","action_type","label","detail","authorized"])
            w.writeheader(); w.writerows(entries)
        if sys.platform == "win32": os.startfile(out)
        else: subprocess.Popen(["xdg-open", os.path.dirname(out)])
    except Exception as e: messagebox.showerror("Export Error", str(e))

