def _grd_load_violations():
    import glob as _glb_v
    zips = sorted(_glb_v.glob(os.path.join(_AI_VIOLS_DIR, "*.zip")), reverse=True)
    _grd_viol_lb.delete(0, tk.END)
    _grd_viol_count_lbl.config(text=f"{len(zips)} ZIPs")
    for z in zips: _grd_viol_lb.insert(tk.END, os.path.basename(z))

def _grd_viol_show(event=None):
    import glob as _glb_v, zipfile as _zf_v
    sel = _grd_viol_lb.curselection()
    if not sel: return
    name = _grd_viol_lb.get(sel[0])
    zpath = os.path.join(_AI_VIOLS_DIR, name)
    _grd_viol_txt.config(state="normal"); _grd_viol_txt.delete("1.0", tk.END)
    try:
        with _zf_v.ZipFile(zpath) as _z:
            txt_files = [f for f in _z.namelist() if f.endswith(".txt")]
            content = "\n".join(
                f"── {fn} ──\n{_z.read(fn).decode('utf-8','replace')}"
                for fn in txt_files
            ) if txt_files else "(no .txt found in ZIP)"
        _grd_viol_txt.insert(tk.END, content)
    except Exception as e: _grd_viol_txt.insert(tk.END, f"Error reading ZIP: {e}")
    _grd_viol_txt.config(state="disabled")

def _grd_viol_delete_sel():
    sel = _grd_viol_lb.curselection()
    if not sel: return
    name = _grd_viol_lb.get(sel[0])
    if messagebox.askyesno("Delete", f"Delete {name}?"):
        try:
            os.remove(os.path.join(_AI_VIOLS_DIR, name))
            _grd_load_violations()
            _grd_viol_txt.config(state="normal"); _grd_viol_txt.delete("1.0",tk.END); _grd_viol_txt.config(state="disabled")
        except Exception as e: messagebox.showerror("Error", str(e))

def _grd_viol_delete_all():
    if messagebox.askyesno("Delete All", "Delete ALL violation ZIPs?\nThis cannot be undone."):
        try:
            import glob as _g4; [os.remove(f) for f in _g4.glob(os.path.join(_AI_VIOLS_DIR,"*.zip"))]
            _grd_load_violations()
            _grd_viol_txt.config(state="normal"); _grd_viol_txt.delete("1.0",tk.END); _grd_viol_txt.config(state="disabled")
        except Exception as e: messagebox.showerror("Error", str(e))

