def _grd_launch_panic():
    lvl = _grd_panic_sv.get()
    desc = _GRD_PANIC_DESCS.get(lvl,"")
    if not messagebox.askyesno("PANIC — AUTODESTRUCTION",
        f"⚠⚠ LAUNCH PANIC LEVEL {lvl}? ⚠⚠\n\n{desc}\n\n"
        f"{'THIS IS IRREVERSIBLE. ' if lvl==4 else ''}Are you absolutely sure?"):
        return
    if lvl >= 3 and not messagebox.askyesno("FINAL CONFIRM",
        f"FINAL CONFIRM — Level {lvl} will destroy data. Proceed?"):
        return
    destruct_path = os.path.join(
        os.path.dirname(os.path.dirname(os.path.abspath(sys.argv[0]))),
        "VX_FAILSAFE", "vx_autodestruction.py")
    try:
        subprocess.Popen([sys.executable, destruct_path, f"--level={lvl}",
                          f"--sector={_AI_SECTOR}"],
                         creationflags=subprocess.CREATE_NO_WINDOW if sys.platform=="win32" else 0)
        _ai_log_guardian_event("PANIC_LAUNCHED", f"level {lvl} — {desc}")
    except Exception as e:
        messagebox.showerror("Panic Error", f"Could not launch autodestruction:\n{e}")

