_trm_hsc = tk.Scrollbar(_tab_ai_trm, orient="horizontal", command=_trm_txt.xview,
                          bg=C["surface1"], troughcolor=C["base"], relief="flat", bd=0, width=7)
_trm_txt.config(xscrollcommand=_trm_hsc.set); _trm_sc.config(command=_trm_txt.yview)
_trm_txt.tag_configure("ok",      foreground=C["green"])
_trm_txt.tag_configure("err",     foreground=C["red"])
_trm_txt.tag_configure("blocked", foreground=C["yellow"])
_trm_txt.tag_configure("sys",     foreground=C["overlay0"])
_trm_txt.tag_configure("prompt",  foreground=C["teal"])

_trm_input_row = tk.Frame(_tab_ai_trm, bg=C["surface0"], padx=8, pady=6)
_trm_cmd_sv = tk.StringVar()
_trm_entry  = tk.Entry(_trm_input_row, textvariable=_trm_cmd_sv, font=("Consolas",9),
                        bg=C["mantle"], fg=C["teal"], insertbackground=C["teal"],
                        relief="flat", bd=2, state="disabled")
_trm_entry.pack(side=tk.LEFT, fill=tk.X, expand=True, padx=(0,6))
_trm_btn_row = tk.Frame(_tab_ai_trm, bg=C["surface0"], padx=8, pady=4)
_trm_btn_row.pack(fill=tk.X, side=tk.BOTTOM)
_trm_input_row.pack(fill=tk.X, side=tk.BOTTOM)
_trm_hsc.pack(side=tk.BOTTOM, fill=tk.X)
_trm_sc.pack(side=tk.RIGHT, fill=tk.Y)
_trm_txt.pack(fill=tk.BOTH, expand=True)

def _trm_log(msg: str, tag: str = "ok"):
    def _do():
        _trm_txt.config(state="normal")
        _trm_txt.insert(tk.END, msg + "\n", tag)
        _trm_txt.see(tk.END)
        _trm_txt.config(state="disabled")
    try: root.after(0, _do)
    except Exception: pass

def _trm_activate():
    if not _is_admin():
        messagebox.showwarning("AI Terminal", "Admin rights required to activate the AI Terminal.")
        return
    if _AI_TERMINAL_ACTIVE[0]: return

    _tw = tk.Toplevel(root)
    _tw.title("Activate AI Terminal")
    _tw.configure(bg="#0a0a10"); _tw.resizable(False, False)
    _tw.attributes("-topmost", True)
    try:
        _tw.update_idletasks()
        _ww, _wh = 520, 340
        _tw.geometry(f"{_ww}x{_wh}+{(_tw.winfo_screenwidth()-_ww)//2}+{(_tw.winfo_screenheight()-_wh)//2}")
    except Exception: _tw.geometry("520x340")
    try: _tw.grab_set()
    except Exception: pass

    tk.Frame(_tw, bg="#94e2d5", height=3).pack(fill="x")
    tk.Label(_tw, text="💻  ACTIVATE AI TERMINAL", font=("Consolas",11,"bold"),
             bg="#0a0a10", fg="#94e2d5", padx=20, pady=10).pack(anchor="w")
    tk.Frame(_tw, bg="#313244", height=1).pack(fill="x", padx=12)

    _body = tk.Frame(_tw, bg="#0a0a10", padx=20, pady=12); _body.pack(fill=tk.BOTH, expand=True)
    for _line, _clr in [
        ("This opens a restricted command terminal controlled by the Guardian.", "#cdd6f4"),
        ("", "#cdd6f4"),
        ("✓  Allowed:  dir · type · ipconfig · netstat · tasklist · ping", "#a6e3a1"),
        ("✗  Blocked:  del · rm · reg add · net user · wget · curl · exec", "#f38ba8"),
        ("", "#cdd6f4"),
        ("All commands are logged. The AI can request commands via TERMINAL action.", "#a6adc8"),
        ("The Guardian monitors and may block commands in real time.", "#a6adc8"),
    ]:
        tk.Label(_body, text=_line, font=("Consolas",8), bg="#0a0a10",
                 fg=_clr, anchor="w", justify="left").pack(anchor="w")

    _btn_row = tk.Frame(_tw, bg="#11111b", padx=16, pady=10); _btn_row.pack(fill=tk.X)
    _result = [False]
    def _do_cancel():
        _result[0] = False
        try: _tw.grab_release()
        except Exception: pass
        _tw.destroy()
    def _do_activate():
        _result[0] = True
        try: _tw.grab_release()
        except Exception: pass
        _tw.destroy()
    tk.Button(_btn_row, text="  ✕  Cancel  ", command=_do_cancel,
              font=("Consolas",9,"bold"), bg="#313244", fg="#cdd6f4",
              relief="flat", bd=0, padx=16, pady=8, cursor="hand2").pack(side=tk.LEFT)
    tk.Button(_btn_row, text="  ▶  Activate Terminal  ", command=_do_activate,
              font=("Consolas",9,"bold"), bg="#094040", fg="#94e2d5",
              relief="flat", bd=0, padx=16, pady=8, cursor="hand2").pack(side=tk.RIGHT)
    _tw.protocol("WM_DELETE_WINDOW", _do_cancel)
    try: _tw.wait_window()
    except Exception: pass

    if not _result[0]: return
    _AI_TERMINAL_ACTIVE[0] = True
    try: open(_AI_TERMINAL_LOCK, "w").close()
    except Exception: pass
    _trm_status_sv.set("● ACTIVE")
    _trm_guardian_sv.set(f"Guardian: monitoring  |  Allowed: {len(_AI_TERMINAL_ALLOWED_CMDS.get('win32' if sys.platform=='win32' else 'linux', []))} commands")
    _trm_entry.config(state="normal")
    _trm_log(f"[{time.strftime('%H:%M:%S')}] AI Terminal activated by user", "sys")
    _trm_log(f"[{time.strftime('%H:%M:%S')}] Type commands below. Guardian verifies all input.", "sys")
    _trm_log(f"[{time.strftime('%H:%M:%S')}] AI can request commands via TERMINAL action.", "sys")
    _ai_log_session_event("TERMINAL_ACTIVATED", "user")
    _ai_log_guardian_event("TERMINAL_ACTIVATED")

def _trm_deactivate():
    if not _AI_TERMINAL_ACTIVE[0]: return
    _AI_TERMINAL_ACTIVE[0] = False
    try: os.remove(_AI_TERMINAL_LOCK)
    except Exception: pass
    _trm_status_sv.set("● INACTIVE")
    _trm_guardian_sv.set("Guardian: inactive")
    _trm_entry.config(state="disabled")
    _trm_log(f"[{time.strftime('%H:%M:%S')}] Terminal deactivated", "sys")
    _ai_log_session_event("TERMINAL_DEACTIVATED")
    _ai_log_guardian_event("TERMINAL_DEACTIVATED")

def _trm_run_cmd(event=None):
    if not _AI_TERMINAL_ACTIVE[0]: return
    cmd = _trm_cmd_sv.get().strip()
    if not cmd: return
    _trm_cmd_sv.set("")
    _trm_log(f"\n[{time.strftime('%H:%M:%S')}] > {cmd}", "prompt")
    def _worker():
        out, err = _ai_terminal_execute(cmd, source="USER")
        if err:
            _trm_log(f"BLOCKED: {err}", "blocked")
        else:
            for line in (out or "").splitlines():
                _trm_log(line, "ok")
    threading.Thread(target=_worker, daemon=True).start()
_trm_entry.bind("<Return>", _trm_run_cmd)

tk.Button(_trm_btn_row, text="▶ Activate Terminal", command=_trm_activate,
          font=("Consolas",8,"bold"), bg=C["teal"], fg=C["base"],
          relief="flat", bd=0, padx=12, pady=5, cursor="hand2").pack(side=tk.LEFT)
tk.Button(_trm_btn_row, text="■ Deactivate", command=_trm_deactivate,
          font=("Consolas",8), bg=C["red"], fg=C["base"],
          relief="flat", bd=0, padx=10, pady=5, cursor="hand2").pack(side=tk.LEFT, padx=6)
tk.Button(_trm_btn_row, text="▶ Run", command=_trm_run_cmd,
          font=("Consolas",8), bg=C["surface2"], fg=C["text"],
          relief="flat", bd=0, padx=10, pady=5, cursor="hand2").pack(side=tk.LEFT)
tk.Label(_trm_btn_row,
         text="Allowed: dir/ls  type/cat  ipconfig/ifconfig  netstat  tasklist/ps  ping  nslookup  systeminfo",
         font=("Consolas",7), bg=C["surface0"], fg=C["overlay0"]).pack(side=tk.LEFT, padx=8)


root.after(4000, lambda: (
    _ai_banner_var.set("⚠ Ollama not found — click to configure") or
    _AI_BANNER_FRAME.pack(fill=tk.X, before=_ai_ctrl_row)
) if not _ai_check_ollama()[0] else None)
root.after(4500, _mdl_refresh_installed)
root.after(5000, _grd_update_lock_status)
def _ai_nb_tab_changed(event=None):
    try:
        idx = _ai_nb.index(_ai_nb.select())
        if idx == 2:
            _mdl_refresh_installed()
        elif idx == 4:
            _trm_guardian_sv.set(
                f"Guardian: {'monitoring' if _AI_TERMINAL_ACTIVE[0] else 'inactive'}  |  "
                f"Lock: {'ACTIVE' if os.path.isfile(_AI_TERMINAL_LOCK) else 'clear'}")
        elif idx == 5:
            _grd_update_lock_status()
    except Exception: pass
_ai_nb.bind("<<NotebookTabChanged>>", _ai_nb_tab_changed)

root.mainloop()
_sl("Mainloop returned — clean exit or window closed", "EXIT")
_sl_copy_to_final()

if _RECOVERY_REQUESTED[0] and not _APP_DYING[0]:
    try: root.destroy()
    except Exception: pass
    import time as _t_rec; _t_rec.sleep(0.15)
    _unified_recovery_ui(tb_str="Launched manually from Settings")